class Maze {
  constructor(
    map = [[]],
    start = [0, 0],
    target = [map.length - 1, map[0].length - 1]
  ) {
    this.map = map;
    this.start = start;
    this.target = target;
    this.visited = {};
    this.path = [];
    this.shortestPath = [];
  }

  isGoal(state = []) {
    return state[0] === this.target[0] && state[1] === this.target[1];
  }

  findNextStates(current) {
    const result = [];
    const directions = [[0, -1], [1, 0], [0, 1], [-1, 0]]; // left, down, right, up

    for (const [dx, dy] of directions) {
      const [x, y] = [current[0] + dx, current[1] + dy];
      if (x >= 0 && x < this.map.length && y >= 0 && y < this.map[0].length && !this.map[x][y]) {
        result.push([x, y]);
      }
    }

    return result;
  }

  dfs(current = this.start) {
    if (this.isGoal(current)) {
      this.path.push(current);
      if (!this.shortestPath.length || this.path.length < this.shortestPath.length) {
        this.shortestPath = [...this.path];
      }
      this.path.pop();
      return;
    }

    this.visited[current] = true;
    this.path.push(current);

    const nextStates = this.findNextStates(current);

    for (const nextState of nextStates) {
      if (!this.visited[nextState]) {
        this.dfs(nextState);
      }
    }

    this.visited[current] = false;
    this.path.pop();
  }

  startDfs() {
    this.path = [];
    this.shortestPath = [];
    this.visited = {};

    this.dfs();

    return this.shortestPath;
  }
}

