class ItemsManager {
  constructor() {
    this.BASE_URL = `${process.env.VUE_APP_BASE_URL}/api/items`;
  }

  /**
   * Fetches a list of items that match the given search query.
   * @param {string} search - The search query to filter items.
   * @returns {Promise} - A promise that resolves to the list of items.
   */
  getList(search) {
    return axios.get(this.BASE_URL, {
      params: { q: search },
    });
  }

  /**
   * Adds a new item to the list.
   * @param {Object} itemData - The data of the item to add.
   * @returns {Promise} - A promise that resolves to the added item.
   */
  addItem(itemData) {
    return axios.post(this.BASE_URL, itemData);
  }

  /**
   * Updates an existing item by its ID.
   * @param {string} id - The ID of the item to update.
   * @param {Object} itemData - The updated data of the item.
   * @returns {Promise} - A promise that resolves to the updated item.
   */
  updateItem(id, itemData) {
    return axios.put(`${this.BASE_URL}/${id}`, itemData);
  }

  /**
   * Deletes an item by its ID.
   * @param {string} id - The ID of the item to delete.
   * @returns {Promise} - A promise that resolves to the deletion confirmation.
   */
  deleteItem(id) {
    return axios.delete(`${this.BASE_URL}/${id}`);
  }
}

