/**
 * Determines if a given word can be spelled using a collection of letter tiles.
 * @param {string} word - The word that needs to be spelled.
 * @param {string} tiles - A string representing the collection of letter tiles available.
 * @return {boolean} - True if the word can be spelled using the tiles, false otherwise.
 */
function canSpell(word, tiles) {
  const wordFreq = {};
  const tilesFreq = {};

  word.toLowerCase().split('').forEach((char) => {
    wordFreq[char] = (wordFreq[char] || 0) + 1;
  });

  tiles.toLowerCase().split('').forEach((char) => {
    tilesFreq[char] = (tilesFreq[char] || 0) + 1;
  });

  for (let [char, count] of Object.entries(wordFreq)) {
    if ((tilesFreq[char] || 0) < count) {
      return false;
    }
  }

  return true;
}

// Test cases
console.log(canSpell("hello", "eollh")); // true
console.log(canSpell("hello", "eolh"));  // false
console.log(canSpell("Python", "typhon")); // true
console.log(canSpell("JavaScript", "scriptjava")); // true
console.log(canSpell("React", "trace")); // true
console.log(canSpell("Angular", "rngula")); // true
console.log(canSpell("Vue", "ev")); // false
