function createReducer() {
    const initialState = {
        language: ['ru', 'kz']
    };

    return function reducer(state = initialState, action) {
        switch (action.type) {
            case 'ADD_LANGUAGE':
                if (state.language.includes(action.payload)) {
                    return state;
                }
                return {
                    ...state,
                    language: [...state.language, action.payload]
                };
            case 'REMOVE_LANGUAGE':
                return {
                    ...state,
                    language: state.language.filter(lang => lang !== action.payload)
                };
            default:
                return state;
        }
    };
}

// Test cases
const reducer = createReducer();

// Test ADD_LANGUAGE action
let state = reducer(undefined, { type: 'ADD_LANGUAGE', payload: 'en' });
console.log(state); // Should print { language: ['ru', 'kz', 'en'] }

// Test REMOVE_LANGUAGE action
state = reducer(state, { type: 'REMOVE_LANGUAGE', payload: 'ru' });
console.log(state); // Should print { language: ['kz', 'en'] }

// Test no mutation
deepFreeze(state); // Ensure no mutations occur
state = reducer(state, { type: 'ADD_LANGUAGE', payload: 'de' });
console.log(state); // Should print { language: ['kz', 'en', 'de'] }

// Test adding an existing language
state = reducer(state, { type: 'ADD_LANGUAGE', payload: 'en' });
console.log(state); // Should print { language: ['kz', 'en', 'de'] }

// Test removing a non-existing language
