    event MinterWalletAddressChanged(address indexed oldAddress, address indexed newAddress);

    function changeRewardsPoolAddress(address newAddress) external onlyOwner {
        emit RewardsPoolAddressChanged(rewardsPoolAddress, newAddress);
        rewardsPoolAddress = newAddress;
    }

    function changeBoxPriceCWOLF(uint256 newPrice) external onlyOwner {
        emit BoxPriceCWOLFChanged(boxPriceCWOLF, newPrice);
        boxPriceCWOLF = newPrice;
