        gasToMinter = newGasAmount;
    }

    function changeCWOLFContractAddress(address newAddress) external onlyOwner {
        emit CWOLFContractAddressChanged(CWOLFContractAddress, newAddress);
        CWOLFContractAddress = newAddress;
    }

    function changeWolfsNFTContractAddress(address newAddress) external onlyOwner {
        emit WolfsNFTContractAddressChanged(WolfsNFTContractAddress, newAddress);
        WolfsNFTContractAddress = newAddress;
    }

    function changeMaterialsNFTContractAddress(address newAddress) external onlyOwner {
        emit MaterialsNFTContractAddressChanged(MaterialsNFTContractAddress, newAddress);
