/**
 * Redux reducer for managing production finishing items.
 * @param {Object} state - The current state of the items.
 * @param {Object} action - The action to be handled.
 * @returns {Object} The updated state after applying the action.
 */
export default function productionFinishingReducer(state = {}, action) {
  switch (action.type) {
    case FETCH_PRODUCTIONFINISHINGS:
      return {
        ...state,
        ..._.mapKeys(action.payload, 'id'),
      };
    case FETCH_PRODUCTIONFINISHING:
    case CREATE_PRODUCTIONFINISHING:
    case EDIT_PRODUCTIONFINISHING:
      return { ...state, [action.payload.id]: action.payload };
    case DELETE_PRODUCTIONFINISHING:
      return _.omit(state, action.payload); // payload is the item id
    default:
