  type: REMOVE_CATEGORY,
  payload: { name }
});

export const checkStatus = () => ({ type: CHECK_STATUS });

// Reducer
const initialState = [];

const categoriesReducer = (state = initialState, action) => {
  switch (action.type) {
    case ADD_CATEGORY:
      if (state.find(category => category.name === action.payload.name)) {
        return state; // Do not add duplicate categories
      }
      return [...state, { name: action.payload.name, description: action.payload.description }];
    case REMOVE_CATEGORY:
      return state.filter(category => category.name !== action.payload.name);
    case CHECK_STATUS:
      return state.length === 0 ? 'System operational' : 'Categories present';
    default:
      return state;
  }
};

export default categoriesReducer;

