const assert = require('assert');

const vespersql = {
  collectionMappedToUniqueID: function(collection) {
    return collection.reduce((acc, item) => {
      acc[item.uniqueID] = item;
      return acc;
    }, {});
  },

  collectionMappedToProperty: function(collection, propertyName) {
    return collection.reduce((acc, item) => {
      acc[item[propertyName]] = item;
      return acc;
    }, {});
  },

  propertiesForObjects: function(collection, propertyName) {
    return collection.map(item => item[propertyName]);
  },

  uniqueIDsForObjects: function(collection, propertyName) {
    return collection.map(item => item.hasOwnProperty(propertyName) ? item[propertyName] : undefined);
  },

  objectInArrayWithUniqueID: function(collection, uniqueID) {
    return collection.find(item => item.uniqueID === uniqueID) || null;
  },

  buildSQLAndParameters: function(request, collection, buildFunction) {
    let sql = "BEGIN TRANSACTION;SET NOCOUNT ON;";
    let parameters = [];

    collection.forEach(item => {
      const result = buildFunction(request, item);
      sql += result.sql;
      parameters = parameters.concat(result.parameters);
    });

    sql += "COMMIT TRANSACTION;";
    return { sql, parameters };
  }
};

