/**
 * Removes all duplicate characters from a string, preserving the order of first occurrences.
 * 
 * @param {string} str - The input string from which to remove duplicate characters.
 * @return {string} A new string with all duplicate characters removed.
 */
const removeDuplicateCharacters = (str) => {
  let result = [];
  let arr = str.split('');
  for (let char of arr) {
    if (!result.includes(char)) {
      result.push(char);
    }
  }
  return result.join('');
};

// Importing the necessary packages
const assert = require('assert');

// Test cases to verify the solution
try {
  assert.strictEqual(removeDuplicateCharacters('banana'), 'ban');
  assert.strictEqual(removeDuplicateCharacters('abracadabra'), 'abrcd');
  assert.strictEqual(removeDuplicateCharacters(''), '');
  assert.strictEqual(removeDuplicateCharacters('a'), 'a');
  assert.strictEqual(removeDuplicateCharacters('aa'), 'a');
  assert.strictEqual(removeDuplicateCharacters('Aa'), 'Aa');
  assert.strictEqual(removeDuplicateCharacters('The quick brown fox jumps over the lazy dog'), 'The quick brown fx jmps v lazy dg');

  console.log('All test cases passed!');
} catch (error) {
  console.error('One or more test cases failed:', error.message);
}

module.exports = removeDuplicateCharacters;
