/**
 * ReconnectingWebSocket is a class that extends the standard WebSocket API to
 * automatically reconnect to the server with an increasing delay between attempts.
 * It also provides a method to manually close the WebSocket connection without
 * attempting to reconnect and an event handler that is called on every reconnection attempt.
 */

class ReconnectingWebSocket extends WebSocket {
  constructor(url, protocols) {
    super(url, protocols);
    this.reconnectDelay = 1000;
    this.maxReconnectDelay = 60000;
    this.shouldReconnect = true;
    this.onReconnect = null;

    this.addEventListener('close', (event) => {
      if (this.shouldReconnect) {
        setTimeout(() => {
          if (typeof this.onReconnect === 'function') {
            this.onReconnect();
          }
          this.reconnect(url, protocols);
        }, this.reconnectDelay);
        this.reconnectDelay = Math.min(this.reconnectDelay * 2, this.maxReconnectDelay);
      }
    });

    this.addEventListener('open', (event) => {
      this.reconnectDelay = 1000;
    });
  }

  reconnect(url, protocols) {
    this.close(1000, 'Reconnecting', { keepClosed: true });
    this.shouldReconnect = true;
    new ReconnectingWebSocket(url, protocols);
  }

  close(code, reason, options = {}) {
    this.shouldReconnect = !(options.keepClosed);
    super.close(code, reason);
  }
}

// Test cases
const wsUrl = 'wss://echo.websocket.org/';

// Create a new ReconnectingWebSocket instance
const ws = new ReconnectingWebSocket(wsUrl);

// Define the onReconnect event handler
ws.onReconnect = () => {
  console.log('Attempting to reconnect...');
};

// Close the WebSocket connection after 5 seconds to trigger a reconnection attempt
setTimeout(() => {
  ws.close(1000, 'Manual close', { keepClosed: false });
}, 5000);

// Manually close the WebSocket connection without reconnection after 10 seconds
setTimeout(() => {
  ws.close(1000, 'Manual close', { keepClosed: true });
}, 10000);
