  showNotification: false,
};

/**
 * Toggles the visibility of the notification panel based on the action provided.
 * 
 * @param {Object} state - The current state of the notification visibility.
 * @param {Object} action - The action to be applied to the state.
 * @returns {Object} The new state after applying the action.
 */
