import jwt from 'jsonwebtoken';
import bcrypt from 'bcrypt';

const secretKey = 'your-secret-key'; // Replace with your actual secret key

export const generateAccessToken = (login, password) => {
  const payload = {
    login,
    password,
  };

  return jwt.sign(payload, secretKey, { expiresIn: '24h' });
};

export const getAllAdmins = async (LoginSchema) => {
  try {
    const users = await LoginSchema.find();
    return users;
  } catch (error) {
    throw new Error('Failed to retrieve admins');
  }
};

export const register = async (LoginSchema, login, password, superAdmin) => {
  try {
    const user = await LoginSchema.findOne({ login });

    if (user) {
      throw new Error('Admin already registered');
    }

    const hashPassword = await bcrypt.hash(password, 7);
    const token = generateAccessToken(login, password);

    const doc = new LoginSchema({
      login,
      password: hashPassword,
      superAdmin,
      token,
    });

    await doc.save();

    return { success: true };
  } catch (error) {
    throw new Error('Failed to register admin');
  }
};

export const login = async (LoginSchema, login, password) => {
  try {
    const user = await LoginSchema.findOne({ login });

    if (!user) {
      throw new Error('Incorrect login or password');
    }

    const isPassEquals = await bcrypt.compare(password, user.password);

    if (!isPassEquals) {
      throw new Error('Incorrect login or password');
    }

    const token = `Bearer ${generateAccessToken(login, password)}`;

    return { token };
  } catch (error) {
    throw new Error('Failed to login');
  }
};

