const validateOpenApiPaths = (openApiContent) => {
  const httpVerbs = ['get', 'post', 'put', 'delete', 'patch', 'options', 'head'];
  const lines = openApiContent.split('\n');
  const errors = [];

  lines.forEach((line) => {
    const match = line.match(/\/paths\/~1(.+):/);
    if (match) {
      const path = match[1].replace(/~1/g, '/');
      httpVerbs.forEach((verb) => {
        if (path.toLowerCase().includes(verb)) {
          errors.push(`path \`/${path}\` should not contain HTTP verb ${verb}`);
        }
      });
    }
  });

  return errors;
};

