const moment = require('moment');

class StakingSystem {
  constructor(inactivityThreshold) {
    this.accounts = new Map();
    this.inactivityThreshold = inactivityThreshold;
    this.currentDay = moment();
  }

  addAccount(accountId, initialStake) {
    this.accounts.set(accountId, {
      stake: initialStake,
      lastActiveDay: this.currentDay.clone(),
    });
  }

  simulateDaysPassing(days) {
    this.currentDay.add(days, 'days');
  }

  markAccountActive(accountId) {
    if (this.accounts.has(accountId)) {
      this.accounts.get(accountId).lastActiveDay = this.currentDay.clone();
    }
  }

  getInactiveAccounts() {
    const inactiveAccounts = [];
    this.accounts.forEach((account, accountId) => {
      if (this.currentDay.diff(account.lastActiveDay, 'days') >= this.inactivityThreshold) {
        inactiveAccounts.push(accountId);
      }
    });
    return inactiveAccounts;
  }

  penalizeInactiveAccounts() {
    const inactiveAccounts = this.getInactiveAccounts();
    const totalRedistributedStake = inactiveAccounts.reduce((sum, accountId) => {
      const account = this.accounts.get(accountId);
      sum += account.stake;
      account.stake = 0; // Reset stake for inactive account
      return sum;
    }, 0);

    const activeAccountsCount = this.accounts.size - inactiveAccounts.length;
    const stakePerActiveAccount = totalRedistributedStake / activeAccountsCount;

    this.accounts.forEach((account, accountId) => {
      if (!inactiveAccounts.includes(accountId)) {
        account.stake += stakePerActiveAccount;
      }
    });
  }

  getAccountStake(accountId) {
    if (this.accounts.has(accountId)) {
      return this.accounts.get(accountId).stake;
    }
    return null;
  }
}

// Test cases
const stakingSystem = new StakingSystem(3); // Inactivity threshold set to 3 days
stakingSystem.addAccount('account1', 100);
stakingSystem.addAccount('account2', 150);
stakingSystem.addAccount('account3', 200);

// Simulate passing of 4 days
stakingSystem.simulateDaysPassing(4);

// Mark account1 as active
stakingSystem.markAccountActive('account1');

// Check inactive accounts
console.log('Inactive accounts:', stakingSystem.getInactiveAccounts()); // Should log account2 and account3

// Penalize inactive accounts and redistribute stakes
stakingSystem.penalizeInactiveAccounts();

// Get account stakes after penalization
console.log('Account1 stake:', stakingSystem.getAccountStake('account1')); // Should be greater than 100
console.log('Account2 stake:', stakingSystem.getAccountStake('account2')); // Should be 0
console.log('Account3 stake:', stakingSystem.getAccountStake('account3')); // Should be 0
