import React from 'react';
import { connect } from 'react-redux';

// Redux action types
const DELETE_TASK = 'DELETE_TASK';

// Redux action creator for deleting a task
const deleteTask = (id) => ({
  type: DELETE_TASK,
  payload: id,
});

// Redux reducer for handling tasks
const tasksReducer = (state = { tasks: [] }, action) => {
  switch (action.type) {
    case DELETE_TASK:
      return {
        ...state,
        tasks: state.tasks.filter(task => task.id !== action.payload),
      };
    default:
      return state;
  }
};

// React component for displaying and deleting tasks
class TaskPage extends React.Component {
  handleDelete = (id) => {
    this.props.deleteTask(id);
  };

  render() {
    const { tasks } = this.props;
    return (
      <div>
        <h1>Tasks</h1>
        <ul>
          {tasks.map(task => (
            <li key={task.id}>
              {task.description}
              <button onClick={() => this.handleDelete(task.id)}>Delete</button>
            </li>
          ))}
        </ul>
      </div>
    );
  }
}

// Mapping Redux state to React component props
const mapStateToProps = (state) => ({
  tasks: state.tasks,
});

// Mapping Redux dispatch to React component props
const mapDispatchToProps = (dispatch) => ({
  deleteTask: (id) => dispatch(deleteTask(id)),
});

// Connecting the React component to the Redux store
export default connect(mapStateToProps, mapDispatchToProps)(TaskPage);

// Sample Redux store state
const sampleState = {
  tasks: [
    { id: 1, description: 'Learn Redux' },
    { id: 2, description: 'Read a book' },
  ],
};

// Test cases
