/**
 * Filters out numbers from a comma-separated string that are divisible by 3 but not by 2.
 * 
 * @param {string} inputStr - A string of comma-separated numbers.
 * @returns {number[]} An array of numbers that are divisible by 3 but not by 2.
 */
function filterDivisibleNumbers(inputStr) {
  const numberArr = inputStr.split(",");
  const divisibleNumbers = [];

  for (let i = 0; i < numberArr.length; i++) {
    const num = parseInt(numberArr[i], 10);
    if (!isNaN(num) && num % 3 === 0 && num % 2 !== 0) {
      divisibleNumbers.push(num);
    }
  }

  return divisibleNumbers;
}

