  updateStateByResourceId(resourceId, newState) {
    const propagation = this.propagations.get(resourceId);
    if (propagation) {
      propagation.State = newState;
    } else {
      throw new Error(`No TransitGatewayPropagation found with ResourceId: ${resourceId}`);
    }
  }

  /**
   * Returns an array of all TransitGatewayPropagation instances in the collection.
   * @returns {Array<TransitGatewayPropagation>} An array of propagation instances.
   */
  listAllPropagations() {
    return Array.from(this.propagations.values());
  }
}

