import useCallbackRef from './useCallbackRef'; // Assuming the given code snippet is in useCallbackRef.js

/**
 * Custom React hook that sets up an interval and ensures the latest callback is used.
 *
 * @param {Function} callback - The callback function to execute on each interval tick.
 * @param {number|null} delay - The delay in milliseconds for the interval. If null, the interval is paused.
 */
export default function useInterval(callback, delay) {
  const savedCallback = useCallbackRef(callback);

  useEffect(() => {
    function tick() {
      savedCallback.current();
    }

    if (delay !== null) {
      let id = setInterval(tick, delay);
      return () => clearInterval(id);
    }
  }, [delay, savedCallback]);
}

// Example usage of the useInterval hook in a functional React component
