import { useEventListener } from "./event-listener";

/**
 * Registers a hotkey and executes a callback when the hotkey is pressed.
 * @param {string} key - The key that triggers the hotkey.
 * @param {Function} onKeyPressed - The callback function to execute when the hotkey is pressed.
 * @param {Object} [opts] - Optional parameters to specify the behavior of the hotkey.
 * @param {boolean} [opts.ctrlKey] - Indicates if the Control key should be held down.
 * @param {boolean} [opts.shiftKey] - Indicates if the Shift key should be held down.
 * @param {boolean} [opts.exact] - Indicates if the combination should match exactly.
 * @param {EventTarget} [opts.target] - The target element for the event listener.
 */
export function useHotkey(key, onKeyPressed, opts) {
    const target = opts?.target || window;

    useEventListener(target, 'keydown', e => {
        if (e.key === key && matchesKeyScheme(opts, e)) {
            e.preventDefault();
            onKeyPressed();
        }
    });
}

/**
 * Checks if the event matches the specified key scheme.
 * @param {Object} opts - The options specifying the key scheme.
 * @param {KeyboardEvent} evt - The event triggered by the key press.
 * @returns {boolean} - True if the event matches the key scheme, false otherwise.
 */
function matchesKeyScheme(opts, evt) {
    const ctrlKey = opts?.ctrlKey ?? false;
    const shiftKey = opts?.shiftKey ?? false;

    if (opts?.exact) {
        return ctrlKey === evt.ctrlKey && shiftKey === evt.shiftKey;
    }

    return (!ctrlKey || evt.ctrlKey) && (!shiftKey || evt.shiftKey);
}

// Example usage:
// Register a hotkey for 'N' that requires the Control key to be held down.
useHotkey('N', () => {
    console.log('New item shortcut triggered!');
}, { ctrlKey: true });

// Test cases to verify the solution correctness:
