import AsyncStorage from '@react-native-async-storage/async-storage';
import * as SecureStore from 'expo-secure-store';

/**
 * A storage system for a React Native application that provides secure and
 * persistent key-value storage using AsyncStorage and SecureStore.
 */
const StorageSystem = {
  /**
   * Saves a value under a given key in the general storage.
   * @param {string} key The key under which to store the value.
   * @param {any} value The value to store.
   * @returns {Promise<void>}
   */
  async saveItem(key, value) {
    try {
      const stringValue = JSON.stringify(value);
      await AsyncStorage.setItem(key, stringValue);
    } catch (error) {
      console.error('Error saving item to storage:', error);
    }
  },

  /**
   * Retrieves a value by its key from the general storage.
   * @param {string} key The key of the value to retrieve.
   * @returns {Promise<any>}
   */
  async getItem(key) {
    try {
      const stringValue = await AsyncStorage.getItem(key);
      return stringValue ? JSON.parse(stringValue) : null;
    } catch (error) {
      console.error('Error retrieving item from storage:', error);
      return null;
    }
  },

  /**
   * Saves a value under a given key in the secure storage.
   * @param {string} key The key under which to store the value.
   * @param {string} value The value to store.
   * @returns {Promise<void>}
   */
  async saveSecureItem(key, value) {
    try {
      await SecureStore.setItemAsync(key, value);
    } catch (error) {
      console.error('Error saving item to secure storage:', error);
    }
  },

  /**
   * Retrieves a value by its key from the secure storage.
   * @param {string} key The key of the value to retrieve.
   * @returns {Promise<string | null>}
   */
  async getSecureItem(key) {
    try {
      return await SecureStore.getItemAsync(key);
    } catch (error) {
      console.error('Error retrieving item from secure storage:', error);
      return null;
    }
  },

  /**
   * Removes a value by its key from the general storage.
   * @param {string} key The key of the value to remove.
   * @returns {Promise<void>}
   */
  async removeItem(key) {
    try {
      await AsyncStorage.removeItem(key);
    } catch (error) {
      console.error('Error removing item from storage:', error);
    }
  },

  /**
   * Removes a value by its key from the secure storage.
   * @param {string} key The key of the value to remove.
   * @returns {Promise<void>}
   */
  async removeSecureItem(key) {
    try {
      await SecureStore.deleteItemAsync(key);
    } catch (error) {
      console.error('Error removing item from secure storage:', error);
    }
  },
};

export default StorageSystem;

// Test cases to verify the solution correctness
(async () => {
  // Test general storage
  await StorageSystem.saveItem('testKey', { foo: 'bar' });
  const retrievedItem = await StorageSystem.getItem('testKey');
  console.log(retrievedItem); // Should log: { foo: 'bar' }
  await StorageSystem.removeItem('testKey');
  const removedItem = await StorageSystem.getItem('testKey');
  console.log(removedItem); // Should log: null

  // Test secure storage
  await StorageSystem.saveSecureItem('secureKey', 'secretValue');
  const secureItem = await StorageSystem.getSecureItem('secureKey');
  console.log(secureItem); // Should log: 'secretValue'
  await StorageSystem.removeSecureItem('secureKey');
  const removedSecureItem = await StorageSystem.getSecureItem('secureKey');
  console.log(removedSecureItem); // Should log: null
})();
