function addUserToContacts(currentUser, newUser) {
  // Check if newUser is the same as currentUser
  if (currentUser._id === newUser._id) {
    return "Cannot add yourself to your contacts list.";
  }

  // Check if newUser is already in currentUser's contacts
  let isContactPresent = currentUser.contacts.some(contact => contact.userID === newUser._id);

  if (isContactPresent) {
    return "This user is already in your contacts list.";
  }

  // Add newUser to currentUser's contacts
  currentUser.contacts.push({
    userID: newUser._id,
    username: newUser.username,
    userEmail: newUser.email,
  });

