const fs = require('fs').promises;
const path = require('path');

/**
 * Asynchronously lists and optionally sanitizes the names of JSON files in a given directory.
 * @param {string} directoryPath - The path to the directory containing the JSON files.
 * @param {boolean} [sanitize=false] - Whether to sanitize file names by removing non-alphanumeric characters.
 * @returns {Promise<string[]>} A promise that resolves with an array of file names.
 */
async function listAndSanitizeJsonFilenames(directoryPath, sanitize = false) {
  try {
    const fileNames = await fs.readdir(directoryPath);
    const jsonFileNames = fileNames
      .filter(file => path.extname(file).toLowerCase() === '.json')
      .map(file => sanitize ? file.replace(/[^a-zA-Z0-9.]/g, '') : file);
    return jsonFileNames;
  } catch (error) {
    throw new Error('Failed to read the directory or directory does not exist.');
  }
}

// Test cases
async function test() {
  try {
    // Assuming there is a directory named 'test_data' with some JSON files
    const directoryPath = path.join(__dirname, 'test_data');

    // Test without sanitization
    const filesWithoutSanitization = await listAndSanitizeJsonFilenames(directoryPath);
    console.log('Files without sanitization:', filesWithoutSanitization);

    // Test with sanitization
    const filesWithSanitization = await listAndSanitizeJsonFilenames(directoryPath, true);
    console.log('Files with sanitization:', filesWithSanitization);
  } catch (error) {
    console.error(error.message);
  }
}

test();
