class UserProfileValidator {
  /**
   * Validates the user profile data.
   * - `username` should be a non-empty string with a maximum length of 20 characters.
   * - `email` should be a valid email address.
   * - `password` should be a non-empty string with a minimum length of 8 characters,
   *   and contain at least one number and one uppercase letter.
   * @returns {Array} An array of validation chain calls.
   */
  static validate() {
    return [
      check('username')
        .not()
        .isEmpty()
        .withMessage('Username is required')
        .isLength({ max: 20 })
        .withMessage('Username must be at most 20 characters long'),
      check('email')
        .isEmail()
        .withMessage('Must be a valid email address'),
      check('password')
        .not()
        .isEmpty()
        .withMessage('Password is required')
        .isLength({ min: 8 })
        .withMessage('Password must be at least 8 characters long')
        .matches(/\d/)
