/**
 * Calculates the net balance of a billing cycle by summing all credits and subtracting all paid debts.
 * 
 * @param {Object} billingCycle - The billing cycle object containing credits and debts.
 * @returns {Number} The net balance of the billing cycle.
 */
function calculateNetBalance(billingCycle) {
    const totalCredits = billingCycle.credits.reduce((sum, credit) => sum + credit.value, 0);
    const totalDebts = billingCycle.debts
        .filter(debt => debt.status === 'PAGO')
        .reduce((sum, debt) => sum + debt.value, 0);
    return totalCredits - totalDebts;
}

