        throw new Error(`Configuration file not found at ${configPath}`);
      }
      // Attempt to load the configuration file
      const config = require(configPath);
      // Validate that the configuration object contains the 'settings' property
      if (!config || typeof config.settings !== 'object') {
        throw new Error('Invalid configuration format: missing "settings" property');
      }
      return config;
    } catch (e) {
      console.error(`Error loading configuration: ${e.message}`);
