import axios from "axios";

// Assuming the REACT_APP_BACKEND_URL environment variable is set to the backend URL
const baseUrl = process.env.REACT_APP_BACKEND_URL;

// Create an Axios instance with a base URL and with credentials
export const axiosInstance = axios.create({
  baseURL: `${baseUrl}/api`,
  withCredentials: true,
});

/**
 * Fetches user data from the server.
 * @param {string} userId - The ID of the user to fetch.
 * @returns {Promise<Object>} A promise that resolves to the user data or an error message.
 */
export async function fetchUserData(userId) {
  try {
    const response = await axiosInstance.get(`/users/${userId}`);
    return response.data;
  } catch (error) {
    return handleError(error);
  }
}

/**
 * Updates user data on the server.
 * @param {string} userId - The ID of the user to update.
 * @param {Object} userData - An object containing the updated user data.
 * @returns {Promise<Object>} A promise that resolves to the updated user data or an error message.
 */
export async function updateUserData(userId, userData) {
  try {
    const response = await axiosInstance.put(`/users/${userId}`, userData);
    return response.data;
  } catch (error) {
    return handleError(error);
  }
}

/**
 * Handles errors from Axios requests.
 * @param {Object} error - The error object from an Axios request.
 * @returns {string} An error message.
 */
function handleError(error) {
  if (error.response) {
    // The request was made and the server responded with a status code
    // that falls out of the range of 2xx
    return error.response.data.message || 'An error occurred during the request.';
  } else if (error.request) {
    // The request was made but no response was received
    return 'No response was received from the server.';
  } else {
    // Something happened in setting up the request that triggered an Error
    return error.message;
  }
}

