const validateGatsbyConfig = (config) => {
  const errors = [];
  const requiredMetadataFields = ['title', 'description', 'author', 'myDescr'];
  const requiredPlugins = [
    'gatsby-plugin-react-helmet',
    'gatsby-plugin-styled-components',
    'gatsby-transformer-sharp',
    'gatsby-plugin-sharp',
  ];
  const requiredManifestOptions = [
    'name',
    'short_name',
    'start_url',
    'background_color',
    'theme_color',
    'display',
    'icon',
  ];

  // Validate siteMetadata
  if (!config.siteMetadata) {
    errors.push('Missing siteMetadata.');
  } else {
    requiredMetadataFields.forEach((field) => {
      if (!config.siteMetadata[field] || typeof config.siteMetadata[field] !== 'string' || config.siteMetadata[field].trim() === '') {
        errors.push(`Missing or empty siteMetadata.${field}.`);
      }
    });
  }

  // Validate plugins
  if (!Array.isArray(config.plugins)) {
    errors.push('Plugins must be an array.');
  } else {
    requiredPlugins.forEach((plugin) => {
      if (!config.plugins.includes(plugin)) {
        errors.push(`Missing required plugin: ${plugin}.`);
      }
    });

    // Validate gatsby-source-filesystem for images
    const imagePlugin = config.plugins.find((plugin) =>
      plugin.resolve === 'gatsby-source-filesystem' && plugin.options && plugin.options.name === 'images'
    );
    if (!imagePlugin) {
      errors.push('Missing gatsby-source-filesystem plugin configured for images.');
    }

    // Validate gatsby-plugin-manifest
    const manifestPlugin = config.plugins.find((plugin) => plugin.resolve === 'gatsby-plugin-manifest');
    if (!manifestPlugin) {
      errors.push('Missing gatsby-plugin-manifest.');
    } else {
      requiredManifestOptions.forEach((option) => {
        if (!manifestPlugin.options[option]) {
          errors.push(`Missing required manifest option: ${option}.`);
        }
      });
    }
  }

  return {
    isValid: errors.length === 0,
    errors,
  };
};

