  const isValidImplicitRole = (set, role) => {
    const validForNodeType = implicitNodeTypeSelector => node.matches(implicitNodeTypeSelector);
    if (role.implicit && role.implicit.some(validForNodeType)) {
      set.push(role.name);
    }
    return set;
  };

  const sortRolesByOptimalAriaContext = (roles, ariaAttributes) => {
    const getScore = role => {
      const allowedAriaAttributes = allowedAttr(role);
      return allowedAriaAttributes.reduce((score, attribute) => score + (ariaAttributes.includes(attribute) ? 1 : 0), 0);
    };

    const scored = roles.map(role => ({ score: getScore(role), name: role }));
    const sorted = scored.sort((a, b) => b.score - a.score);
    return sorted.map(sortedRole => sortedRole.name);
  };

  const roles = Object.keys(lookupTable.role).map(role => ({
    name: role,
    implicit: lookupTable.role[role]?.implicit
  }));

  const availableImplicitRoles = roles.reduce(isValidImplicitRole, []);

  if (!availableImplicitRoles.length) {
    return null;
  }

  const nodeAttributes = Array.from(node.attributes);
  const ariaAttributes = nodeAttributes
    .filter(attr => attr.name.startsWith('aria-'))
    .map(attr => attr.name);

  return sortRolesByOptimalAriaContext(availableImplicitRoles, ariaAttributes).shift();
}

export default getImplicitAriaRole;

// Test cases
