export class AnimatedLake extends GameObject {
    /**
     * Creates an instance of AnimatedLake.
     * @param {number} radius - The radius of the lake geometry.
     * @param {THREE.Vector2} resolution - The resolution of the lake shader.
     * @param {string} vertexShaderPath - The path to the vertex shader file.
     * @param {string} fragmentShaderPath - The path to the fragment shader file.
     */
    constructor(radius, resolution, vertexShaderPath, fragmentShaderPath) {
        const shaderMat = shaderMaterial(vertexShaderPath, fragmentShaderPath, {
            side: THREE.DoubleSide,
            uniforms: {
                time: { value: 0.0 },
                resolution: { value: resolution }
            },
        });

        const lakeGeometry = new THREE.CircleGeometry(radius, 32);
        const lakeMesh = new THREE.Mesh(lakeGeometry, shaderMat);
        lakeMesh.rotateX(Math.PI / 2);
        lakeMesh.position.set(0, 0.1, 0);

        super('AnimatedLake', lakeMesh);

        this.aniTime = 0;
        this.shaderMat = shaderMat;
    }

    /**
     * Updates the lake animation based on the elapsed time.
     * @param {number} delta - The time elapsed since the last update.
     */
    stepWorld(delta) {
        this.aniTime += delta;
        const newR = Math.sin(this.aniTime / 200) / 2 + 0.5; // get a number between 0-1
        this.shaderMat.uniforms.resolution.value.x = newR;
        this.shaderMat.uniforms.time.value = this.aniTime * 0.001; // pass in the time in seconds
    }
}

