const readline = require('readline');
const { EventEmitter } = require('events');

// Constants for the game
const QUESTIONS = {
  gameMode: "Do you want to play against the computer (p) or watch a simulation (s)? (p/s): ",
  inputs: "Choose Rock (r), Paper (p), or Scissors (s): ",
  playAgain: "Do you want to play again? (y/n): "
};

// Helper functions
const askQuestion = (question, server) => {
  const rl = readline.createInterface({
    input: server.stdin,
    output: server.stdout
  });
  return new Promise(resolve => {
    rl.question(question, answer => {
      rl.close();
      resolve(answer);
    });
  });
};

const terminateServer = (server) => {
  server.close();
};

const getWinner = (player1, player2) => {
  const rules = {
    r: 's',
    s: 'p',
    p: 'r'
  };
  if (player1.input === player2.input) {
    return null;
  }
  return rules[player1.input] === player2.input ? player1.name : player2.name;
};

// Player class
class Player {
  constructor(name, input = null) {
    this.name = name;
    this.input = input || this.getRandomInput();
  }

  getRandomInput() {
    const inputs = ['r', 'p', 's'];
    return inputs[Math.floor(Math.random() * inputs.length)];
  }

  logInput() {
    console.log(`${this.name} chose: ${this.input}`);
  }
}

// Main game function
const playCLI = async (server) => {
  let shouldPlayAgain = false;
  do {
    const player1 = new Player("Computer");

    const mode = await askQuestion(QUESTIONS.gameMode, server);

    const player2 =
      mode === "p"
        ? new Player("Player", await askQuestion(QUESTIONS.inputs, server))
        : new Player("Computer 2");

    player1.logInput();
    player2.logInput();

    console.log("\nAnd the winner is: ", getWinner(player1, player2) || "Draw");
    const playAgain = await askQuestion(QUESTIONS.playAgain, server);
    shouldPlayAgain = playAgain === "y";
  } while (shouldPlayAgain);

  terminateServer(server);
};

// Mock server object to simulate server input/output
const mockServer = new EventEmitter();
mockServer.stdin = process.stdin;
mockServer.stdout = process.stdout;
mockServer.close = () => console.log('Server terminated');

// Run the game
playCLI(mockServer).catch(err => console.error(err));

