const nodemailer = require("nodemailer");
const handlebars = require("handlebars");
const fs = require("fs").promises;
const path = require("path");

/**
 * Asynchronously sends an email using a Handlebars template.
 *
 * @param {string} recipientEmail - The email address of the recipient.
 * @param {string} emailSubject - The subject of the email.
 * @param {Object} emailPayload - An object containing the key-value pairs for placeholder replacement in the template.
 * @param {string} templatePath - The path to the email template file.
 * @returns {Promise<string>} A promise that resolves to a string indicating the result of the email sending process.
 */
const sendTemplatedEmail = async (recipientEmail, emailSubject, emailPayload, templatePath) => {
  try {
    const transporter = nodemailer.createTransport({
      host: process.env.EMAIL_HOST,
      port: 587,
      auth: {
        user: process.env.EMAIL_USERNAME,
        pass: process.env.EMAIL_PASSWORD,
      },
      tls: {
        rejectUnauthorized: false,
      }
    });

    const source = await fs.readFile(path.join(__dirname, templatePath), "utf8");
    const compiledTemplate = handlebars.compile(source);
    const options = {
      from: process.env.FROM_EMAIL,
      to: recipientEmail,
      subject: emailSubject,
      html: compiledTemplate(emailPayload),
    };

    const info = await transporter.sendMail(options);
    return `Email sent successfully to ${recipientEmail}: ${info.response}`;
  } catch (error) {
    throw error;
  }
};

module.exports = sendTemplatedEmail;

// Test cases
(async () => {
  try {
    const result = await sendTemplatedEmail(
      'test@example.com',
      'Test Email',
      { name: 'John Doe', message: 'This is a test message.' },
      './emailTemplates/welcomeTemplate.hbs'
    );
    console.log(result);
  } catch (error) {
    console.error('Failed to send email:', error);
  }
})();
