const getters = {
    cartItem: (state) => {
        return state.cartItemList.flat(Infinity);
    },
    cartValue: (state) => {
        let res = 0;
        for (let item of state.cartItemList.flat(Infinity)) {
            res += item.price * item.number;
        }
        return res;
    }
};

// Define mutations to update the state
const mutations = {
    updateCart(state, data) {
        let record = state.cartItemList.flat(1).find(prod => prod.id === data.id);
        if (record) {
            record.number = data.number;
            record.NewPrice = data.price * data.number;
        } else {
            state.cartItemList.push(data);
        }
    },
    setCart(state, productList) {
        state.cartItemList = productList;
    },
    removeItem(state, item) {
        let flat = state.cartItemList.flat(1);
        let index = flat.findIndex(prod => prod.id === item.id);
        if (index !== -1) {
            flat.splice(index, 1);
            state.cartItemList = flat;
        }
    },
};

// Define actions to commit mutations
const actions = {
    removeCart({ commit }) {
        commit('setCart', []);
    }
};

// Export the shopping cart system
export default {
    state,
    getters,
    actions,
    mutations
};

