/** Node class for graph. */
class Node {
  constructor(value, adjacent = new Set()) {
    this.value = value;
    this.adjacent = adjacent;
  }
}

/** Graph class. */
class Graph {
  constructor() {
    this.nodes = new Set();
  }

  addVertex(vertex) {
    this.nodes.add(vertex);
  }

  addVertices(vertexArray) {
    for (let vertex of vertexArray) {
      this.addVertex(vertex);
    }
  }

  addEdge(v1, v2) {
    v1.adjacent.add(v2);
    v2.adjacent.add(v1);
  }

  removeEdge(v1, v2) {
    v1.adjacent.delete(v2);
    v2.adjacent.delete(v1);
  }

  removeVertex(vertex) {
    this.nodes.delete(vertex);
    for (let adjacentVertex of vertex.adjacent) {
      adjacentVertex.adjacent.delete(vertex);
    }
  }

  depthFirstSearch(start) {
    let result = [];
    let toVisitStack = [start];
    let seen = new Set();

    while (toVisitStack.length > 0) {
      let current = toVisitStack.pop();
      if (!seen.has(current)) {
        seen.add(current);
        result.push(current.value);
        for (let adjacentNode of current.adjacent) {
          toVisitStack.push(adjacentNode);
        }
      }
    }

    return result;
  }

  breadthFirstSearch(start) {
    let result = [];
    let toVisitQueue = [start];
    let seen = new Set([start]);

    while (toVisitQueue.length > 0) {
      let current = toVisitQueue.shift();
      result.push(current.value);
      for (let adjacentNode of current.adjacent) {
        if (!seen.has(adjacentNode)) {
          seen.add(adjacentNode);
          toVisitQueue.push(adjacentNode);
        }
      }
    }

    return result;
  }

  distanceOfShortestPath(start, end) {
    if (start === end) return 0;
    let toVisitQueue = [[start, 0]];
    let seen = new Set([start]);

    while (toVisitQueue.length > 0) {
      let [current, distance] = toVisitQueue.shift();
      if (current === end) return distance;
      for (let adjacentNode of current.adjacent) {
        if (!seen.has(adjacentNode)) {
          seen.add(adjacentNode);
          toVisitQueue.push([adjacentNode, distance + 1]);
        }
      }
    }

    return -1; // If no path exists
  }
}

// Test cases
let graph = new Graph();
let S = new Node("S");
let P = new Node("P");
