  dispatch({ type: LOADING });
  try {
    const response = await axios.post(API_ENDPOINT, bug);
    dispatch({ type: BUGS_ADD, payload: response.data });
  } catch (error) {
    dispatch({ type: FAILED, payload: error.message });
  }
};

// Get all bugs
export const getBugs = () => async (dispatch) => {
  dispatch({ type: LOADING });
  try {
    const response = await axios.get(API_ENDPOINT);
    dispatch({ type: BUGS_GET, payload: response.data });
  } catch (error) {
    dispatch({ type: FAILED, payload: error.message });
  }
};

// Delete a bug by ID
export const deleteBug = (id) => async (dispatch) => {
  dispatch({ type: LOADING });
  try {
    await axios.delete(`${API_ENDPOINT}/${id}`);
    dispatch({ type: BUGS_DELETE, payload: id });
  } catch (error) {
    dispatch({ type: FAILED, payload: error.message });
  }
};

// Update a bug by ID
