  dispatch({ type: LOADING });
  try {
    const response = await axios.patch(`${API_ENDPOINT}/${id}`, updates);
    dispatch({ type: BUGS_UPDATE, payload: response.data });
  } catch (error) {
    dispatch({ type: FAILED, payload: error.message });
  }
};

