Write a JavaScript function `mergeTagLists` that takes two arrays of tag objects, `leftTags` and `rightTags`, each with properties `id` and `content`. The function should merge both arrays into a single array, sorted alphabetically by the `content` property. If there are tags with the same `content` in both arrays, only the tag from the `leftTags` array should be included in the merged array.

The function should return the merged and sorted array of tag objects.

### Example:

```javascript
let leftTags = [
  { id: 'apple', content: 'apple' },
  { id: 'banana', content: 'banana' }
];

let rightTags = [
  { id: 'carrot', content: 'carrot' },
  { id: 'banana', content: 'banana' }
];

let mergedTags = mergeTagLists(leftTags, rightTags);
console.log(mergedTags);
```

The output should be:

```javascript
[
  { id: 'apple', content: 'apple' },
  { id: 'banana', content: 'banana' },
  { id: 'carrot', content: 'carrot' }
]
```

**Note**: The `id` property is unique within each array but not necessarily across both arrays.

output:
```javascript
function mergeTagLists(leftTags, rightTags) {
  // Create a new map to store the merged tags with content as the key
  const tagMap = new Map();

  // Add all tags from the leftTags array to the map
  leftTags.forEach(tag => tagMap.set(tag.content, tag));

  // Add tags from the rightTags array to the map only if they don't exist
  rightTags.forEach(tag => {
    if (!tagMap.has(tag.content)) {
      tagMap.set(tag.content, tag);
    }
  });

  // Convert the map values to an array and sort it alphabetically by content
  return Array.from(tagMap.values()).sort((a, b) => a.content.localeCompare(b.content));
}

// Test cases
console.log(mergeTagLists(
  [
    { id: 'apple', content: 'apple' },
    { id: 'banana', content: 'banana' }
  ],
  [
    { id: 'carrot', content: 'carrot' },
    { id: 'banana', content: 'banana' }
  ]
)); // Expected output: [{ id: 'apple', content: 'apple' }, { id: 'banana', content: 'banana' }, { id: 'carrot', content: 'carrot' }]

console.log(mergeTagLists(
  [
    { id: 'lemon', content: 'lemon' },
    { id: 'orange', content: 'orange' }
  ],
  [
    { id: 'apple', content: 'apple' },
    { id: 'banana', content: 'banana' }
  ]
)); // Expected output: [{ id: 'apple', content: 'apple' }, { id: 'banana', content: 'banana' }, { id: 'lemon', content: 'lemon' }, { id: 'orange', content: 'orange' }]
