import { useRef, useState, useCallback } from 'react';

/**
 * Custom React hook that lazily initializes a state variable with a computationally expensive function.
 * @template S
 * @param {() => S} initialStateFunc - A function that computes the initial state.
 * @param {...any} args - Arguments to pass to the initialStateFunc.
 * @returns {[S, (value: S | ((prevState: S) => S)) => void]} - Returns a tuple with the state and a setter function.
 */
export function useLazyInitializedState(initialStateFunc, ...args) {
  const isInitialized = useRef(false);
  const [state, setState] = useState(() => {
    if (!isInitialized.current) {
      isInitialized.current = true;
      return initialStateFunc(...args);
    }
  });

  const setLazyState = useCallback((value) => {
    setState(value);
  }, []);

  return [state, setLazyState];
}

export default useLazyInitializedState;

// Example usage:
// This is a test component to demonstrate the use of the useLazyInitializedState hook.
function ExpensiveInitialStateComponent({ computeExpensiveValue }) {
  const [expensiveValue, setExpensiveValue] = useLazyInitializedState(computeExpensiveValue);

  return (
    <div>
      <p>Expensive Value: {expensiveValue}</p>
      <button onClick={() => setExpensiveValue(prevValue => prevValue + 1)}>
        Increment Value
      </button>
    </div>
  );
}

// Test cases:
// Assuming we have a function that computes an expensive value:
function computeExpensiveValue() {
