const { EventEmitter } = require('events');

class TaskManager extends EventEmitter {
  constructor() {
    super();
    this.tasks = {};
    this.nextId = 1;
  }

  createTask(title) {
    const task = {
      id: this.nextId++,
      title: title,
      completed: false
    };
    this.tasks[task.id] = task;
    this.emit('taskCreated', task);
    return task;
  }

  updateTask(id, updates) {
    if (!this.tasks[id]) {
      throw new Error(`Task with id ${id} not found.`);
    }
    Object.assign(this.tasks[id], updates);
    this.emit('taskUpdated', this.tasks[id]);
    return this.tasks[id];
  }

  deleteTask(id) {
    if (!this.tasks[id]) {
      throw new Error(`Task with id ${id} not found.`);
    }
    const deletedTask = this.tasks[id];
    delete this.tasks[id];
    this.emit('taskDeleted', deletedTask);
    return deletedTask;
  }

  getCompletedTasks() {
    return Object.values(this.tasks).filter(task => task.completed);
  }
}

// Usage
const taskManager = new TaskManager();

// Event listeners
