const { createFilter, attachScopes, normalizePath } = require('@rollup/pluginutils');
const MagicString = require('magic-string');

/**
 * Transforms the given source code by replacing "console.log" with "console.debug"
 * and generates a source map for the transformed code.
 * 
 * @param {string} code - The source code to transform.
 * @param {string} id - The identifier for the source file.
 * @returns {object} An object with the transformed code and a getter for the source map.
 */
function transformAndGenerateSourceMap(code, id) {
  const s = new MagicString(code);
  const logRegex = /console\.log/g;

  let match;
  while ((match = logRegex.exec(code)) !== null) {
    s.overwrite(match.index, match.index + match[0].length, 'console.debug');
  }

  if (s.hasChanged()) {
    return {
      code: s.toString(),
      get map() {
        return s.generateMap({
          source: id,
          includeContent: true,
          hires: true
        });
      }
    };
  } else {
    return { code, map: null };
  }
}

// Export the function
module.exports = { transformAndGenerateSourceMap };

// Test cases
const originalCode = `function sayHello() {
  console.log("Hello, world!");
}`;
const transformedResult = transformAndGenerateSourceMap(originalCode, 'sayHello.js');

console.log('Transformed Code:', transformedResult.code);
console.log('Source Map:', transformedResult.map());
