class MutableRangeSum {
    constructor(nums) {
        this.nums = nums;
        this.tree = new Array(nums.length + 1).fill(0);
        for (let i = 0; i < nums.length; i++) {
            this._updateTree(i + 1, nums[i]);
        }
    }

    update(index, val) {
        const delta = val - this.nums[index];
        this.nums[index] = val;
        this._updateTree(index + 1, delta);
    }

    sumRange(i, j) {
        return this._queryTree(j + 1) - this._queryTree(i);
    }

    _updateTree(index, val) {
        while (index < this.tree.length) {
            this.tree[index] += val;
            index += index & -index;
        }
    }

    _queryTree(index) {
        let sum = 0;
        while (index > 0) {
            sum += this.tree[index];
            index -= index & -index;
        }
        return sum;
    }
}

// Test cases
const nums = [1, 3, 5];
const obj = new MutableRangeSum(nums);
console.log(obj.sumRange(0, 2)); // Output: 9
obj.update(1, 2);
console.log(obj.sumRange(0, 2)); // Output: 8
