    this.placeholder = options.placeholder || '';
    this.cancelText = options.cancelText || '取消';
    this.value = options.value || '';
    this.icon = options.icon || 'research';
    this.iconColor = options.iconColor || '#bdbdbd';
    this.iconSize = options.iconSize || '28';
    this.bgColor = options.bgColor || '#f3f3f3';
    this.showCancel = options.showCancel !== undefined ? options.showCancel : true;
    this.shape = options.shape || 'primary';
    this.textAlign = options.textAlign || 'left';
    this.focus = options.focus || false;
    this.clear = options.clear !== undefined ? options.clear : true;
    this.maxlength = options.maxlength || 140;
    this.disabled = options.disabled || false;
    this.placeholderStyle = options.placeholderStyle || '';
  }

  onCancel() {
    this.onCancelHandler();
  }

  handleInputChange(value) {
    if (this.disabled) return;
    this.value = value.slice(0, this.maxlength);
    this.onChangeHandler(this.value);
  }

  handleInputFocus() {
    if (this.disabled) return;
    this.focus = true;
    this.onFocusHandler();
  }

  handleInputBlur() {
    this.focus = false;
    this.onBlurHandler();
  }

  handleInputConfirm() {
    if (this.disabled) return;
    this.onConfirmHandler(this.value);
  }

  onClearTap() {
    if (this.disabled || !this.clear) return;
    this.value = '';
    this.onClearHandler();
  }

  // Event handlers (to be overridden)
