import { ThrowMyError } from "./Error";
import { GetCardsFromSecretDwarfDeck, GetMythologicalCreatureCardsFromSecretMythologicalCreatureDeck } from "./helpers/DecksHelpers";
import { DiscardCurrentCard, RemoveCardFromTavern } from "./helpers/DiscardCardHelpers";
import { AssertTavernCardId, AssertTavernIndex, AssertTierIndex } from "./is_helpers/AssertionTypeHelpers";
import { AddDataToLog } from "./Logging";
import { ErrorNames, GameModeNames, LogTypeNames, TavernNames } from "./typescript/enums";

// The functions below are implementations based on the given code snippet.

export const CheckIfCurrentTavernEmpty = ({ G }) => {
    return G.taverns[G.currentTavern].every((card) => card === null);
};

export const DiscardCardIfTavernHasCardFor2Players = ({ G, ctx, ...rest }) => {
    if ((G.mode === GameModeNames.Basic || G.mode === GameModeNames.Multiplayer) && ctx.numPlayers !== 2) {
        return ThrowMyError({ G, ctx, ...rest }, ErrorNames.OnlyInSoloOrTwoPlayersGame);
    }
    AddDataToLog({ G, ctx, ...rest }, LogTypeNames.Game, `Extra card from the current tavern ${TavernNames[G.currentTavern]} must be discarded in a game for two players or solo mode.`);
    DiscardCardFromTavern({ G, ctx, ...rest });
};

export const DiscardCardFromTavern = ({ G, ctx, ...rest }) => {
    const tavernCardId = G.taverns[G.currentTavern].findIndex((card) => card !== null);
    if (tavernCardId === -1) {
        return ThrowMyError({ G, ctx, ...rest }, ErrorNames.DoNotDiscardCardFromCurrentTavernIfNoCardInTavern, G.currentTavern);
    }
    AssertTavernCardId(tavernCardId);
    DiscardConcreteCardFromTavern({ G, ctx, ...rest }, tavernCardId);
};

export const DiscardConcreteCardFromTavern = ({ G, ctx, ...rest }, tavernCardId) => {
    const discardedCard = RemoveCardFromTavern({ G, ctx, ...rest }, tavernCardId);
    DiscardCurrentCard({ G, ctx, ...rest }, discardedCard);
    AddDataToLog({ G, ctx, ...rest }, LogTypeNames.Game, `Card '${discardedCard.type}' '${discardedCard.name}' from tavern ${TavernNames[G.currentTavern]} has been discarded.`);
};

export const RefillTaverns = ({ G, ctx, ...rest }) => {
    for (let t = 0; t < G.tavernsNum; t++) {
        let refillDeck;
        if (G.expansions.Idavoll.active && G.tierToEnd === 2 && G.round < 3 && t === 1) {
            refillDeck = GetMythologicalCreatureCardsFromSecretMythologicalCreatureDeck({ G, ctx, ...rest });
        } else {
            const tier = G.secret.decks.length - G.tierToEnd;
            AssertTierIndex(tier);
            refillDeck = GetCardsFromSecretDwarfDeck({ G, ctx, ...rest }, tier, 0, G.drawSize);
        }
        if (refillDeck.length !== G.drawSize) {
            return ThrowMyError({ G, ctx, ...rest }, ErrorNames.TavernCanNotBeRefilledBecauseNotEnoughCards, t);
        }
        AssertTavernIndex(t);
        const tavern = G.taverns[t];
        const removedCardsFromTavern = tavern.splice(0, tavern.length, ...refillDeck);
        if (tavern.length !== removedCardsFromTavern.length) {
            throw new Error(`Not enough cards in the tavern array with id '${t}': required - '${tavern.length}', available - '${removedCardsFromTavern.length}'.`);
        }
        AddDataToLog({ G, ctx, ...rest }, LogTypeNames.Game, `Tavern ${TavernNames[t]} has been refilled with new cards.`);
    }
    AddDataToLog({ G, ctx, ...rest }, LogTypeNames.Game, `All taverns have been refilled with new cards.`);
};

// Test cases to verify the solution correctness
// Note: The actual implementation of the test cases would depend on the full game context and setup, which is not provided here.
// The test cases below are pseudo-code and would need the full game implementation to run.

// Test case 1: Check if the current tavern is empty
const testContext1 = { G: { taverns: [[null, null, null]], currentTavern: 0 } };
console.assert(CheckIfCurrentTavernEmpty(testContext1) === true, "The current tavern should be empty.");

// Test case 2: Discard a card from the current tavern in a two-player game
const testContext2 = { G: { mode: GameModeNames.Basic, taverns: [[{ type: 'Dwarf', name: 'Miner' }, null, null]], currentTavern: 0 }, ctx: { numPlayers: 2 } };
DiscardCardIfTavernHasCardFor2Players(testContext2);
console.assert(testContext2.G.taverns[0][0] === null, "The card should be discarded from the current tavern.");

// Test case 3: Refill all taverns with new cards
const testContext3 = { G: { tavernsNum: 3, taverns: [[], [], []], secret: { decks: [[], [], []] }, tierToEnd: 1, drawSize: 3, expansions: { Idavoll: { active: false } }, round: 1 }, ctx: {} };
RefillTaverns(testContext3);
console.assert(testContext3.G.taverns.every(tavern => tavern.length === testContext3.G.drawSize), "All taverns should be refilled with new cards.");
