class Product {
    /**
     * Creates a new Product instance with a name and price.
     * @param {string} name - The name of the product.
     * @param {number} price - The price of the product.
     */
    constructor(name, price) {
        if (typeof name !== 'string' || typeof price !== 'number') {
            throw new Error('Invalid input types: name must be a string and price must be a number.');
        }
        this.name = name;
        this.price = price;
    }

    /**
     * Applies a discount to the product's price.
     * @param {number} discountPercentage - The discount percentage to apply.
     */
    applyDiscount(discountPercentage) {
        if (typeof discountPercentage !== 'number' || discountPercentage < 0 || discountPercentage > 100) {
            throw new Error('Invalid discount percentage. It must be a number between 0 and 100.');
        }
        this.price -= (this.price * discountPercentage) / 100;
    }

    /**
     * Displays the product's name and current price.
     */
    displayInfo() {
        console.log(`Product: ${this.name}, Price: $${this.price.toFixed(2)}`);
    }

    /**
     * Compares the prices of two products.
     * @param {Product} productA - The first product to compare.
     * @param {Product} productB - The second product to compare.
     * @returns {Product} - The product with the lower price.
     */
    static comparePrices(productA, productB) {
        if (productA.price < productB.price) {
            return productA;
        } else {
            return productB;
        }
    }
}

