   * @param {mongoose.Types.ObjectId} _id - The unique ID of the award record.
   * @returns {Promise<Object|null>} The award record, or null if not found.
   */
  static async findById(_id) {
    const award = await AwardModel.findById(_id);
    return award;
  }

  /**
   * Updates an existing award record's details.
   * @param {Object} updateParams - The parameters for updating the award.
   * @param {mongoose.Types.ObjectId} updateParams._id - The ID of the award to update.
   * @param {string} updateParams.fieldToUpdate - The field name to update.
   * @param {*} updateParams.newValue - The new value for the field.
   * @returns {Promise<Object|null>} The updated award record, or null if not found.
   */
  static async update({ _id, fieldToUpdate, newValue }) {
    const filter = { _id };
    const update = { [fieldToUpdate]: newValue };
    const option = { returnOriginal: false };

    const updatedAward = await AwardModel.findOneAndUpdate(
      filter,
      update,
      option
    );
    return updatedAward;
  }

  /**
   * Deletes an award record by its unique ID.
   * @param {mongoose.Types.ObjectId} _id - The ID of the award to delete.
   * @returns {Promise<Object>} The result of the deletion operation.
   */
  static async delete(_id) {
    const deletedAward = await AwardModel.deleteOne({ _id });
    return deletedAward;
  }
}

