function spiceMustFlow(initialYield) {
    const yieldConsumption = 26;
    let yieldStored = 0;
    let yieldTotal = 0;
    let days = 0;

    while (initialYield >= 100) {
        days++;
        yieldStored = initialYield - yieldConsumption;
        yieldTotal += yieldStored;
        initialYield -= 10;
    }

    if (yieldStored >= 26) {
        yieldTotal -= yieldConsumption;
    } else {
        yieldTotal -= yieldStored;
    }

    return {
        days: days,
        totalExtracted: yieldTotal
    };
}

