        var theId = "drop" + times;
        var element = $("<div class='drop' id='" + theId + "' style='top: -200px;'></div>");
        $('body').append(element);
        var spread = 100000;
        var x = Math.round(Math.random() * spread);
        x = (x / spread) * width;
        var y = Math.random() * 100 - 100;
        var size = Math.round(Math.random() * 20);
        $("#" + theId).css("left", x);

        var change = 6;
        function doIt(a, b, c) {
            $("#" + theId).css("width", a).css("height", b);
            var c = setInterval(function(){
                $("#" + theId).css("top", y);
                y += change;
                if (y > height) {
                    clearInterval(c);
                    $("#" + theId).remove();
                }
            }, c);
        }

        switch (size) {
