/**
 * Converts the input argument to a number if possible.
 * @param {*} input - The input to be converted to a number.
 * @returns {number} - The number representation of the input, or NaN if conversion is not possible.
 */
function convertToNumber(input) {
    if (typeof input === 'number') {
        return input; // No conversion needed
    } else if (typeof input === 'string') {
        // Attempt to parse the string as a number
        const parsed = Number(input);
        return isNaN(parsed) ? NaN : parsed;
    } else if (typeof input === 'boolean') {
        return input ? 1 : 0; // Convert boolean to 1 or 0
    } else if (input === null || input === undefined) {
        return NaN; // null and undefined cannot be converted to a number
    } else {
        // For other types, use the unary plus operator to attempt conversion
        return +input;
    }
}

// Test cases
