console.assert(convertToNumber(Number.MAX_VALUE) === Number.MAX_VALUE, 'Error: convertToNumber(Number.MAX_VALUE) should be Number.MAX_VALUE');
console.assert(convertToNumber(Number.MIN_VALUE) === Number.MIN_VALUE, 'Error: convertToNumber(Number.MIN_VALUE) should be Number.MIN_VALUE');
console.assert(isNaN(convertToNumber('not a number')), 'Error: convertToNumber("not a number") should be NaN');
console.assert(convertToNumber('   42   ') === 42, 'Error: convertToNumber("   42   ") should be 42');
