const path = require('path');
const glob = require('glob');

/**
 * Retrieves all files with a given extension within a directory and its subdirectories.
 * 
 * @param {string} dir - The directory to search within.
 * @param {string} ext - The file extension to filter by (without the dot).
 * @returns {Object} An object where keys are the relative paths without the extension,
 *                   and values are the relative paths with the extension.
 */
function getFilesByExtension(dir, ext) {
    const files = glob.sync(path.join(dir, `**/*.${ext}`), {nocase: true});
    const result = {};

    files.forEach(file => {
        const relativePath = path.relative(dir, file);
        const relativeName = relativePath.slice(0, relativePath.lastIndexOf('.'));
        result[relativeName] = './' + relativePath;
    });

    return result;
}

module.exports = getFilesByExtension;

