const EventEmitter = require('events');

class DatabaseMock extends EventEmitter {
  constructor() {
    super();
    this.storage = {};
  }

  get(key, options, callback) {
    process.nextTick(() => {
      const error = this.storage.hasOwnProperty(key) ? null : new Error('Key not found');
      const value = this.storage[key];
      callback(error, value);
    });
  }

  put(key, value, callback) {
    process.nextTick(() => {
      this.storage[key] = value;
      this.emit('put', key, value);
      callback(null);
    });
  }
}

class PersistentObject {
  constructor(db, name, fields) {
    this.db = db;
    this.name = name;
    this.fields = fields.slice();
    this.key = name + '-backup';
    this.restoreState();
    if (!process.env.TEST) {
      this.intervalId = setInterval(() => this.sync(), 1000);
    }
  }

  restoreState() {
    this.db.get(this.key, { sync: true }, (err, value) => {
      if (!err && value) {
        const backup = JSON.parse(value);
        for (const field of this.fields) {
          if (backup.hasOwnProperty(field)) {
            this[field] = backup[field];
          }
        }
      }
    });
  }

  sync() {
    const backup = this.fields.reduce((backup, field) => {
      if (this.hasOwnProperty(field)) {
        backup[field] = this[field];
      }
      return backup;
    }, {});
    this.db.put(this.key, JSON.stringify(backup), () => {});
  }

  dispose() {
    if (this.intervalId) {
      clearInterval(this.intervalId);
    }
  }
}

// Test cases
const db = new DatabaseMock();
const fields = ['name', 'age', 'email'];
const persistentObject = new PersistentObject(db, 'user1', fields);

// Simulate restoring from a backup
db.storage['user1-backup'] = JSON.stringify({ name: 'Alice', age: 30 });
persistentObject.restoreState();

setTimeout(() => {
  console.log(persistentObject.name); // Should log 'Alice'
  console.log(persistentObject.age); // Should log 30
  console.log(persistentObject.email); // Should be undefined

  // Simulate manual sync
  persistentObject.name = 'Bob';
  persistentObject.age = 25;
  persistentObject.sync();

  db.on('put', (key, value) => {
    if (key === 'user1-backup') {
      console.log('Backup updated:', value); // Should log the updated backup with Bob and 25
    }
  });

  // Clean up
  persistentObject.dispose();
}, 100);
