  StyleSheet,
  Text,
  View,
  ListView,
  TouchableHighlight,
  AsyncStorage,
  Image,
  Alert,
  StatusBar,
} from 'react-native';
import dateFormat from 'dateformat';
import Icon from 'react-native-vector-icons/FontAwesome';

// Define the key for storing diary entries
const DIARY_KEY = '@DiaryApp:diaries';

export default class DiaryTimeline extends Component {
  constructor(props) {
    super(props);
    this.state = {
      dataSource: new ListView.DataSource({rowHasChanged: (r1, r2) => r1 !== r2}),
      diaryEntries: [],
    };
  }

  componentDidMount() {
    this.loadDiaryEntries();
  }

  loadDiaryEntries = async () => {
    try {
      const entries = await AsyncStorage.getItem(DIARY_KEY);
      const parsedEntries = JSON.parse(entries) || [];
      this.setState({
        diaryEntries: parsedEntries,
        dataSource: this.state.dataSource.cloneWithRows(parsedEntries),
      });
    } catch (error) {
      Alert.alert('Error', 'Failed to load diary entries.');
    }
  };

  deleteDiaryEntry = async (index) => {
    try {
      let updatedEntries = [...this.state.diaryEntries];
      updatedEntries.splice(index, 1);
      await AsyncStorage.setItem(DIARY_KEY, JSON.stringify(updatedEntries));
      this.loadDiaryEntries();
    } catch (error) {
      Alert.alert('Error', 'Failed to delete diary entry.');
    }
  };

  renderDiaryEntry = (entry, sectionID, rowID) => {
    let entryDate = new Date(entry.timestamp);
    return (
      <View style={styles.entryContainer}>
        <View style={styles.dateContainer}>
          <Text style={styles.monthText}>{dateFormat(entryDate, 'mmm')}.</Text>
          <Text style={styles.dayText}>{dateFormat(entryDate, 'dd')}</Text>
