          <Text style={styles.entryDetails}>
            <Icon name="clock-o" /> {dateFormat(entryDate, 'HH:MM:ss')}{' '}
            <Icon name="map-marker" /> {entry.city}
          </Text>
          {entry.imageUrl && (
            <Image style={styles.entryImage} source={{ uri: entry.imageUrl }} />
          )}
          <TouchableHighlight
            onPress={() => this.deleteDiaryEntry(rowID)}
            style={styles.deleteButton}
          >
            <Text>Delete</Text>
          </TouchableHighlight>
        </View>
      </View>
    );
  };

  render() {
    return (
      <View style={styles.container}>
        <StatusBar barStyle="dark-content" />
        <ListView
          dataSource={this.state.dataSource}
          renderRow={this.renderDiaryEntry}
          enableEmptySections={true}
        />
      </View>
    );
  }
}

