// Importing the fetch API polyfill for environments that do not support it natively
import 'whatwg-fetch';

const $selectPrimary = document.getElementById("select-primary");
const $selectSecondary = document.getElementById("select-secondary");

function loadStates() {
    fetch(`https://api.copomex.com/query/get_estados?token=pruebas`)
        .then(response => response.json())
        .then(data => {
            const states = data.response.estados;
            $selectPrimary.innerHTML = states.map(state => `<option value="${state}">${state}</option>`).join('');
