        .then(response => response.json())
        .then(data => {
            const towns = data.response.municipios;
            $selectSecondary.innerHTML = towns.map(town => `<option value="${town}">${town}</option>`).join('');
        })
        .catch(error => {
            console.error(`Error fetching towns for state ${state}:`, error);
        });
}

document.addEventListener("DOMContentLoaded", loadStates);

