// Middleware to protect routes and ensure the user is logged in
exports.protect = catchAsync(async (req, res, next) => {
  let token;
  if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
    token = req.headers.authorization.split(' ')[1];
  }

  if (!token) {
    return next(new AppError('You are not logged in! Please log in to get access', 401));
  }

  const decoded = await promisify(jwt.verify)(token, process.env.SECRET_JWT_SEED);

  const user = await User.findOne({
    where: {
      id: decoded.id,
      status: true,
    },
  });

  if (!user) {
    return next(new AppError('The owner of this token is not longer available', 401));
  }

  if (user.passwordChangedAt) {
    const changedTimeStamp = parseInt(user.passwordChangedAt.getTime() / 1000, 10);
    if (decoded.iat < changedTimeStamp) {
      return next(new AppError('User recently changed password! Please log in again.', 401));
    }
  }

  req.sessionUser = user;
  next();
});

// Middleware to verify if the authenticated user is the account owner
exports.protectAccountOwner = catchAsync(async (req, res, next) => {
  const { user, sessionUser } = req;

  if (user.id !== sessionUser.id) {
    return next(new AppError('You do not own this account.', 401));
  }

  next();
});

// Middleware to restrict access based on user role
exports.restrictTo = (...roles) => {
  return (req, res, next) => {
    if (!roles.includes(req.sessionUser.role)) {
