```javascript
const grpc = require("grpc");
const loader = require("@grpc/proto-loader");
const PATH = "127.0.0.1:50050";

// Load the protobuf
const packageDefinition = loader.loadSync("./notes.proto", {
  keepCase: true,
  longs: String,
  enums: String,
  defaults: true,
  oneofs: true
});

// Load package definition
const notePackage = grpc.loadPackageDefinition(packageDefinition).notes;

// Create gRPC client
const client = new notePackage.NoteService(PATH, grpc.credentials.createInsecure());

/**
 * Create a new note using the NoteService.
 * @param {string} title - The title of the note.
 * @param {string} content - The content of the note.
 * @returns {Promise<Object>} - The promise object containing the note ID.
 */
function createNote(title, content) {
  return new Promise((resolve, reject) => {
    const note = { title, content };
    client.CreateNote(note, (error, response) => {
      if (error) {
        reject(error);
      } else {
        resolve(response);
      }
    });
  });
}

/**
 * List all notes using the NoteService.
 * @returns {Promise<Array>} - The promise object containing an array of notes.
 */
function listNotes() {
  return new Promise((resolve, reject) => {
    client.ListNotes({}, (error, response) => {
      if (error) {
        reject(error);
      } else {
        resolve(response.notes);
      }
    });
  });
}

// Export the client and functions for external use
module.exports = {
  client,
  createNote,
  listNotes
};

// Test cases
async function test() {
  try {
    // Create a new note
    const noteId = await createNote("My first note", "This is the content of my first note.");
    console.log("Note created with ID:", noteId.id);

    // List all notes
    const notes = await listNotes();
    console.log("List of notes:", notes);
  } catch (error) {
    console.error("Error:", error);
  }
}

test();
