const { JSDOM } = require("jsdom");
const fetch = require("node-fetch");

/**
 * Crawls a web page and all linked pages within the same domain.
 * @param {string} baseUrl - The base URL to start crawling from.
 * @param {string} currentUrl - The current URL being crawled.
 * @param {Object} pages - An object mapping URLs to the number of times they have been visited.
 * @returns {Promise<Object>} A promise that resolves to the updated pages object.
 */
async function crawlPage(baseUrl, currentUrl, pages) {
    const baseURLObj = new URL(baseUrl);
    const currentURLObj = new URL(currentUrl);

    if (baseURLObj.hostname !== currentURLObj.hostname) {
        return pages;
    }

    const normalizedCurrentUrl = normalizeUrl(currentUrl);
    if (pages[normalizedCurrentUrl] > 0) {
        pages[normalizedCurrentUrl]++;
        return pages;
    }

    pages[normalizedCurrentUrl] = 1;
    console.log(`Actively crawling ${currentUrl}`);

    try {
        const resp = await fetch(currentUrl);

        if (resp.status > 399) {
            console.log(`Error with status code: ${resp.status} on page: ${currentUrl}`);
            return pages;
        }

        const contentType = resp.headers.get("content-type");
        if (!contentType.includes("text/html")) {
            console.log(`Non-html content type: ${contentType}, on page: ${currentUrl}`);
            return pages;
        }

        const htmlBody = await resp.text();
        const nextURLs = getUrlsFromHtml(htmlBody, baseUrl);

        for (const nextURL of nextURLs) {
            pages = await crawlPage(baseUrl, nextURL, pages);
        }
    } catch (err) {
        console.log(`Failed due to error: ${err.message} on page: ${currentUrl}`);
    }
    return pages;
}

/**
 * Extracts and normalizes URLs from the HTML content of a page.
 * @param {string} htmlBody - The HTML content of the page.
 * @param {string} baseUrl - The base URL used for resolving relative URLs.
 * @returns {string[]} An array of normalized URLs found in the HTML content.
 */
function getUrlsFromHtml(htmlBody, baseUrl) {
    const urls = [];
    const dom = new JSDOM(htmlBody);
    const linkElements = dom.window.document.querySelectorAll("a");

    for (const linkElement of linkElements) {
        const href = linkElement.href.startsWith('/') ? `${baseUrl}${linkElement.href}` : linkElement.href;
        try {
            const urlObj = new URL(href);
            urls.push(urlObj.href);
        } catch (error) {
            console.log(`Error with URL: ${error.message}`);
        }
    }
    return urls;
}

/**
 * Normalizes a URL by removing the trailing slash if present.
 * @param {string} urlString - The URL string to normalize.
 * @returns {string} The normalized URL string.
 */
function normalizeUrl(urlString) {
    const urlObj = new URL(urlString);
    const hostPath = `${urlObj.hostname}${urlObj.pathname}`;

    return hostPath.endsWith('/') ? hostPath.slice(0, -1) : hostPath;
}

// Export the functions for testing or other modules
module.exports = {
    normalizeUrl,
    getUrlsFromHtml,
    crawlPage
};

// Example usage:
(async () => {
    const baseUrl = 'http://example.com';
    const pages = await crawlPage(baseUrl, baseUrl, {});
    console.log(pages);
})();
