function printRangeAndComputeSum(start, end) {
    // Validate input
    if (!Number.isInteger(start) || !Number.isInteger(end)) {
        throw new Error('Both start and end must be integers.');
    }
    if (start > end) {
        throw new Error('Start must be less than or equal to end.');
    }

    let sum = 0;
    let printedRange = "";

    for (let i = start; i <= end; i++) {
        printedRange += i + " ";
        sum += i;
    }

    // Print the range
    console.log(printedRange.trim());
    // Print the sum
    console.log(`Sum: ${sum}`);

    return { printedRange: printedRange.trim(), sum: sum };
