import renderPage from './renderPage';

/**
 * Renders an array of blog entries to HTML and JSON files on the filesystem.
 * Each entry is processed sequentially to avoid file system conflicts.
 * 
 * @param {Array} entries - An array of blog entry objects.
 * @returns {Promise<void>} A promise that resolves when all entries have been rendered.
 */
export default async function renderBlogEntries(entries) {
  for (let entry of entries) {
    const url = `/entries/${entry.slug}/`;

    const hydratedEntries = {};
    hydratedEntries[entry.slug] = true;

    const data = {
      entries: {
        entries: [entry],
        hydratedEntries: hydratedEntries,
        hydratedList: false
      }
    };

    mkdirp(`_site/entries/${entry.slug}`);
    const htmlPath = `_site/entries/${entry.slug}/index.html`;
    const jsonPath = `_site/entries/${entry.slug}/data.json`;

    // Render the page to HTML
    await renderPage({
      data: data,
      url: url,
      path: htmlPath
    });

    // Write the entry data to a JSON file
    const entryJson = JSON.stringify(entry);
    writeFileSync(jsonPath, entryJson, { encoding: 'utf8' });
  }
}

