/**
 * Removes HTML comments from a string based on the provided options.
 *
 * @param {string} html - The HTML string to process.
 * @param {Object} options - The options object.
 * @param {number} options.removeHTMLComments - The level of HTML comment removal.
 * @returns {Object} - An object with the result and applicable options.
 */
function removeHtmlComments(html, options) {
  const { removeHTMLComments } = options;
  let result = html;
  const applicableOpts = {
    removeHTMLComments: removeHTMLComments !== 0,
    removeCSSComments: false,
  };

  if (removeHTMLComments === 1) {
    // Remove all HTML comments except for conditional comments
    result = html.replace(/<!--(?!\s*\[if\s+).*?-->/gs, '');
  } else if (removeHTMLComments === 2) {
    // Remove all HTML comments, including conditional comments
    result = html.replace(/<!--.*?-->/gs, '');
  }

  return { result, applicableOpts };
}

// Test cases
import tap from "tap";

tap.test('removeHtmlComments - no removal', (t) => {
  const html = '<!-- comment --><div>content</div><!-- another comment -->';
  t.same(removeHtmlComments(html, { removeHTMLComments: 0 }), {
    result: html,
    applicableOpts: {
      removeHTMLComments: false,
      removeCSSComments: false,
    },
  });
  t.end();
});

tap.test('removeHtmlComments - remove non-conditional comments', (t) => {
  const html = '<!-- comment --><div>content</div><!--[if IE]>conditional<![endif]-->';
  t.same(removeHtmlComments(html, { removeHTMLComments: 1 }), {
    result: '<div>content</div><!--[if IE]>conditional<![endif]-->',
    applicableOpts: {
      removeHTMLComments: true,
      removeCSSComments: false,
    },
  });
  t.end();
});

tap.test('removeHtmlComments - remove all comments', (t) => {
  const html = '<!-- comment --><div>content</div><!--[if IE]>conditional<![endif]-->';
  t.same(removeHtmlComments(html, { removeHTMLComments: 2 }), {
    result: '<div>content</div>',
    applicableOpts: {
      removeHTMLComments: true,
      removeCSSComments: false,
    },
  });
  t.end();
});
