/**
 * AudioPlayer encapsulates the functionality of an audio player.
 * It handles the creation of an HTML audio element, controls playback,
 * and manages audio metadata for the media session.
 */
class AudioPlayer {
  /**
   * Creates an instance of AudioPlayer.
   * @param {HTMLElement} element - The HTML element where the audio player will be attached.
   */
  constructor(element) {
    this.element = element;
    this.audio = null;
    this.metadata = {};
    this.isPlaying = false;
  }

  /**
   * Creates and configures the internal <audio> element.
   */
  buildAudioElement() {
    this.audio = document.createElement('audio');
    this.audio.controls = true;
    this.propagateAttributes([
      'src',
      'preload',
      'autoplay',
      'muted',
      'loop',
      'aria-label',
      'aria-describedby',
      'aria-labelledby',
      'controlsList',
    ], this.audio);
    this.element.appendChild(this.audio);

    this.audio.addEventListener('playing', () => this.audioPlaying());
    this.audio.addEventListener('play', () => this.triggerAnalyticsEvent('audio-play'));
    this.audio.addEventListener('pause', () => this.triggerAnalyticsEvent('audio-pause'));
  }

  /**
   * Plays the audio if the player is valid and not part of an <amp-story> element.
   */
  play() {
    if (this.isInvocationValid()) {
      this.audio.play();
      this.isPlaying = true;
    }
  }

  /**
   * Pauses the audio if the player is valid and not part of an <amp-story> element.
   */
  pause() {
    if (this.isInvocationValid()) {
      this.audio.pause();
      this.isPlaying = false;
    }
  }

  /**
   * Sets the media session metadata.
   * @param {Object} metadata - The metadata for the media session.
   */
  setMediaSession(metadata) {
    this.metadata = metadata;
    // Implementation for setting the media session would go here.
  }

  /**
   * Checks if the audio player is a descendant of an <amp-story> element.
   * @return {boolean}
   */
  isStoryDescendant() {
    let parent = this.element.parentElement;
    while (parent) {
      if (parent.tagName === 'AMP-STORY') {
        return true;
      }
      parent = parent.parentElement;
    }
    return false;
  }

  /**
   * Propagates specified attributes to the audio element.
   * @param {string[]} attributes - The attributes to propagate.
   * @param {HTMLElement} audio - The audio element.
   */
  propagateAttributes(attributes, audio) {
    attributes.forEach(attr => {
      if (this.element.hasAttribute(attr)) {
        audio.setAttribute(attr, this.element.getAttribute(attr));
      }
    });
  }

  /**
   * Triggers a custom analytics event.
   * @param {string} eventName - The name of the event to trigger.
   */
  triggerAnalyticsEvent(eventName) {
    // Implementation for triggering analytics events would go here.
    console.log(`Analytics event triggered: ${eventName}`);
  }

  /**
   * Checks if the function is allowed to be called.
   * @return {boolean}
   */
  isInvocationValid() {
    if (!this.audio) {
      return false;
    }
    if (this.isStoryDescendant()) {
      console.warn('<amp-story> elements do not support actions on <audio> elements');
      return false;
    }
    return true;
  }

  /**
   * Handles the 'playing' event of the audio element.
   */
  audioPlaying() {
    this.isPlaying = true;
    // Additional logic for when the audio starts playing would go here.
  }
}

