const mongoose = require('mongoose');
const { Schema } = mongoose;

// Assuming the connection to MongoDB is established elsewhere in the application
// and the mongoose instance is connected to the database.

// Define the User schema
const userSchema = new Schema({
  name: String,
  tenant: { type: Schema.Types.ObjectId, ref: 'Tenant' }
});
const UserModel = mongoose.model('User', userSchema);

// Define the Tenant schema
const tenantSchema = new Schema({
  name: { type: String, unique: true },
  version: String,
  users: [{ ref: { type: Schema.Types.ObjectId, ref: 'User' } }]
});
const TenantModel = mongoose.model('Tenant', tenantSchema);

// Implement the required functions
function getAllTenants_IdVersion() {
    return TenantModel.find().select('name version').exec();
}

function getAllTenants_Full() {
    return TenantModel.find().populate('users.ref', 'name').exec();
}

function getTenantByName_Full(name) {
    return TenantModel.findOne({ name }).populate('users.ref', 'name').exec();
}

function getTenantById_IdVersion(id) {
    return TenantModel.findById(id).select('name version').exec();
}

function createTenant(name, version) {
    return new Promise((resolve, reject) => {
        TenantModel.findOne({ name }).then(tenant => {
            if (!tenant) {
                const newTenant = new TenantModel({ name, version, users: [] });
                newTenant.save((err, savedTenant) => {
                    if (err) reject(err);
                    else resolve(savedTenant);
                });
            } else {
                reject(new Error(`Tenant already exists: ${name}`));
            }
        }).catch(reject);
    });
}

function linkUserToTenant(tenant_id, user_id) {
    return new Promise((resolve, reject) => {
        TenantModel.findById(tenant_id).exec().then(tenant => {
            if (tenant.users.some(user => user.ref.toString() === user_id)) {
                reject(new Error("User already linked to this tenant."));
            } else {
                tenant.users.push({ ref: user_id });
                tenant.save(err => {
                    if (err) reject(err);
                    else {
                        UserModel.findByIdAndUpdate(user_id, { tenant: tenant_id }, err => {
                            if (err) reject(err);
                            else resolve();
                        });
                    }
                });
            }
        }).catch(reject);
    });
}

function upgradeTenant(name, version) {
    return new Promise((resolve, reject) => {
        TenantModel.findOne({ name }).select('name version').exec().then(tenant => {
            if (!tenant) {
                reject(new Error(`Tenant not found: ${name}`));
            } else {
                tenant.version = version;
                tenant.save((err, updatedTenant) => {
                    if (err) reject(err);
                    else resolve(updatedTenant);
                });
            }
        }).catch(reject);
    });
}

// Export the functions for use in other parts of the application
module.exports = {
  getAllTenants_IdVersion,
  getAllTenants_Full,
  getTenantById_IdVersion,
  linkUserToTenant,
  createTenant,
  getTenantByName_Full,
  upgradeTenant
};

// Test cases to verify the solution correctness
async function runTests() {
  try {
    // Test case 1: Create a new tenant
    const newTenant = await createTenant('TenantA', '1.0');
    console.log('New Tenant:', newTenant);

    // Test case 2: Link a user to the new tenant
    const newUser = await UserModel.create({ name: 'UserA' });
