'use strict';

const { Transform } = require('stream');

const FRAMESEQUENCE = 'END'; // Example frame sequence
const FRAMESEQUENCEBUFFER = Buffer.from(FRAMESEQUENCE);

const IDS = new Set();

class FrameHeader {
    constructor({ id, index, end }) {
        this.id = id;
        this.index = index;
        this.end = end;
    }

    toBuffer() {
        const buffer = Buffer.alloc(9);
        buffer.writeUInt32BE(this.id, 0);
        buffer.writeUInt32BE(this.index, 4);
        buffer[8] = this.end ? 1 : 0;
        return buffer;
    }
}

class ResponseFrameMarker extends Transform {
    constructor() {
        super();

        this._index = 0;
        this._id = ResponseFrameMarker.randomId();
    }

    _transform(chunk, encoding, next) {
        this._index += 1;
        const labeledChunk = this.labelChunk(chunk);
        this.push(labeledChunk);
        next();
    }

    _flush(next) {
        this._index += 1;
        const labeledChunk = this.labelChunk(Buffer.from(''), true);
        this.push(labeledChunk);
        IDS.delete(this._id);
        next();
    }

    labelChunk(buffer, isEnd = false) {
        const header = new FrameHeader({ id: this._id, index: this._index, end: isEnd }).toBuffer();
        return Buffer.concat([header, buffer, FRAMESEQUENCEBUFFER]);
    }

    static randomId() {
        let id;
        do {
            id = ResponseFrameMarker.generateId();
        } while (IDS.has(id));
        IDS.add(id);
        return id;
    }

    static generateId() {
        return Math.floor(Math.random() * 4294967295);
    }
}

module.exports = ResponseFrameMarker;

// Test cases
const assert = require('assert');

function testResponseFrameMarker() {
    const testChunks = [Buffer.from('chunk1'), Buffer.from('chunk2'), Buffer.from('chunk3')];
    const transformer = new ResponseFrameMarker();

    let index = 0;
    transformer.on('data', (data) => {
        const expectedHeader = new FrameHeader({ id: transformer._id, index: ++index, end: false }).toBuffer();
        const expectedFrame = Buffer.concat([expectedHeader, testChunks[index - 1], FRAMESEQUENCEBUFFER]);
        assert.deepStrictEqual(data.slice(0, expectedFrame.length), expectedFrame, 'Frame does not match expected output');
    });

    transformer.on('end', () => {
        console.log('All frames have been processed correctly.');
    });

    testChunks.forEach(chunk => transformer.write(chunk));
    transformer.end();
}

testResponseFrameMarker();
