const { Readable } = require('stream');

class BufferedStream extends Readable {
  /**
   * Creates an instance of BufferedStream.
   * @param {Function} dataSource - An async function that returns a Promise that resolves to a Buffer or null.
   */
  constructor(dataSource) {
    super();
    this.dataSource = dataSource;
    this.internalBuffer = Buffer.alloc(0);
    this.reading = false;
  }

  /**
   * Internal method called by the stream consumer to request more data.
   * @param {number} size - The number of bytes to read.
   */
  async _read(size) {
    if (this.reading) return;
    this.reading = true;

    try {
      while (this.internalBuffer.length < size) {
        const data = await this.dataSource();
        if (data === null) {
          this.push(null);
          return;
        }
        this.internalBuffer = Buffer.concat([this.internalBuffer, data]);
      }

      const chunk = this.internalBuffer.slice(0, size);
      this.internalBuffer = this.internalBuffer.slice(size);
      this.push(chunk);
    } catch (error) {
      this.emit('error', error);
    } finally {
      this.reading = false;
    }
  }

  /**
   * Internal method called to clean up resources.
   * @param {Error|null} error - An error that occurred while reading or null.
   * @param {Function} callback - A callback function to call after cleanup.
   */
  _destroy(error, callback) {
    this.internalBuffer = null;
    this.dataSource = null;
    callback(error);
  }
}

// Test cases
(async () => {
  // Mock data source function
  const mockData = [Buffer.from('Hello'), Buffer.from(' '), Buffer.from('World'), null];
  const dataSource = async () => {
    return mockData.shift();
  };

  const bufferedStream = new BufferedStream(dataSource);

  // Consume the stream
  bufferedStream.on('data', (chunk) => {
    console.log(chunk.toString());
  });

  bufferedStream.on('end', () => {
    console.log('Stream ended.');
  });

  bufferedStream.on('error', (error) => {
    console.error('Stream encountered an error:', error);
  });
})();
