var glob = require('glob');
var async = require('async');
var fs = require('fs');
var path = require('path');

/**
 * Reads the content of a file at the given path.
 * @param {string} path - The path to the file.
 * @param {function} done - The callback function.
 */
var readFile = function(path, done) {
  return fs.readFile(path, 'utf8', done);
};

/**
 * Compares the contents of text files in two directories to determine if they are identical.
 * @param {string} referenceDir - The directory containing the reference files.
 * @param {string} targetDir - The directory containing the files to compare against the reference.
 * @param {function} done - The callback function called with an error or a boolean indicating whether all files matched.
 */
module.exports = function(referenceDir, targetDir, done) {
  var compareFile = function(file, done) {
    var referenceFile = path.join(referenceDir, file);
    var targetFile = path.join(targetDir, file);

    async.map([referenceFile, targetFile], readFile, function(err, results) {
      if (err) {
        return done(err);
      }

      done(null, results[0] === results[1]);
    });
  };

  glob('**/*.txt', { cwd: referenceDir, nodir: true }, function(err, files) {
    if (err) {
      return done(err);
    }

    async.map(files, compareFile, function(err, results) {
      if (err) {
        return done(err);
      }

      done(null, !results.some(function(result) { return !result; }));
    });
  });
};

// Test cases to verify the solution correctness
const compareDirectories = require('./compareDirectories');

compareDirectories('./referenceDir', './targetDir', (err, match) => {
  if (err) {
    console.error('An error occurred:', err);
  } else if (match) {
    console.log('All files match!');
  } else {
    console.log('Files do not match.');
  }
});
