        if (err) {
            console.error('Error initializing log:', err);
        } else {
            console.log('Log initialized successfully.');
        }
    });
}

/**
 * Appends a new entry to the log file with the current timestamp.
 * @param {string} message - The log message to be added.
 */
function addEntry(message) {
    const logEntry = `${new Date().toISOString()} - ${message}\n`;
    fs.appendFile(logFilePath, logEntry, (err) => {
        if (err) {
            console.error('Error adding entry:', err);
        } else {
            console.log('Entry added successfully.');
        }
    });
}

/**
