import axios from 'axios';
import Resizer from 'react-image-file-resizer';

/**
 * Resizes an image file and uploads it to a server.
 *
 * @param {File} file - The image file to be resized and uploaded.
 * @param {number} maxWidth - The maximum width of the resized image.
 * @param {number} maxHeight - The maximum height of the resized image.
 * @param {string} uploadUrl - The server endpoint to which the image will be uploaded.
 * @param {function} onProgress - A callback function that receives the upload progress percentage.
 * @param {function} onSuccess - A callback function that is called when the upload is successful.
 * @param {function} onError - A callback function that is called when an error occurs.
 */
function resizeAndUploadImage(file, maxWidth, maxHeight, uploadUrl, onProgress, onSuccess, onError) {
  Resizer.imageFileResizer(
    file,
    maxWidth,
    maxHeight,
    'JPEG',
    100,
    0,
    (uri) => {
      const formData = new FormData();
      formData.append('image', uri);

      axios.post(uploadUrl, formData, {
        headers: {
          'Content-Type': 'multipart/form-data',
        },
        onUploadProgress: (progressEvent) => {
          const percentCompleted = Math.round((progressEvent.loaded * 100) / progressEvent.total);
          onProgress(percentCompleted);
        },
      })
      .then((response) => {
        onSuccess(response.data);
      })
      .catch((error) => {
        onError(error);
      });
    },
    'base64'
  );
}

