function closePlayerConfig() {
  playerConfigOverlayElement.style.display = 'none';
  backdropElement.style.display = 'none';
  formElement.firstElementChild.classList.remove('error');
  errorsOutputConfigElement.textContent = '';
  playernameInputElement.value = '';
}

// Function to save player configuration
function savePlayerConfig(event) {
  event.preventDefault();
  const formData = new FormData(event.target);
  const enteredPlayername = formData.get('playername').trim();

  if (!enteredPlayername) { // Player name is empty
    event.target.firstElementChild.classList.add('error');
    errorsOutputConfigElement.textContent = 'Please enter a valid name!';
    return;
  }

  players[editedPlayer - 1].name = enteredPlayername;

  closePlayerConfig();
}

// Function to start a new game
function startNewGame() {
  if (players[0].name === '' || players[1].name === '') {
    errorsOutputPlayersElement.textContent = 'Please set custom player names for both players!';
    return;
  }

  errorsOutputPlayersElement.textContent = '';
  activePlayer = 0;
  currentRound = 1;
  isGameOver = false;
  gameData = [
    [0, 0, 0],
    [0, 0, 0],
    [0, 0, 0],
  ];

  activePlayerNameElement.textContent = players[activePlayer].name;
  gameOverElement.style.display = 'none';

  for (const gameFieldElement of gameFieldElements) {
    gameFieldElement.textContent = '';
    gameFieldElement.classList.remove('disabled');
  }

  gameAreaElement.style.display = 'block';
}

// Function to handle game field selection
function selectGameField(event) {
  if (event.target.tagName !== 'LI' || isGameOver) {
    return;
  }

  const selectedField = event.target;
  const selectedColumn = selectedField.dataset.col - 1;
  const selectedRow = selectedField.dataset.row - 1;

  if (gameData[selectedRow][selectedColumn] > 0) {
    return;
  }

  selectedField.textContent = players[activePlayer].symbol;
  selectedField.classList.add('disabled');

  gameData[selectedRow][selectedColumn] = activePlayer + 1;

  const winnerId = checkForGameOver();

  if (winnerId !== 0) {
    endGame(winnerId);
  }

  currentRound++;
  switchPlayer();
}

// Function to switch the active player
function switchPlayer() {
  if (activePlayer === 0) {
    activePlayer = 1;
  } else {
    activePlayer = 0;
  }

  activePlayerNameElement.textContent = players[activePlayer].name;
}

// Function to check if the game is over
function checkForGameOver() {
  // Check for a winner
  for (let i = 0; i < 3; i++) {
    if (
      gameData[i][0] > 0 &&
      gameData[i][0] === gameData[i][1] &&
      gameData[i][1] === gameData[i][2]
    ) {
      return gameData[i][0];
    }
  }

  for (let i = 0; i < 3; i++) {
    if (
      gameData[0][i] > 0 &&
      gameData[0][i] === gameData[1][i] &&
      gameData[1][i] === gameData[2][i]
    ) {
      return gameData[0][i];
    }
  }

  if (
    gameData[0][0] > 0 &&
    gameData[0][0] === gameData[1][1] &&
    gameData[1][1] === gameData[2][2]
  ) {
    return gameData[0][0];
  }

  if (
    gameData[0][2] > 0 &&
    gameData[0][2] === gameData[1][1] &&
    gameData[1][1] === gameData[2][0]
  ) {
    return gameData[0][2];
  }

  // Check for a draw
  if (currentRound === 9) {
    return -1; // Draw
  }

  return 0; // Game is not over
}

// Function to end the game
function endGame(winnerId) {
  isGameOver = true;
  gameOverElement.style.display = 'block';

  if (winnerId > 0) {
    winnerNameElement.textContent = players[winnerId - 1].name;
  } else {
    winnerNameElement.textContent = 'It\'s a draw!';
  }

  for (const gameFieldElement of gameFieldElements) {
    gameFieldElement.classList.add('disabled');
  }
}

