import path from 'path';
import gulp from 'gulp';
import plumber from 'gulp-plumber';
import notify from 'gulp-notify';
import pug from 'gulp-pug';
import prettyHtml from 'gulp-pretty-html';
import fs from 'fs';
import browserSync from 'browser-sync';
import data from 'gulp-data';
import debug from 'gulp-debug';

// Configuration object
const cfg = {
  dir: {
    src: './src',
    app: 'app',
    all: '**/*',
  },
  template: {
    view: 'views',
    page: 'pages',
    pug: '*.pug',
  },
  entries: {
    pug: 'index.pug',
  },
};

// Task target directory
const taskTarget = './dist';

// BrowserSync instance
const bs = browserSync.create();

// Error handling function
function showError(title, err) {
  notify.onError({
    title: `Error: ${title}`,
    message: '<%= error.message %>',
  })(err);
  this.emit('end');
}

// Pug filter for displaying code
function filterShowCode(text, options) {
  let lines = text.split('\n');
  let result = '<pre class="code">\n';
  if (typeof options['first-line'] !== 'undefined') {
    result += `  <code>  ${options['first-line']}  </code>\n`;
  }
  for (let i = 0; i < lines.length - 1; i++) {
    result += `<code>  ${lines[i].replace(/</gm, '&lt;')}  </code>\n`;
  }
  result += '</pre>\n';
  result = result.replace(/<code><\/code>/g, '<code>&nbsp;</code>');
  return result;
}

// Gulp task for compiling Pug templates
gulp.task('pug', () => {
  let dir = cfg.dir;
  let template = cfg.template;
  let dest = path.join(taskTarget);
  let filePath = path.join(
    dir.src,
    dir.app,
    template.view,
    template.page,
    dir.all,
    template.pug
  );
  let pugOption = {
    pretty: '\t',
    data: { repoUrl: 'https://github.com/ngocsangyem/NNS-Start-Project' },
    filters: { 'show-code': filterShowCode },
  };
  let prettyOption = {
    indent_size: 2,
    indent_char: ' ',
    unformatted: ['code', 'em', 'strong', 'span', 'i', 'b', 'br', 'script'],
    content_unformatted: [],
  };

  return gulp
    .src(filePath)
    .pipe(
      plumber({
        errorHandler: notify.onError('Error: <%= error.message %>'),
      })
    )
    .pipe(
      data(() => JSON.parse(fs.readFileSync('./src/seo.json')))
    )
    .pipe(pug(pugOption).on('error', function(err) {
      showError.apply(this, ['Pug compile error', err]);
    }))
    .pipe(prettyHtml(prettyOption))
    .pipe(debug({ title: 'Compiles:' }))
    .pipe(gulp.dest(dest))
    .pipe(bs.reload({ stream: true }));
});

// Gulp task for serving files with BrowserSync
gulp.task('serve', () => {
  bs.init({
    server: {
      baseDir: taskTarget,
    },
  });

  // Watch for changes in Pug files
  gulp.watch(cfg.dir.src + '/**/*.pug', gulp.series('pug'));
});

// Default task
gulp.task('default', gulp.series('pug', 'serve'));

// Test cases to verify the solution correctness
