import Matrix from 'some-matrix-library'; // Replace with actual matrix library import
import Tensor from 'some-tensor-library'; // Replace with actual tensor library import

/**
 * Applies the Concatenated ReLU activation function to the input matrix or tensor.
 * @param {Matrix|Tensor} input - The input matrix or tensor.
 * @returns {Matrix|Tensor} - The output after applying the CReLU activation function.
 */
function concatenatedReluActivation(input) {
  if (input instanceof Matrix) {
    const output = new Matrix(input.rows, input.cols * 2);
    for (let i = 0; i < input.rows; i++) {
      for (let j = 0; j < input.cols; j++) {
        output.set(i, j, Math.max(0, input.get(i, j)));
        output.set(i, j + input.cols, Math.max(0, -input.get(i, j)));
      }
    }
    return output;
  } else if (input instanceof Tensor) {
    const sizes = [...input.sizes];
    sizes[sizes.length - 1] *= 2;
    const output = new Tensor(sizes);
    input.forEach((value, ...indices) => {
      const lastIdx = indices.pop();
      output.set(...indices, lastIdx, Math.max(0, value));
      output.set(...indices, lastIdx + input.sizes[input.sizes.length - 1], Math.max(0, -value));
    });
    return output;
  }
  throw new Error('Input must be a Matrix or Tensor');
}

/**
 * Computes the gradient of the CReLU activation function.
 * @param {Matrix|Tensor} input - The original input matrix or tensor.
 * @param {Matrix|Tensor} gradOutput - The gradient of the output.
 * @returns {Matrix|Tensor} - The gradient of the input.
 */
function concatenatedReluGradient(input, gradOutput) {
  if (input instanceof Matrix && gradOutput instanceof Matrix) {
    const gradInput = new Matrix(input.rows, input.cols);
    for (let i = 0; i < input.rows; i++) {
      for (let j = 0; j < input.cols; j++) {
        gradInput.set(i, j, input.get(i, j) >= 0 ? gradOutput.get(i, j) : -gradOutput.get(i, j + input.cols));
      }
    }
    return gradInput;
  } else if (input instanceof Tensor && gradOutput instanceof Tensor) {
    const gradInput = new Tensor(input.sizes);
    input.forEach((value, ...indices) => {
      const lastIdx = indices.pop();
      gradInput.set(
        ...indices,
        lastIdx,
        value >= 0 ? gradOutput.get(...indices, lastIdx) : -gradOutput.get(...indices, lastIdx + input.sizes[input.sizes.length - 1])
      );
    });
    return gradInput;
  }
  throw new Error('Input and gradOutput must be both Matrices or both Tensors');
}

// Test cases
const matrixInput = new Matrix([[1, -2], [3, -4]]);
const tensorInput = new Tensor([[[1, -2], [3, -4]]]);

console.log('CReLU Activation (Matrix):', concatenatedReluActivation(matrixInput).toString());
console.log('CReLU Activation (Tensor):', concatenatedReluActivation(tensorInput).toString());

const gradOutputMatrix = new Matrix([[1, 0, 0, 1], [1, 0, 0, 1]]);
const gradOutputTensor = new Tensor([[[1, 0, 0, 1], [1, 0, 0, 1]]]);

console.log('CReLU Gradient (Matrix):', concatenatedReluGradient(matrixInput, gradOutputMatrix).toString());
console.log('CReLU Gradient (Tensor):', concatenatedReluGradient(tensorInput, gradOutputTensor).toString());
