'use strict';

const sfccCodeApi = require('sfcc-ci').code;

/**
 * Upload a code archive to a Commerce Cloud instance.
 * @param {string} instance - A hostname for a Commerce Cloud instance.
 * @param {string} archive - The file path to the local archive.
 * @param {string} token - The OAuth token to use for authentication.
 * @param {Object} options - An object containing upload options (2FA credentials).
 * @returns {Promise} - A promise that resolves to the result of deploying the code archive.
 */
function deploy(instance, archive, token, options) {
    const pfx = options.p12;
    const passphrase = options.passphrase;

    return new Promise((resolve, reject) => {
        sfccCodeApi.deploy(instance, archive, token, { pfx, passphrase }, (result) => {
            if (typeof (result) !== 'undefined') {
                reject(result);
                return;
            }
            resolve(true);
        });
    });
}

/**
 * Upload code archives to Commerce Cloud instances.
 * @param {string[]} instances - An array of hostnames for Commerce Cloud instances.
 * @param {string[]} archives - The file paths to the local archive files.
 * @param {string} token - The OAuth token to use for authentication.
 * @param {Object} options - An object containing upload options (2FA credentials).
 * @returns {Promise[]} - A promise that resolves to an array of results of deploying the code archives.
 */
function deployArchivesToInstances(instances, archives, token, options) {
    if (!instances || !instances.length) {
        throw new Error('At least one instance hostname is required');
    }
    if (!archives || !archives.length) {
        throw new Error('At least one archive file path is required');
    }

    let deploymentPromises = [];
    instances.forEach(instance => {
        archives.forEach(archive => {
            deploymentPromises.push(deploy(instance, archive, token, options));
        });
    });

    return Promise.all(deploymentPromises);
}

// Export the function for use in other modules
