// This variable should be set with your New York Times API key
// It should be kept secret and not exposed in the code
const authKey = process.env.NYT_API_KEY;

const articleSearchHelper = {
  /**
   * Searches for articles in the New York Times Article Search API.
   * @param {string} term - The search term for querying articles.
   * @param {string} [startDate] - The start date for the date range filter (optional).
   * @param {string} [endDate] - The end date for the date range filter (optional).
   * @returns {Promise<Array>} A promise that resolves to an array of articles.
   */
  runQuery: function(term, startDate, endDate) {
    let queryURL = `https://api.nytimes.com/svc/search/v2/articlesearch.json?api-key=${authKey}&q=${term}`;

    // Append date range to the query URL if provided
    if (startDate) {
      queryURL += `&begin_date=${startDate}`;
    }
    if (endDate) {
      queryURL += `&end_date=${endDate}`;
    }

    return axios.get(queryURL).then(function(response) {
      // Extract the articles from the response
      const articles = response.data.response.docs.map(doc => ({
        headline: doc.headline.main,
        pub_date: doc.pub_date,
        web_url: doc.web_url
      }));
      return articles;
    });
  }
};

// Export the articleSearchHelper module
module.exports = articleSearchHelper;

// Test cases
(async () => {
  try {
    // Test case 1: Search for articles with the term "space"
    const articles1 = await articleSearchHelper.runQuery("space");
