    template: `
      <StackLayout class="home-panel">
          <Button v-if="boolValue" text="${config.toggleTexts.trueState}" @tap="boolValue = !boolValue"></Button>
          <Button v-if="!boolValue" text="${config.toggleTexts.falseState}" @tap="boolValue = !boolValue"></Button>
