Create a function `transformProductData` that takes in a product object with nested store information and transforms it into a flat object based on the provided `ProductDTO` template. The function should map the properties of the input object to the corresponding keys in the `ProductDTO`, where the keys represent the path to the value in the input object.

The input product object will have the following structure:

```javascript
{
  _id: "unique_product_id",
  name: "Product Name",
  description: "Product Description",
  stores: [
    {
      name: "Store Name",
      price: 99.99,
      shipping: "5-7 days",
      url: "https://store.example.com/product"
    },
    // ... more stores
  ]
}
```

The output should be a flat object with keys as specified in the `ProductDTO` and values from the input object. If the input object does not have a value for a specified path, the output should have that key with a value of `null`.

For example, if the input object does not have a `description`, the output should have `{ description: null }`.

output:
```javascript
const ProductDTO = {
  _id: 'id',
  name: 'name',
  description: 'description',
  'stores[].name': 'stores[].name',
  'stores[].price': 'stores[].price',
  'stores[].shipping': 'stores[].shipping',
  'stores[].url': 'stores[].url',
};

/**
 * Transforms a product object into a flat object based on the ProductDTO template.
 * @param {Object} product - The product object to transform.
 * @returns {Object} The transformed product object.
 */
function transformProductData(product) {
  const transformed = {};

  for (const key in ProductDTO) {
    const path = key.split('.');
    let value = product;

    for (const segment of path) {
      if (segment.endsWith('[]')) {
        const arrayKey = segment.slice(0, -2);
        if (!value[arrayKey]) {
          value = null;
          break;
        }
        value = value[arrayKey].map((item) => item[ProductDTO[key]]);
      } else {
        value = value[segment] !== undefined ? value[segment] : null;
      }
    }

    transformed[ProductDTO[key]] = value;
  }

  return transformed;
}

// Test cases
console.log(transformProductData({
  _id: "123",
  name: "Widget",
  description: "A useful widget.",
  stores: [
    {
      name: "Store A",
      price: 12.99,
      shipping: "2-4 days",
      url: "https://store-a.example.com/widget"
    },
    {
      name: "Store B",
      price: 11.99,
      shipping: "5-7 days",
      url: "https://store-b.example.com/widget"
    }
  ]
}));

console.log(transformProductData({
  _id: "456",
  name: "Gadget",
  stores: [
    {
      name: "Store C",
      price: 22.99,
      shipping: "1-3 days",
      url: "https://store-c.example.com/gadget"
    }
  ]
}));
