function parseMarkdownTitle(markdown) {
  const titleTypes = {
    '"': 'double',
    "'": 'single',
    '(': 'parenthesized'
  };

  const startChar = markdown[0];
  const endChar = titleTypes[startChar] === 'parenthesized' ? ')' : startChar;

  if (!titleTypes[startChar] || markdown[markdown.length - 1] !== endChar) {
    throw new Error('Invalid markdown title format');
  }

  let title = '';
  let isEscaped = false;

  for (let i = 1; i < markdown.length - 1; i++) {
    const char = markdown[i];

    if (isEscaped) {
      if (char !== startChar && char !== '\\') {
        title += '\\';
      }
      title += char;
      isEscaped = false;
    } else if (char === '\\') {
      isEscaped = true;
    } else if (char !== endChar) {
      title += char;
    } else {
      throw new Error('Unescaped end character found in markdown title');
    }
  }

  if (isEscaped) {
    throw new Error('Markdown title ends with an incomplete escape sequence');
  }

  return {
    type: titleTypes[startChar],
    title: title
  };
}

// Test cases
console.log(parseMarkdownTitle(`"This is a \\"quoted\\" title"`)); // { type: 'double', title: 'This is a "quoted" title' }
console.log(parseMarkdownTitle(`'A single-quoted title'`)); // { type: 'single', title: 'A single-quoted title' }
console.log(parseMarkdownTitle(`(A title with (parentheses))`)); // { type: 'parenthesized', title: 'A title with (parentheses)' }
console.log(parseMarkdownTitle(`"Mismatched quotes'`)); // Error: Invalid markdown title format
console.log(parseMarkdownTitle(`"No ending quote`)); // Error: Invalid markdown title format
console.log(parseMarkdownTitle(`"Escape at the end\\"`)); // Error: Markdown title ends with an incomplete escape sequence
