  const { name, email } = req.body;
  const id = uuidv4();
  users[id] = { id, name, email };
  res.status(201).send(users[id]);
});

// Retrieve all users
app.get('/users', (req, res) => {
  res.send(Object.values(users));
});

// Retrieve a single user by ID
app.get('/users/:id', userExists, (req, res) => {
  const { id } = req.params;
  res.send(users[id]);
});

// Update a user by ID
app.put('/users/:id', userExists, (req, res) => {
  const { id } = req.params;
  const { name, email } = req.body;
  users[id] = { ...users[id], name, email };
  res.send(users[id]);
});

// Delete a user by ID
app.delete('/users/:id', userExists, (req, res) => {
  const { id } = req.params;
