const { challenges, searchTestCases } = require('./path-to-challenges-module');

/**
 * Searches through a collection of challenge objects and returns the number of challenges
 * that match a given search query.
 * 
 * @param {Object} challenges - An object containing challenge details.
 * @param {string} query - The search term to match against challenge names.
 * @return {number} The count of challenges that match the search query.
 */
function searchChallenges(challenges, query) {
  let count = 0;
  const lowerCaseQuery = query.toLowerCase();
  for (const challengeKey in challenges) {
    if (challenges.hasOwnProperty(challengeKey)) {
      const challengeName = challenges[challengeKey].name.toLowerCase();
      if (challengeName.includes(lowerCaseQuery)) {
        count++;
      }
    }
  }
  return count;
}

// Test cases
console.log('Running test cases...');
for (const testCaseKey in searchTestCases) {
  if (searchTestCases.hasOwnProperty(testCaseKey)) {
    const testCase = searchTestCases[testCaseKey];
    const result = searchChallenges(challenges, testCase.query);
    console.log(`${testCaseKey}: ${result === testCase.expectedCount ? 'Passed' : 'Failed'}`);
  }
}
