/**
 * This script sets up a Redux store for a web application with Redux-Saga middleware
 * for handling asynchronous actions and side effects. It also integrates Reactotron
 * for enhanced debugging capabilities in development mode. The store is configured
 * with a root reducer and a root saga, and Reactotron is conditionally applied based
 * on the environment. The configured store is exported for use throughout the application.
 *
 * To verify the correctness of the store configuration, test cases are provided that
 * check the integration of middlewares, enhancers, and the running of the root saga.
 */

import { createStore, compose, applyMiddleware } from 'redux';
import createSagaMiddleware from 'redux-saga';
import reducers from './ducks'; // Assume this is the root reducer
import rootSaga from './sagas'; // Assume this is the root saga

// Conditionally apply Reactotron configuration in development mode
let sagaMonitor = null;
let reactoTronRedux = null;
if (process.env.NODE_ENV === 'development') {
  const reactotron = require('../config/reactotron').default;
  sagaMonitor = reactotron.createSagaMonitor();
  reactoTronRedux = reactotron.createEnhancer();
}

const sagaMiddleware = createSagaMiddleware({ sagaMonitor });
const middlewares = [sagaMiddleware];

// Create the Redux store with the root reducer, middleware, and enhancers
const store = createStore(
  reducers,
  compose(
    applyMiddleware(...middlewares),
    reactoTronRedux ? reactoTronRedux : f => f // Apply Reactotron enhancer if available
  )
);

// Run the root saga
sagaMiddleware.run(rootSaga);

export default store;

// Test cases to verify the correctness of the store configuration
if (process.env.NODE_ENV === 'test') {
  // Test 1: Store should be an object
  console.assert(typeof store === 'object', 'Store is not an object');

  // Test 2: Store should have a dispatch function
  console.assert(typeof store.dispatch === 'function', 'Store does not have a dispatch function');

  // Test 3: Store should have a getState function
  console.assert(typeof store.getState === 'function', 'Store does not have a getState function');

  // Test 4: Store should have a subscribe function
  console.assert(typeof store.subscribe === 'function', 'Store does not have a subscribe function');

  // Test 5: Store should have a replaceReducer function
  console.assert(typeof store.replaceReducer === 'function', 'Store does not have a replaceReducer function');

  // Additional tests can be written to simulate actions and check if sagas handle them correctly
}
