/* global describe, it, beforeEach, after */
/* jshint expr: true */

const html = `
    <body>
      <div id="one">
          <p>one-1</p>
          <p>one-2</p>
          <p>one-3</p>
          <p>one-4</p>
      </div>
      <div id="two">
          <p>two-1</p>
          <p>two-2</p>
          <p>two-3</p>
          <p>two-4</p>
      </div>
    </body>`;

const helper = {
  isCli: () => typeof process !== 'undefined'
};

let domQuery, chai;

if (helper.isCli()) {
  const jsdom = require('jsdom');
  const { JSDOM } = jsdom;
  const dom = new JSDOM(html);
  const { window } = dom;
  const { document } = window;

  global.window = window;
  global.document = document;
  chai = require('chai');
} else {
  document.body.innerHTML = html;
  chai = window.chai;
}

const expect = chai.expect;

// Define the domQuery library
domQuery = (function() {
  const _domQuery = function(selector) {
    const elements = Array.from(document.querySelectorAll(selector));
    return new QueryCollection(elements);
  };

  class QueryCollection {
    constructor(elements) {
      this.elements = elements;
    }

    select(selector) {
      this.elements = this.elements.map(el => Array.from(el.querySelectorAll(selector))).flat();
      return this;
    }

    filter(predicate) {
      this.elements = this.elements.filter(predicate);
      return this;
    }

    first() {
      this.elements = this.elements.length > 0 ? [this.elements[0]] : [];
      return this;
    }

    last() {
      this.elements = this.elements.length > 0 ? [this.elements[this.elements.length - 1]] : [];
      return this;
    }

    nth(index) {
      this.elements = index >= 0 && index < this.elements.length ? [this.elements[index]] : [];
      return this;
    }

    each(callback) {
      this.elements.forEach(callback);
      return this;
    }

    addClass(className) {
      this.elements.forEach(el => el.classList.add(className));
      return this;
    }

    removeClass(className) {
      this.elements.forEach(el => el.classList.remove(className));
      return this;
    }

    toggleClass(className) {
      this.elements.forEach(el => el.classList.toggle(className));
      return this;
    }

    text(content) {
      this.elements.forEach(el => el.textContent = content);
      return this;
    }

    html(content) {
      this.elements.forEach(el => el.innerHTML = content);
      return this;
    }
  }

  return _domQuery;
})();

// Test cases
describe('domQuery tests', () => {
  beforeEach(() => {
    // Reset the HTML content before each test
    document.body.innerHTML = html;
  });

  it('should select elements by CSS selector', () => {
    const paragraphs = domQuery('p');
    expect(paragraphs.elements.length).to.equal(8);
  });

  it('should filter elements', () => {
    const paragraphsInOne = domQuery('p').filter(el => el.parentElement.id === 'one');
    expect(paragraphsInOne.elements.length).to.equal(4);
  });

  it('should select the first element', () => {
    const firstParagraph = domQuery('p').first();
    expect(firstParagraph.elements.length).to.equal(1);
    expect(firstParagraph.elements[0].textContent).to.equal('one-1');
  });

  it('should select the last element', () => {
    const lastParagraph = domQuery('p').last();
    expect(lastParagraph.elements.length).to.equal(1);
    expect(lastParagraph.elements[0].textContent).to.equal('two-4');
  });

  it('should select the nth element', () => {
    const thirdParagraph = domQuery('p').nth(2);
    expect(thirdParagraph.elements.length).to.equal(1);
    expect(thirdParagraph.elements[0].textContent).to.equal('one-3');
  });

  it('should execute a callback on each element', () => {
    domQuery('p').each((el, i) => el.textContent = `Paragraph ${i}`);
    const paragraphs = domQuery('p');
    paragraphs.elements.forEach((el, i) => {
      expect(el.textContent).to.equal(`Paragraph ${i}`);
    });
  });

  it('should add a class to all selected elements', () => {
    domQuery('p').addClass('test-class');
    const paragraphs = domQuery('p.test-class');
    expect(paragraphs.elements.length).to.equal(8);
  });

  it('should remove a class from all selected elements', () => {
    domQuery('p').addClass('test-class').removeClass('test-class');
    const paragraphs = domQuery('p.test-class');
    expect(paragraphs.elements.length).to.equal(0);
  });

  it('should toggle a class on all selected elements', () => {
    domQuery('p').toggleClass('test-class');
    const paragraphs = domQuery('p.test-class');
    expect(paragraphs.elements.length).to.equal(8);
    domQuery('p').toggleClass('test-class');
    const paragraphsAfterToggle = domQuery('p.test-class');
    expect(paragraphsAfterToggle.elements.length).to.equal(0);
  });

  it('should set the text content of all selected elements', () => {
    domQuery('p').text('New content');
    const paragraphs = domQuery('p');
    paragraphs.elements.forEach(el => {
      expect(el.textContent).to.equal('New content');
    });
  });

  it('should set the HTML content of all selected elements', () => {
    domQuery('p').html('<span>HTML content</span>');
    const paragraphs = domQuery('p');
    paragraphs.elements.forEach(el => {
      expect(el.innerHTML).to.equal('<span>HTML content</span>');
    });
  });
});

after(() => {
