const express = require('express');
const path = require('path');

const app = express();
const port = 5000;

// Middleware to check if the current time is within business hours
const businessHoursMiddleware = (req, res, next) => {
    const date = new Date();
    const hour = date.getHours();
    const day = date.getDay();

    // Business hours are 9:00 AM to 5:00 PM, Monday to Friday
    if (hour >= 9 && hour < 17 && day >= 1 && day <= 5) {
        next();
    } else {
        res.send('Come Back Later');
    }
};

// Apply the middleware to all routes
app.use(businessHoursMiddleware);

// Serve static files from the 'public' directory
app.use(express.static(path.join(__dirname, 'public')));

// Route handlers
app.get('/', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'HomePage.html'));
});

app.get('/contactus', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'ContactUs.html'));
});

app.get('/ourservice', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'OurService.html'));
});

app.get('/styles.css', (req, res) => {
    res.sendFile(path.join(__dirname, 'public', 'styles.css'));
});

// Start the server
app.listen(port, () => console.log(`Server is running on http://localhost:${port}`));

// Test cases
// Note: These test cases are meant to be run manually to verify the server's response.
// 1. Access the root URL (http://localhost:5000/) during business hours - should serve HomePage.html
// 2. Access the /contactus URL (http://localhost:5000/contactus) during business hours - should serve ContactUs.html
// 3. Access the /ourservice URL (http://localhost:5000/ourservice) during business hours - should serve OurService.html
// 4. Access any URL outside of business hours - should display "Come Back Later"
