/**
 * Validates a configuration object for a JavaScript testing environment.
 * @param {Object} config - The configuration object to validate.
 * @returns {Object} An object with a boolean `isValid` and an array of `errors`.
 */
function validateConfig(config) {
  const errors = [];

  if (config.testEnvironment !== 'jsdom' && config.testEnvironment !== 'node') {
    errors.push('testEnvironment must be either \'jsdom\' or \'node\'.');
  }

  if (config.preset !== 'ts-jest') {
    errors.push('preset must be \'ts-jest\'.');
  }

  if (!Array.isArray(config.setupFilesAfterEnv) || !config.setupFilesAfterEnv.every(path => typeof path === 'string' && path.startsWith('<rootDir>'))) {
    errors.push('setupFilesAfterEnv must be an array containing at least one string with a valid file path starting with \'<rootDir>\'.');
  }

  if (!Array.isArray(config.testPathIgnorePatterns) || !config.testPathIgnorePatterns.includes('/node_modules/')) {
    errors.push('testPathIgnorePatterns must be an array containing the string \'/node_modules/\'.');
  }

  if (!Array.isArray(config.testMatch) || !config.testMatch.every(pattern => pattern === '<rootDir>/src/**/*.{spec,test}.{ts,tsx}')) {
    errors.push('testMatch must be an array containing strings that match the pattern \'<rootDir>/src/**/*.{spec,test}.{ts,tsx}\'.');
  }

  if (typeof config.moduleNameMapper !== 'object' || Object.keys(config.moduleNameMapper).some(key => !key.startsWith('^')) || Object.values(config.moduleNameMapper).some(value => !value.startsWith('<rootDir>'))) {
    errors.push('moduleNameMapper must be an object where keys start with \'^\' and values start with \'<rootDir>\'.');
  }

  return {
    isValid: errors.length === 0,
    errors: errors
  };
}

// Test cases
const validConfig = {
  testEnvironment: 'jsdom',
  preset: 'ts-jest',
  setupFilesAfterEnv: ['<rootDir>/src/setupTests.ts'],
  testPathIgnorePatterns: ['/node_modules/'],
  testMatch: ['<rootDir>/src/**/*.{spec,test}.{ts,tsx}'],
  moduleNameMapper: {
    '^.+(css|sass|scss)$': 'identity-obj-proxy',
    '^@components(.*)$': '<rootDir>/src/components$1',
    '^@hooks(.*)$': '<rootDir>/src/hooks$1',
    '^@api(.*)$': '<rootDir>/src/api$1',
    '^@shared(.*)$': '<rootDir>/src/shared$1',
  },
};

const invalidConfig = {
  testEnvironment: 'unknown',
  preset: 'jest',
  setupFilesAfterEnv: ['/setupTests.ts'],
  testPathIgnorePatterns: ['/vendor/'],
  testMatch: ['<rootDir>/tests/**/*.{spec,test}.{js,jsx}'],
  moduleNameMapper: {
    '^.+(css|sass|scss)$': '/styles',
    '^@components(.*)$': '/components$1',
  },
};

console.log(validateConfig(validConfig)); // Should return { isValid: true, errors: [] }
console.log(validateConfig(invalidConfig)); // Should return { isValid: false, errors: [...] }
