const withPWA = require('next-pwa');

/**
 * Generates a Next.js configuration object with security headers and PWA support.
 * @param {Object} options - Configuration options.
 * @param {boolean} [options.isDevelopment=false] - Indicates if the environment is for development.
 * @param {string} [options.pwaDestination='public'] - Destination directory for PWA assets.
 * @param {boolean} [options.includeSecurityHeaders=true] - Indicates if security headers should be included.
 * @returns {Object} Next.js configuration object.
 */
function configureNextApp({ isDevelopment = false, pwaDestination = 'public', includeSecurityHeaders = true } = {}) {
  const headers = async () => {
    if (!includeSecurityHeaders) return [];
    return [
      {
        source: '/(.*)',
        headers: [
          {
            key: 'X-Content-Type-Options',
            value: 'nosniff',
          },
          {
            key: 'X-Frame-Options',
            value: 'SAMEORIGIN',
          },
          {
            key: 'X-XSS-Protection',
            value: '1; mode=block',
          },
        ],
      },
    ];
  };

  const pwaConfig = withPWA({
    dest: pwaDestination,
    disable: isDevelopment,
  });

  return pwaConfig({
    experimental: {
      appDir: true,
      fontLoaders: [
        { loader: '@next/font/google', options: { subsets: ['latin'] } },
      ],
    },
    headers,
  });
}

module.exports = configureNextApp;

// Test cases
