const fetch = require('node-fetch');

/**
 * Fetches details of a given Pokémon and its weaknesses and strengths.
 * @param {string} pokemonName - The name of the Pokémon to search for.
 * @returns {Promise<object>} A promise that resolves to an object containing Pokémon details.
 */
function fetchPokemonDetails(pokemonName) {
  const baseUrl = 'https://pokeapi.co/api/v2';
  let pokemonDetails = {};

  return fetch(`${baseUrl}/pokemon/${pokemonName.toLowerCase()}/`)
    .then((response) => {
      if (!response.ok) {
        throw new Error(`Pokémon not found: ${pokemonName}`);
      }
      return response.json();
    })
    .then((data) => {
      pokemonDetails = {
        name: data.name,
        id: data.id,
        types: data.types.map((typeObj) => typeObj.type.name),
        stats: data.stats.map((statObj) => ({
          name: statObj.stat.name,
          base_stat: statObj.base_stat,
        })),
      };

      // Fetch type details to find weaknesses and strengths
      return fetch(`${baseUrl}/type/${pokemonDetails.types[0]}/`);
    })
    .then((response) => response.json())
    .then((typeData) => {
      const weaknesses = typeData.damage_relations.double_damage_from.map((typeObj) => typeObj.name);
      const strengths = typeData.damage_relations.double_damage_to.map((typeObj) => typeObj.name);

      return {
        ...pokemonDetails,
        weaknesses,
        strengths,
      };
    })
    .catch((error) => {
      return { error: error.message };
    });
}

// Test cases
fetchPokemonDetails('pikachu').then(console.log); // Should return details for Pikachu
fetchPokemonDetails('charizard').then(console.log); // Should return details for Charizard
fetchPokemonDetails('nonexistent').then(console.log); // Should return an error message
