/**
 * The ModuleRegistry class manages the registration and retrieval of dynamically
 * loaded code modules. It also tracks the loaded chunks by their names.
 */
class ModuleRegistry {
  constructor(initialState = []) {
    this.modules = {};
    this.chunks = {};

    // Register initial state modules if provided
    initialState.forEach(({ id, module }) => {
      this.registerModule(id, module);
    });
  }

  /**
   * Registers a module with a unique identifier.
   * @param {string} moduleHash - The unique identifier for the module.
   * @param {Function} module - The module function to register.
   */
  registerModule(moduleHash, module) {
    this.modules[moduleHash] = module;
  }

  /**
   * Retrieves a registered module by its identifier.
   * @param {string} moduleHash - The unique identifier for the module.
   * @returns {Function|undefined} - The registered module function or undefined if not found.
   */
  retrieveModule(moduleHash) {
    return this.modules[moduleHash];
  }

  /**
   * Registers a chunk as loaded by its name.
   * @param {string} chunkName - The name of the chunk to register as loaded.
   */
  registerChunkLoaded(chunkName) {
    this.chunks[chunkName] = true;
  }

  /**
   * Checks if a chunk has been loaded by its name.
   * @param {string} chunkName - The name of the chunk to check.
   * @returns {boolean} - True if the chunk is loaded, false otherwise.
   */
  isChunkLoaded(chunkName) {
    return !!this.chunks[chunkName];
  }
}

// Test cases to verify the solution correctness
const registry = new ModuleRegistry();

// Registering modules and chunks
registry.registerModule('module1', () => 'Module 1 Function');
registry.registerChunkLoaded('chunk1');

// Retrieving registered modules
console.log(registry.retrieveModule('module1')()); // Should output: Module 1 Function

// Checking if chunks are loaded
console.log(registry.isChunkLoaded('chunk1')); // Should output: true
console.log(registry.isChunkLoaded('chunk2')); // Should output: false

// Registering modules with initial state
const initialState = [
  { id: 'module2', module: () => 'Module 2 Function' },
  { id: 'module3', module: () => 'Module 3 Function' },
];
const registryWithState = new ModuleRegistry(initialState);

// Retrieving modules from initial state
console.log(registryWithState.retrieveModule('module2')()); // Should output: Module 2 Function
console.log(registryWithState.retrieveModule('module3')()); // Should output: Module 3 Function
