function parseBetResult(str) {
    var data = {};
    const regexGales = /Fazer até (\d+) gales/;
    const regexWin = /WIN/;
    const regexLoss = /LOSS/;
    const matchGales = str.match(regexGales);
    let galesNumber;

    if (matchGales && matchGales.length > 1) {
        galesNumber = matchGales[1];
    }

    if (galesNumber !== undefined) {
        data.gales = galesNumber;
        data.enter = str.includes('Apostar no ⚫️') ? 'BLACK' : 'RED';
        data.protect = 'WHITE';
    } else if (regexWin.test(str)) {
        data.gales = 'WIN';
        data.enter = 'WIN';
        data.protect = 'WIN';
    } else if (regexLoss.test(str)) {
        data.gales = 'LOSS';
        data.enter = 'LOSS';
        data.protect = 'LOSS';
    } else {
        return false;
    }

    return data;
}

// Test cases
console.log(parseBetResult("Fazer até 3 gales Apostar no ⚫️")); // { gales: '3', enter: 'BLACK', protect: 'WHITE' }
console.log(parseBetResult("Fazer até 5 gales")); // { gales: '5', enter: 'RED', protect: 'WHITE' }
console.log(parseBetResult("WIN")); // { gales: 'WIN', enter: 'WIN', protect: 'WIN' }
console.log(parseBetResult("LOSS")); // { gales: 'LOSS', enter: 'LOSS', protect: 'LOSS' }
console.log(parseBetResult("Invalid input")); // false
