const { Sequelize, DataTypes } = require('sequelize');

// Assuming that a Sequelize instance `sequelize` has been initialized and connected to the database.
const sequelize = new Sequelize('database', 'username', 'password', {
  dialect: 'postgres',
  // other options
});

/**
 * Creates the 'member_events' table and sets it up as a hypertable.
 * @returns {Promise} A promise that resolves when the table and hypertable have been created.
 */
function createMemberEventsTable() {
  return sequelize.transaction(async (t) => {
    await sequelize.define('member_events', {
      user_id: {
        allowNull: false,
        primaryKey: true,
        type: DataTypes.BIGINT,
      },
      guild_id: {
        allowNull: false,
        primaryKey: true,
        type: DataTypes.BIGINT,
      },
      type: {
        allowNull: false,
        primaryKey: true,
        type: DataTypes.ENUM('JOIN', 'LEAVE'),
      },
      timestamp: {
        allowNull: false,
        primaryKey: true,
        type: DataTypes.DATE,
      },
    }).sync({ transaction: t });

    await sequelize.query('SELECT create_hypertable(\'member_events\', \'timestamp\')', { transaction: t });
  });
}

/**
 * Drops the 'member_events' table and the associated ENUM type.
 * @returns {Promise} A promise that resolves when the table and ENUM type have been dropped.
 */
function dropMemberEventsTable() {
  return sequelize.transaction(async (t) => {
    await sequelize.getQueryInterface().dropTable('member_events', { transaction: t });
    await sequelize.query('DROP TYPE IF EXISTS enum_member_events_type', { transaction: t });
  });
}

// Test cases
async function test() {
  try {
    console.log('Creating member_events table...');
    await createMemberEventsTable();
    console.log('member_events table created successfully.');

    console.log('Dropping member_events table...');
    await dropMemberEventsTable();
    console.log('member_events table dropped successfully.');
  } catch (error) {
    console.error('An error occurred:', error);
  }
}

test();
