  /**
   * Constructs a new DeliveryPackage instance.
   * @param {string} name - The name of the package.
   * @param {string} location - The location where the package is to be delivered.
   * @param {number} weight - The weight of the package in kilograms.
   * @param {boolean} isFragile - Indicates if the package contains fragile items.
   * @param {string} deliveryDate - The expected delivery date in "YYYY-MM-DD" format.
   */
  constructor(name, location, weight, isFragile, deliveryDate) {
    super(name, location);
    this.weight = weight;
    this.isFragile = isFragile;
    this.deliveryDate = deliveryDate;
  }

  /**
   * Calculates the shipping cost for the package.
   * @returns {number} The total shipping cost.
   */
  calculateShippingCost() {
    const baseCostPerKg = 2;
    const fragileItemFee = this.isFragile ? 10 : 0;
    return (this.weight * baseCostPerKg) + fragileItemFee;
  }
}

