/**
 * Executes a mathematical function within a guardrail mechanism.
 * @param {Function} mathFunction - A zero-argument function that performs a calculation.
 * @returns {Array} An array containing the result of the mathFunction or an error message, and a string "Guardrail was processed".
 */
function guardrail(mathFunction) {
  const queue = [];

  try {
    const result = mathFunction();
    queue.push(result);
  } catch (error) {
    queue.push(`Error: ${error.message}`);
  } finally {
    queue.push('Guardrail was processed');
  }

  return queue;
}

function executeWithGuardrail(mathFunction) {
  return guardrail(mathFunction);
}

// Test cases
console.log(executeWithGuardrail(() => 10 / 2)); // Should return [5, "Guardrail was processed"]
console.log(executeWithGuardrail(() => 10 / 0)); // Should return ["Error: Division by zero", "Guardrail was processed"]
console.log(executeWithGuardrail(() => { throw new Error('Test error'); })); // Should return ["Error: Test error", "Guardrail was processed"]

// Exporting the function for use in other modules
export default executeWithGuardrail;
