/**
 * Trims file paths from the stack trace, leaving only function names and line numbers.
 * @param {string} stack - The stack trace string.
 * @return {string} The trimmed stack trace.
 */
function TrimStackTracePath(stack) {
    return stack.split('\n').map(line => {
        return line.replace(/(\s+at\s+).*\((.*?):(\d+):(\d+)\)/, '$1$2:$3:$4');
    }).join('\n');
}

/**
 * Logs output to the console or alerts it, depending on the environment.
 * @param {string} output - The output to log or alert.
 */
function Dump(output) {
    if (typeof console !== 'undefined') {
        console.log(output);
    } else if (typeof alert !== 'undefined') {
        alert(output);
    }
}

/**
 * Creates a chain of nested functions that throw an error at the specified depth.
 * @param {number} depth - The number of nested functions to create.
 * @param {boolean} catchException - Whether to catch the exception or let it propagate.
 */
function createExceptionThrower(depth, catchException) {
    var helper = function(i) {
        return function() {
            if (i === 0) {
                if (catchException) {
                    try {
                        throw new Error("Error at depth " + depth);
                    } catch (e) {
                        Dump(TrimStackTracePath(e.stack));
                    }
                } else {
                    throw new Error("Error at depth " + depth);
                }
            } else {
                that["function" + (i - 1)]();
            }
        };
    };

    var that = {};
    for (var i = 0; i < depth; i++) {
        that["function" + i] = helper(i);
    }
    that["function" + (depth - 1)]();
}

// Test cases to verify the solution
try {
    createExceptionThrower(3, false);
} catch (e) {
    console.log("Caught exception from createExceptionThrower with catchException=false:", e.message);
}

createExceptionThrower(3, true);
