// Required packages for the webpack configuration
const path = require('path');
const HtmlWebpackPlugin = require('html-webpack-plugin');
const MiniCssExtractPlugin = require('mini-css-extract-plugin');
const { CleanWebpackPlugin } = require('clean-webpack-plugin');

/**
 * Generates a webpack configuration object for a given environment and project settings.
 * @param {string} environment - The environment mode ('development' or 'production').
 * @param {Object} settings - The project-specific settings.
 * @returns {Object} The webpack configuration object.
 */
function configureWebpack(environment, settings) {
  // Set environment variables for Babel
  process.env.BABEL_ENV = environment;
  process.env.NODE_ENV = environment;

  // Create plugin instances
  const htmlPlugin = new HtmlWebpackPlugin({
    title: settings.title,
    template: settings.templatePath,
    filename: 'index.html',
    favicon: settings.faviconPath,
    minify: environment === 'production' ? { removeAttributeQuotes: true } : false,
  });

  const cssPlugin = new MiniCssExtractPlugin({
    filename: 'main.css?[hash]',
  });

  const cleanPlugin = new CleanWebpackPlugin({
    cleanOnceBeforeBuildPatterns: [settings.outputPath],
    verbose: true,
    dry: false,
  });

  // Return the webpack configuration object
  return {
    entry: ['babel-polyfill', settings.entryPoint],
    mode: environment,
    output: {
      filename: 'main.js?[hash]',
      path: path.resolve(__dirname, settings.outputPath),
    },
    resolve: {
      modules: [path.resolve(__dirname, '../node_modules')],
    },
    plugins: [cleanPlugin, htmlPlugin, cssPlugin],
    module: {
      rules: [
        {
          test: /\.(js|jsx)$/,
          use: 'babel-loader',
          exclude: /node_modules/,
        },
        {
          test: /\.css$/,
          use: [MiniCssExtractPlugin.loader, 'css-loader'],
        },
        {
          test: /\.(less)$/,
          use: [MiniCssExtractPlugin.loader, 'css-loader', 'less-loader'],
        },
        {
          test: /\.(sass|scss)$/,
          use: [MiniCssExtractPlugin.loader, 'css-loader', 'sass-loader'],
        },
        {
          test: /\.(gif|png|jpg|woff|svg|ttf|eot)$/,
          use: [
            {
              loader: 'url-loader',
              options: {
                limit: 1024,
                outputPath: settings.assetsPath,
                name: '[name].[ext]?[hash]',
              },
            },
          ],
        },
      ],
    },
  };
}

