/**
 * Returns the complementary DNA strand for a given DNA sequence.
 * 
 * @param {string} dna - A string representing a DNA sequence.
 * @returns {string} The complementary DNA strand.
 */
function complementDNA(dna) {
    let complementaryStrand = "";
    for (let i = 0; i < dna.length; i++) {
        switch (dna[i]) {
            case 'A':
                complementaryStrand += "T";
                break;
            case 'T':
                complementaryStrand += "A";
                break;
            case 'G':
                complementaryStrand += "C";
                break;
            case 'C':
                complementaryStrand += "G";
                break;
        }
    }
    return complementaryStrand;
}

