    if (!name || !contact || !email || !address || !password) {
        return res.status(400).send("All fields are required");
    }

    const exists = mockDB.find(
        (user) => user.contact === contact || user.email === email
    );

    if (exists) {
        return res.status(400).send("A user with these properties already exists.");
    }

    bcrypt.hash(password, saltRounds, async function (err, hash) {
        if (err) {
            return res.status(500).send("Error hashing the password.");
        }
        const newUser = mockDB.create({
            name,
            contact,
            email,
            address,
            password: hash,
        });
        res.status(201).send({ message: "User created successfully", user: newUser });
    });
});

