/**
 * Calculates the n-th number in the Fibonacci sequence.
 * @param {number} num - The position in the Fibonacci sequence.
 * @returns {number|string} The n-th Fibonacci number or 'OOPS' if the input is negative.
 * @throws {TypeError} If the input is not an integer.
 */
function fibonacciExtended(num) {
    if (!Number.isInteger(num)) {
        throw new TypeError('Input must be an integer');
    }
    if (num < 0) {
        return 'OOPS';
    }
    if (num === 0) {
        return 0;
    }
    if (num === 1) {
        return 1;
    }

    let prev = 0;
    let current = 1;
    for (let i = 2; i <= num; i++) {
        [prev, current] = [current, prev + current];
    }
    return current;
}

// Test cases
console.log(fibonacciExtended(0)); // Should return 0
console.log(fibonacciExtended(1)); // Should return 1
console.log(fibonacciExtended(10)); // Should return 55
console.log(fibonacciExtended(20)); // Should return 6765
try {
    console.log(fibonacciExtended(-1)); // Should return 'OOPS'
} catch (e) {
    console.error(e.message); // Should not be called
}
try {
    console.log(fibonacciExtended(3.5)); // Should throw TypeError
} catch (e) {
    console.error(e.message); // Should output 'Input must be an integer'
}
try {
    console.log(fibonacciExtended("5")); // Should throw TypeError
} catch (e) {
    console.error(e.message); // Should output 'Input must be an integer'
