var fs = require('fs');

// Read the port number and the path to the JSON file from command-line arguments
var port = process.argv[2];
var filename = process.argv[3];

// Create an instance of Express
var app = express();

// Define the route for the '/books' endpoint
app.get('/books', function(req, res) {
    // Read the JSON file
    fs.readFile(filename, function(err, data) {
        if (err) {
            // Respond with a 500 status code if there's a file read error
            return res.status(500).send('Error reading file.');
        }
        try {
            // Parse the JSON data and send it as a response
            res.json(JSON.parse(data));
        } catch (e) {
            // Respond with a 500 status code if there's a JSON parsing error
            res.status(500).send('Error parsing JSON.');
        }
    });
});

// Start the server and listen on the specified port
app.listen(port, function() {
    console.log('Server is listening on port ' + port);
});

// Export the app for testing purposes
module.exports = app;
