function getValuesFromStringOfArray(str) {
    // Extract numbers from the string and convert them to integers
    const array = str.match(/\d+/g).map(Number);

    // Calculate total, greater, smaller, and average
    const total = array.reduce((a, b) => a + b, 0);
    const greater = Math.max(...array);
    const smaller = Math.min(...array);
    const average = total / array.length;

    // Return the result object
    return { array, total, greater, smaller, average };
}

