/**
 * Manages a list of teachers based on the provided action.
 * 
 * @param {Array} state - The initial state of the teachers' list.
 * @param {Object} action - The action to be performed on the teachers' list.
 * @returns {Array} The new state of the teachers' list after the action is applied.
 */
function manageTeachers(state, action) {
    switch (action.type) {
        case 'LOAD_TEACHERS_DATA_SUCCESS':
            return action.payload;
        case 'ADD_TEACHER':
            return [...state, action.payload];
        case 'DELETE_TEACHER':
            return state.filter(teacher => teacher._id !== action.payload);
        case 'EDIT_TEACHER':
            return state.map(teacher => {
                if (teacher._id === action.payload._id) {
                    return { ...teacher, ...action.payload };
                }
                return teacher;
            });
        default:
            return state;
    }
}

