"use strict";

const { Kind, GraphQLError, parse, validate, buildSchema } = require("graphql");

/**
 * Validates a GraphQL query against a given schema and returns the operation and fragments.
 * 
 * @param {GraphQLSchema} schema - The GraphQL schema object.
 * @param {string} query - The GraphQL query string.
 * @param {string} [operationName] - The name of the operation to be executed (optional).
 * @returns {object} An object containing the operation and fragments.
 * @throws {GraphQLError} If the query is invalid.
 */
function validateGraphQLQuery(schema, query, operationName) {
    const document = parse(query);
    const errors = validate(schema, document);

    if (errors.length > 0) {
        throw new GraphQLError(errors.map(error => error.message).join('\n'));
    }

    let operation;
    let operationCount = 0;
    const fragments = Object.create(null);

    document.definitions.forEach(definition => {
        switch (definition.kind) {
            case Kind.OPERATION_DEFINITION:
                operationCount++;
                if (!operationName && operationCount > 1) {
                    throw new GraphQLError('Must provide operation name if query contains multiple operations.');
                }
                if (!operationName || (definition.name && definition.name.value === operationName)) {
                    operation = definition;
                }
                break;
            case Kind.FRAGMENT_DEFINITION:
                fragments[definition.name.value] = definition;
                break;
        }
    });

    if (!operation) {
        if (operationName) {
            throw new GraphQLError(`Unknown operation named "${operationName}".`);
        } else {
            throw new GraphQLError('Must provide an operation.');
        }
    }

    return {
        schema,
        operation,
        fragments,
    };
}

// Test cases
const schema = buildSchema(`
  type Query {
    hello: String
  }
`);

const query = `
  query GetHello {
    hello
  }
`;

const queryWithFragments = `
  fragment HelloFragment on Query {
    hello
  }

  query GetHello {
    ...HelloFragment
  }
`;

const queryWithMultipleOperations = `
  query GetHello {
    hello
  }

  query GetHelloAgain {
    hello
  }
`;

try {
    console.log(validateGraphQLQuery(schema, query)); // Should succeed
    console.log(validateGraphQLQuery(schema, queryWithFragments)); // Should succeed
    console.log(validateGraphQLQuery(schema, queryWithMultipleOperations, 'GetHello')); // Should succeed
    console.log(validateGraphQLQuery(schema, queryWithMultipleOperations)); // Should throw an error
} catch (error) {
    console.error(error.message);
}
