const regexpExactMatch = /^abc$/;
const regexpEmpty = /^$/;
const regexpWhitespace = /\s+/g;
const regexpNewline = /\r|\n|\r\n/gm;
const regexpSpecialChar = /[^\w\s]/gi;
const regexpAlphanumericDashUnderscore = /^[a-zA-Z0-9-_]+$/;
const regexpAlphaSpace = /^[A-Za-z\s]+$/;
const regexpExcludesPatterns = /^((?!(abc|bcd)).)*$/;
const regexpParenthesesContent = /\(([^)]+)\)/g;
const regexpValidDate = /^(0?[1-9]|[12][0-9]|3[01])[\/\-](0?[1-9]|1[012])[\/\-]\d{4}$/;

function validateInput(input) {
  return {
    isExactMatch: regexpExactMatch.test(input),
    isEmpty: regexpEmpty.test(input),
    hasWhitespace: regexpWhitespace.test(input),
    hasNewline: regexpNewline.test(input),
    hasSpecialChar: regexpSpecialChar.test(input),
    isAlphanumericDashUnderscore: regexpAlphanumericDashUnderscore.test(input),
    isAlphaSpace: regexpAlphaSpace.test(input),
    excludesPatterns: regexpExcludesPatterns.test(input),
    hasParenthesesContent: regexpParenthesesContent.test(input),
    isValidDate: regexpValidDate.test(input)
  };
}

// Test cases to verify the solution correctness
