  posts.push({ content: postContent });
  return { ...state, posts };
}

/**
 * Removes a post from the user's blog.
 * @param {Object} state - The current state of the blog.
 * @param {number} idx - The index of the post to be removed.
 * @returns {Object} - The updated state with the specified post removed.
 */
export const removePost = (idx, state) => {
  if (idx < 0 || idx >= state.posts.length) {
    throw new Error('Invalid index for post removal.');
  }
  const posts = copyJSON(state.posts);
  posts.splice(idx, 1);
  return { ...state, posts };
}

