const crypto = require('crypto');

class UserRepository {
  #data = []
  constructor(data) {
    this.#data = data
  }

  async findMany() {
    return this.#data
  }

  async find(id) {
    return this.#data.find(user => user.id === id);
  }

  async save({ name, email, telefone, endereco }) {
    const id = crypto.randomUUID();
    const newUser = { id, name, email, telefone, endereco };
    this.#data.push(newUser);
    return newUser;
  }

  async update(id, newData) {
    const userIndex = this.#data.findIndex(user => user.id === id);
    if (userIndex === -1) {
      throw new Error(`User with id "${id}" not found!`);
    }
    this.#data[userIndex] = { ...this.#data[userIndex], ...newData };
    return this.#data[userIndex];
  }

  async delete(id) {
    const userIndex = this.#data.findIndex(user => user.id === id);
    if (userIndex === -1) {
      throw new Error(`User with id "${id}" not found!`);
    }
    this.#data.splice(userIndex, 1);
  }
}

