const initialState = {
    // ... (same as the given initialState)
};

function vendingMachineTransaction(selection, insertedCoins) {
    let product = null;
    let change = [];
    let message = '';

    // Check if the product exists and is not stuck
    if (!initialState.stock.hasOwnProperty(selection) || initialState.stock[selection].stuck) {
        message = initialState.stock.hasOwnProperty(selection) ? "Machine error. Please contact maintenance." : "Invalid selection. Please choose a different product.";
        return { product, change, message };
    }

    // Check if the product is in stock
    if (initialState.stock[selection].quantity === 0) {
        message = "Out of stock. Please choose a different product.";
        return { product, change, message };
    }

    // Calculate total inserted amount
    const totalInserted = insertedCoins.reduce((sum, coin) => sum + coin, 0);
    const productPrice = initialState.stock[selection].price;

    // Check if enough funds were inserted
    if (totalInserted < productPrice) {
        message = "Insufficient funds. Please insert more coins.";
        return { product, change, message };
    }

    // Calculate change to return
    let changeDue = totalInserted - productPrice;
    const coinTypes = Object.keys(initialState.float).map(Number).sort((a, b) => b - a);

    for (let coin of coinTypes) {
        while (changeDue >= coin && initialState.float[coin.toString()] > 0) {
            changeDue -= coin;
            changeDue = parseFloat(changeDue.toFixed(2)); // Avoid floating point precision issues
            change.push(coin);
            initialState.float[coin.toString()]--;
        }
    }

    // Check if exact change could be given
    if (changeDue > 0) {
        message = "Machine error. Please contact maintenance.";
        return { product, change: [], message };
    }

    // Complete the transaction
    product = initialState.stock[selection];
    product.quantity--;
    message = `Enjoy your ${product.name}!`;

    // Update the float with the inserted coins
    insertedCoins.forEach(coin => {
        initialState.float[coin.toString()] = (initialState.float[coin.toString()] || 0) + 1;
    });

    return { product, change, message };
}

// Test cases
console.log(vendingMachineTransaction('A1', [1])); // Should return product A1 and change if any
console.log(vendingMachineTransaction('A3', [0.5])); // Should ask for more coins
console.log(vendingMachineTransaction('Z9', [1])); // Invalid selection
console.log(vendingMachineTransaction('A2', [1])); // A2 is out of stock after 8 purchases
console.log(vendingMachineTransaction('A1', [0.85])); // Exact amount, no change
