  if (token === 'valid-token') {
    next();
  } else {
    res.status(401).send('Unauthorized: Invalid token');
  }
};

// Menu controller functions
const menuController = {
  getAllMenu: (req, res) => {
    res.json(menuItems);
  },
  addMenu: (req, res) => {
    const { name, description, price } = req.body;
    const newMenuItem = {
      id: menuItems.length + 1,
      name,
      description,
      price
    };
    menuItems.push(newMenuItem);
    res.status(201).json(newMenuItem);
  },
  findMenu: (req, res) => {
    const { name } = req.body;
    const menuItem = menuItems.find(item => item.name.toLowerCase() === name.toLowerCase());
    if (menuItem) {
      res.json(menuItem);
    } else {
      res.status(404).send('Menu item not found');
    }
  },
  updateMenu: (req, res) => {
    const { id } = req.params;
    const { name, description, price } = req.body;
    const menuItemIndex = menuItems.findIndex(item => item.id === parseInt(id));
    if (menuItemIndex > -1) {
      const updatedMenuItem = { id: parseInt(id), name, description, price };
      menuItems[menuItemIndex] = updatedMenuItem;
      res.json(updatedMenuItem);
    } else {
      res.status(404).send('Menu item not found');
    }
  },
  deleteMenu: (req, res) => {
    const { id } = req.params;
    const menuItemIndex = menuItems.findIndex(item => item.id === parseInt(id));
    if (menuItemIndex > -1) {
      menuItems.splice(menuItemIndex, 1);
      res.status(204).send();
    } else {
      res.status(404).send('Menu item not found');
    }
  }
};

// Routes
