import Chart from 'chart.js/auto';

/**
 * Generates a chart to visualize the number of male and female employees in a company over a series of months.
 * @param {Array} employeeData - Array of objects containing the data for male and female employees.
 * @param {HTMLElement} chartContainer - DOM element where the chart will be rendered.
 * @param {Array} months - Array of strings representing the months to be displayed on the x-axis.
 * @param {String} chartType - Type of chart to be created (e.g., 'bar', 'line').
 * @param {Number} chartOption - Chart construction option to use (1, 2, or 3).
 */
export const createEmployeeGenderChart = (employeeData, chartContainer, months, chartType, chartOption) => {
  if (!Array.isArray(employeeData) || !chartContainer || !Array.isArray(months) || typeof chartType !== 'string' || ![1, 2, 3].includes(chartOption)) {
    throw new Error('Invalid input parameters');
  }

  switch (chartOption) {
    case 1:
      constructOption1(employeeData, chartContainer, months, chartType);
      break;
    case 2:
      constructOption2(employeeData, chartContainer, months, chartType);
      break;
    case 3:
      constructOption3(employeeData, chartContainer, months, chartType);
      break;
    default:
      throw new Error('Invalid chart option');
  }
};

function constructOption1(employeeData, chartContainer, months, chartType) {
  const chart = new Chart(chartContainer, {
    type: chartType,
    data: {
      labels: months,
      datasets: [{
        label: employeeData[0].title,
        data: employeeData[0].values,
        borderColor: employeeData[0].color,
        backgroundColor: employeeData[0].color,
        borderWidth: 2,
      }],
    },
    options: {
      scales: {
        y: {
          beginAtZero: true,
        },
      },
    },
  });
}

function constructOption2(employeeData, chartContainer, months, chartType) {
  const chart = new Chart(chartContainer, {
    type: chartType,
    data: {
      labels: months,
      datasets: employeeData.map((dataset) => ({
        label: dataset.title,
        data: dataset.values,
        borderColor: dataset.color,
        backgroundColor: dataset.color,
        borderWidth: 2,
        yAxisID: `${dataset.title.toLowerCase()}-axis`,
      })),
    },
    options: {
      scales: {
        y: employeeData.map((dataset, index) => ({
          id: `${dataset.title.toLowerCase()}-axis`,
          type: 'linear',
          display: true,
          position: index === 0 ? 'left' : 'right',
          grid: {
            drawOnChartArea: false,
          },
        })),
      },
    },
  });
}

function constructOption3(employeeData, chartContainer, months, chartType) {
  const chart = new Chart(chartContainer, {
    type: chartType,
    data: {
      labels: months,
      datasets: [{
        label: "Custom Data",
        data: employeeData[0].values,
        borderColor: employeeData[0].color,
        backgroundColor: employeeData[0].color,
        borderWidth: 2,
      }],
    },
    options: {
      scales: {
        y: {
          beginAtZero: true,
        },
      },
    },
  });
}

