let jwt = require('jwt-simple');
let moment = require('moment');

const jwtKey = 'vvg';

/**
 * Creates a JWT token for a user with a specified ID.
 * @param {string} id - The user's ID.
 * @returns {string} A JWT token.
 */
let createToken = function(id) {
    let timeOut = moment().add(7, 'days').valueOf();
    let token = jwt.encode({
        iss: id,
        exp: timeOut
    }, jwtKey);
    return token;
};

/**
 * Verifies the validity of a JWT token.
 * @param {string} token - The JWT token to verify.
 * @returns {object} An object with a `msg` boolean indicating success, and a `data` field with the user's ID or an error message.
 */
var tokenVerify = function(token) {
    let msg = {
        msg: true,
        data: null
    };
    try {
        var code = jwt.decode(token, jwtKey);
        if (code.exp >= Date.now()) {
            msg.data = code.iss;
            return msg;
        } else {
            msg.msg = false;
            msg.data = 'Token has expired';
            return msg;
        }
    } catch (err) {
        msg.msg = false;
        msg.data = 'Error decoding token';
        return msg;
    }
};

// Test cases
let userId = '12345';
let token = createToken(userId);
console.log('Token created for user ID:', userId);
console.log('Token:', token);

let verificationResult = tokenVerify(token);
console.log('Token verification result:', verificationResult);

// Simulate an expired token by creating a token with a past expiration date
let expiredToken = jwt.encode({
    iss: userId,
    exp: moment().subtract(1, 'days').valueOf()
}, jwtKey);

let expiredResult = tokenVerify(expiredToken);
console.log('Expired token verification result:', expiredResult);

// Simulate an invalid token by tampering with the token string
let invalidToken = token.slice(0, -1) + 'X';
let invalidResult = tokenVerify(invalidToken);
console.log('Invalid token verification result:', invalidResult);
