 * Creates a new user in the database.
 * @param {Object} userData - An object containing the username and email.
 * @returns {Promise<Object>} The created user document.
 */
async function createUser(userData) {
  try {
    const user = new User(userData);
    return await user.save();
  } catch (error) {
    console.error('Error creating user:', error);
    throw error;
  }
}

/**
 * Finds a user by username.
 * @param {string} username - The username to search for.
 * @returns {Promise<Object|null>} The user document or null if not found.
 */
async function findUserByUsername(username) {
  try {
    return await User.findOne({ username });
  } catch (error) {
    console.error('Error finding user:', error);
    throw error;
  }
}

/**
 * Updates a user's email.
 * @param {string} username - The username of the user to update.
 * @param {string} newEmail - The new email to set.
 * @returns {Promise<Object>} The updated user document.
 */
async function updateUserEmail(username, newEmail) {
  try {
    return await User.findOneAndUpdate({ username }, { email: newEmail }, { new: true });
  } catch (error) {
    console.error('Error updating user email:', error);
    throw error;
  }
}

/**
