/**
 * Makes an authenticated HTTP request to a backend server.
 * @param {string} endPoint - The API endpoint to which the request is made.
 * @param {object} options - Additional configurations for the request.
 * @returns {Promise} A promise that resolves with the response data or rejects with an error message.
 */
const makeAuthenticatedRequest = async (endPoint, options) => {
  let token = storage('token');
  const headers = { 'Content-Type': 'application/json' };
  if (token) {
    headers.Authorization = `Bearer ${token}`;
  }

  const config = {
    ...options,
    headers: headers,
    url: `${BACKEND_URL}${endPoint}`,
  };

  try {
    const response = await axios(config);
    if (response.statusText === 'OK') {
      return response.data;
    } else {
      throw new Error('Request failed with status: ' + response.statusText);
    }
  } catch (error) {
    throw error;
  }
};

export default makeAuthenticatedRequest;

// Test cases
