                leagues: state.leagues.map((league, index) => {
                    if (index === action.index) {
                        return {
                            ...league,
                            [action.target]: action.payload
                        };
                    }
                    return league;
                })
            };
        case "DEFAULTCREATELEAGUE":
            return {
                ...state,
