    throw new Error('Component name must be a string.');
  }

  // Normalize the component name to match the case of the keys in the components object
  const normalizedComponentName = componentName.charAt(0).toUpperCase() + componentName.slice(1).toLowerCase();

  // Return the component if found, otherwise return NotFound
  return components[normalizedComponentName] || NotFound;
}

