const Body = Matter.Body;
const Render = Matter.Render;
const Constraint = Matter.Constraint;

// Create an engine
const engine = Engine.create();
const world = engine.world;

// Create a renderer
const render = Render.create({
  element: document.body,
  engine: engine,
  options: {
    width: 800,
    height: 600,
    wireframes: false
  }
});

// Create roof
const roof = Bodies.rectangle(400, 100, 250, 20, { isStatic: true });
World.add(world, roof);

// Create bobs
const bobDiameter = 40;
const startBobPositionY = 300;
let bobs = [];
let ropes = [];

for (let i = 0; i < 5; i++) {
  let bobX = 400 - bobDiameter + i * (bobDiameter * 2);
  let bob = Bodies.circle(bobX, startBobPositionY, bobDiameter / 2);
  let rope = Constraint.create({
    bodyA: bob,
    pointA: { x: 0, y: 0 },
    bodyB: roof,
    pointB: { x: -100 + i * 50, y: 0 },
    stiffness: 1,
    length: 200
  });
  World.add(world, bob);
  World.add(world, rope);
  bobs.push(bob);
  ropes.push(rope);
}

// Add mouse control
const mouse = Matter.Mouse.create(render.canvas);
const mouseConstraint = Matter.MouseConstraint.create(engine, {
  mouse: mouse,
  constraint: {
    render: { visible: false }
  }
});
World.add(world, mouseConstraint);

// Keep the mouse in sync with rendering
render.mouse = mouse;

// Run the engine
Engine.run(engine);

// Run the renderer
Render.run(render);

