/**
 * Generates a Google Fonts import URL given an array of font families and their weights.
 * @param {Array} fonts - An array of objects representing font families and their weights.
 * @returns {string} - The generated Google Fonts import URL.
 */
function generateGoogleFontsUrl(fonts) {
  const baseUrl = 'https://fonts.googleapis.com/css';
  const fontFamilies = fonts.map(font => {
    const weights = font.weights.join(',');
    return `${font.family.replace(/ /g, '+')}:${weights}`;
  }).join('|');
  return `${baseUrl}?family=${fontFamilies}`;
}

/**
 * Injects font styles from Google Fonts into the document.
 * @param {Array} fonts - An array of objects representing font families and their weights.
 */
function injectFontStyles(fonts) {
  const googleFontsUrl = generateGoogleFontsUrl(fonts);
  const GlobalStyle = createGlobalStyle`
    @import url('${googleFontsUrl}');
  `;
  // Render the global style to inject the fonts
  GlobalStyle();
}

