import { createStore, combineReducers, compose } from 'redux';

// Define action types
const INCREMENT = 'INCREMENT';
const DECREMENT = 'DECREMENT';
const SET_USER = 'SET_USER';

// Define the counterReducer
const counterInitialState = { count: 0 };
const counterReducer = (state = counterInitialState, action) => {
  switch (action.type) {
    case INCREMENT:
      return { ...state, count: state.count + 1 };
    case DECREMENT:
      return { ...state, count: state.count - 1 };
    default:
      return state;
  }
};

// Define the userReducer
const userInitialState = { user: { name: '', age: null } };
const userReducer = (state = userInitialState, action) => {
  switch (action.type) {
    case SET_USER:
      return { ...state, user: action.payload };
    default:
      return state;
  }
};

// Combine reducers
const rootReducer = combineReducers({
  counter: counterReducer,
  user: userReducer
});

// Configure store with or without Redux DevTools extension
let composeEnhancer = compose;
if (typeof __DEV__ !== 'undefined' && __DEV__) {
  composeEnhancer = window.__REDUX_DEVTOOLS_EXTENSION_COMPOSE__ || compose;
}

const configureStore = () => createStore(rootReducer, composeEnhancer());

// Export the action creators
export const increment = () => ({ type: INCREMENT });
export const decrement = () => ({ type: DECREMENT });
export const setUser = (user) => ({ type: SET_USER, payload: user });

// Test cases
const store = configureStore();

// Test increment action
store.dispatch(increment());
console.assert(store.getState().counter.count === 1, 'Increment action failed');

// Test decrement action
store.dispatch(decrement());
console.assert(store.getState().counter.count === 0, 'Decrement action failed');

// Test setUser action
const newUser = { name: 'Alice', age: 30 };
store.dispatch(setUser(newUser));
console.assert(store.getState().user.user.name === 'Alice' && store.getState().user.user.age === 30, 'SetUser action failed');

console.log('All test cases passed!');
