/**
 * Creates a new order with the given room ID, menu ID, and optional remarks.
 * @param {number} roomId - The ID of the room placing the order.
 * @param {number} menuId - The ID of the menu item being ordered.
 * @param {string} [remarks] - Optional remarks for the order.
 * @returns {Promise<MenuOrders>} A promise that resolves with the created order.
 */
async function createOrder(roomId, menuId, remarks = '') {
  try {
    const newOrder = await MenuOrders.create({
      room_id: roomId,
      menu_id: menuId,
      remarks: remarks
    });
    return newOrder;
  } catch (error) {
    console.error('Error creating order:', error);
    throw error;
  }
}

/**
 * Updates the status of an order identified by orderId to the newStatus.
 * @param {number} orderId - The ID of the order to update.
 * @param {string} newStatus - The new status to set for the order.
 * @returns {Promise<MenuOrders>} A promise that resolves with the updated order.
 */
async function updateOrderStatus(orderId, newStatus) {
  try {
    const order = await MenuOrders.findByPk(orderId);
    if (!order) {
      throw new Error('Order not found');
    }
    order.status = newStatus;
    await order.save();
    return order;
  } catch (error) {
    console.error('Error updating order status:', error);
    throw error;
  }
}

/**
 * Lists all orders that have a specific status.
 * @param {string} status - The status of the orders to list.
 * @returns {Promise<MenuOrders[]>} A promise that resolves with the list of orders.
 */
async function listOrdersByStatus(status) {
  try {
    const orders = await MenuOrders.findAll({
      where: { status: status }
    });
    return orders;
  } catch (error) {
    console.error('Error listing orders by status:', error);
    throw error;
  }
}

