const express = require('express');
const bodyParser = require('body-parser');
const mongoose = require('mongoose');
const { Schema } = mongoose;

// Connect to MongoDB (Replace 'mongodb://localhost:27017/vmDB' with your MongoDB URI)
mongoose.connect('mongodb://localhost:27017/vmDB', { useNewUrlParser: true, useUnifiedTopology: true });

// Define the VM schema and model
const vmSchema = new Schema({
  VmId: Number,
  VmName: String,
  VmType: String,
  VmLocation: String
});
const VM = mongoose.model('VM', vmSchema);

// Initialize Express app
const app = express();
app.use(bodyParser.json());

// POST endpoint to create a new VM detail
app.post('/vms', (req, res) => {
  if (!req.body.vmName || !req.body.vmType || !req.body.vmLocation) {
    return res.status(400).json({
      message: "Please fill up all details",
    });
  } else {
    const newVM = new VM({
      VmId: Math.round(Math.random() * 1000000000 + Math.random() * 10000000),
      VmName: req.body.vmName,
      VmType: req.body.vmType,
      VmLocation: req.body.vmLocation,
    });
    newVM.save((err, data) => {
      if (err) {
        return res.status(400).json({ message: "Error occurred", err });
      }
      res.status(200).json({
        message: "VM details created successfully",
        vm: data,
      });
    });
  }
});

// GET endpoint to retrieve all VM details
app.get('/vms', (req, res) => {
  VM.find({}, { _id: 0 }, (err, docs) => {
    if (err) {
      return res.status(400).json({
        isError: true,
        message: "Failed",
        statuscode: 500,
        details: null
      });
    }
    res.status(200).json({
      isError: false,
      message: "VM details",
      statuscode: 200,
      details: docs
    });
  });
});

// PUT endpoint to update an existing VM detail
app.put('/vms', (req, res) => {
  if (!req.body.vmId || !req.body.vmName || !req.body.vmType || !req.body.vmLocation) {
    return res.status(404).json({
      message: "Please fill up all details",
    });
  }
  const queryWith = { VmId: req.body.vmId };
  const updateWith = {
    VmName: req.body.vmName,
    VmType: req.body.vmType,
    VmLocation: req.body.vmLocation,
  };

  VM.updateOne(queryWith, updateWith, (err, result) => {
    if (err) {
      return res.status(400).json({
        isError: true,
        message: "Some error occurred",
        statuscode: 501,
        details: null
      });
    } else {
      if (result.modifiedCount === 1) {
        res.status(200).json({
          isError: false,
          message: "VM Details Updated Successfully",
          statuscode: 200,
          details: null
        });
      } else {
        res.status(400).json({
          isError: true,
          message: "No changes made or VM not found",
          statuscode: 502,
          details: null
        });
      }
    }
  });
});

// DELETE endpoint to delete a VM detail
app.delete('/vms', (req, res) => {
  if (!req.body.vmId) {
    return res.status(404).json({
      message: "Please send vmId to delete",
    });
  }

  VM.deleteOne({ "VmId": req.body.vmId }, (err, result) => {
    if (err) {
      return res.status(400).json({
        isError: true,
        message: "Some error occurred",
        statuscode: 502,
        details: err
      });
    } else {
      res.status(200).json({
        isError: false,
        message: "Deleted successfully",
        statuscode: 200,
        details: result
      });
    }
  });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

// Export the app for testing purposes
module.exports = app;
