import AsyncStorage from '@react-native-async-storage/async-storage';

const STORAGE_ERROR_NULL_KEY = 'Parameter key could not be null';

const LocalKeyStore = {
  async get(key) {
    if (!key) throw new Error(STORAGE_ERROR_NULL_KEY);
    try {
      const value = await AsyncStorage.getItem(key);
      return value ? JSON.parse(value) : null;
    } catch (error) {
      console.error(`Error getting item (${key}) from local storage: ${error.message}`);
      throw error;
    }
  },

  async set(key, value) {
    if (!key) throw new Error(STORAGE_ERROR_NULL_KEY);
    try {
      if (value !== null) {
        const encoded = JSON.stringify(value);
        await AsyncStorage.setItem(key, encoded);
      } else {
        await this.delete(key);
      }
    } catch (error) {
      console.error(`Error setting item (${key}) in local storage: ${error.message}`);
      throw error;
    }
  },

  async delete(key) {
    if (!key) throw new Error(STORAGE_ERROR_NULL_KEY);
    try {
      await AsyncStorage.removeItem(key);
    } catch (error) {
      console.error(`Error deleting item (${key}) from local storage: ${error.message}`);
      throw error;
    }
  },

  async clear() {
    try {
      await AsyncStorage.clear();
    } catch (error) {
      console.error(`Error clearing local storage: ${error.message}`);
      throw error;
    }
  }
};

export default LocalKeyStore;

// Test cases
(async () => {
  try {
    // Set a value
    await LocalKeyStore.set('user', { name: 'Alice', age: 30 });
    console.log('Value set successfully.');

    // Get the value
    const user = await LocalKeyStore.get('user');
    console.log('Retrieved value:', user);

    // Update the value
    await LocalKeyStore.set('user', { ...user, age: 31 });
    console.log('Value updated successfully.');

    // Delete the value
    await LocalKeyStore.delete('user');
    console.log('Value deleted successfully.');

    // Attempt to get a deleted value
    const deletedUser = await LocalKeyStore.get('user');
    console.log('Deleted value:', deletedUser);

    // Clear all values
    await LocalKeyStore.clear();
    console.log('Local storage cleared.');
  } catch (error) {
    console.error('Error during test cases:', error.message);
  }
})();
