export default function initializeBoxTypeSelector(editor, opts = {}) {
  opts = {
    name: "box-type-selector",
    selectedClassName: "selected",
    defaultValues: {
      type: "checkbox",
    },
    options: [
      {
        value: "checkbox",
      },
      {
        label: "x box",
        value: "xbox",
      },
      {
        value: "radio",
      },
    ],
    ...opts,
  };

  const { name, defaultValues, options } = opts;
  const sm = editor.StyleManager;

  sm.addType(name, {
    create({ change }) {
      const el = document.createElement("div");
      el.classList.add(name, "gjs-sm-property--full");
      el.innerHTML = `<div class="gjs-field gjs-select">
        <span id="box-type">
          <select>
            ${options
              .map(
                (o) =>
                  `<option value="${o.value}" ${
                    defaultValues.type === o.value ? "selected" : ""
                  }>${o.label || o.value}</option>`
              )
              .join("")}
          </select>
        </span>
        <div class="gjs-sel-arrow">
          <div class="gjs-d-s-arrow"></div>
        </div>
      </div>
      `;

      this.inputEl = el;

      el.querySelector("select").addEventListener("change", ({ target }) => {
        this.setBoxType(target.value);
      });

      editor.on("component:selected", () => this.updateUI());

      return el;
    },

    setBoxType(inType) {
      const { box } = this.getBoxType();
      box && box.addAttributes({ "data-type": inType });
    },

    getBoxType() {
      const selectedComponent = editor.getSelected();
      if (!selectedComponent || !selectedComponent.getAttributes) return {};
      const boxType = selectedComponent.getAttributes()["data-type"];
      return { box: selectedComponent, boxType };
    },

    updateUI() {
      const { boxType } = this.getBoxType();
      const inputIn = this.inputEl && this.inputEl.querySelector("select");
      inputIn && (inputIn.value = boxType);
    },

    destroy() {
      // Clean up if necessary
    },
  });
}

