class TimeInput {
  constructor() {
    this.invalid = false;
    this.value = '';
    this._minutes = 0;
    this._seconds = 0;
    this.validator = /^([0-5]?[0-9]):([0-5]?[0-9])$/;
  }

  setTime(minutes, seconds) {
    if (this._isValidNumber(minutes) && this._isValidNumber(seconds)) {
      this._minutes = minutes < 10 ? `0${minutes}` : String(minutes);
      this._seconds = seconds < 10 ? `0${seconds}` : String(seconds);
      this._validateTime();
    } else {
      throw new Error('Invalid time: minutes and seconds must be numbers between 0 and 59.');
    }
  }

  getTime() {
    return this.value;
  }

  _validateTime() {
    const time = `${this._minutes}:${this._seconds}`;
    if (this.validator.test(time)) {
      this.value = time;
      this.invalid = false;
    } else {
      this.invalid = true;
    }
  }

  _isValidNumber(value) {
    return typeof value === 'number' && value >= 0 && value < 60;
  }
}

// Test cases
const timeInput = new TimeInput();

// Test setting and getting valid time
timeInput.setTime(9, 30);
console.log(timeInput.getTime()); // Should output "09:30"
console.log(timeInput.invalid); // Should output false

