  timeInput.setTime(60, 30);
} catch (error) {
  console.error(error.message); // Should output "Invalid time: minutes and seconds must be numbers between 0 and 59."
}
console.log(timeInput.invalid); // Should output true if invalid time was set

// Test setting and getting edge case time
timeInput.setTime(0, 59);
console.log(timeInput.getTime()); // Should output "00:59"
