import generateZipFile from './generateZipFile';
import getCurrentVersionNumber from './getCurrentVersionNumber';
import deleteExistingZipFiles from './deleteExistingZipFiles';

/**
 * Bundles a WordPress plugin into a ZIP file for distribution.
 *
 * @param {string} pluginDirectoryPath - The file path to the WordPress plugin directory.
 * @param {boolean} useComposer - Whether to include Composer dependencies in the build.
 * @param {string|boolean} outputFileName - The name of the output ZIP file or true to auto-determine.
 * @param {boolean} deleteOldZips - Whether to delete existing ZIP files in the plugin directory.
 * @returns {string} The path to the created ZIP file.
 */
function bundleWordPressPlugin(pluginDirectoryPath, useComposer, outputFileName, deleteOldZips) {
  if (deleteOldZips) {
    deleteExistingZipFiles(pluginDirectoryPath);
  }

  let fileName = outputFileName;
  if (outputFileName === true) {
    const version = getCurrentVersionNumber();
    fileName = `web-stories-${version}${useComposer ? '-composer' : ''}.zip`;
  }

  generateZipFile(pluginDirectoryPath, fileName);
  return `${pluginDirectoryPath}/${fileName}`;
}

// Test cases
