 * @param {Object} options - The options for rotation.
 * @param {number} options.speed - The rotation speed.
 * @param {string} options.directionX - The direction of rotation around the X-axis ('ArrowLeft' or 'ArrowRight').
 * @param {string} options.directionY - The direction of rotation around the Y-axis ('ArrowUp' or 'ArrowDown').
 * @param {number} options.degreeX - The current angle of rotation around the X-axis.
 * @param {number} options.degreeY - The current angle of rotation around the Y-axis.
 * @param {Function} options.setDegreeX - Function to update degreeX.
 * @param {Function} options.setDegreeY - Function to update degreeY.
 */
const rotateObject = options => {
  const { 
    speed,
    directionX,
    directionY,
    degreeX, 
    setDegreeX,
    degreeY,
    setDegreeY
  } = options;

  switch (directionX) {
    case 'ArrowLeft':
      setDegreeX(degreeX - speed);
      break;
    case 'ArrowRight':
      setDegreeX(degreeX + speed);
      break;
    default:
      // No rotation around the X-axis if the direction is not specified
      break;
  }
  switch (directionY) {
    case 'ArrowDown':
      setDegreeY(degreeY - speed);
      break;
    case 'ArrowUp':
      setDegreeY(degreeY + speed);
      break;
    default:
      // No rotation around the Y-axis if the direction is not specified
      break;
  }
}

