/**
 * Counts the number of vowels and consonants in a given string.
 * 
 * @param {string} data - The string to be analyzed.
 * @returns {object} An object with properties 'vowels' and 'consonants'.
 */
function countVowelsAndConsonants(data) {
  const vowelsSet = new Set(['a', 'e', 'i', 'o', 'u']);
  let vowelsCount = 0;
  let consonantsCount = 0;

  for (let char of data.toLowerCase()) {
    if (vowelsSet.has(char)) {
      vowelsCount++;
    } else if (char >= 'a' && char <= 'z') {
      consonantsCount++;
    }
  }

  return { vowels: vowelsCount, consonants: consonantsCount };
}

