 * Class to replace specific values in an input object based on provided rules.
 */
class ValueReplacer {
    /**
     * Initializes the ValueReplacer instance.
     * @param {Object} env - An optional environment parameter.
     */
    constructor(env) {
        // The environment parameter is not used in this example,
        // but could be used for more complex scenarios.
    }

    /**
     * Applies replacement rules to the input object.
     * @param {Object} inputs - The input object with key-value pairs to process.
     * @param {Array} state - The state array containing rule objects.
     * @returns {Object} - A new object with the replacements applied.
     */
    applyRules(inputs, state) {
        let replacement = undefined;
        let valueToReplace = undefined;

        // Find the replacement value and the value to replace from the state
        for (let rule of state) {
            if (rule.name === "replacement") {
                replacement = rule.value;
            } else if (rule.name === "value") {
                valueToReplace = rule.value;
            }
        }

        // Create a new object for the outputs
        let outputs = {};

        // Apply the replacement rules to the input object
        for (let key in inputs) {
            if (inputs.hasOwnProperty(key)) {
                outputs[key] = inputs[key] === valueToReplace ? replacement : inputs[key];
            }
        }

        return outputs;
    }
}

// Export the ValueReplacer class
module.exports = ValueReplacer;

// Test cases to verify the solution correctness
