    var charType = prompt('Enter character types to include: special, numeric, uppercase, lowercase, all. (Or mix and match Ex. "special and numeric")');
    var password = generatePassword(length, charType);
    var passwordText = document.querySelector("#password");

    passwordText.value = password;
  } else {
    alert('Please enter a number between 8 and 128');
    writePassword();
  }
}

// Generates password
function generatePassword(length, charType) {
  // Evaluates character type based on user input
  var charSet = "";
  var charTypeLower = charType.toLowerCase();

  if (charTypeLower.includes("lowercase")) {
    charSet += "abcdefghijklmnopqrstuvwxyz";
  }
  if (charTypeLower.includes("uppercase")) {
    charSet += "ABCDEFGHIJKLMNOPQRSTUVWXYZ";
  }
  if (charTypeLower.includes("numeric")) {
    charSet += "0123456789";
  }
  if (charTypeLower.includes("special")) {
    charSet += "!\"#$%&'()*+,-./:;<=>?@[\]^_`{|}~";
  }

  if (charSet === "") {
    alert("Please enter at least one valid character type");
    return writePassword();
  }

  // Generate password
  var customPassword = "";
  for (var i = 0; i < parseInt(length); i++) {
    // Picks a character within charSet at index of a random number
    customPassword += charSet.charAt(Math.floor(Math.random() * charSet.length));
  }
  return customPassword;
}

