const dependencySetup = require('./dependencySetup.js');
const middlewares = require('./middlewares.js');
const routes = require('./routes.js');

/**
 * ApplicationStarter class encapsulates the process of setting up and starting an Express.js application server.
 */
class ApplicationStarter {
  /**
   * Static method to start the application server.
   * @param {Object} app - The Express app instance.
   * @param {number} port - The port number on which the server should listen.
   */
  static start(app, port = 8080) {
    // Initialize application dependencies
    dependencySetup(app);

    // Set up pre-routing middlewares
    middlewares.pre(app);

    // Configure application routes
    routes(app);

    // Set up post-routing middlewares
    middlewares.post(app);

    // Set the application's listening port
    app.set('port', port);
  }
}

module.exports = ApplicationStarter;

// Test cases
if (require.main === module) {
  // Mock Express app instance
  const app = {
    set: jest.fn(),
    use: jest.fn(),
  };

