function manageFruits(fruits, newFruitEnd, newFruitStart, specificFruit) {
  let result = {
    finalArray: [...fruits],
    removedLast: '',
    removedFirst: '',
    indexOfFruit: -1,
    removedSpecific: '',
    arrayCopy: []
  };

  // Add a new fruit to the end of the array
  result.finalArray.push(newFruitEnd);

  // Remove the last fruit from the array
  result.removedLast = result.finalArray.pop();

  // Add a new fruit to the beginning of the array
  result.finalArray.unshift(newFruitStart);

  // Remove the first fruit from the array
  result.removedFirst = result.finalArray.shift();

  // Find the index of a specific fruit in the array
  result.indexOfFruit = result.finalArray.indexOf(specificFruit);

  // Remove a specific fruit from the array by its name
  if (result.indexOfFruit !== -1) {
    result.removedSpecific = result.finalArray.splice(result.indexOfFruit, 1)[0];
  }

  // Copy the array
  result.arrayCopy = result.finalArray.slice();

  return result;
}

