const { selectorMap } = require('./path-to-selector-map-module');

/**
 * Retrieves CSS selectors for a given domain.
 * @param {string} domain - The domain URL to retrieve selectors for.
 * @returns {Object|null} An object containing the CSS selectors, or null if the domain is not found.
 */
function getSelectorsForDomain(domain) {
  // Normalize the domain to ensure case-insensitivity and remove protocol
  const normalizedDomain = domain.toLowerCase().replace(/^https?:\/\//, '');

  // Iterate over the selectorMap keys to find a matching domain
  for (let key of selectorMap.keys()) {
    if (key.toLowerCase().includes(normalizedDomain)) {
      return selectorMap.get(key);
    }
  }

  // Return null if no matching domain is found
  return null;
}

