// Define the module
const modelPropertiesConverter = (() => {
    // Helper functions (not exposed)
    const sanitizeKey = (key, orig, replace) => key.split(orig).join(replace);

    const sanitizeKeys = (indexes, operation) => {
        for (const indexObject in indexes) {
            const index = indexes[indexObject];
            const sanitizedKeys = operation(index.keys || index);
            if ('keys' in index) {
                index.keys = sanitizedKeys;
            } else {
                indexes[indexObject] = sanitizedKeys;
            }
        }
    };

    const sanitizeSchema = (data, value) => {
        data['%24schema'] = value;
        delete data.$schema;
    };

    const sanitizeLinks = (links, orig, replace) => {
        links.forEach(link => {
            if (link.schema && link.schema.properties) {
                const properties = link.schema.properties;
                for (const propertyName in properties) {
                    if (propertyName.includes(orig)) {
                        properties[sanitizeKey(propertyName, orig, replace)] = properties[propertyName];
                        delete properties[propertyName];
                    }
                }
            }
        });
    };

    const arrayToOrderedObject = (orderedKeys) => {
        if (!Array.isArray(orderedKeys)) return null;
        return orderedKeys.reduce((acc, curr) => ({ ...acc, ...curr }), {});
    };

    // Public API
    const convertModelProperties = (data) => {
        if (data.indexes) {
            sanitizeKeys(data.indexes, keys => arrayToOrderedObject(keys.orderedKeys) || keys);
            sanitizeKeys(data.indexes, keys => sanitizeKeys(keys, '.', '%2E'));
        }

        if (data.$schema) {
            sanitizeSchema(data, data.$schema);
        }

        ['collectionLinks', 'links', 'versionIndexes'].forEach(property => {
            if (data[property]) {
                sanitizeLinks(data[property], '.', '%2E');
            }
        });
    };

    const restoreModelProperties = (model) => {
        ['indexes', 'collectionLinks', 'links', 'versionIndexes'].forEach(property => {
            if (model[property]) {
                sanitizeKeys(model[property], keys => sanitizeKeys(keys, '%2E', '.'));
            }
        });

        if (model['%24schema']) {
            model.$schema = model['%24schema'];
            delete model['%24schema'];
        }
    };

    // Expose the public API
    return {
        convert: convertModelProperties,
        restore: restoreModelProperties
    };
})();

// Export the module
module.exports = modelPropertiesConverter;

// Test cases to verify the solution
const testModel = {
    indexes: {
        'user.email': { unique: true },
        'user.name': { unique: false }
    },
    $schema: 'http://json-schema.org/draft-07/schema#',
    collectionLinks: [
        { schema: { properties: { 'link.url': { type: 'string' } } } }
    ]
};

console.log('Original model:', testModel);

modelPropertiesConverter.convert(testModel);
console.log('Converted model:', testModel);

modelPropertiesConverter.restore(testModel);
console.log('Restored model:', testModel);
