/**
 * A simple asynchronous module loader.
 */
class AsyncModuleLoader {
  constructor() {
    this.modules = {};
  }

  /**
   * Loads a module asynchronously and registers a callback to be executed once loaded.
   * @param {number} moduleId - The ID of the module to load.
   * @param {Function} callback - The callback function to execute once the module is loaded.
   */
  loadModule(moduleId, callback) {
    // Simulate asynchronous module loading with a timeout
    setTimeout(() => {
      this.modules[moduleId] = true;
      callback();
      this.runCallbacks(moduleId);
    }, Math.random() * 1000);
  }

  /**
   * Executes all callbacks associated with a loaded module.
   * @param {number} moduleId - The ID of the module whose callbacks need to be executed.
   */
  runCallbacks(moduleId) {
    if (this.modules[moduleId]) {
      // Execute all callbacks for the module
      // For simplicity, we assume that the callback is directly stored
      // In a real-world scenario, we would have an array of callbacks
      console.log(`Module ${moduleId} loaded and callback executed.`);
    }
  }

  /**
   * Checks if a module has been loaded.
   * @param {number} moduleId - The ID of the module to check.
   * @returns {boolean} - True if the module is loaded, false otherwise.
   */
  isModuleLoaded(moduleId) {
    return !!this.modules[moduleId];
  }

  /**
   * Registers a callback for a module that has already been loaded.
   * @param {number} moduleId - The ID of the module to register the callback for.
   * @param {Function} callback - The callback function to register.
   */
  registerCallback(moduleId, callback) {
    if (this.isModuleLoaded(moduleId)) {
      callback();
    } else {
      console.log(`Module ${moduleId} is not loaded yet. Cannot register callback.`);
    }
  }
}

// Test cases to verify the solution correctness
const moduleLoader = new AsyncModuleLoader();

// Load module 1 and provide a callback
moduleLoader.loadModule(1, () => {
  console.log('Callback for module 1');
});

// Check if module 1 is loaded immediately after requesting load (should be false)
console.log(`Is module 1 loaded? ${moduleLoader.isModuleLoaded(1)}`);

// Register a callback for module 1 (should not execute immediately)
moduleLoader.registerCallback(1, () => {
  console.log('Registered callback for module 1');
});

// After a delay, check if module 1 is loaded and try to register a callback again
setTimeout(() => {
  console.log(`Is module 1 loaded after delay? ${moduleLoader.isModuleLoaded(1)}`);
  moduleLoader.registerCallback(1, () => {
    console.log('Registered callback for module 1 after delay');
  });
}, 1500);
