/**
 * Determines if a number is prime.
 * @param {number} num - The number to check for primality.
 * @returns {boolean} - True if the number is prime, false otherwise.
 */
const isPrime = (num) => {
  if (num <= 1) {
    return false;
  }

  for (let i = 2; i <= Math.sqrt(num); i++) {
    if (num % i === 0) {
      return false;
    }
  }

  return true;
};

/**
 * Generates a random number within a range and checks if it is prime.
 * @param {number} min - The minimum value in the range (inclusive).
 * @param {number} max - The maximum value in the range (inclusive).
 * @returns {object} - An object containing the random number and the result of the primality test.
 */
const generatePrimeTest = (min, max) => {
  const randomNumber = Math.floor(Math.random() * (max - min + 1)) + min;
  const booleanResult = isPrime(randomNumber);

  return {
    number: randomNumber,
    isPrime: booleanResult
  };
};

// Test cases to verify the solution
console.log(isPrime(2)); // true
console.log(isPrime(3)); // true
console.log(isPrime(4)); // false
console.log(isPrime(29)); // true
console.log(isPrime(1)); // false
console.log(isPrime(0)); // false
console.log(isPrime(-1)); // false

console.log(generatePrimeTest(1, 10)); // Object with a random number between 1 and 10 and its primality
console.log(generatePrimeTest(10, 100)); // Object with a random number between 10 and 100 and its primality
console.log(generatePrimeTest(100, 1000)); // Object with a random number between 100 and 1000 and its primality
