import prisma from './prisma';

/**
 * Adds a comment to a post and notifies the post owner if necessary.
 * 
 * @param {string} token - The authentication token of the user.
 * @param {number} postId - The ID of the post to add the comment to.
 * @param {string} text - The text of the comment.
 * @param {Function} isAuthenticated - A function to authenticate the user.
 * @param {Object} pubsub - An object with a publish method for event subscription.
 * @returns {Object|null} The created comment object or null if an error occurs.
 */
async function addComment(token, postId, text, isAuthenticated, pubsub) {
  try {
    const userId = await isAuthenticated(token);
    const post = await prisma.post.findUnique({
      where: { id: postId },
      select: { userId: true },
    });
    if (!post) {
      console.log("Post doesn't exist");
      return null;
    }
    const newComment = await prisma.comment.create({
      data: {
        text,
        userId,
        postId,
      },
    });
    if (post.userId !== userId) {
      const notification = await prisma.notification.create({
        data: {
          userId: post.userId,
          commentId: newComment.id,
        },
      });
      pubsub.publish(NEW_COMMENT, {
        newNotification: notification,
      });
    }
    return newComment;
  } catch (error) {
    console.error(error);
    return null;
  }
}

