const bcrypt = require('bcrypt');
const bluebird = require('bluebird');

// MongoDB connection string
const db = 'mongodb://localhost/imooc-app-server';

// Set mongoose to use bluebird for promises
mongoose.Promise = bluebird;
// Connect to MongoDB
mongoose.connect(db, { useNewUrlParser: true, useUnifiedTopology: true });

// Define the User schema
const userSchema = new mongoose.Schema({
  username: { type: String, unique: true, required: true },
  password: { type: String, required: true }
});

// Pre-save hook to hash the password before saving it to the database
userSchema.pre('save', function(next) {
  const user = this;
  if (!user.isModified('password')) return next();
  bcrypt.hash(user.password, 10, (err, hash) => {
    if (err) return next(err);
    user.password = hash;
    next();
  });
});

// Create the User model
const User = mongoose.model('User', userSchema);

/**
 * Registers a new user.
 * @param {string} username - The username of the new user.
 * @param {string} password - The password of the new user.
 * @returns {Promise<Object>} A promise that resolves with the new user object.
 */
function registerUser(username, password) {
  if (!username || !password) {
    return Promise.reject(new Error('Username and password are required.'));
  }

  return User.findOne({ username }).then(existingUser => {
    if (existingUser) {
      throw new Error('Username is already taken.');
    }

    const newUser = new User({ username, password });
    return newUser.save();
  });
}

// Test cases
async function testRegistration() {
  try {
    // Attempt to register a new user
    const newUser = await registerUser('john_doe', 'password123');
    console.log('User registered:', newUser);

    // Attempt to register a user with an existing username
