const express = require('express');
const builder = require('xmlbuilder');

const app = express();
app.use(express.json());

class MovieDatabase {
  constructor() {
    this.directors = [];
    this.movies = [];
    this.characters = [];
  }

  addMovie(director, movieName, ID) {
    let directorIndex = this.directors.findIndex(d => d === director);
    if (directorIndex === -1) {
      directorIndex = this.directors.length;
      this.directors.push(director);
    }
    this.movies.push({ movieName, directorIndex, ID });
  }

  addCharacter(movieID, characterName) {
    const movieIndex = this.movies.findIndex(movie => movie.ID === movieID);
    if (movieIndex !== -1) {
      this.characters.push({ characterName, movieIndex });
    }
  }

  getMovieByID(ID) {
    const movie = this.movies.find(movie => movie.ID === ID);
    if (movie) {
      const characters = this.characters
        .filter(character => this.movies[character.movieIndex].ID === ID)
        .map(character => character.characterName);
      return {
        title: movie.movieName,
        SWAPI_ID: movie.ID,
        characters: characters
      };
    }
    return null;
  }

  getMoviesXML() {
    const root = builder.create('root');
    this.directors.forEach((director, index) => {
      const directorElem = root.ele('director');
      directorElem.ele('name', director);
      this.movies
        .filter(movie => movie.directorIndex === index)
        .forEach(movie => {
          directorElem.ele('movies', movie.movieName);
        });
    });
    return root.end({ pretty: true });
  }
}

const movieDB = new MovieDatabase();

app.post('/movie', (req, res) => {
