/**
 * Creates a function that restricts the invocation of `fn` to once.
 * Repeated calls to the function return `undefined`.
 *
 * @param {Function} fn - The function to restrict.
 * @return {Function} A new function that can only be invoked once.
 */
var once = function (fn) {
  let called = false;
  let result;

  return function (...args) {
    if (!called) {
      called = true;
      result = fn(...args);
    }
    return result;
  };
};

// Test cases
// Importing necessary packages
const assert = require('assert');

// Test function
let add = (a, b, c) => a + b + c;
let onceAdd = once(add);

// Test case 1: Function should work on first call
assert.strictEqual(onceAdd(1, 2, 3), 6, 'Function did not return expected result on first call');

// Test case 2: Function should return undefined on second call
assert.strictEqual(onceAdd(2, 3, 4), undefined, 'Function did not return undefined on second call');

// Test case 3: Function should not call the original function on second call
let wasCalled = false;
let testFn = () => { wasCalled = true; };
let onceTestFn = once(testFn);

onceTestFn(); // should set wasCalled to true
assert.strictEqual(wasCalled, true, 'Original function was not called on first call');

wasCalled = false; // reset flag
onceTestFn(); // should not change wasCalled
assert.strictEqual(wasCalled, false, 'Original function was called on second call');

console.log('All test cases passed!');
