import React, { useContext, useState } from 'react';
import { useDispatch, useSelector } from 'react-redux';
import PropTypes from 'prop-types';
import Tooltip from './ui/tooltip';
import Button from './ui/button';
import Typography from './ui/typography';
import { requestAddNetwork } from './store/networkActions';
import { getPreferredNetworks } from './store/selectors';
import { Icon } from './ui/icon';

const NetworkList = ({ networks }) => {
  const dispatch = useDispatch();
  const preferredNetworks = useSelector(getPreferredNetworks);
  const [addedNetworks, setAddedNetworks] = useState([]);

  const handleAddNetwork = (network) => {
    dispatch(requestAddNetwork(network));
    setAddedNetworks([...addedNetworks, network.chainId]);
  };

  const isNetworkAdded = (chainId) => addedNetworks.includes(chainId);

  return (
    <div className="network-list">
      {networks
        .filter((network) => !preferredNetworks.includes(network.chainId))
        .map((network) => (
          <div key={network.chainId} className="network-list-item">
            <div className="network-info">
              {network.logo && <img src={network.logo} alt={network.name} />}
              <Typography>{network.name}</Typography>
            </div>
            {!/infura\.io/u.test(network.rpcUrl) && (
              <Tooltip content="This network does not use Infura as its RPC provider.">
                <Icon name="warning" />
              </Tooltip>
            )}
            <Button
              onClick={() => handleAddNetwork(network)}
              disabled={isNetworkAdded(network.chainId)}
            >
              Add
            </Button>
          </div>
        ))}
    </div>
  );
};

