function findShortestPathInUndirectedGraph(graph, start, end) {
    const queue = [start];
    const visited = new Set([start]);
    const path = new Map([[start, null]]);

    while (queue.length > 0) {
        const currentNode = queue.shift();

        if (currentNode === end) {
            const result = [];
            let current = end;
            while (current !== null) {
                result.unshift(current);
                current = path.get(current);
            }
            return result;
        }

        for (let neighbor of graph[currentNode]) {
            if (!visited.has(neighbor)) {
                visited.add(neighbor);
                queue.push(neighbor);
                path.set(neighbor, currentNode);
            }
        }
    }

    return null;
}

// Test cases
const graph1 = [
    [1, 2],
    [0, 3],
    [0, 3],
    [1, 2, 4],
    [3]
];

console.log(findShortestPathInUndirectedGraph(graph1, 0, 4)); // [0, 2, 3, 4]

const graph2 = [
    [1],
    [0, 2, 3],
    [1],
    [1],
    []
];

console.log(findShortestPathInUndirectedGraph(graph2, 0, 4)); // null (no path exists)

const graph3 = [
    [1, 2, 3],
    [0, 4],
    [0],
    [0, 5],
    [1],
    [3]
];

console.log(findShortestPathInUndirectedGraph(graph3, 0, 5)); // [0, 3, 5]
