// Function to get the next departure time for a given route
function getNextDepartureTime(timeSchedule, currentTime) {
  for (var i = 0; i < timeSchedule.length; i++) {
    if (timeSchedule[i] > currentTime) {
      return timeSchedule[i];
    }
  }
  return null; // No more buses today
}

// Function to update the HTML with the waiting time or no buses message
function updateBusScheduleDisplay(elementId, routeSchedule, currentTime) {
  var nextDepartureTime = getNextDepartureTime(routeSchedule, currentTime);
  var message = nextDepartureTime
    ? "In " + (nextDepartureTime - currentTime) + " mins"
    : "No buses";
  document.getElementById(elementId).innerHTML = message;
}

// Update the HTML document with the waiting times or no buses messages
updateBusScheduleDisplay("soton_soton", timeSotSot, timeMins);
updateBusScheduleDisplay("soton_chil", timeSotChil, timeMins);
updateBusScheduleDisplay("rom_soton", timeRomSot, timeMins);
updateBusScheduleDisplay("rom_chil", timeRomChil, timeMins);

