      event.preventDefault();
      $(foreground).fadeOut(200);
      Object.values(actions).forEach((action) => {
        action.form.fadeOut(200);
      });
    });
  }

  // Public API
  return {
    init
  };
})();

// Initialize the file manager when the page:browse event is triggered
