// filename: client/src/utils/pagination.js
export default function paginate(list, itemsPerPage, currentPage) {
    // Handle edge cases for itemsPerPage
    itemsPerPage = Math.max(itemsPerPage, 1);

    // Calculate the total number of pages
    const numPages = Math.ceil(list.length / itemsPerPage);

    // Calculate the index range for the current page
    const startIndex = (currentPage - 1) * itemsPerPage;
    const endIndex = startIndex + itemsPerPage;

    // Slice the list to get the items for the current page
    const paginatedList = list.slice(startIndex, endIndex);

    // Generate an array of page numbers for pagination controls
    const pages = Array.from({ length: numPages }, (v, k) => k + 1);

    return {
        pages,
        paginatedList
    };
}

// Test cases to verify the solution correctness
