function calculateWeightedAverage(grades, weights) {
    if (grades.length !== weights.length) {
        throw new Error('Grades and weights arrays must be of the same length.');
    }

    const sumOfWeights = weights.reduce((acc, weight) => acc + weight, 0);
    if (sumOfWeights !== 1) {
        throw new Error('Sum of weights must equal 1.');
    }

    let weightedSum = 0;
    for (let i = 0; i < grades.length; i++) {
        weightedSum += grades[i] * weights[i];
    }

    return parseFloat((weightedSum).toFixed(2));
}

// Test cases
