import nodeDriver from 'arweave/node/lib/crypto/node-driver.js';

// Extend the driver to include a method for getting the public key from a JWK
export class CryptoDriver extends nodeDriver {
    /**
     * Converts a JSON Web Key (JWK) to a PEM-formatted public key.
     * @param {Object} jwk - The JSON Web Key.
     * @returns {string} The PEM-formatted public key.
     */
    getPublicKey(jwk) {
        return createPublicKey({
            key: this.jwkToPem(jwk),
            type: 'pkcs1',
            format: 'pem',
        })
            .export({
                format: 'pem',
                type: 'pkcs1',
            })
            .toString();
    }
}

// Singleton instance of the CryptoDriver
let driverInstance;

/**
 * Returns a singleton instance of the CryptoDriver.
 * @returns {CryptoDriver} The singleton instance.
 */
