 * Uploads a user's profile image to Firebase Storage and updates the user's profile in Firestore.
 * @param {string} userId - The unique ID of the user.
 * @param {File} imageFile - The image file to be uploaded.
 * @returns {Promise<string>} A promise that resolves with the download URL of the uploaded image.
 */
function uploadUserProfileImage(userId, imageFile) {
  // Create a storage reference for the image
  const imageRef = ref(storage, `profileImages/${userId}/${imageFile.name}`);

  // Upload the image to Firebase Storage
  return uploadBytes(imageRef, imageFile)
    .then((snapshot) => {
      // Get the download URL of the uploaded image
      return getDownloadURL(snapshot.ref);
    })
    .then((downloadURL) => {
      // Update the user's profile in Firestore with the image URL
      const userDocRef = doc(db, 'users', userId);
      return updateDoc(userDocRef, {
        profileImageUrl: downloadURL
      });
    })
    .then(() => {
      // Return the download URL of the uploaded image
      return getDownloadURL(imageRef);
    });
}

