// Required packages
var fs = require('fs');
var yaml = require('js-yaml');
var path = require('path');
var should = require('should');

/**
 * ConfigLoader class to load and merge configurations from YAML files, directories, and object literals.
 */
class ConfigLoader {
  constructor() {
    this.configs = [];
  }

  /**
   * Add a configuration source to the loader.
   * @param {string|object} source - The path to a YAML file, a directory of YAML files, or an object literal.
   */
  add(source) {
    this.configs.push(source);
  }

  /**
   * Load and merge all configurations.
   * @param {function} callback - The callback function to call with an error or the merged configuration.
   */
  load(callback) {
    let mergedConfig = {};
    let loadNext = (index) => {
      if (index >= this.configs.length) {
        return callback(null, mergedConfig);
      }

      let source = this.configs[index];
      if (typeof source === 'string') {
        fs.stat(source, (err, stats) => {
          if (err) {
            return callback(err);
          }

          if (stats.isDirectory()) {
            fs.readdir(source, (err, files) => {
              if (err) {
                return callback(err);
              }

              let yamlFiles = files.filter(file => path.extname(file) === '.yaml');
              let readNextFile = (fileIndex) => {
                if (fileIndex >= yamlFiles.length) {
                  return loadNext(index + 1);
                }

                let filePath = path.join(source, yamlFiles[fileIndex]);
                fs.readFile(filePath, 'utf8', (err, data) => {
                  if (err) {
                    return callback(err);
                  }

                  try {
                    let config = yaml.load(data);
                    mergedConfig = { ...mergedConfig, ...config };
                    readNextFile(fileIndex + 1);
                  } catch (yamlErr) {
                    return callback(yamlErr);
                  }
                });
              };

              readNextFile(0);
            });
          } else {
            fs.readFile(source, 'utf8', (err, data) => {
              if (err) {
                return callback(err);
              }

              try {
                let config = yaml.load(data);
                mergedConfig = { ...mergedConfig, ...config };
                loadNext(index + 1);
              } catch (yamlErr) {
                return callback(yamlErr);
              }
            });
          }
        });
      } else if (typeof source === 'object') {
        mergedConfig = { ...mergedConfig, ...source };
        loadNext(index + 1);
      } else {
        return callback(new Error('Unsupported configuration source type'));
      }
    };

    loadNext(0);
  }
}

// Export the ConfigLoader class
module.exports = ConfigLoader;

// Test cases
describe('ConfigLoader', function() {
  it('should load and merge configurations from various sources', function(done) {
    var loader = new ConfigLoader();
    loader.add(path.join(__dirname, 'fixtures', 'config1.yaml'));
    loader.add(path.join(__dirname, 'fixtures', 'valid'));
    loader.add({ 'overrideKey': 'newValue' });
    loader.load(function(error, config) {
      should.not.exist(error);
      config.should.have.property('overrideKey', 'newValue');
      // Add more assertions based on the expected merged configuration
      done();
    });
  });

  it('should report an error for non-existent file paths', function(done) {
    var loader = new ConfigLoader();
    loader.add('invalid-path.yaml');
    loader.load(function(error, config) {
      should.exist(error);
      error.message.should.containEql('ENOENT');
      done();
    });
  });
});
