/**
 * Fetches data from an array of URLs sequentially and returns a promise that resolves to an array of results.
 * @param {string[]} urls - An array of API URLs to fetch data from.
 * @returns {Promise<any[]>} A promise that resolves to an array of results from each API call.
 */
async function fetchTodosInSequence(urls) {
  const results = [];
  for (const url of urls) {
    try {
      const response = await fetch(url);
      if (!response.ok) {
        throw new Error('Failed to fetch data');
      }
      const data = await response.json();
      results.push(data);
    } catch (error) {
      throw new Error('Failed to fetch data');
    }
  }
  return results;
}

