    const { message, severity } = req.body;
    if (!message || !severity) {
        return res.status(400).json({ message: "Missing message or severity" });
    }
    const id = uuidv4();
    alerts[id] = { id, message, severity };
    res.status(201).json(alerts[id]);
});

// Get Alerts
app.get("/alerts", (req, res) => {
    res.json(Object.values(alerts));
});

// Get Alert by ID
app.get("/alerts/:id", checkAlertExists, (req, res) => {
    const { id } = req.params;
    res.json(alerts[id]);
});

