const axios = require('axios');

/**
 * Waits for a server to start by periodically checking if it's running on a specified port.
 * @param {number} port - The port to check.
 * @param {number} interval - The time in milliseconds between checks.
 * @returns {Promise<void>} A promise that resolves when the server is running or rejects after 5 failed attempts.
 */
function waitForServerToStart(port, interval) {
  let attempts = 0;

  return new Promise((resolve, reject) => {
    const checkServer = () => {
      attempts++;
      axios.get(`http://localhost:${port}/`)
        .then(response => {
          if (response.status === 200) {
            resolve();
          } else {
            throw new Error(`Server responded with status: ${response.status}`);
          }
        })
        .catch(error => {
          if (attempts < 5) {
            setTimeout(checkServer, interval);
          } else {
            reject(new Error('Server did not start after 5 attempts'));
          }
        });
    };

    checkServer();
  });
}

// Test cases
waitForServerToStart(3000, 1000)
  .then(() => console.log('Server is running'))
  .catch(error => console.error('Failed to start server:', error.message));
