class ResponsiveHelper {
    /**
     * Create a ResponsiveHelper.
     */
    constructor() {
        this.updateDimensions();
        this.attachResizeEvent();
    }

    /**
     * Update the dimensions of the window.
     */
    updateDimensions() {
        this.windowWidth = $(window).width();
        this.windowHeight = $(window).height();
    }

    /**
     * Check if the current window size is mobile.
     * @returns {boolean} True if window width is less than 768 pixels.
     */
    isMobile() {
        return this.windowWidth < 768;
    }

    /**
     * Check if the current window size is tablet.
     * @returns {boolean} True if window width is between 768 and 1024 pixels.
     */
    isTablet() {
        return this.windowWidth >= 768 && this.windowWidth <= 1024;
    }

    /**
     * Check if the current window size is desktop.
     * @returns {boolean} True if window width is greater than 1024 pixels.
     */
    isDesktop() {
        return this.windowWidth > 1024;
    }

    /**
     * Attach an event listener to the window resize event.
     */
    attachResizeEvent() {
        $(window).on('resize', () => {
            this.updateDimensions();
        });
    }
}

