// Define the AsyncLoader module
const AsyncLoader = (function() {
    "use strict";

    // Private method to get the document head
    function getDocumentHead() {
        return document.head || document.getElementsByTagName('head')[0];
    }

    // Method to load text content from a URL
    function loadText(url, callback) {
        var xhr = new XMLHttpRequest();
        xhr.open('GET', url, true);
        xhr.onreadystatechange = function () {
            if (xhr.readyState === 4) {
                if (xhr.status === 200) {
                    callback(null, xhr.responseText);
                } else {
                    callback(new Error('Failed to load text from ' + url), null);
                }
            }
        };
        xhr.send(null);
    }

    // Method to load a script from a path
    function loadScript(scriptPath, callback) {
        var head = getDocumentHead();
        var script = document.createElement('script');

        script.src = scriptPath;
        head.appendChild(script);

        script.onload = script.onreadystatechange = function(_, isAbort) {
            if (isAbort || !script.readyState || script.readyState === "loaded" || script.readyState === "complete") {
                script.onload = script.onreadystatechange = null;
                if (!isAbort) {
                    callback(null);
                } else {
                    callback(new Error('Failed to load script ' + scriptPath));
                }
            }
        };
    }

    // Public API
    return {
        loadText: loadText,
        loadScript: loadScript
    };
})();

// Export the module for use in other files
module.exports = AsyncLoader;

