/**
 * Merges overlapping intervals and calculates the sum of their lengths.
 * @param {Array<Array<number>>} intervals - An array of interval pairs.
 * @returns {number} The sum of the lengths of the merged intervals.
 */
function sumOverlappingIntervals(intervals) {
  // Helper function to calculate the total sum of interval lengths.
  const totalSum = (arr) =>
    arr.reduce((total, pair) => {
      return total + (pair[1] - pair[0]);
    }, 0);

  // Helper function to check if two intervals overlap.
  const compareIntervals = (pairA, pairB) => {
    return (
      (pairA[0] <= pairB[0] && pairB[0] <= pairA[1]) ||
      (pairA[0] <= pairB[1] && pairB[1] <= pairA[1])
    );
  };

  // Helper function to combine two overlapping intervals into one.
  const combinePair = (arr) => {
    return [Math.min(...arr), Math.max(...arr)];
  };

  // Recursive function to merge intervals and calculate the sum.
  function mergeAndSumIntervals(intervals, counter = 0) {
    const interLength = intervals.length;
    if (counter >= interLength - 1) return totalSum(intervals);
    const sortedIntervals = intervals.sort((pairA, pairB) =>
      pairA[0] < pairB[0] ? -1 : 1
    );
    const firstPair = sortedIntervals[counter];
    const secondPair = sortedIntervals[counter + 1];
    if (!compareIntervals(firstPair, secondPair))
      return mergeAndSumIntervals(intervals, counter + 1);
    const newPair = combinePair(firstPair.concat(secondPair));
    intervals.splice(counter, 2, newPair);
    return mergeAndSumIntervals(intervals, counter);
  }

  return mergeAndSumIntervals(intervals);
}

// Test cases to verify the solution
console.log(sumOverlappingIntervals([
  [1, 4],
  [7, 10],
  [3, 5],
])); // Expected output: 7 (intervals [1, 4] and [3, 5] are merged into [1, 5], and [7, 10] is separate)

console.log(sumOverlappingIntervals([
  [5, 8],
  [1, 3],
  [2, 4],
  [6, 7]
])); // Expected output: 6 (intervals [1, 3] and [2, 4] are merged into [1, 4], and [5, 8] is separate)

console.log(sumOverlappingIntervals([
  [1, 2],
  [2, 3],
  [3, 4],
  [4, 5]
])); // Expected output: 4 (all intervals are merged into [1, 5])
