const fs = require('fs');

/**
 * Updates the value of a specified key in the manifest.json file.
 * 
 * @param {string} keyPath - A dot-separated path to the key within the JSON structure.
 * @param {*} newValue - The new value to be assigned to the key.
 */
function updateManifestValue(keyPath, newValue) {
  const manifestPath = './src/manifest.json';
  let manifestContent = fs.readFileSync(manifestPath, { encoding: 'utf-8' });
  let manifest = JSON.parse(manifestContent);

  const keys = keyPath.split('.');
  let current = manifest;

  for (let i = 0; i < keys.length - 1; i++) {
    if (!(keys[i] in current)) {
      // Key path does not exist, do not make changes
      return;
    }
    current = current[keys[i]];
  }

  const lastKey = keys[keys.length - 1];
  if (!(lastKey in current)) {
    // Key does not exist, do not make changes
    return;
  }

  current[lastKey] = newValue;
  fs.writeFileSync(manifestPath, JSON.stringify(manifest, null, 2), { flag: 'w' });
}

// Test cases
