import Koa from 'koa';
import uuidV4 from 'uuid/v4';

/**
 * Middleware that assigns a unique identifier to each incoming HTTP request.
 *
 * @param {Object} [options={}] - Optional configuration.
 * @param {string} [options.header='X-Request-Id'] - Request and response header name.
 * @param {string} [options.fieldName='requestId'] - Context property name.
 * @param {function} [options.generator=uuidV4] - ID generator function.
 * @return {function} Koa middleware.
 */
export default function requestId(options = {}) {
  const {
    header = 'X-Request-Id',
    fieldName = 'requestId',
    generator = uuidV4
  } = options;

  return async (ctx, next) => {
    const id = ctx.request.get(header) || generator();

    ctx[fieldName] = id;
    ctx.set(header, id);

    await next();
  };
}

// Test cases
const app = new Koa();

// Apply the middleware with default options
app.use(requestId());

// Dummy response for testing
