import { getLicenses } from './licenseService';

/**
 * Checks for licenses that are expired or expiring within a given number of days.
 * @param {number} daysUntilExpiry - The threshold number of days to check for expiry.
 * @returns {Array} An array of license objects that are expiring or expired.
 */
export const checkLicenseExpiry = (daysUntilExpiry) => {
  const licenses = getLicenses();
  const currentDate = new Date();
  const expiryThreshold = new Date(currentDate.getTime() + daysUntilExpiry * 24 * 60 * 60 * 1000);

  return licenses.filter(license => {
    const expirationDate = new Date(license.expirationDate);
    return expirationDate <= expiryThreshold;
  });
};

