'use strict';

/**
 * Finds the smallest divisor of a number other than 1.
 * If the number is prime, it returns the number itself.
 * @param {number} number - The number to find the smallest divisor for.
 * @returns {number} The smallest divisor or the number itself if it is prime.
 * @throws Will throw an error if the input is not a positive integer.
 */
function findSmallestDivisor(number) {
  if (!Number.isInteger(number) || number < 1) {
    throw new Error('Input must be a positive integer');
  }

  if (number === 1) {
    return 1;
  }

  for (let i = 2; i <= Math.sqrt(number); i++) {
    if (number % i === 0) {
      return i;
    }
  }

  return number; // The number is prime
}

// Test cases to verify the solution
try {
  console.log(findSmallestDivisor(15)); // Should return 3
  console.log(findSmallestDivisor(17)); // Should return 17 (since 17 is prime)
  console.log(findSmallestDivisor(1));  // Should return 1
  console.log(findSmallestDivisor(0));  // Should throw an error
} catch (error) {
