const express = require("express");
const multer = require("multer");
const fs = require("fs");
const mongoose = require("mongoose");
const session = require("express-session");
const app = express();

// Set up MongoDB connection
mongoose.connect("mongodb://localhost:27017/videoFileManagement", { useNewUrlParser: true, useUnifiedTopology: true });
const db = mongoose.connection;
db.on("error", console.error.bind(console, "MongoDB connection error:"));

// Define file schema
const fileSchema = new mongoose.Schema({
    path: String,
    userID: String,
    name: String
});
const fileModel = mongoose.model("File", fileSchema);

// Set up session middleware
app.use(session({
    secret: "video file management secret",
    resave: false,
    saveUninitialized: true
}));

// Set up multer for file uploads
const upload = multer({ dest: 'public/videos/' });

// Set base URLs
const baseUrl1 = "./public/videos/";
const baseUrl2 = "http://localhost:3020/videos/";

// GET endpoint to list video files
app.get("/videos", (req, res) => {
    fs.readdir(baseUrl1, (err, items) => {
        if (err) {
            return res.status(404).send({ code: "404", data: err.message });
        }
        let result = items.map(item => {
            return { url: baseUrl2 + item, name: item };
        });
        res.json(result);
    });
});

// POST endpoint to upload video files
app.post("/videos", upload.array('videos'), async (req, res) => {
    try {
        if (!req.session.userID) {
            throw new Error("User ID is not found in session");
        }
        const files = req.files;
        await Promise.all(files.map(async (file) => {
            const newpath = baseUrl1 + file.originalname;
            const fileEntry = new fileModel({
                path: newpath,
                userID: req.session.userID,
                name: file.originalname
            });
            await fileEntry.save();
            fs.renameSync(file.path, newpath);
        }));
        res.send("Files uploaded successfully");
    } catch (err) {
        res.status(500).send({ code: "500", data: err.message });
    }
});

// Start the server
const server = app.listen(3020, () => {
    console.log("Server running on port 3020");
});

// Test cases
const request = require("supertest");
describe("Video File Management API", () => {
    it("should list all video files", async () => {
        const response = await request(server).get("/videos");
        expect(response.statusCode).toBe(200);
        expect(response.body).toBeInstanceOf(Array);
    });

    it("should upload video files", async () => {
        const response = await request(server)
            .post("/videos")
            .attach('videos', 'path/to/video/file.mp4')
            .set('Cookie', [`connect.sid=${sessionID}`]); // Replace with actual session ID
        expect(response.statusCode).toBe(200);
        expect(response.text).toEqual("Files uploaded successfully");
    });
});

module.exports = app;
