// Firebase configuration object containing keys and identifiers for the app
const firebaseConfig = {
  apiKey: "YOUR_API_KEY",
  authDomain: "YOUR_AUTH_DOMAIN",
  projectId: "YOUR_PROJECT_ID",
  storageBucket: "YOUR_STORAGE_BUCKET",
  messagingSenderId: "YOUR_MESSAGING_SENDER_ID",
  appId: "YOUR_APP_ID",
};

// Initialize Firebase app with the provided configuration
const firebaseApp = initializeApp(firebaseConfig);

// Initialize Firebase Auth and Firestore services
const auth = getAuth(firebaseApp);
const db = getFirestore(firebaseApp);

// Create a GoogleAuthProvider instance for Google OAuth
const provider = new GoogleAuthProvider();
provider.setCustomParameters({ prompt: "select_account" });

/**
 * Signs in the user using Google OAuth popup and creates a user document in Firestore.
 * @returns {Promise} A promise that resolves to the user document reference in Firestore.
 */
const signInAndCreateUserDocument = async () => {
  try {
    // Sign in the user with Google OAuth popup
    const { user } = await signInWithPopup(auth, provider);

    // Reference to the user document in Firestore
    const userDocRef = doc(db, "users", user.uid);

    // Check if the user document already exists
    const userSnapshot = await getDoc(userDocRef);

    // If the user document does not exist, create a new one
    if (!userSnapshot.exists()) {
      const { displayName, email } = user;
      const createdAt = new Date();

      await setDoc(userDocRef, {
        displayName,
        email,
        createdAt,
      });
    }

    // Return the user document reference
    return userDocRef;
  } catch (error) {
    // Log any errors that occur during the sign-in or document creation process
    console.error("Error signing in with Google or creating user document:", error.message);
    throw error;
  }
};

// Test cases to verify the solution correctness
(async () => {
