/**
 * Scales the RGB components of a color by a given factor.
 * @param {Object} color - An object with r, g, b, and a properties.
 * @param {number} factor - A non-negative number to scale the RGB components.
 * @returns {Object} A new color object with scaled RGB values and the original alpha value.
 */
function scaleRGBComponents(color, factor) {
    if (typeof color !== 'object' || typeof factor !== 'number' || factor < 0) {
        throw new Error('Invalid input: color must be an object and factor must be a non-negative number.');
    }

    const { r, g, b, a } = color;

    if ([r, g, b, a].some(component => typeof component !== 'number' || component < 0 || component > 1)) {
        throw new Error('Color components must be numbers in the range [0, 1].');
    }

    const clamp = (value) => Math.min(Math.max(value, 0), 1);

    return {
        r: clamp(r * factor),
        g: clamp(g * factor),
        b: clamp(b * factor),
        a: a // Alpha value remains unchanged
    };
}

// Test cases
console.log(scaleRGBComponents({ r: 0.5, g: 0.5, b: 0.5, a: 1 }, 2)); // Should output { r: 1, g: 1, b: 1, a: 1 }
console.log(scaleRGBComponents({ r: 0.2, g: 0.3, b: 0.4, a: 0.5 }, 0.5)); // Should output { r: 0.1, g: 0.15, b: 0.2, a: 0.5 }
console.log(scaleRGBComponents({ r: 0, g: 0, b: 0, a: 0 }, 1)); // Should output { r: 0, g: 0, b: 0, a: 0 }
