const { Builder, By, until, Options } = require('selenium-webdriver');
const { login } = require('./login.js');
const { checkDisponibility } = require('./disponibility.js');

async function scheduleAppointmentBot(state) {
  const chromeOptions = new Options();
  chromeOptions.addArguments('--headless');

  const driver = await new Builder().forBrowser('chrome').setChromeOptions(chromeOptions).build();

  try {
    await driver.get('https://citas.sre.gob.mx/');
    let attempts = 0;

    while (attempts < 5) {
      const loginResult = await login(driver, state.userdata);
      if (loginResult) {
        break;
      } else {
        await driver.navigate().refresh();
        attempts++;
      }
      if (attempts >= 5) {
        throw new Error('Login failed after 5 attempts');
      }
    }

    console.log('Logged in');
    await driver.wait(until.elementLocated(By.css('a.btn.btn-primary')), 20000);

    attempts = 0;
    while (attempts < 5) {
      try {
        await driver.findElement(By.css('a.btn.btn-primary')).click();
        break;
      } catch (error) {
        console.log(`Attempt ${attempts + 1}: Click failed. Waiting 3 seconds before retrying.`);
        await driver.sleep(3000);
        attempts++;
      }
      if (attempts >= 5) {
        throw new Error('Failed to click the button after 5 attempts');
      }
    }

    await driver.wait(async function () {
      const currentUrl = await driver.getCurrentUrl();
      return currentUrl !== 'https://citas.sre.gob.mx/appointment';
    }, 3000);

    attempts = 0;
    while (attempts < 3) {
      const checkResult = await checkDisponibility(driver, state.cities);
      if (checkResult) {
        break;
      } else {
        await driver.navigate().refresh();
        attempts++;
      }
      if (attempts >= 3) {
        throw new Error('No appointments available after 3 attempts');
      }
    }
  } finally {
    await driver.quit();
  }
}

module.exports = scheduleAppointmentBot;

// Test cases
