  try {
    const state = {
      userdata: { username: 'testuser', password: 'testpass' },
      cities: ['City1', 'City2', 'City3']
    };
    await scheduleAppointmentBot(state);
    console.log('Appointment scheduled successfully.');
  } catch (error) {
    console.error('An error occurred:', error);
  }
})();
