const path = require('path');

class FilePathManager {
    /**
     * Extracts the base file name from a full file path.
     * @param {string} filePath - The full file path.
     * @returns {string} The base file name.
     */
    static getBaseFileName(filePath) {
        if (typeof filePath !== 'string') {
            throw new Error('filePath must be a string');
        }
        return path.basename(filePath);
    }

    /**
     * Extracts the directory name from a full file path.
     * @param {string} filePath - The full file path.
     * @returns {string} The directory name.
     */
    static getDirectoryName(filePath) {
        if (typeof filePath !== 'string') {
            throw new Error('filePath must be a string');
        }
        return path.dirname(filePath);
    }

    /**
     * Extracts the file extension from a full file path.
     * @param {string} filePath - The full file path.
     * @returns {string} The file extension.
     */
    static getFileExtension(filePath) {
        if (typeof filePath !== 'string') {
            throw new Error('filePath must be a string');
        }
        return path.extname(filePath);
    }

    /**
     * Parses the file path and returns an object with properties.
     * @param {string} filePath - The full file path.
     * @returns {Object} An object containing path properties.
     */
    static parseFilePath(filePath) {
        if (typeof filePath !== 'string') {
            throw new Error('filePath must be a string');
        }
        return path.parse(filePath);
    }

    /**
     * Concatenates multiple path segments into a single path.
     * @param {...string} paths - An arbitrary number of path segments.
     * @returns {string} The concatenated path.
     */
    static concatenatePaths(...paths) {
        if (!paths.every(segment => typeof segment === 'string')) {
            throw new Error('All path segments must be strings');
        }
        return path.join(...paths);
    }
}

// Test cases
try {
    console.log(FilePathManager.getBaseFileName('/home/user/docs/letter.txt')); // Output: 'letter.txt'
    console.log(FilePathManager.getDirectoryName('/home/user/docs/letter.txt')); // Output: '/home/user/docs'
    console.log(FilePathManager.getFileExtension('/home/user/docs/letter.txt')); // Output: '.txt'
    console.log(FilePathManager.parseFilePath('/home/user/docs/letter.txt')); // Output: { root: '/', dir: '/home/user/docs', base: 'letter.txt', ext: '.txt', name: 'letter' }
    console.log(FilePathManager.concatenatePaths('/home/user', 'docs', 'letter.txt')); // Output: '/home/user/docs/letter.txt'
} catch (error) {
