/**
 * Listens for push events, parses the event data, and displays a notification.
 * Also handles notification click events by opening the associated URL.
 */

// Listening for 'push' events
self.addEventListener('push', function (event) {
    // Check if Notifications are permitted
    if (!(self.Notification && self.Notification.permission === 'granted')) {
        return;
    }

    /**
     * Sends a notification with the parsed JSON data.
     * @param {string} body - The JSON string payload from the push event.
     * @returns {Promise} - A promise that resolves to the display of the notification.
     */
    const sendNotification = body => {
        // Parse the JSON string
        var json = JSON.parse(body);
        // Display the notification with the parsed data
        return self.registration.showNotification(json.title, {
            body: json.body,
            tag: json.tag,
            data: {
                url: json.url
            }
        });
    };

    // Check if the event has data
    if (event.data) {
        // Extract the message from the event data
        const message = event.data.text();
        // Wait until the notification is sent
        event.waitUntil(sendNotification(message));
    }
});

// Listening for 'notificationclick' events
self.addEventListener('notificationclick', function(event) {
    // Wait until the browser window is opened with the notification's URL
    event.waitUntil(
