class TerminalDisplay {
  constructor(width, height) {
    this.width = width;
    this.height = height;
    this.clearTerminal();
    this.fontSize = 12; // Fixed font size for simplicity
  }

  draw(x, y, char, fgColor, bgColor, clear = false) {
    if (x < 0 || x >= this.width || y < 0 || y >= this.height) {
      return; // Bail if coordinates are outside the terminal
    }
    if (clear) {
      char = char || ' '; // Provide a space if we're clearing
    } else if (!char) {
      return; // Bail if not provided with a character and not clearing
    }
    // Replace the character at the specified position
    this.grid[y] = this.grid[y].substring(0, x) + char + this.grid[y].substring(x + 1);
  }

  clearTerminal(char = ' ') {
    this.grid = new Array(this.height).fill(char.repeat(this.width));
  }

  computeSize() {
    return [this.width, this.height];
  }

  computeFontSize() {
