'use strict';

/**
 * Timer class to manage multiple stopwatch instances.
 */
class Timer {
    constructor() {
        this.clockList = [];
        this.runControl = null;
        console.log('%c🕒 Ready', 'color: #196F3D');
    }

    Export() {
        return this.clockList.map(clock => ({
            created: clock.created,
            seconds: clock.seconds,
            id: clock.id,
            active: clock.active
        }));
    }

    Import(clocks = []) {
        this.clockList = this.clockList.concat(clocks);
    }

    Create(activate = false) {
        let dt = new Date();
        let d = (dt.getDate() < 10) ? '0' + dt.getDate() : dt.getDate();
        let m = ((dt.getMonth() + 1) < 10) ? '0' + (dt.getMonth() + 1) : (dt.getMonth() + 1);
        let clock = {
            created: dt.getFullYear() + '-' + m + '-' + d,
            seconds: 0,
            getTime: function () {
                const m = Math.floor((this.seconds / 60) % 60);
                const h = Math.floor(this.seconds / 3600);
                const s = this.seconds % 60;
                return { seconds: s, minutes: m, hours: h };
            },
            id: Date.now(),
            active: activate,
            reset: function () {
                this.seconds = 0;
            },
            context: this,
            tick: null
        };
        let proxy = new Proxy(clock, {
            set: function (target, prop, value) {
                if (prop === 'active') {
                    if (target.active !== value) {
                        target.active = value;
                        target.context.Run();
                    }
                } else if (prop === 'tick') {
                    target.tick = value;
                }
                return true;
            }
        });
        this.clockList.push(proxy);
        if (activate) {
            this.Run();
        }
        return proxy;
    }

    IsAllInactive() {
        return this.clockList.every(clock => !clock.active);
    }

    Run() {
        if (this.IsAllInactive()) {
            window.clearInterval(this.runControl);
        } else {
            this.runControl = window.setInterval(() => {
                this.clockList.forEach(clock => {
                    if (clock.active) {
                        clock.seconds++;
                        if (typeof clock.tick === 'function') {
                            clock.tick(clock.getTime());
                        }
                    }
                });
                if (this.IsAllInactive()) {
                    window.clearInterval(this.runControl);
                }
            }, 1000);
        }
    }

    LoopFunction(fun, ms = 1000) {
        this.loopFun = fun;
        this.loopTime = ms;
    }

    LoopStart() {
        if (this.loopFun) {
            this.loopController = window.setInterval(this.loopFun, this.loopTime);
        }
    }

    LoopStop() {
        if (this.loopController) {
            window.clearInterval(this.loopController);
        }
    }
}

// Test cases
const timer = new Timer();

// Create a new stopwatch and start it immediately
const stopwatch = timer.Create(true);
stopwatch.tick = (time) => {
    console.log(`Stopwatch tick: ${time.hours}h ${time.minutes}m ${time.seconds}s`);
};

// After 3 seconds, reset the stopwatch and stop it
setTimeout(() => {
    stopwatch.reset();
    stopwatch.active = false;
}, 3000);

// Export the current stopwatches
const exported = timer.Export();
console.log('Exported stopwatches:', exported);

// Import stopwatches
timer.Import(exported);

// Set a loop function to be called every 2 seconds
timer.LoopFunction(() => console.log('Custom loop function called'), 2000);
timer.LoopStart();

// After 6 seconds, stop the loop function
setTimeout(() => {
    timer.LoopStop();
}, 6000);
