'use strict';

/**
 * Represents an integer value and provides methods for parsing and converting integers.
 */
class IntegerValue {
  /**
   * Creates an instance of IntegerValue.
   * @param {object} options - The options for creating the integer value.
   * @param {string} options.integralDigits - The digits to the left of the decimal point.
   * @param {boolean} options.positive - Whether the integer is positive.
   */
  constructor(options) {
    if (!/^[0-9]+$/.test(options.integralDigits)) {
      throw new Error('integralDigits must contain only digits');
    }
    if (options.integralDigits.length === 0) {
      throw new Error('integralDigits must not be empty');
    }
    this.integralDigits = options.integralDigits;
    this.positive = options.positive;
  }

  /**
   * Parses a string representing an integer value.
   * @param {string} s - The string representation of the integer.
   * @return {IntegerValue} The parsed integer value.
   */
  static parse(s) {
    const pattern = /^[\x09\x0A\x0D\x20]*([+-]?)([0-9]+)[\x09\x0A\x0D\x20]*$/;
    const m = pattern.exec(s);
    if (!m) {
      throw new Error('Invalid integer string "' + s + '"');
    }
    return new IntegerValue({
      integralDigits: m[2],
      positive: m[1] !== '-'
    });
  }

  /**
   * Creates an IntegerValue from a number.
   * @param {number} value - The number to create the IntegerValue from.
   * @return {IntegerValue} The created IntegerValue.
   */
  static createFromNumber(value) {
    if (!Number.isSafeInteger(value)) {
      throw new Error('Expecting a safe integer');
    }
    return IntegerValue.parse(value.toString(10));
  }

  /**
   * Converts the integer value to its string representation.
   * @return {string} The string representation of the integer value.
   */
  toString() {
    return (this.positive ? '' : '-') + this.integralDigits;
  }
}

// Test cases
try {
  const intValue1 = IntegerValue.parse('42');
  console.log(intValue1.toString()); // '42'

  const intValue2 = IntegerValue.createFromNumber(-123456);
  console.log(intValue2.toString()); // '-123456'

  const intValue3 = new IntegerValue({ integralDigits: '00123', positive: true });
  console.log(intValue3.toString()); // '00123'

  // This should throw an error
  const intValue4 = IntegerValue.parse('3.14');
} catch (error) {
  console.error(error.message);
}
