function calculateMatchWinner(player1Name, player2Name, scoresPlayer1, scoresPlayer2) {
    let pointsPlayer1 = 0;
    let pointsPlayer2 = 0;
    for (let i = 0; i < scoresPlayer1.length; i++) {
        if (scoresPlayer1[i] > scoresPlayer2[i]) {
            pointsPlayer1++;
        } else if (scoresPlayer1[i] < scoresPlayer2[i]) {
            pointsPlayer2++;
        }
    }
    if (pointsPlayer1 > pointsPlayer2) {
        return player1Name;
    } else if (pointsPlayer1 < pointsPlayer2) {
        return player2Name;
    } else {
        return "Draw";
    }
}

