    this.id = id;
    this.teams = teams;
    this.puzzles = puzzles;
    this.challenges = challenges;
  }

  getId() {
    return this.id;
  }

  getTeams() {
    return this.teams;
  }

  getPuzzles() {
    return this.puzzles;
  }

  getChallenges() {
    return this.challenges;
  }

  /**
   * Adds a new team to the game.
   * @param {Object} team - The team object to add.
   * @returns {boolean} - Returns true if the team was added successfully, false otherwise.
   */
  addTeam(team) {
    if (this.teams.some(t => t.id === team.id)) {
      return false; // Team with the same ID already exists.
    }
    this.teams.push(team);
    return true;
  }

  /**
   * Removes a team from the game by its ID.
   * @param {number} teamId - The ID of the team to remove.
   * @returns {boolean} - Returns true if the team was removed successfully, false otherwise.
   */
  removeTeam(teamId) {
    const teamIndex = this.teams.findIndex(team => team.id === teamId);
    if (teamIndex === -1) {
      return false; // Team with the given ID does not exist.
    }
    this.teams.splice(teamIndex, 1);
    return true;
  }
}

