                console.error('Error capturing screenshot:', err);
                core.setFailed('Failed to capture screenshot.');
            } else {
                console.log("Screenshot captured and saved to", file);
                core.setOutput("image-path", file);
            }
        });
    } catch (error) {
        console.error('Error:', error);
        core.setFailed('An error occurred while capturing the screenshot.');
    }
}

