function getColumnElBounds(contentGrid, index) {
    const { width } = contentGrid.children[index].getBoundingClientRect();
    const { transform } = contentGrid.children[index].style;

    return { colWidth: parseInt(width, 10), colTransform: +transform.replace(/[^0-9\-.,]/g, '') };
}

function getLowerBoundsTransforms(
    contentGrid,
    ghostWidth,
    ghostTransform,
    targetGhostIndex,
    draggedElIndex,
    ghostIndex,
) {
    const transforms = {};
    let lowerBound = ghostIndex - 1;
    let updatedGhostTransform = ghostTransform;

    while (lowerBound >= targetGhostIndex) {
        const index = draggedElIndex <= lowerBound ? lowerBound + 1 : lowerBound;

        if (lowerBound !== draggedElIndex) {
            const { colWidth, colTransform } = getColumnElBounds(contentGrid, index);

            if (colTransform > 0) {
                transforms[index] = 0;
                updatedGhostTransform += colWidth;
            } else {
                transforms[index] = lowerBound > draggedElIndex ? 0 : ghostWidth;
                updatedGhostTransform -= colWidth;
            }
        } else {
            transforms[index] = 0;
            updatedGhostTransform = 0;
        }

        lowerBound -= 1;
    }

    return { transforms, updatedGhostTransform };
}

function getUpperBoundsTransforms(
    contentGrid,
    ghostWidth,
    ghostTransform,
    targetGhostIndex,
    draggedElIndex,
    ghostIndex,
) {
    const transforms = {};
    let upperBound = ghostIndex + 1;
    let updatedGhostTransform = ghostTransform;

    while (upperBound <= targetGhostIndex) {
        const index = draggedElIndex >= upperBound ? upperBound - 1 : upperBound;

        if (upperBound !== draggedElIndex) {
            const { colWidth, colTransform } = getColumnElBounds(contentGrid, index);

            if (colTransform < 0) {
                transforms[index] = 0;
                updatedGhostTransform -= colWidth;
            } else {
                transforms[index] = upperBound < draggedElIndex ? 0 : -ghostWidth;
                updatedGhostTransform += colWidth;
            }
        } else {
            transforms[index] = 0;
            updatedGhostTransform = 0;
        }

        upperBound += 1;
    }

    return { transforms, updatedGhostTransform };
}

function rearrangeGridColumns(targetGhostIndex, draggedElIndex, ghostIndex) {
    const contentGrid = document.querySelector('.grid__content');
    const { width: ghostWidth } = contentGrid.children[draggedElIndex].getBoundingClientRect();
    const ghostTransform = +contentGrid.children[draggedElIndex].style.transform.replace(/[^0-9\-.,]/g, '');
    let bounds = {};

    if (targetGhostIndex < ghostIndex) {
        bounds = getLowerBoundsTransforms(
            contentGrid, ghostWidth, ghostTransform, targetGhostIndex, draggedElIndex, ghostIndex,
        );
    } else {
        bounds = getUpperBoundsTransforms(
            contentGrid, ghostWidth, ghostTransform, targetGhostIndex, draggedElIndex, ghostIndex,
        );
    }

    Object.keys(bounds.transforms).forEach((index) => {
        contentGrid.children[index].style.transform = `translateX(${bounds.transforms[index]}px)`;
    });

    contentGrid.children[draggedElIndex].style.transform = `translateX(${bounds.updatedGhostTransform}px)`;
}

// Test cases
document.body.innerHTML = `
  <div class="grid__content">
    <div style="transform: translateX(0px);"></div>
    <div style="transform: translateX(0px);"></div>
    <div style="transform: translateX(0px);"></div>
  </div>
`;

// Mock getBoundingClientRect
HTMLElement.prototype.getBoundingClientRect = function() {
  return { width: 100 };
};

// Simulate dragging the first column to the last position
rearrangeGridColumns(2, 0, 0);

console.log(document.querySelector('.grid__content').children[0].style.transform); // Should log "translateX(200px)"
console.log(document.querySelector('.grid__content').children[1].style.transform); // Should log "translateX(0px)"
console.log(document.querySelector('.grid__content').children[2].style.transform); // Should log "translateX(0px)"
