        body: JSON.stringify({
            "quantity": parseInt(quantity, 10)
        }),
        headers: {
            "Content-type": "application/json; charset=UTF-8"
        }
    }).then(res => {
        if (!res.ok) {
            throw new Error(`HTTP error! status: ${res.status}`);
        }
        console.info('Quantity updated:', res);
        window.location.reload();
    }).catch(error => {
        console.error('Error updating quantity:', error);
    });
}

/**
 * Removes a cart item by sending a DELETE request to the server.
 * @param {string} endpoint - The base API endpoint for deleting a cart item.
 * @param {string|number} productId - The unique identifier of the product to be removed.
 */
function removeCartItem(endpoint, productId) {
    let deleteEndpoint = `${endpoint}${productId}`;

    fetch(deleteEndpoint, {
        method: "DELETE"
    }).then(res => {
        if (!res.ok) {
            throw new Error(`HTTP error! status: ${res.status}`);
        }
        console.info('Item removed:', res);
        window.location.reload();
    }).catch(error => {
