// Create a new JSDOM instance and get the document
const dom = new JSDOM(`<!DOCTYPE html><p>Hello world</p>`);
const document = dom.window.document;

/*
 * SingleStatWidget Class.
 */
class SingleStatWidget {
    constructor(div_id, widget_color, pos_x = 5, pos_y = 5) {
        this.div_id = div_id;
        this.widget_color = widget_color;
        this.pos_x = pos_x;
        this.pos_y = pos_y;
        this.fill_x = 210;
        this.fill_y = 210;
        this.msg = '';

        // Initialize the canvas and context
        this.drawing = document.createElement('canvas');
        this.drawing.width = this.fill_x + 10; // Adding some extra space for shadow
        this.drawing.height = this.fill_y + 10;
        document.body.appendChild(this.drawing);
        this.con = this.drawing.getContext('2d');

        // Draw the initial widget
        this.redraw_widget();
    }

    redraw_widget(widget_color) {
        if (widget_color !== undefined) {
            this.widget_color = widget_color;
        }

        this.con.clearRect(0, 0, this.drawing.width, this.drawing.height);
        this.con.shadowBlur = 10;
        this.con.shadowColor = 'black';
        this.con.fillStyle = this.widget_color;
        this.con.fillRect(this.pos_x, this.pos_y, this.fill_x, this.fill_y);
    }

    set_text(msg, id, fontstyle = '12pt sans-serif') {
        this.con.clearRect(this.pos_x, this.pos_y, this.fill_x, this.fill_y);
        this.redraw_widget();

        this.con.lineWidth = '2';
        const x_pos = this.pos_x + this.fill_x / 2;
        const y_pos = this.pos_y + this.fill_y / 2;
        this.con.textAlign = 'center';
        this.con.font = fontstyle;
        this.con.shadowBlur = 0;
        this.con.fillStyle = 'yellow';
        this.con.fillText(msg, x_pos, y_pos);
    }
}

// Test cases to verify the solution correctness
