import { createReducer, createActions } from 'reduxsauce';
import Immutable from 'seamless-immutable';

/* ------------- Types and Action Creators ------------- */
const { Types, Creators } = createActions({
    increment: ['amount'],
    decrement: ['amount'],
    reset: null
});

export const CounterTypes = Types;
export default Creators;

/* ------------- Initial State ------------- */
export const INITIAL_STATE = Immutable({
    count: 0
});

/* ------------- Reducers ------------- */
export const increment = (state, { amount = 1 }) => {
    return state.merge({ count: state.count + amount });
};

export const decrement = (state, { amount = 1 }) => {
    return state.merge({ count: state.count - amount });
};

export const reset = (state) => {
    return state.merge({ count: INITIAL_STATE.count });
};

/* ------------- Hookup Reducers To Types ------------- */
export const reducer = createReducer(INITIAL_STATE, {
    [Types.INCREMENT]: increment,
    [Types.DECREMENT]: decrement,
    [Types.RESET]: reset,
});

/* ------------- Test Cases ------------- */
console.log('Initial State:', INITIAL_STATE);

const stateAfterIncrement = reducer(INITIAL_STATE, Creators.increment(5));
console.log('State after incrementing by 5:', stateAfterIncrement);

const stateAfterDecrement = reducer(stateAfterIncrement, Creators.decrement(3));
console.log('State after decrementing by 3:', stateAfterDecrement);

const stateAfterReset = reducer(stateAfterDecrement, Creators.reset());
console.log('State after reset:', stateAfterReset);

// Expected Output:
// Initial State: { count: 0 }
// State after incrementing by 5: { count: 5 }
// State after decrementing by 3: { count: 2 }
// State after reset: { count: 0 }
