 * Validates the email and password, submits the form via AJAX if valid, and handles errors.
 */
function validateAndSubmitForm() {
  $("#loginForm").on("submit", function(e) {
    e.preventDefault();

    $("#errorWrapper").hide();
    $("#error").text("");

    var email = $("#email").val();
    var password = $("#password").val();

    // Validate email and password
    if (!validateEmail(email)) {
      $("#errorWrapper").show();
      $("#error").text("Please enter a valid email address.");
      return;
    }

    if (!validatePassword(password)) {
      $("#errorWrapper").show();
      $("#error").text("Password must be at least 8 characters long.");
      return;
    }

    // Submit form via AJAX
    $.post("/api/auth.php", { email: email, password: password }, function(data) {
      if (!data.success) {
        $("#errorWrapper").show();
        $("#error").text(data.error);
        return;
      }

      window.location.href = "/";
    });
  });
}

/**
 * Validates the email format.
 * @param {string} email - The email to validate.
 * @returns {boolean} - True if the email is valid, false otherwise.
 */
function validateEmail(email) {
  var emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
  return emailRegex.test(email);
}

/**
 * Validates the password length.
 * @param {string} password - The password to validate.
 * @returns {boolean} - True if the password is at least 8 characters long, false otherwise.
 */
function validatePassword(password) {
  return password.length >= 8;
}

