import { createSecretKey } from 'crypto';
import { jwtDecrypt } from 'jose/jwt/decrypt';
import { MongoClient } from 'mongodb';
import express from 'express';
import dotenv from 'dotenv';

dotenv.config();

const app = express();
app.use(express.json());

app.post('/update-username', async (req, res) => {
  try {
    const jwt = req.cookies.HarOnline;
    if (!jwt) {
      return res.status(401).json({ message: 'Unauthorized' });
    }

    const secretKey = createSecretKey(Buffer.from(process.env.JWT_KEY));
    const { payload } = await jwtDecrypt(jwt, secretKey);

    if (payload.username.length === 0) {
      return res.status(406).json({ message: 'User Not Found' });
    }

    const client = new MongoClient(process.env.MONGO_URI);
    await client.connect();
    const db = client.db('WEB');
    const users = db.collection('Users');
    const entries = db.collection('Entries');

    const newUsername = req.body.username;
    if (newUsername) {
      const existingUser = await users.findOne({ username: newUsername });
      if (existingUser) {
        return res.status(409).json({ message: 'Username Already Exists' });
      }

      const userResult = await users.updateOne(
        { username: payload.username },
        { $set: { username: newUsername } },
      );

      const entriesResult = await entries.updateMany(
        { username: payload.username },
        { $set: { username: newUsername } },
      );

      if (userResult.modifiedCount > 0 || entriesResult.modifiedCount > 0) {
        return res.status(200).json({ message: 'Update Successful' });
      } else {
        return res.status(500).json({ message: 'Error updating username' });
      }
    }
  } catch (err) {
    console.error(err);
    return res.status(500).json({ message: 'Internal Server Error' });
  }
});

app.use((req, res, next) => {
  res.status(405).json({ message: 'Method Not Allowed' });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

