import queryString from 'query-string';

/**
 * Parses a YouTube URL query string and extracts video and playlist information.
 * @param {string} urlQueryString - The query string containing the YouTube URL.
 * @returns {object} An object with properties videoID, playlistID, startTime, and captionsEnabled.
 */
function parseYouTubeURL(urlQueryString) {
  const params = queryString.parse(urlQueryString);
  const fullUrl = params.fullUrl;
  const urlObj = new URL(fullUrl);
  const searchParams = urlObj.searchParams;
  const result = {};

  // Extract videoID
  const videoIDMatch = urlObj.pathname.match(/\/watch\?v=([^&]+)/) || urlObj.pathname.match(/\/([^/]+)$/);
  if (videoIDMatch) {
    result.videoID = videoIDMatch[1];
  }

  // Extract playlistID
  const playlistID = searchParams.get('list');
  if (playlistID) {
    result.playlistID = playlistID;
  }

  // Extract startTime
  const startTime = searchParams.get('t');
  if (startTime) {
    const timeInSeconds = parseInt(startTime, 10);
    if (!isNaN(timeInSeconds)) {
      result.startTime = timeInSeconds;
    }
  }

  // Extract captionsEnabled
  const captionsEnabled = searchParams.get('captionsEnabled');
  if (captionsEnabled) {
    result.captionsEnabled = captionsEnabled === 'true';
  }

  return result;
}

// Test cases
console.log(parseYouTubeURL('?fullUrl=https://youtu.be/kg12uhZu9_o')); // { videoID: 'kg12uhZu9_o' }
console.log(parseYouTubeURL('?fullUrl=https://youtu.be/TCCJOTY7uRI?t=10')); // { videoID: 'TCCJOTY7uRI', startTime: 10 }
console.log(parseYouTubeURL('?fullUrl=https://www.youtube.com/watch?v=TCCJOTY7uRI&list=PL_90hJucBAcPmFxcbTea81OKGkQevH2F9&index=95&t=20')); // { videoID: 'TCCJOTY7uRI', playlistID: 'PL_90hJucBAcPmFxcbTea81OKGkQevH2F9', startTime: 20 }
console.log(parseYouTubeURL('?fullUrl=https://www.youtube.com/playlist?list=PL_90hJucBAcPmFxcbTea81OKGkQevH2F9')); // { playlistID: 'PL_90hJucBAcPmFxcbTea81OKGkQevH2F9' }
console.log(parseYouTubeURL('?fullUrl=https://www.youtube.com/watch?v=TCCJOTY7uRI&list=PL_90hJucBAcPmFxcbTea81OKGkQevH2F9&index=95&t=0s')); // { videoID: 'TCCJOTY7uRI', playlistID: 'PL_90hJucBAcPmFxcbTea81OKGkQevH2F9' }
