// Import necessary packages
import moment from 'moment';

// Helper function to generate error messages based on validation rules
const getError = (value, rules) => {
    for (let rule of rules) {
        switch (rule) {
            case 'requiredField':
                if (!value) {
                    return 'This field is required.';
                }
                break;
            case 'isDateFormat':
                if (!moment(value, 'YYYY-MM-DD', true).isValid()) {
                    return 'Invalid date format. Please use YYYY-MM-DD.';
                }
                break;
            case 'isNumberFormat':
                if (isNaN(value)) {
                    return 'This field must be a number.';
                }
                break;
            case 'isPositive':
                if (value <= 0) {
                    return 'The amount must be greater than 0.';
                }
                break;
            default:
                return '';
        }
    }
    return '';
};

// Main validation function for the expense form
export const validateExpenseForm = (values) => {
    const errors = {};
    const {
        expense_date,
        expense_category_id,
        amount
    } = values;

    errors.expense_date = getError(
        expense_date,
        ['requiredField', 'isDateFormat'],
    );

    errors.expense_category_id = getError(
        expense_category_id,
        ['requiredField'],
    );

    errors.amount = getError(
        amount,
        ['requiredField', 'isNumberFormat', 'isPositive'],
    );

    return errors;
};

