const R = require('ramda');

/**
 * Finds the intersection of two arrays, returning a new array of unique elements
 * that are present in both input arrays.
 * @param {Array} arr1 - The first array.
 * @param {Array} arr2 - The second array.
 * @returns {Array} A new array containing the elements common to both arrays.
 */
function intersection(arr1, arr2) {
  const set2 = new Set(arr2);
  return arr1.filter((item, index, self) => {
    return set2.has(item) && self.indexOf(item) === index;
  });
}

