import { readOnly } from '@ember/object/computed';
import Slots from '../mixins/slots';

function createDynamicSlots(slotDefinitions) {
  const DynamicSlotsComponent = Component.extend(Slots, {
    init() {
      this._super(...arguments);
      Object.keys(slotDefinitions).forEach(slotName => {
        this._activateSlot(slotName);
        const blockParams = slotDefinitions[slotName];
        blockParams.forEach((param, index) => {
          if (index < 9) { // Limit to 9 block parameters
            defineProperty(this, `${slotName}Param${index}`, readOnly(`_slots.${slotName}.blockParams.${index}`));
          }
        });
      });
    },
    willDestroyElement() {
      Object.keys(slotDefinitions).forEach(slotName => {
        this._deactivateSlot(slotName);
      });
      this._super(...arguments);
    }
  });

  return DynamicSlotsComponent;
}

// Example usage:
// Assuming `Slots` mixin is properly defined and manages the activation/deactivation of slots.
