/**
 * ProgressStep component represents a single step in a multi-step progress bar.
 * It uses context to determine if the step is active, completed, or pending.
 *
 * @param {Object} props - The props for the component.
 * @param {number} props.id - The unique identifier for the step.
 * @param {string} props.label - The text label for the step.
 * @returns {JSX.Element} The JSX code for progress step component.
 */
const ProgressStep = ({ id, label }) => {
  const { activeStep, completedSteps } = useContext(ProgressContext);
  const isActive = id === activeStep;
  const isCompleted = completedSteps.includes(id);
  let statusClass = '';

  if (isActive) {
    statusClass = 'active';
  } else if (isCompleted) {
    statusClass = 'completed';
  } else {
    statusClass = 'pending';
  }

  return (
    <li className={`progress-step ${statusClass}`}>
      <span className="progress-step__dot"></span>
      {isCompleted && (
        <span className="progress-step__check">
          <Check />
        </span>
      )}
      <span className="progress-step__label">{label}</span>
    </li>
  );
};

