import { configureStore, createSlice } from '@reduxjs/toolkit';

// Define the initial state of the counter
const initialState = {
  value: 0,
};

// Create a slice for the counter with our three reducers
const counterSlice = createSlice({
  name: 'counter',
  initialState,
  reducers: {
    increment: state => {
      state.value += 1;
    },
    decrement: state => {
      state.value -= 1;
    },
    reset: state => {
      state.value = 0;
    },
    incrementByAmount: (state, action) => {
      state.value += action.payload;
    },
  },
});

// Destructure and export the plain action creators
export const { increment, decrement, reset, incrementByAmount } = counterSlice.actions;

// Create the store with the counter reducer
const store = configureStore({
  reducer: counterSlice.reducer,
});

export default store;

// Test cases
console.log('Initial state:', store.getState().value); // Should be 0

store.dispatch(increment());
console.log('After increment:', store.getState().value); // Should be 1

