var webpack = require('webpack');

/**
 * Takes a webpack configuration object and returns a new configuration object
 * with updated properties for entry, output, loaders, extensions, and plugins.
 * 
 * @param {Object} config - The original webpack configuration object.
 * @returns {Object} The new webpack configuration object.
 */
function bundleProject(config) {
  // Clone the original configuration to avoid mutating it
  let newConfig = JSON.parse(JSON.stringify(config));

  // Update the entry point
  newConfig.entry = './src/index.js';

  // Update the output configuration
  newConfig.output = {
    filename: './dist/bundle.js'
  };

  // Add a new loader for .css files
  newConfig.module.loaders.push({
    test: /\.css$/,
    loader: 'style-loader!css-loader'
  });

  // Add .css to the resolvable extensions
  newConfig.resolve.extensions.push('.css');

  // Add the UglifyJsPlugin to the plugins array
  newConfig.plugins.push(new webpack.optimize.UglifyJsPlugin());

  return newConfig;
}

// Example usage:
var originalConfig = {
  entry: './src/main',
  output: {
    filename: './lib/main.js'
  },
  module: {
    loaders: [
      { test: /\.imba$/, loader: './src/imba-loader' }
    ]
  },
  resolve: {
    extensions: ['', '.js', '.imba']
  },
  plugins: [
    new webpack.DefinePlugin({
      "typeof window": JSON.stringify("object")
    })
  ]
};

