import React, { Suspense, lazy } from "react";
import Loader from "./utils/loader";

/**
 * Attempts to dynamically import a module with retries.
 * @param {string} modulePath - The path of the module to import.
 * @param {number} retries - The number of times to retry the import.
 * @param {number} interval - The interval between retries in milliseconds.
 * @returns {Promise} - A promise that resolves to the imported module.
 */
const retryAsyncImport = (modulePath, retries = 5, interval = 1000) => {
  const importModule = () => import(modulePath);
  return new Promise((resolve, reject) => {
    const attemptImport = (retriesLeft) => {
      importModule()
        .then(resolve)
        .catch((error) => {
          if (retriesLeft === 0) {
            reject(error);
          } else {
            setTimeout(() => attemptImport(retriesLeft - 1), interval);
          }
        });
    };
    attemptImport(retries);
  });
};

/**
 * React component that lazily loads a component with retries.
 * @param {string} modulePath - The path of the module to import.
 * @param {number} retries - The number of times to retry the import.
 * @param {number} interval - The interval between retries in milliseconds.
 */
const LazyWithRetry = ({ modulePath, retries, interval }) => {
  const Component = lazy(() => retryAsyncImport(modulePath, retries, interval));
  return (
    <Suspense fallback={<Loader />}>
      <Component />
    </Suspense>
  );
};

// Test cases
const testRetryAsyncImport = async () => {
  try {
    const module = await retryAsyncImport('./nonexistentModule', 3, 500);
    console.log('Module was imported successfully:', module);
  } catch (error) {
    console.error('Failed to import module:', error);
  }
};

const TestComponent = () => (
  <div>
    <h1>Test Component</h1>
  </div>
);

const App = () => {
  return (
    <div>
      <LazyWithRetry modulePath="./TestComponent" retries={3} interval={500} />
    </div>
  );
};

export default App;
export { retryAsyncImport, LazyWithRetry, testRetryAsyncImport };
