"use strict";

const express = require('express');
const redis = require('redis');
const bodyParser = require('body-parser');

const app = express();
app.use(bodyParser.json());

const db = redis.createClient(process.env.REDIS_URL);

app.post('/api/register', (req, res) => {
    const { username, password } = req.body;
    if (!username || !password) {
        return res.status(400).json({ result: 'error', desc: 'username and password are required' });
    }

    db.sismember('users', username, (err, exists) => {
        if (exists) {
            return res.status(409).json({ result: 'error', desc: 'username already exists' });
        }

        const newUser = { username, password };
        db.hmset(`user:${username}`, newUser, (err) => {
            if (err) {
                return res.status(500).json({ result: 'error', desc: 'internal server error' });
            }
            db.sadd('users', username, () => {
                return res.status(201).json({ result: 'success', username });
            });
        });
    });
});

app.post('/api/login', (req, res) => {
    const { username, password } = req.body;
    db.hgetall(`user:${username}`, (err, user) => {
        if (!user || user.password !== password) {
            return res.status(401).json({ result: 'error', desc: 'invalid credentials' });
        }
        return res.status(200).json({ result: 'success', username });
    });
});

app.post('/api/addTweet', (req, res) => {
    const { username, text } = req.body;
    const tweetId = Date.now().toString(); // Use timestamp as a simple unique ID
    const tweetObj = { id: tweetId, username, text, timestamp: Date.now() };

    db.hmset(`tweet:${tweetId}`, tweetObj, (err) => {
        if (err) {
            return res.status(500).json({ result: 'error', desc: 'internal server error' });
        }
        db.sadd('tweets', tweetId, () => {
            return res.status(201).json(tweetObj);
        });
    });
});

app.post('/api/editTweet', (req, res) => {
    const { id, text } = req.body;
    db.hexists(`tweet:${id}`, 'id', (err, exists) => {
        if (!exists) {
            return res.status(404).json({ result: 'error', desc: 'tweet not found' });
        }
        db.hset(`tweet:${id}`, 'text', text, (err) => {
            if (err) {
                return res.status(500).json({ result: 'error', desc: 'internal server error' });
            }
            return res.status(200).json({ id, text });
        });
    });
});

app.post('/api/removeTweet', (req, res) => {
    const { id } = req.body;
    db.hdel(`tweet:${id}`, 'id', 'username', 'text', 'timestamp', (err) => {
        if (err) {
            return res.status(500).json({ result: 'error', desc: 'internal server error' });
        }
        db.srem('tweets', id, () => {
            return res.status(204).send();
        });
    });
});

app.get('/api/getUsers', (req, res) => {
    db.smembers('users', (err, users) => {
        if (err) {
            return res.status(500).json({ result: 'error', desc: 'internal server error' });
        }
        const userPromises = users.map((username) => {
            return new Promise((resolve) => {
                db.hgetall(`user:${username}`, (err, user) => {
                    delete user.password; // Remove password from user object
                    resolve(user);
                });
            });
        });
        Promise.all(userPromises).then((users) => {
            return res.status(200).json(users);
        });
    });
});

app.get('/api/getTweets', (req, res) => {
    db.smembers('tweets', (err, tweetIds) => {
        if (err) {
            return res.status(500).json({ result: 'error', desc: 'internal server error' });
        }
        const tweetPromises = tweetIds.map((id) => {
            return new Promise((resolve) => {
                db.hgetall(`tweet:${id}`, (err, tweet) => {
                    resolve(tweet);
                });
            });
        });
        Promise.all(tweetPromises).then((tweets) => {
            return res.status(200).json(tweets);
        });
    });
});

const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
});

module.exports = app;
