    this.refs.startBtn.addEventListener('click', this.onStartBtnClick.bind(this));
    this.refs.stopBtn.addEventListener('click', this.onStopBtnClick.bind(this));

    this.timer = null;
  }

  onStartBtnClick() {
    this.refs.startBtn.setAttribute('disabled', 'disabled');
    this.refs.stopBtn.removeAttribute('disabled');

    this.timer = setInterval(() => {
      this.refs.body.style.backgroundColor = this.getRandomHexColor();
    }, 1000);
  }

  onStopBtnClick() {
    if (this.refs.startBtn.getAttribute('disabled')) {
      this.refs.stopBtn.setAttribute('disabled', 'disabled');
      this.refs.startBtn.removeAttribute('disabled');
    }
    clearInterval(this.timer);
  }

  getRandomHexColor() {
    return `#${Math.floor(Math.random() * 16777215).toString(16)}`;
  }
}

