// Import action types
const LOGIN_USER = 'LOGIN_USER';
const LOGOUT_USER = 'LOGOUT_USER';
const GET_CHATS = 'GET_CHATS';
const SEND_MESSAGE = 'SEND_MESSAGE';

// Initial state of the chat application
const initialState = {
    isLoggedIn: false,
    chats: []
};

/**
 * Reducer function for the chat application.
 * @param {Object} state - The current state of the application.
 * @param {Object} action - The action to be handled.
 * @returns {Object} The new state of the application.
 */
export const chatReducer = (state = initialState, action) => {
    switch (action.type) {
        case LOGIN_USER:
            return {
                ...state,
                isLoggedIn: true
            };
        case LOGOUT_USER:
            return {
                ...state,
                isLoggedIn: false,
                chats: []
            };
        case GET_CHATS:
            return {
                ...state,
                chats: action.payload
            };
        case SEND_MESSAGE:
            return {
                ...state,
                chats: [...state.chats, action.payload]
            };
        default:
            return state;
    }
};

// Test cases
const testReducer = () => {
    // Test initial state
    console.assert(JSON.stringify(chatReducer(undefined, {})) === JSON.stringify(initialState), 'Initial state should match');

    // Test login action
    console.assert(chatReducer(undefined, { type: LOGIN_USER }).isLoggedIn === true, 'LOGIN_USER action should set isLoggedIn to true');

    // Test logout action
    let state = chatReducer(undefined, { type: LOGIN_USER });
    state = chatReducer(state, { type: LOGOUT_USER });
    console.assert(state.isLoggedIn === false && state.chats.length === 0, 'LOGOUT_USER action should set isLoggedIn to false and clear chats');

    // Test get chats action
    const chats = [{ message: 'Hello', timestamp: Date.now() }];
    state = chatReducer(state, { type: GET_CHATS, payload: chats });
    console.assert(JSON.stringify(state.chats) === JSON.stringify(chats), 'GET_CHATS action should update the state with new chats');

    // Test send message action
    const newMessage = { message: 'Hi there!', timestamp: Date.now() };
    state = chatReducer(state, { type: SEND_MESSAGE, payload: newMessage });
    console.assert(state.chats.includes(newMessage), 'SEND_MESSAGE action should append new message to chats');

    console.log('All tests passed!');
};

// Run test cases
