const JsonML = require('jsonml.js/lib/utils');

/**
 * Processes a Markdown document represented as JsonML to separate the main content,
 * API section, and common problems section.
 * 
 * @param {Array} markdownData Preprocessed JsonML from previous plugin
 * @return {Object} An object with properties `content`, `api`, and `commonProblems`
 * containing the corresponding sections of the document as JsonML.
 */
module.exports = function (markdownData) {
  const contentChildren = JsonML.getChildren(markdownData.content);
  const apiStartIndex = contentChildren.findIndex(node =>
    JsonML.getTagName(node) === 'h2' && /^API/.test(JsonML.getChildren(node)[0])
  );

  const commonProblemsIndex = contentChildren.findIndex(node =>
    JsonML.getTagName(node) === 'h2' && /^Common Problems/.test(JsonML.getChildren(node)[0])
  );

  if (apiStartIndex > -1) {
    const content = contentChildren.slice(0, apiStartIndex);
    markdownData.content = ['section'].concat(content);

    let apiEndIndex = commonProblemsIndex > -1 ? commonProblemsIndex : contentChildren.length;
    const api = contentChildren.slice(apiStartIndex, apiEndIndex);
    markdownData.api = ['section'].concat(api);

    if (commonProblemsIndex > -1) {
      const commonProblems = contentChildren.slice(commonProblemsIndex);
      markdownData.commonProblems = ['section'].concat(commonProblems);
    }
  }

  return markdownData;
};

// Test cases
