  content: [
    'article',
    ['h1', 'Documentation'],
    ['p', 'This is the main content of the document.'],
    ['h2', 'API'],
    ['p', 'This section describes the API.'],
    ['h2', 'Common Problems'],
    ['p', 'This section describes common problems.']
  ]
};

