/**
 * Finds the next square number greater than the given number if it is a perfect square.
 * @param {number} n - The number to check and find the next square for.
 * @returns {number} - The next square number if n is a perfect square, otherwise -1.
 */
const findNextSquare = n => {
    if (Math.sqrt(n) % 1 === 0) {
        return (Math.sqrt(n) + 1) ** 2;
    } else {
        return -1;
    }
}

