// Import necessary packages
const express = require('express');
const { v4: uuidv4 } = require('uuid');

// Initialize express app
const app = express();
const PORT = process.env.PORT || 3000;

// Middleware to parse JSON bodies
app.use(express.json({ type: '*/*' }));

// In-memory database substitute
const students = {};

// POST endpoint to add a new student record
app.post('/students', (req, res) => {
    const { name, age, grade } = req.body;
    if (!name || !age || !grade) {
        return res.status(400).send('Missing required student fields');
    }
    const id = uuidv4();
    students[id] = { id, name, age, grade };
    res.status(201).send(students[id]);
});

// GET endpoint to retrieve a student record by ID
app.get('/students/:id', (req, res) => {
    const { id } = req.params;
    const student = students[id];
    if (!student) {
        return res.status(404).send('Student not found');
    }
    res.send(student);
});

// PUT endpoint to update a student record by ID
app.put('/students/:id', (req, res) => {
    const { id } = req.params;
    const { name, age, grade } = req.body;
    const student = students[id];
    if (!student) {
        return res.status(404).send('Student not found');
    }
    students[id] = { ...student, name, age, grade };
    res.send(students[id]);
});

// DELETE endpoint to delete a student record by ID
app.delete('/students/:id', (req, res) => {
    const { id } = req.params;
    const student = students[id];
    if (!student) {
        return res.status(404).send('Student not found');
    }
    delete students[id];
    res.status(204).send();
});

// Start the server
app.listen(PORT, () => {
    console.log('Server listening on port %s', PORT);
});

// Export the app for testing purposes
module.exports = app;
