/**
 * Slugify function that converts a string into a URL-friendly slug.
 * @param {string} text - The string to be slugified.
 * @returns {string} - The slugified string.
 */
function slugify(text) {
  return text.toString().toLowerCase()
    .replace(/\s+/g, '-')           // Replace spaces with -
    .replace(/[^\w\-]+/g, '')       // Remove all non-word chars
    .replace(/\-\-+/g, '-')         // Replace multiple - with single -
    .trim();                        // Trim - from start and end of text
}

// Create schema for Organization
const OrganizationSchema = new Schema({
  name: {
    type: String,
    minlength: 6,
    required: [true, "Please add a name"],
    unique: true,
  },
  slug: {
    type: String,
    index: true,
    unique: true,
  },
  createdAt: {
    type: Date,
    default: Date.now,
  },
  updatedAt: {
    type: Date,
    default: Date.now,
  },
});

// Pre-save middleware to slugify the name
OrganizationSchema.pre("save", function(next) {
  if (this.isNew || this.isModified('name')) {
    this.slug = slugify(this.name);
  }
  this.updatedAt = new Date();
  next();
});

// Create model for Organization
const Organization = mongoose.model("Organization", OrganizationSchema);

