  return bcrypt.hashSync(password, 10);
}

function comparePassword(password, passwordDb) {
  return bcrypt.compareSync(password, passwordDb);
}

// In-memory user store
var users = {};

function registerUser(username, password) {
  if (users[username]) {
    throw new Error('User already exists');
  }
  users[username] = {
    password: hashPassword(password)
  };
}

function authenticateUser(username, password) {
  var user = users[username];
  if (!user) {
    return false;
  }
  return comparePassword(password, user.password);
}

function changeUserPassword(username, oldPassword, newPassword) {
  var user = users[username];
  if (!user || !comparePassword(oldPassword, user.password)) {
    throw new Error('Old password is incorrect or user does not exist');
  }
  user.password = hashPassword(newPassword);
}

// Test cases
