const assert = require('assert');

/**
 * Splits the given JavaScript code into segments at include statements.
 * @param {string} source - The JavaScript code to split.
 * @returns {string[]} An array of code segments.
 */
function splitIncludes(source) {
    const lines = source.split('\n');
    const segments = [];
    let currentSegment = '';

    lines.forEach((line, index) => {
        const trimmedLine = line.trim();
        const isIncludeLine = trimmedLine.startsWith('include(') && trimmedLine.endsWith(');');
        const isCommentedOut = trimmedLine.startsWith('//') || trimmedLine.startsWith('\\\\');

        if (isIncludeLine && !isCommentedOut) {
            if (currentSegment) {
                segments.push(currentSegment.trim());
                currentSegment = '';
            }
            segments.push(trimmedLine);
        } else {
            if (index > 0 && lines[index - 1].trim().endsWith(');') && !isCommentedOut) {
                if (currentSegment) {
                    segments.push(currentSegment.trim());
                    currentSegment = '';
                }
            }
            currentSegment += line + '\n';
        }
    });

    if (currentSegment) {
        segments.push(currentSegment.trim());
    }

    return segments;
}

// Test cases
describe('splitIncludes', function () {
    it('should split include statements into separate groups', function () {
        const source = 'include("a")\nvar a = 1;\ninclude("b");\nvar b = 1;';
        const output = splitIncludes(source);
        const expected = [
            'include("a")',
            'var a = 1;',
            'include("b")',
            'var b = 1;'
        ];
        assert.deepEqual(output, expected);
    });

    // Additional test cases would be similar to those provided in the original snippet,
    // adjusted to use the `splitIncludes` function and the `assert.deepEqual` method.
});

// Run the tests
describe.run();
