    let client;
    let server;
    const port = 8080;
    const url = `ws://localhost:${port}`;

    before(function () {
        server = new WsTgServer();
        server.start(port);
        client = new WsTgClient();
    });

    after(function () {
        client.disconnect();
        server.stop();
    });

    it('should connect to the server', function (done) {
        client.connect(url)
            .then(() => {
                expect(client.isConnected()).to.be.true;
                done();
            })
            .catch(done);
    });

    it('should send a message to the server', function (done) {
        const message = 'Hello, server!';
        server.onMessage((receivedMessage) => {
            expect(receivedMessage).to.equal(message);
            done();
        });
        client.sendMessage(message);
    });

    it('should receive a broadcast message from the server', function (done) {
        const message = 'Hello, clients!';
        client.onMessage((receivedMessage) => {
            expect(receivedMessage).to.equal(message);
            done();
        });
        server.broadcastMessage(message);
    });

    it('should disconnect from the server', function (done) {
        client.disconnect()
            .then(() => {
                expect(client.isConnected()).to.be.false;
                done();
            })
            .catch(done);
    });
});

describe('WsTgServer', function () {
