/**
 * Sums even numbers in an array until a number greater than 100 is encountered.
 * 
 * @param {number[]} numbers - An array of integers.
 * @return {number} The sum of the even numbers before any number greater than 100.
 */
function filterAndSumEvenNumbers(numbers) {
  let sum = 0;
  for (let i = 0; i < numbers.length; i++) {
    if (numbers[i] > 100) {
      break;
    }
    if (numbers[i] % 2 !== 0) {
      continue;
    }
    sum += numbers[i];
  }
  return sum;
}

// Test cases
console.log(filterAndSumEvenNumbers([2, 3, 4, 101, 6])); // 6
console.log(filterAndSumEvenNumbers([1, 22, 34, 55, 78])); // 134
console.log(filterAndSumEvenNumbers([102, 3, 4, 5])); // 0
console.log(filterAndSumEvenNumbers([10, 20, 30, 40, 50])); // 150
console.log(filterAndSumEvenNumbers([])); // 0
