/*!
 * FormBuilder Example
 * A simple form builder class to dynamically create forms with various input types.
 *
 * Date: 2023-04-01
 */

// Importing necessary packages
import $ from 'jquery'; // Assuming jQuery is used for DOM manipulation

class FormBuilder {
    constructor(selector) {
        this.form = $('<form>').addClass('dynamic-form');
        this.fields = {};
        this.validationRules = {};
        $(selector).append(this.form);
    }

    addInput(name, type = 'text', placeholder = '') {
        this.fields[name] = $('<input>').attr({ name, type, placeholder });
        return this;
    }

    addSelect(name, options, defaultValue) {
        const select = $('<select>').attr({ name });
        Object.entries(options).forEach(([value, text]) => {
            const option = $('<option>').val(value).text(text);
            if (value === defaultValue) {
                option.attr('selected', 'selected');
            }
            select.append(option);
        });
        this.fields[name] = select;
        return this;
    }

    addCheckbox(name, checked = false) {
        const checkbox = $('<input>').attr({ name, type: 'checkbox' });
        if (checked) {
            checkbox.attr('checked', 'checked');
        }
        this.fields[name] = checkbox;
        return this;
    }

    addTextarea(name, placeholder = '') {
        this.fields[name] = $('<textarea>').attr({ name, placeholder });
        return this;
    }

    setValidationRule(name, rule) {
        this.validationRules[name] = rule;
        return this;
    }

    render() {
        Object.values(this.fields).forEach(field => {
            this.form.append(field);
        });
        this.form.append($('<button>').attr({ type: 'submit' }).text('Submit'));
        this.form.on('submit', (e) => {
            e.preventDefault();
            const data = this.getData();
            console.log(data);
        });
        return this;
    }

    getData() {
        const data = {};
        Object.keys(this.fields).forEach(name => {
            const field = this.fields[name];
            if (field.is(':checkbox')) {
                data[name] = field.is(':checked');
            } else {
                data[name] = field.val();
            }
            // Apply validation rules and add success/error classes
            if (this.validationRules[name] && !this.validationRules[name](data[name])) {
                field.addClass('error');
            } else {
                field.removeClass('error').addClass('success');
            }
        });
        return data;
    }
}

// Exporting the FormBuilder class
export default FormBuilder;

