const { expect } = require('chai');
const sinon = require('sinon');

/**
 * Reverses a given string without using .split or .slice methods.
 * @param {string} str - The string to be reversed.
 * @returns {string} - The reversed string.
 * @throws {TypeError} - If the input is not a string.
 */
function reverseWithoutSplitSlice(str) {
  if (typeof str !== 'string') {
    throw new TypeError('Input must be a string.');
  }

  let reversed = '';
  for (let i = str.length - 1; i >= 0; i--) {
    reversed += str[i];
  }
  return reversed;
}

// Test cases
describe('function reverseWithoutSplitSlice()', () => {
  let splitSpy, sliceSpy;
  beforeEach('spy on .split and .slice string methods', () => {
    splitSpy = sinon.spy(String.prototype, 'split');
    sliceSpy = sinon.spy(String.prototype, 'slice');
  });
  afterEach('restore spies to original methods', () => {
    splitSpy.restore();
    sliceSpy.restore();
  });

  it('takes a string and returns the reverse', () => {
    expect(reverseWithoutSplitSlice('abcdefg')).to.equal('gfedcba');
  });

  it('does not use .slice or .split string methods', () => {
    reverseWithoutSplitSlice('abc');
    expect(splitSpy.notCalled).to.be.true;
    expect(sliceSpy.notCalled).to.be.true;
  });

  it('handles empty strings', () => {
    expect(reverseWithoutSplitSlice('')).to.equal('');
  });

  it('throws TypeError if the input is not a string', () => {
    expect(() => reverseWithoutSplitSlice(123)).to.throw(TypeError, 'Input must be a string.');
    expect(() => reverseWithoutSplitSlice(null)).to.throw(TypeError, 'Input must be a string.');
    expect(() => reverseWithoutSplitSlice(undefined)).to.throw(TypeError, 'Input must be a string.');
  });
});
