const express = require('express');

/**
 * Middleware function to extract a Bearer token from the Authorization header.
 * @param {Object} request - The HTTP request object.
 * @param {Object} response - The HTTP response object.
 * @param {Function} next - The callback function to pass control to the next middleware.
 */
const extractBearerToken = (request, response, next) => {
  try {
    const authorization = request.get('authorization');
    if (authorization && authorization.toLowerCase().startsWith('bearer ')) {
      request.token = authorization.substring(7);
    } else {
      request.token = null;
    }
    next();
  } catch (error) {
    next(new Error('Failed to extract Bearer token'));
  }
};

// Create an Express application
const app = express();

// Use the extractBearerToken middleware
app.use(extractBearerToken);

// Define a route that responds with the extracted token or an error message
app.get('/token', (req, res) => {
  if (req.token) {
    res.status(200).send({ token: req.token });
  } else {
    res.status(401).send({ error: 'No Bearer token provided' });
  }
});

// Error handling middleware
app.use((err, req, res, next) => {
  res.status(500).send({ error: err.message });
});

// Start the server on port 3000
const server = app.listen(3000, () => {
  console.log('Server running on port 3000');
});

// Export the server for testing purposes
module.exports = server;

// Test cases
if (require.main === module) {
  const axios = require('axios');

  const testBearerTokenExtraction = async () => {
    try {
      // Test with a valid Bearer token
      let response = await axios.get('http://localhost:3000/token', {
        headers: { Authorization: 'Bearer mytesttoken123' }
      });
      console.log('Test with valid token:', response.data);

      // Test without Bearer token
      response = await axios.get('http://localhost:3000/token');
      console.log('Test without token:', response.data);
    } catch (error) {
      console.error('Test failed:', error.response.data);
    } finally {
      server.close();
    }
  };

  testBearerTokenExtraction();
}
