/**
 * Determines if there is a path between two nodes in a directed graph using BFS.
 * @param {Object} graph - The adjacency list of the graph.
 * @param {string} start - The starting node.
 * @param {string} end - The target node.
 * @returns {boolean} - True if a path exists, false otherwise.
 */
const isPathExist = (graph, start, end) => {
  let queue = [];
  queue.push(start);
  const visited = new Set();

  while (queue.length > 0) {
    let current = queue.shift();
    visited.add(current);

    if (current === end) {
      return true;
    }

    if (!graph[current]) {
      continue;
    }

    for (const neighbor of graph[current]) {
      if (!visited.has(neighbor)) {
        queue.push(neighbor);
      }
    }
  }

  return false;
};

// Test cases
console.log(isPathExist({ a: ["b", "c"], b: ["f"], c: ["d", "e"], d: ["f"], e: ["f"], f: ["g"] }, 'a', 'g')); // true
console.log(isPathExist({ a: ["b", "c"], b: ["f"], c: ["d", "e"], d: ["f"], e: ["f"], f: ["g"] }, 'a', 'e')); // true
console.log(isPathExist({ a: ["b", "c"], b: ["f"], c: ["d", "e"], d: ["f"], e: ["f"], f: ["g"] }, 'g', 'a')); // false
console.log(isPathExist({ a: ["b", "c"], b: ["f"], c: [], d: ["f"], e: ["f"], f: ["g"] }, 'c', 'f')); // false
