Vue.use(VueRouter);

/**
 * Creates and configures a VueRouter instance with NProgress integration.
 * @param {Array} routes - An array of route configurations for VueRouter.
 * @returns {VueRouter} - The configured VueRouter instance.
 */
export function createRouter(routes) {
  const router = new VueRouter({
    mode: 'history',
    routes
  });

  router.beforeResolve((to, from, next) => {
    if (to.name) {
      NProgress.start();
    }
    next();
  });

  router.afterEach((to, from) => {
    NProgress.done();
  });

  return router;
}

