const tap = require('tap');
const sqlite3 = require('sqlite3').verbose();

// Mock classes and methods for the test
class TableGeometry {
  create(db) {
    db.run('CREATE TABLE geometry (id INTEGER PRIMARY KEY, geom BLOB)');
  }

  drop(db) {
    db.run('DROP TABLE IF EXISTS geometry');
  }
}

class GeoColumnGeom {
  create(db) {
    db.run('ALTER TABLE geometry ADD COLUMN geom BLOB');
  }

  drop(db) {
    // SQLite does not support dropping a column directly
    // This would require creating a new table without the column and copying data over
  }
}

class GeoIndexGeom {
  create(db) {
    db.run('SELECT CreateSpatialIndex("geometry", "geom")');
  }

  drop(db) {
    db.run('SELECT DisableSpatialIndex("geometry", "geom")');
  }
}

class SqliteIntrospect {
  constructor(db) {
    this.db = db;
  }

  geometryColumns(tableName) {
    return new Promise((resolve, reject) => {
      this.db.all(
        'PRAGMA table_info(' + tableName + ')',
        (err, columns) => {
          if (err) {
            reject(err);
          } else {
            resolve(columns.filter(c => c.name === 'geom'));
          }
        }
      );
    });
  }
}

// Test cases
tap.test('create & drop', async (t) => {
  let db = new sqlite3.Database(':memory:');
  let introspect = new SqliteIntrospect(db);

  // create table
  let table = new TableGeometry();
  table.create(db);

  // create column
  let column = new GeoColumnGeom();
  column.create(db);

  // create index
  let index = new GeoIndexGeom();
  index.create(db);

  // column exists
  let columnsBeforeDrop = await introspect.geometryColumns('geometry');
  t.equal(columnsBeforeDrop.length, 1, 'create');

  // drop index
  index.drop(db);

  // index should not exist
  let columnsAfterDrop = await introspect.geometryColumns('geometry');
  t.equal(columnsAfterDrop.length, 0, 'drop');

  t.end();
});
