const express = require('express');
const dataGatherMiddleware = require('./dataGatherMiddleware').default;

const app = express();
app.use(dataGatherMiddleware.gatherData);

app.post('/upload', (req, res) => {
    // Access the gathered data
    const requestData = req.fetch();
    res.json(requestData);
});

app.listen(3000, () => console.log('Server running on port 3000'));
```

The `req.fetch` function should return an object containing the gathered data. If the JWT is not present in the request, the `jwt` property should be `null`.

