function updateWorkflowRunCounts() {
    var workflowRun = __.response.getBody(); // Get the updated WorkflowRun document

    if (workflowRun.type !== "WorkflowRun") {
        throw new Error("Document is not a WorkflowRun type");
    }

    var workflowId = workflowRun.workflow_id;
    var recordType = "Workflow";
    var filterQuery = `SELECT * FROM r WHERE r.workflow_id = "${workflowId}" AND r.type = "${recordType}"`;

    var accept = __.queryDocuments(__.getSelfLink(), filterQuery, function(err, documents, responseOptions) {
        if (err) throw new Error("Error querying Workflow document: " + err.message);
        if (documents.length < 1) throw new Error('Unable to find Workflow document');
        if (documents.length > 1) throw new Error('Found more than one Workflow document');

        var workflow = documents[0];
        var statusHistory = workflowRun.status_history;
        var currentStatus = statusHistory[statusHistory.length - 1].status;
        var previousStatus = statusHistory.length > 1 ? statusHistory[statusHistory.length - 2].status : null;

        // Initialize the workflow_run_counts object if it doesn't exist
        workflow.workflow_run_counts = workflow.workflow_run_counts || {};

        // Decrement the count for the previous status, if applicable
        if (previousStatus && workflow.workflow_run_counts[previousStatus]) {
            workflow.workflow_run_counts[previousStatus] -= 1;
        }

        // Increment the count for the current status
        workflow.workflow_run_counts[currentStatus] = (workflow.workflow_run_counts[currentStatus] || 0) + 1;

        var acceptReplace = __.replaceDocument(workflow._self, workflow, function(err, docReplaced) {
            if (err) throw new Error("Unable to update Workflow document: " + err.message);
        });

        if (!acceptReplace) throw new Error("Unable to update Workflow document, abort");
    });

    if (!accept) throw new Error("Unable to query Workflow document, abort");
}

