/**
 * LinkPreviewGenerator class generates a preview for a hyperlink element.
 * It fetches the page title, description, and thumbnail image if available,
 * and displays them in a specified container.
 */
class LinkPreviewGenerator {
    constructor() {
        // Constructor does not need any parameters for this task.
    }

    /**
     * Generates a preview for the given hyperlink element.
     * @param {HTMLAnchorElement} linkElement - The hyperlink element to attach the preview to.
     * @param {HTMLElement} previewContainer - The container where the preview should be displayed.
     * @param {Function} fetchPageData - A function that fetches page data as a Promise.
     */
    generatePreview(linkElement, previewContainer, fetchPageData) {
        fetchPageData(linkElement.href)
            .then(data => {
                // Create the preview elements
                const preview = document.createElement('div');
                preview.className = 'link-preview';

                if (data.title) {
                    const titleElement = document.createElement('h1');
                    titleElement.appendChild(document.createTextNode(data.title));
                    preview.appendChild(titleElement);
                }

                if (data.description) {
                    const descriptionElement = document.createElement('p');
                    descriptionElement.appendChild(document.createTextNode(data.description));
                    preview.appendChild(descriptionElement);
                }

                if (data.thumbnail) {
                    const imageElement = document.createElement('img');
                    imageElement.src = data.thumbnail;
                    imageElement.className = 'link-preview-thumbnail';
                    preview.appendChild(imageElement);
                }

                // Clear the preview container and append the new preview
                previewContainer.innerHTML = '';
                previewContainer.appendChild(preview);
            })
            .catch(error => {
                console.error('Error fetching page data:', error);
            });
    }
}

// Example usage:
const linkPreviewGenerator = new LinkPreviewGenerator();
const linkElement = document.querySelector('a');
