const assert = require("chai").assert;

/**
 * Takes elements from the beginning of an array until the callback function returns true.
 * @param {Array} array - The array to process.
 * @param {Function} callback - The function to execute on each element.
 * @returns {Array} A slice of the original array.
 */
const takeUntil = (array, callback) => {
  const result = [];
  for (const item of array) {
    if (callback(item)) {
      break;
    }
    result.push(item);
  }
  return result;
};

// Test cases
describe(`#takeUntil`, () => {
  it(`returns [1, 2, 5, 7, 2] for [1, 2, 5, 7, 2, -1, 2, 4, 5] with x < 0 condition`, () => {
    const data1 = [1, 2, 5, 7, 2, -1, 2, 4, 5];
    const results1 = takeUntil(data1, (x) => x < 0);
    assert.deepEqual(results1, [1, 2, 5, 7, 2]);
  });
  it(`returns ['I've', 'been', 'to', 'Hollywood'] for ['I've', 'been', 'to', 'Hollywood', ',', 'I've', 'been', 'to', 'Redwood'] with x === "," condition`, () => {
