const cheerio = require('cheerio');
const got = require('got');
const formatPubDate = require('./utils/date.js'); // Assuming this is a custom date formatting utility

// Simple in-memory cache
const cache = {
  get: async (key) => cache[key],
  set: async (key, value) => { cache[key] = value; }
};

const scrapeWebsite = async () => {
  const url = `https://www.gtn9.com/index.aspx`;

  const res = await got.get(url);
  const $ = cheerio.load(res.body);
  const list = $('.recommend .content_list_box').get();

  const proList = [];
  const indexList = [];
  const out = await Promise.all(
    list.map(async (item, i) => {
      const $item = cheerio.load(item);
      const times = $item('.zan_box_right').text().trim();
      const timess = times.replace('内', '前');
      const timesss = timess.replace('天', '天 00:00');
      const pubDate = formatPubDate(timesss);

      const title = $item('.title_big').text();
      const imageUrl1 = `<img src="${$item('.effect-ming img').attr('src')}"/>`;
      const imageUrl = imageUrl1.replace('?imageView2/1/w/280/h/200/q/100', '');
      const category = $item('.title_small').text();
      const author = $item('.zan_box_foot span a').text();
      const itemUrl = 'https://www.gtn9.com/' + $item('.grid a').attr('href');
      const cacheContent = await cache.get(itemUrl);
      if (cacheContent) {
        return JSON.parse(cacheContent);
      }
      const single = {
        title,
        category,
        author,
        imageUrl,
        pubDate,
        link: itemUrl,
        guid: itemUrl,
      };
      proList.push(got.get(itemUrl));
      indexList.push(i);
      return single;
    })
  );

  const responses = await Promise.all(proList);
  responses.forEach((res, i) => {
    const $content = cheerio.load(res.body);
    const content = $content('.imgBox-content').html();
    out[indexList[i]].description = out[indexList[i]].imageUrl + content;
    cache.set(out[indexList[i]].link, JSON.stringify(out[indexList[i]]));
  });

  return {
    title: `古田路9号 品牌创意设计社区`,
    link: `https://www.gtn9.com/index.aspx`,
    item: out,
  };
};

// Example usage:
scrapeWebsite().then(data => {
  console.log(JSON.stringify(data, null, 2));
}).catch(error => {
  console.error('Error scraping website:', error);
});
