  console.log('connected to MongoDB');
}).catch(err => {
  console.log('error connecting to MongoDB: ' + err.message);
});

// Define the Note schema
const noteSchema = new mongoose.Schema({
  title: String,
  author: String,
  description: String,
  important: Boolean
});

// Transform the returned JSON object
noteSchema.set('toJSON', {
  transform: (document, returnedObject) => {
    returnedObject.id = returnedObject._id.toString();
    delete returnedObject._id;
    delete returnedObject.__v;
  }
});

// Create the Note model
const Note = mongoose.model('Note', noteSchema);

// Initialize Express app
const app = express();
app.use(express.json());

// POST /notes - Create a new note
app.post('/notes', (req, res) => {
  const note = new Note({
    title: req.body.title,
    author: req.body.author,
    description: req.body.description,
    important: req.body.important || false
  });

  note.save().then(savedNote => {
    res.json(savedNote.toJSON());
  }).catch(error => res.status(400).json({ error: error.message }));
});

// GET /notes - Retrieve all notes
app.get('/notes', (req, res) => {
  Note.find({}).then(notes => {
    res.json(notes.map(note => note.toJSON()));
  });
});

// GET /notes/:id - Retrieve a single note by its ID
app.get('/notes/:id', (req, res) => {
  Note.findById(req.params.id).then(note => {
    if (note) {
      res.json(note.toJSON());
    } else {
      res.status(404).end();
    }
  }).catch(error => res.status(400).json({ error: error.message }));
});

// PUT /notes/:id - Update the details of an existing note by its ID
app.put('/notes/:id', (req, res) => {
  const { title, author, description, important } = req.body;

  Note.findByIdAndUpdate(req.params.id, { title, author, description, important }, { new: true })
    .then(updatedNote => {
      res.json(updatedNote.toJSON());
    })
    .catch(error => res.status(400).json({ error: error.message }));
});

// DELETE /notes/:id - Delete a note by its ID
app.delete('/notes/:id', (req, res) => {
  Note.findByIdAndRemove(req.params.id)
    .then(() => {
      res.status(204).end();
    })
    .catch(error => res.status(400).json({ error: error.message }));
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server running on port ${PORT}`);
});

module.exports = app; // for testing purposes
