/**
 * Initializes a number of agents that will wait asynchronously on a shared BigInt64Array.
 * @param {number} numAgents - The number of agents to start.
 * @param {number} waitIndex - The index in the BigInt64Array where agents will wait.
 * @param {bigint} waitValue - The value that agents will wait for before proceeding.
 * @param {number} notifyCount - The number of agents to be notified.
 * @returns {Promise<Array<string>>} A promise that resolves with an array of reports from the agents.
 */
function setupWaitAsyncAgents(numAgents, waitIndex, waitValue, notifyCount) {
  const RUNNING = 1;
  const sharedBuffer = new SharedArrayBuffer(BigInt64Array.BYTES_PER_ELEMENT * 4);
  const i64a = new BigInt64Array(sharedBuffer);

  // Start agents and have them wait asynchronously
  for (let id = 0; id < numAgents; id++) {
    agent.start(async () => {
      Atomics.add(i64a, RUNNING, 1n);
      try {
        await Atomics.waitAsync(i64a, waitIndex, waitValue).value;
        agent.report(`Agent ${id} ok`);
      } catch (e) {
        agent.report(`Agent ${id} not-ok`);
      }
      agent.leaving();
    });
  }

  // Notify the agents after they are all waiting
  setTimeout(() => {
    Atomics.notify(i64a, waitIndex, notifyCount);
  }, 1000); // Delay to ensure all agents are waiting

  // Collect reports from agents
  const reports = [];
  for (let id = 0; id < numAgents; id++) {
    reports.push(agent.getReportAsync());
  }

  return Promise.all(reports);
}

