/**
 * Calculates the total cost of a recipe based on ingredients, prices, and labor.
 * 
 * @param {Array} ingredients - Array of tuples [ingredientName, quantity, unit]
 * @param {Array} prices - Array of tuples [ingredientName, quantity, unit, price]
 * @param {Array} timeSalary - Array of a single tuple [timeSpentHours, hourlyWage]
 * @returns {Number} - The total cost of the recipe
 */
function calculateTotalCost(ingredients, prices, timeSalary) {
    let custoTotal = 0;

    function reduceQuantityToUnit(quantity, unit) {
        // Assuming the unit is either 'g' for grams or 'kg' for kilograms
        // and we want to convert everything to kilograms.
        if (unit === 'g') {
            return quantity / 1000; // Convert grams to kilograms
        }
        return quantity; // If already in kilograms, return as is
    }

    for (let i = 0; i < ingredients.length; i++) {
        for (let j = 0; j < prices.length; j++) {
            if (ingredients[i][0] === prices[j][0]) {
                let quantidadeMinimaIngrediente = reduceQuantityToUnit(ingredients[i][1], ingredients[i][2]);
                let quantidadeMinimaPreco = reduceQuantityToUnit(precos[j][1], precos[j][2]);

                let precoMinimoIngrediente = prices[j][3] / quantidadeMinimaPreco;
                let custoIngrediente = precoMinimoIngrediente * quantidadeMinimaIngrediente;
                custoTotal += custoIngrediente;
            }
        }
    }

    // Calculate labor cost
    let laborCost = timeSalary[0][0] * timeSalary[0][1];
    custoTotal += laborCost;

    return custoTotal;
}

