// LocalStorageManager.js
/**
 * A simple local storage manager for web applications.
 * It provides methods to store, retrieve, and clear key-value pairs in local storage.
 * The values are stored in JSON format.
 */

// Importing necessary packages
// (No packages are necessary for this solution, as localStorage is a built-in Web API)

/**
 * Retrieves the value associated with the given key from the local storage.
 * If the key does not exist, it returns an empty object.
 * @param {string} key - The key to retrieve the value for.
 * @returns {Object} The value associated with the key, parsed from JSON.
 */
export const getStorage = key => {
  const val = localStorage.getItem(key) || '{}';
  return JSON.parse(val);
};

/**
 * Stores the value under the given key in the local storage.
 * The value is serialized to a JSON string before being stored.
 * @param {string} key - The key to store the value under.
 * @param {Object} val - The value to store, which will be serialized to JSON.
 * @returns {void}
 */
export const setStorage = (key, val) => {
  localStorage.setItem(key, JSON.stringify(val));
};

/**
 * Clears all key-value pairs from the local storage.
 * @returns {void}
 */
export const clearStorage = () => {
  localStorage.clear();
};

// Default export containing the local storage manager methods
export default {
  get: getStorage,
  set: setStorage,
  clear: clearStorage,
};

// Test cases to verify the solution correctness
// Assuming the local storage is empty before running these tests

