/**
 * Creates a new object that inherits from the given base object and adds a new property.
 * @param {Object|null} baseObject - The object to inherit from, or null for no inheritance.
 * @param {string} propertyName - The name of the new property to add.
 * @param {*} propertyValue - The value of the new property.
 * @returns {Object} The new object with the added property.
 * @throws {TypeError} If baseObject is not an object or null, or if propertyName is not a string.
 */
function createObject(baseObject, propertyName, propertyValue) {
  if (typeof baseObject !== 'object' && baseObject !== null) {
    throw new TypeError('Invalid base object');
  }
  if (typeof propertyName !== 'string') {
    throw new TypeError('Property name must be a string');
  }

  const newObject = Object.create(baseObject);
  newObject[propertyName] = propertyValue;
  return newObject;
}

// Test cases
