  const newObj = createObject(base, 'c', 3);
  console.log(newObj); // Should output: { c: 3 }
  console.log(newObj.a); // Should output: 1 (inherited)
  console.log(newObj.__proto__ === base); // Should output: true

  const noInheritObj = createObject(null, 'd', 4);
  console.log(noInheritObj); // Should output: { d: 4 }
  console.log(noInheritObj.__proto__ === Object.prototype); // Should output: false

  createObject({}, 123, 'invalid'); // Should throw TypeError: Property name must be a string
} catch (e) {
