// Importing necessary packages
// Note: This code snippet is meant to be run in a browser environment where the DOM is available.

/**
 * Signature Pad Application
 * 
 * This application allows users to draw their signature on a canvas element using mouse or touch input.
 * It provides functionality to clear the signature pad, save the signature as a PNG image, and open a
 * predefined contract page in a new window.
 */

// Selecting DOM elements
const canvas = document.querySelector('canvas');
const form = document.querySelector('.firma-pad-form');
const botonLimpiar = document.querySelector('.boton-limpiar');
const botonImagen = document.querySelector('.boton-imagen');
const botonContrato = document.querySelector('.boton-contrato');

// Canvas context for drawing
const ctx = canvas.getContext('2d');
let modoEscritura = false;
let xAnterior = 0, yAnterior = 0, xActual = 0, yActual = 0;
const COLOR = "blue";
const GROSOR = 2;

// Event listener for form submission
form.addEventListener('submit', (e) => {
    e.preventDefault();

    const resultadoContenedor = document.querySelector(".firma-resultado-contenedor");
    const imagenAnterior = document.querySelector(".firma-imagen");
    if(imagenAnterior){
        imagenAnterior.remove();
    }

    const imagenURL = canvas.toDataURL();
    const imagen = document.createElement("img");
    imagen.src = imagenURL;
    imagen.height = canvas.height;
    imagen.width = canvas.width;
    imagen.classList.add("firma-imagen");

    resultadoContenedor.appendChild(imagen);

    limpiarPad();
});

// Function to clear the signature pad
const limpiarPad = () => {
    ctx.fillStyle = "white";
    ctx.fillRect(0, 0, canvas.width, canvas.height);
}

// Event listener for the "Clear" button
botonLimpiar.addEventListener("click", (e) => {
    e.preventDefault();
    limpiarPad();
});

// Event listener for the "Save as Image" button
botonImagen.addEventListener("click", (e) => {
    e.preventDefault();
    const enlace = document.createElement("a");
    enlace.download = "Firma.png";
    enlace.href = canvas.toDataURL();
    enlace.click();
});

// Event listener for the "View Contract" button
botonContrato.addEventListener("click", (e) =>{
    e.preventDefault();
    const ventana = window.open("contrato.html");
});

// Function to get the cursor position relative to the canvas
const obtenerPosicionCursor = (e) =>{
    const positionX = e.clientX - e.target.getBoundingClientRect().left;
    const positionY = e.clientY - e.target.getBoundingClientRect().top;
    return [positionX, positionY];
};

// Event handlers for drawing on the canvas
const OnClicOToqueIniciado = (e) =>{
    modoEscritura = true;
    [xActual, yActual] = obtenerPosicionCursor(e);
    ctx.beginPath();
    ctx.fillStyle = COLOR;
    ctx.fillRect(xActual, yActual, GROSOR, GROSOR);
    ctx.closePath();
};

const OnMouseODedoMovido = (e) => {
    if (!modoEscritura){
        return;
    }
    let target = e;
    if(e.type.includes("touch")){
        target = e.touches[0];
    }
    xAnterior = xActual;
    yAnterior = yActual;
    [xActual, yActual] = obtenerPosicionCursor(target);
    ctx.beginPath();
    ctx.lineWidth = GROSOR;
    ctx.strokeStyle = COLOR;
    ctx.moveTo(xAnterior, yAnterior);
    ctx.lineTo(xActual, yActual);
    ctx.stroke();
    ctx.closePath();
};

