import axios from 'axios';
import jwtDecode from 'jwt-decode';
import EventEmitter from 'events';
import qs from 'qs';
import aes256 from 'aes256';

class AuthenticationService extends EventEmitter {
    constructor() {
        super();
        this.init();
    }

    init() {
        this.setInterceptors();
        this.handleAuthentication();
    }

    setInterceptors() {
        axios.interceptors.response.use(response => {
            return response;
        }, err => {
            if (err.response && err.response.status === 401 && !err.config.__isRetryRequest) {
                this.emit('onAutoLogout', 'Invalid access_token');
                this.setSession(null);
            }
            return Promise.reject(err);
        });
    }

    handleAuthentication() {
        const access_token = this.getAccessToken();
        if (!access_token) {
            return;
        }
        if (this.isAuthTokenValid(access_token)) {
            this.setSession(access_token);
            this.emit('onAutoLogin', true);
        } else {
            this.setSession(null);
            this.emit('onAutoLogout', 'Access token has expired.');
        }
    }

    signInWithEmailAndPassword(email, password) {
        const key = process.env.REACT_APP_KEY_PASS;
        const encryptedEmail = aes256.encrypt(key, email.toLowerCase().trim());
        const encryptedPassword = aes256.encrypt(key, password.trim());
        const data = { email: encryptedEmail, password: encryptedPassword };
        const options = {
            method: 'POST',
            url: `${process.env.REACT_APP_API_HOST}/users/login`,
            headers: { 'content-type': 'application/x-www-form-urlencoded' },
            data: qs.stringify(data)
        };
        return axios(options).then(response => {
            if (response.data.auth) {
                this.setSession(response.data.token);
                return response.data.user;
            } else {
                throw new Error(response.data.error);
            }
        });
    }

    signInWithToken() {
        const options = {
            method: 'GET',
            url: `${process.env.REACT_APP_API_HOST}/users/access-token`,
            headers: {
                'content-type': 'application/x-access-token',
                "Authorization": `Bearer ${this.getAccessToken()}`
            }
        };
        return axios(options).then(response => {
            if (response.data.user) {
                this.setSession(response.data.token);
                return response.data.user;
            } else {
                throw new Error(response.data.error);
            }
        });
    }

    updateUserData(user) {
        return axios.post(`${process.env.REACT_APP_API_HOST}/users/update`, { user });
    }

    setSession(access_token) {
        if (access_token) {
            localStorage.setItem('jwt_access_token', access_token);
            axios.defaults.headers.common['Authorization'] = `Bearer ${access_token}`;
        } else {
            localStorage.removeItem('jwt_access_token');
            delete axios.defaults.headers.common['Authorization'];
        }
    }

    logout() {
        this.setSession(null);
        const logoutUrl = `${process.env.REACT_APP_AUTHORITY}${process.env.REACT_APP_TENANT_ID}/oauth2/v2.0/logout?post_logout_redirect_uri=${process.env.REACT_APP_REDIRECT_URI}`;
        window.open(logoutUrl, '_self');
    }

    isAuthTokenValid(access_token) {
        if (!access_token) {
            return false;
        }
        const decoded = jwtDecode(access_token);
        const currentTime = Date.now() / 1000;
        return decoded.exp > currentTime;
    }

    getAccessToken() {
        return localStorage.getItem('jwt_access_token');
    }
}

// Usage example (assuming environment variables are set):
const authService = new AuthenticationService();

// Test cases to verify solution correctness:
// Note: These test cases would normally be run in an environment where the API_HOST and other environment variables are set.
// Since we cannot actually call the API or set environment variables here, these are just examples of how you might test the class.

// Test signInWithEmailAndPassword
authService.signInWithEmailAndPassword('user@example.com', 'password123')
    .then(user => console.log('Signed in user:', user))
    .catch(error => console.error('SignIn failed:', error));

// Test signInWithToken
authService.signInWithToken()
    .then(user => console.log('Signed in with token:', user))
    .catch(error => console.error('SignIn with token failed:', error));

// Test logout
authService.logout();
console.log('User logged out.');

// Test isAuthTokenValid
const isValid = authService.isAuthTokenValid(authService.getAccessToken());
console.log('Is auth token valid:', isValid);

// Test updateUserData
