const express = require('express');
const bodyParser = require('body-parser');
const mongoose = require('mongoose');
const bcrypt = require('bcryptjs');

// Connect to MongoDB
mongoose.connect('mongodb://localhost:27017/authSystem', { useNewUrlParser: true, useUnifiedTopology: true });

// User Schema
const UserSchema = new mongoose.Schema({
  email: { type: String, default: '' },
  password: { type: String, default: '' },
  firstName: { type: String, default: '' },
  lastName: { type: String, default: '' }
});

UserSchema.methods.generateHash = function(password) {
  return bcrypt.hashSync(password, bcrypt.genSaltSync(8), null);
};

UserSchema.methods.validPassword = function(password) {
  return bcrypt.compareSync(password, this.password);
};

const User = mongoose.model('User', UserSchema);

// User Session Schema
const UserSessionSchema = new mongoose.Schema({
  userId: { type: mongoose.Schema.Types.ObjectId, default: '' },
  isDeleted: { type: Boolean, default: false }
});

const UserSession = mongoose.model('UserSession', UserSessionSchema);

// Initialize Express App
const app = express();
app.use(bodyParser.json());

// Sign Up Endpoint
app.post('/api/account/signup', (req, res) => {
  const { email, firstName, lastName, password } = req.body;

  if (!firstName || !lastName || !email || !password) {
    return res.status(400).send({
      success: false,
      message: 'All fields must be filled!'
    });
  }

  const newUser = new User({
    email: email.toLowerCase(),
    firstName,
    lastName,
    password: new User().generateHash(password)
  });

  User.findOne({ email: newUser.email }, (err, existingUser) => {
    if (err) return res.status(500).send({ success: false, message: 'Server error' });
    if (existingUser) return res.status(400).send({ success: false, message: 'Account already exists!' });

    newUser.save((err, user) => {
      if (err) return res.status(500).send({ success: false, message: 'Server error' });
      return res.status(200).send({ success: true, message: 'Sign up successful.' });
    });
  });
});

// Sign In Endpoint
app.post('/api/account/signin', (req, res) => {
  const { email, password } = req.body;

  if (!email || !password) {
    return res.status(400).send({
      success: false,
      message: 'Email and password fields cannot be empty!'
    });
  }

  User.findOne({ email: email.toLowerCase() }, (err, user) => {
    if (err) return res.status(500).send({ success: false, message: 'Server error' });
    if (!user || !user.validPassword(password)) {
      return res.status(401).send({ success: false, message: 'Invalid login credentials!' });
    }

    const userSession = new UserSession({ userId: user._id });
    userSession.save((err, doc) => {
      if (err) return res.status(500).send({ success: false, message: 'Server error' });
      return res.status(200).send({ success: true, message: 'Sign in successful.', token: doc._id });
    });
  });
});

// Verify Session Endpoint
app.get('/api/account/verify', (req, res) => {
  const { token } = req.query;

  UserSession.findOne({ _id: token, isDeleted: false }, (err, session) => {
    if (err) return res.status(500).send({ success: false, message: 'Server error' });
    if (!session) return res.status(401).send({ success: false, message: 'Invalid token' });

    return res.status(200).send({ success: true, message: 'Session verified.' });
  });
});

// Sign Out Endpoint
app.get('/api/account/signout', (req, res) => {
  const { token } = req.query;

  UserSession.findOneAndUpdate({ _id: token, isDeleted: false }, { $set: { isDeleted: true } }, (err) => {
    if (err) return res.status(500).send({ success: false, message: 'Server error' });
    return res.status(200).send({ success: true, message: 'Sign out successful.' });
  });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

// Export the app for testing purposes
module.exports = app;
