import jwt from "jsonwebtoken";
const { sign, decode, verify } = jwt;

/**
 * Middleware function to validate and refresh JSON Web Tokens (JWT).
 * @param {Object} req - The HTTP request object.
 * @param {Object} res - The HTTP response object.
 * @param {Function} next - The next middleware function in the stack.
 */
export const jwtMiddleware = (req, res, next) => {
  const authorizationHeader =
    req.header("Authorization") || req.headers["refresh-token"];

  if (!authorizationHeader) {
    return res
      .status(401)
      .json({ message: "Access denied. No token provided." });
  }

  try {
    const token = authorizationHeader.replace("Bearer ", "");

    if (token) {
      verify(token, process.env.JWT_KEY, (error, decoded) => {
        if (error) {
          if (error.name === "TokenExpiredError") {
            const payload = decode(token);
            const refreshedToken = refreshToken(payload);
            if (refreshedToken) {
              res.setHeader("Authorization", `Bearer ${refreshedToken}`);
              req.userRole = payload.userRole;
              next();
            } else {
              res.status(401).send("Unauthorized");
            }
          } else if (error.message === "invalid token") {
            res.status(401).json({ message: "Access denied. Invalid token." });
          } else {
            res.status(401).json({ message: "Token verification error", error });
          }
        } else {
          req.userRole = decoded.userRole;
          next();
        }
      });
    }
  } catch (error) {
    console.error("Token verification error:", error);
    return res.status(401).json({ message: "Token verification error", error });
  }
};

/**
 * Refreshes an expired JWT token.
 * @param {Object} payload - The decoded JWT payload.
 * @returns {string} The refreshed JWT token.
 */
function refreshToken(payload) {
  const newExp = Math.floor(Date.now() / 1000) + 3600; // 1 hour
  payload.exp = newExp;
  const refreshedToken = sign(payload, process.env.REFRESH_TOKEN_PRIVATE_KEY);
  return refreshedToken;
}

// Example usage:
// Assuming express is used as the web framework
import express from 'express';
const app = express();

// Set up the middleware for all routes
app.use(jwtMiddleware);

// Define a protected route
app.get('/protected', (req, res) => {
  res.json({ message: 'You have accessed a protected route!', role: req.userRole });
});

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
