// Import the necessary package for creating a Next.js API route
import { NextApiRequest, NextApiResponse } from 'next';

/**
 * This is an API route handler for on-demand revalidation of the root page in a Next.js application.
 * It checks for a valid secret token and triggers revalidation if the token is correct.
 *
 * @param {NextApiRequest} req - The HTTP request object.
 * @param {NextApiResponse} res - The HTTP response object.
 */
export default async function handler(req, res) {
  // Check for the secret token in the query parameters
  if (req.query.secret !== "testtoken") {
    // Respond with a 401 Unauthorized status code if the token is invalid
    return res.status(401).json({ message: "Invalid token" });
  }

  try {
    // Attempt to revalidate the root page
    await res.revalidate("/");
    // Respond with a 200 OK status code and indicate successful revalidation
    return res.json({ revalidated: true });
  } catch (err) {
    // Respond with a 500 Internal Server Error status code if revalidation fails
    return res.status(500).send("Error revalidating");
  }
}

// Test cases to verify the solution correctness
// Note: These test cases are for illustrative purposes and would typically be run in a test environment.

// Mock the NextApiResponse object
const mockRes = {
  revalidate: jest.fn().mockResolvedValueOnce(true),
  status: jest.fn().mockReturnThis(),
  json: jest.fn().mockReturnThis(),
  send: jest.fn().mockReturnThis(),
};

// Test case 1: Valid token should trigger revalidation
handler({ query: { secret: "testtoken" } }, mockRes);
expect(mockRes.revalidate).toHaveBeenCalledWith("/");
expect(mockRes.status).toHaveBeenCalledWith(200);
expect(mockRes.json).toHaveBeenCalledWith({ revalidated: true });

// Test case 2: Invalid token should not trigger revalidation and return 401
handler({ query: { secret: "wrongtoken" } }, mockRes);
expect(mockRes.status).toHaveBeenCalledWith(401);
expect(mockRes.json).toHaveBeenCalledWith({ message: "Invalid token" });

// Test case 3: Revalidation error should return 500
// Simulate a revalidation error
mockRes.revalidate.mockRejectedValueOnce(new Error("Revalidation failed"));
handler({ query: { secret: "testtoken" } }, mockRes);
expect(mockRes.status).toHaveBeenCalledWith(500);
expect(mockRes.send).toHaveBeenCalledWith("Error revalidating");
