const jimp = require("jimp");
const express = require("express");
const multer = require("multer");
const { User } = require("./models/users"); // Assuming this is the correct path to the User model

const upload = multer({ dest: "uploads/" });
const app = express();
const avatarsDir = path.join(__dirname, "public", "avatars");

/**
 * Updates the user's avatar image.
 * 
 * @param {Object} req - The request object containing the user and file information.
 * @param {Object} res - The response object.
 * @returns {Promise<void>} - A promise that resolves when the avatar is updated.
 */
const updateAvatar = async (req, res) => {
  try {
    const { path: tempUpload, originalname } = req.file;
    const { _id } = req.user;
    const filename = `${_id}_${originalname}`;
    const resultUpload = path.join(avatarsDir, filename);
    const img = await jimp.read(tempUpload);
    await img
      .autocrop()
      .cover(250, 250, jimp.HORIZONTAL_ALIGN_CENTER || jimp.VERTICAL_ALIGN_MIDDLE)
      .writeAsync(tempUpload);
    await fs.rename(tempUpload, resultUpload);
    const avatarURL = path.join("avatars", filename);
    await User.findByIdAndUpdate(_id, { avatarURL });

    res.json({
      avatarURL,
    });
  } catch (error) {
    res.status(500).json({ message: "Failed to update avatar", error: error.message });
  }
};

// Endpoint to handle avatar updates
app.post("/users/avatar", upload.single('avatar'), updateAvatar);

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => {
  console.log(`Server is running on port ${PORT}`);
});

module.exports = updateAvatar;
