```javascript
// Importing necessary packages
// (No external packages are required for this solution)

// Event broker for handling attribute queries
class Event {
  constructor() {
    this.handlers = new Map();
    this.count = 0;
  }

  subscribe(handler) {
    this.handlers.set(++this.count, handler);
    return this.count;
  }

  unsubscribe(idx) {
    this.handlers.delete(idx);
  }

  fire(sender, args) {
    this.handlers.forEach((handler) => {
      handler(sender, args);
    });
  }
}

// Enumeration for query types
const WhatToQuery = Object.freeze({
  attack: 1,
  defense: 2,
});

// Query class for creature attribute requests
class Query {
  constructor(creatureName, whatToQuery, value) {
    this.creatureName = creatureName;
    this.whatToQuery = whatToQuery;
    this.value = value;
  }
}

// Centralized game class
class Game {
  constructor() {
    this.queries = new Event();
  }

  performQuery(sender, query) {
    this.queries.fire(sender, query);
  }
}

// Creature class with dynamic attribute calculation
class Creature {
  constructor(game, name, attack, defense) {
    this.game = game;
    this.name = name;
    this.initialAttack = attack;
    this.initialDefense = defense;
  }

  get attack() {
    const q = new Query(this.name, WhatToQuery.attack, this.initialAttack);
    this.game.performQuery(this, q);
    return q.value;
  }

  get defense() {
    const q = new Query(this.name, WhatToQuery.defense, this.initialDefense);
    this.game.performQuery(this, q);
    return q.value;
  }

  toString() {
    return `${this.name}(${this.attack}/${this.defense})`;
  }
}

// Base class for creature modifiers
class CreatureModifier {
  constructor(game, creature) {
    this.game = game;
    this.creature = creature;
    this.token = game.queries.subscribe(this.handle.bind(this));
  }

  handle(sender, query) {
    // To be overridden by subclasses
  }

  dispose() {
    this.game.queries.unsubscribe(this.token);
  }
}

// Modifier that doubles the creature's attack
class DoubleAttackModifier extends CreatureModifier {
  handle(sender, query) {
    if (
      query.creatureName === this.creature.name &&
      query.whatToQuery === WhatToQuery.attack
    ) {
      query.value *= 2;
    }
  }
}

// Modifier that increases the creature's defense
class IncreaseDefenseModifier extends CreatureModifier {
  handle(sender, query) {
    if (
      query.creatureName === this.creature.name &&
      query.whatToQuery === WhatToQuery.defense
    ) {
      query.value += 3;
    }
  }
}

// Test cases
const game = new Game();
const goblin = new Creature(game, 'Goblin', 2, 2);
console.log(goblin.toString()); // Expected: Goblin(2/2)

const dam = new DoubleAttackModifier(game, goblin);
console.log(goblin.toString()); // Expected: Goblin(4/2)

const idm = new IncreaseDefenseModifier(game, goblin);
console.log(goblin.toString()); // Expected: Goblin(4/5)

dam.dispose();
console.log(goblin.toString()); // Expected: Goblin(2/5)

idm.dispose();
console.log(goblin.toString()); // Expected: Goblin(2/2)
