function activateTab(event) {
    // Prevent the default action of the event
    event.preventDefault();

    // Get all tabs and content panels
    const tabs = document.querySelectorAll('.tabs li');
    const contentPanels = document.querySelectorAll('.tabs-panel');

    // Deactivate all tabs and content panels
    tabs.forEach(tab => tab.classList.remove('active'));
    contentPanels.forEach(panel => panel.classList.remove('active'));

    // Activate the clicked tab
    const clickedTab = event.target.closest('li');
    clickedTab.classList.add('active');

    // Activate the corresponding content panel
    const panelId = `#tab-content-${clickedTab.id.split('-').pop()}`;
    const activePanel = document.querySelector(panelId);
    activePanel.classList.add('active');
}

// Adding event listeners to all tabs
