function findKeywordInObject(obj, keyword) {
  const lowerCaseKeyword = keyword.toLowerCase();
  const values = Object.values(obj);

  for (let i = 0; i < values.length; i++) {
    // Convert the current value to string and make it lower case for case-insensitive comparison
    if (String(values[i]).toLowerCase().includes(lowerCaseKeyword)) {
      return "Keyword found!";
    }
  }
  return "Keyword not found.";
}

