/**
 * Constructs a new LRU cache with a given capacity.
 * @param {number} capacity - The maximum number of items the cache can hold.
 */
var LRUCache = function (capacity) {
  this.max = capacity;
  this.cache = new Map();
};

/**
 * Retrieves the value associated with the given key from the cache.
 * @param {number} key - The key of the item to retrieve.
 * @return {number} - The value associated with the key if it exists, otherwise -1.
 */
LRUCache.prototype.get = function (key) {
  if (!this.cache.has(key)) {
    return -1;
  }
  // Move the accessed item to the end to signify recent use
  const value = this.cache.get(key);
  this.cache.delete(key);
  this.cache.set(key, value);
  return value;
};

/**
 * Inserts a new key-value pair or updates an existing key-value pair in the cache.
 * If the cache is at capacity, the least recently used item is removed.
 * @param {number} key - The key of the item to insert or update.
 * @param {number} value - The value to associate with the key.
 */
LRUCache.prototype.put = function (key, value) {
  // If the key exists, delete it first to update its position
  if (this.cache.has(key)) {
    this.cache.delete(key);
  } else if (this.cache.size >= this.max) {
    // If at capacity, remove the least recently used item
    const firstKey = this.cache.keys().next().value;
    this.cache.delete(firstKey);
  }
  // Insert the item at the end to signify recent use
  this.cache.set(key, value);
};

// Example usage:
const cache = new LRUCache(2);

cache.put(1, 1);
cache.put(2, 2);
console.log(cache.get(1)); // returns 1

cache.put(3, 3); // evicts key 2
console.log(cache.get(2)); // returns -1 (not found)

cache.put(4, 4); // evicts key 1
console.log(cache.get(1)); // returns -1 (not found)
console.log(cache.get(3)); // returns 3
console.log(cache.get(4)); // returns 4
