import { combineReducers } from 'redux';

// Action types
const ADD_ITEM = 'ADD_ITEM';
const REMOVE_ITEM = 'REMOVE_ITEM';
const COOK_ITEM = 'COOK_ITEM';

// Helper function to create list reducers
function createList(listType) {
  return function(state = [], action) {
    switch (action.type) {
      case ADD_ITEM:
        if (action.listType === listType) {
          return [...state, { name: action.name, quantity: action.quantity }];
        }
        return state;
      case REMOVE_ITEM:
        if (action.listType === listType) {
          return state.filter(item => item.name !== action.name);
        }
        return state;
      default:
        return state;
    }
  };
}

// Reducer for cooked items
function cookedReducer(state = [], action) {
  switch (action.type) {
    case COOK_ITEM:
      return [...state, { name: action.name, quantity: action.quantity }];
    default:
      return state;
  }
}

// Combine reducers to create the root reducer
const rootReducer = combineReducers({
  inventory: createList('inventory'),
  shoppingList: createList('shoppingList'),
  cooked: cookedReducer,
});

export default rootReducer;

// Test cases
