import mitt from 'mitt';

/**
 * Creates a new event bus instance.
 * @returns {mitt.Emitter} The event bus instance.
 */
export function createEventBus() {
    return mitt();
}

/**
 * Registers a handler for a specific event on the event bus.
 * @param {mitt.Emitter} eventBus - The event bus instance.
 * @param {string} eventName - The name of the event.
 * @param {Function} handler - The handler function to register.
 */
export function registerHandler(eventBus, eventName, handler) {
    eventBus.on(eventName, handler);
}

/**
 * Emits an event with an optional payload to all registered handlers.
 * @param {mitt.Emitter} eventBus - The event bus instance.
 * @param {string} eventName - The name of the event.
 * @param {any} [payload] - The optional payload to pass to the handlers.
 */
export function emitEvent(eventBus, eventName, payload) {
    eventBus.emit(eventName, payload);
}

/**
 * Removes a handler for a specific event on the event bus.
 * @param {mitt.Emitter} eventBus - The event bus instance.
 * @param {string} eventName - The name of the event.
 * @param {Function} handler - The handler function to remove.
 */
export function removeHandler(eventBus, eventName, handler) {
    eventBus.off(eventName, handler);
}

// Test cases
const bus = createEventBus();

// Handler functions
const handler1 = (payload) => console.log(`Handler 1 received: ${payload}`);
const handler2 = (payload) => console.log(`Handler 2 received: ${payload}`);

// Register handlers
registerHandler(bus, 'test-event', handler1);
registerHandler(bus, 'test-event', handler2);

// Emit event
emitEvent(bus, 'test-event', 'Hello, World!');

// Remove a handler
removeHandler(bus, 'test-event', handler1);

// Emit event again to see if handler1 has been removed
emitEvent(bus, 'test-event', 'Hello again!');
