const Spinner = require('cli-spinner').Spinner;
const colors = require('colors');

class Output {
  constructor() {
    Spinner.setDefaultSpinnerString(Spinner.spinners[9]);
    this.currentSpinnerStop = null;
  }

  spinner(message = '%s', finalMessage, clearOnStop = false) {
    const spinner = new Spinner(message);
    spinner.start();

    let stopped = false;
    this.currentSpinnerStop = () => {
      if (!stopped) {
        spinner.stop(clearOnStop);
        if (finalMessage) {
          console.log(this.colorize(finalMessage, 'green'));
        }
        stopped = true;
      }
      return arguments[0]; // Return the first argument passed to the function
    };

    return this.currentSpinnerStop;
  }

  toStdOut(message, color) {
    if (this.currentSpinnerStop) {
      this.currentSpinnerStop();
    }
    console.log(this.colorize(message, color));
  }

  colorize(message, color) {
    if (color && colors[color]) {
      return colors[color](message);
    }
    return message;
  }
}

module.exports = Output;
