const { parser } = require('@vuese/parser');
const { Render } = require('@vuese/markdown-render');
const path = require('path');
const fs = require('fs');

/**
 * This function appends API documentation to a markdown file if a specific pattern is detected.
 * It parses a Vue.js single-file component to extract API information and renders it as markdown.
 * 
 * @param {string} source - The original markdown content.
 * @returns {string} - The markdown content with appended API documentation if applicable.
 */
module.exports = function appendAPIDocumentation(source) {
  // Check for the pattern indicating API documentation should be appended
  if (/\r\n## API/.test(source)) {
    // Extract the component name from the markdown heading
    let name = source.match(/# (?<name>\w+)\r\n/).groups.name;
    // Construct the file path to the Vue.js SFC
    let filePath = path.resolve(__dirname, `../../../src/components/${name}/${name}.vue`);

    // Check if the SFC file exists
    if (fs.existsSync(filePath)) {
      // Read the SFC file content
      let vueString = fs.readFileSync(filePath, 'utf-8');
      // Parse the SFC to extract API information
      let parserResult = parser(vueString);
      // Render the API information as markdown
      let mdResult = new Render(parserResult).renderMarkdown();
      let content = mdResult.content;
      // Modify the rendered markdown content
      content = content.replace(/(# \w+)\r?\n+/, '');
      content = content.replace(/##/g, '###');
      // Append the modified API documentation to the original source
      return source + '\r\n' + content;
    } else {
      // Return the original source if the SFC file does not exist
      return source;
    }
  } else {
    // Return the original source if the pattern is not found
    return source;
  }
};

// Test cases
const originalMarkdown = `# Button\r\n\r\nA simple button component.\r\n\r\n## API`;
const updatedMarkdown = appendAPIDocumentation(originalMarkdown);
console.log(updatedMarkdown); // Should print the original markdown content with appended API documentation

const markdownWithoutPattern = `# Button\r\n\r\nA simple button component.`;
const unchangedMarkdown = appendAPIDocumentation(markdownWithoutPattern);
console.log(unchangedMarkdown); // Should print the original markdown content without changes
