import { Redirect } from "react-router";

/**
 * Stores the user and token in local storage to simulate authentication.
 * @param {Object} user - The user object to store.
 * @param {string} token - The authentication token to store.
 */
export const authenticate = (user, token) => {
    if (typeof window !== "undefined") {
        localStorage.setItem("user", JSON.stringify(user));
        localStorage.setItem("token", JSON.stringify(token));
    }
};

/**
 * Checks if the user is authenticated by looking for a token in local storage.
 * @returns {boolean|Object} - The parsed token if authenticated, otherwise false.
 */
export const isAuthenticated = () => {
    if (typeof window === "undefined") {
        return false;
    }

    if (localStorage.getItem("token")) {
        return JSON.parse(localStorage.getItem("token"));
    } else {
        return false;
    }
};

/**
 * Retrieves the stored user from local storage.
 * @returns {boolean|Object} - The parsed user object if found, otherwise false.
 */
export const getUser = () => {
    if (typeof window === "undefined") {
        return false;
    }

    if (localStorage.getItem("user")) {
        return JSON.parse(localStorage.getItem("user"));
    } else {
        return false;
    }
};

/**
 * Signs out the user by removing the user and token from local storage.
 * @param {Function} callback - A callback function to run after signing out.
 */
export const signout = (callback) => {
    if (typeof window !== "undefined") {
        localStorage.removeItem("token");
        localStorage.removeItem("user");
        callback();
    }
};

// Test cases to verify the solution correctness
