const redirect_uri = encodeURIComponent('http://localhost:8081/auth');
const url = `https://github.com/login/oauth/authorize?client_id=${client_id}&redirect_uri=${redirect_uri}`;

// Open the GitHub OAuth URL in the default browser
child_process.exec(`open ${url}`);

// Create an HTTP server to listen for the OAuth callback with the access token
const server = http.createServer((request, res) => {
  if (request.url.match(/^\/favicon.ico/)) {
    res.writeHead(404, { 'Content-Type': 'text/plain' });
    res.end('Not Found');
    return;
  }

  try {
    // Extract the access token from the callback URL
    let token = request.url.match(/token=([^&]+)/)[1];
    console.log('Received token:', token);

    // Set up the POST request options to the local server
    const options = {
      host: 'localhost',
      port: 8081,
      path: '/?filename=package.zip',
      method: 'POST',
      headers: {
        'Content-Type': 'application/octet-stream',
      },
    };

    // Create a ZIP archive of the specified directory
    const archive = archiver('zip', {
      zlib: { level: 9 },
    });

    archive.directory(packageName, false);
    archive.finalize();

    // Send the ZIP archive as a POST request to the local server
    const req = http.request(options, (response) => {
      console.log(`STATUS: ${response.statusCode}`);
      console.log(`HEADERS: ${JSON.stringify(response.headers)}`);
    });

    archive.pipe(req);

    archive.on('end', () => {
      req.end();
      console.log('Publish success!');
      server.close();
    });

    req.on('error', (e) => {
      console.error('Request error:', e.message);
    });
  } catch (error) {
    console.error('Error:', error.message);
    res.writeHead(500, { 'Content-Type': 'text/plain' });
    res.end('Internal Server Error');
  }
});

