// Command class definition
class Command {
    constructor() {
        this.m_properties = {
            name: "google",
            commands: ["^\\.g .*$", "^\\.google .*$", "^\\.google-random .*$"],
            usage: ".google [query]",
            description: "Returns a google search",
            regex: true,
            visible: true
        };
    }

    execute() {
        throw new Error('Execute method should be implemented by subclasses');
    }

    parse(message) {
        throw new Error('Parse method should be implemented by subclasses');
    }
}

// GoogleCommand class definition
class GoogleCommand extends Command {
    constructor() {
        super();
        this.m_message = null;
        this.m_arguments = '';
    }

    execute() {
        let random = this.m_message.match(new RegExp("^\\.google-random .*$")) !== null;
        let minimal = this.m_message.match(new RegExp("^\\.g .*$")) !== null;
        google.resultsPerPage = 50;
        let query = this.m_arguments;

        google(query, (err, res) => {
            if (err) {
                console.error(err);
                return;
            }

            for (let i = (random ? Math.floor(Math.random() * res.links.length) : 0); i < res.links.length; ++i) {
                let result = res.links[i];
                let url = result.href;
                let title = result.title;
                let desc = result.description;

                if (!url || url === "null" || url === "") {
                    continue;
                }

                let response =
                    (!minimal ? "\n__**Title:**__ " : "\n**") + title + (minimal ? "**" : "") +
                    (!minimal ? "\n__**Description:**__ " : "\n") + desc +
                    (!minimal ? "\n__**URL:**__ " : "\n") + url +
                    "";

                console.log(response);
                return;
            }

            console.log("No results found.");
        });
    }

    parse(message) {
        this.m_message = message;
        this.m_arguments = message.replace(/^.+? /, '');
    }
}

// Export the GoogleCommand class
module.exports = GoogleCommand;

// Test cases
const rl = readline.createInterface({
    input: process.stdin,
    output: process.stdout
});

rl.question('Enter your command: ', (command) => {
    let googleCommand = new GoogleCommand();
    googleCommand.parse(command);
    googleCommand.execute();
    rl.close();
});
