/**
 * Computes the num-th number in the Zibonacci sequence.
 * 
 * @param {number} num - The index in the Zibonacci sequence.
 * @returns {number} The num-th Zibonacci number.
 */
function Zibonacci(num, memo = {}) {
    if (num in memo) return memo[num];
    if (num < 2) {
        return 1;
    } else if (num == 2) {
        return 2;
    } else if (num % 2 == 1) {
        memo[num] = Zibonacci((num - 1) / 2, memo) + Zibonacci((num - 1) / 2 - 1, memo) + 1;
    } else {
        memo[num] = Zibonacci(num / 2, memo) + Zibonacci(num / 2 + 1, memo) + 1;
    }
    return memo[num];
}

// Test Cases
