'use strict';

// Import the necessary function to get the session expiration time
import { getTimeSession } from './time.js';

/**
 * Sets a cookie with the given name and value, along with optional settings.
 * @param {string} name - The name of the cookie.
 * @param {string} value - The value of the cookie.
 * @param {Object} [options] - Optional settings for the cookie.
 */
export function setCookie(name, value, options = {}) {
  options = {
    path: '/',
    // Default expiration is set to the end of the session
    expires: getTimeSession(),
    ...options
  };
  if (options.expires instanceof Date) {
    options.expires = options.expires.toUTCString();
  }
  let updatedCookie = encodeURIComponent(name) + '=' + encodeURIComponent(value);
  for (let optionKey in options) {
    updatedCookie += '; ' + optionKey;
    let optionValue = options[optionKey];
    if (optionValue !== true) {
      updatedCookie += '=' + optionValue;
    }
  }
  document.cookie = updatedCookie;
}

/**
 * Retrieves the value of a cookie by name.
 * @param {string} name - The name of the cookie to retrieve.
 * @returns {string} The value of the cookie, or an empty string if not found.
 */
export function getCookie(name) {
  let matches = document.cookie.match(
    new RegExp('(?:^|; )' + name.replace(/([\.$?*|{}\(\)\[\]\\\/\+^])/g, '\\$1') + '=([^;]*)')
  );
  return matches ? decodeURIComponent(matches[1]) : '';
}

/**
 * Deletes all cookies for the current domain.
 */
export function deleteAllCookies() {
  var cookies = document.cookie.split(';');

  for (var i = 0; i < cookies.length; i++) {
    var cookie = cookies[i];
    var eqPos = cookie.indexOf('=');
    var name = eqPos > -1 ? cookie.substr(0, eqPos) : cookie;
    document.cookie = name + '=;expires=Thu, 01 Jan 1970 00:00:00 GMT';
  }
}

// Test cases to verify the correctness of the solution
// Note: These tests should be run in a browser environment

// Test setCookie function
setCookie('test', '123', { path: '/', expires: new Date(Date.now() + 86400 * 1000) });
console.assert(document.cookie.includes('test=123'), 'setCookie test failed');

// Test getCookie function
console.assert(getCookie('test') === '123', 'getCookie test failed');

// Test deleteAllCookies function
deleteAllCookies();
console.assert(document.cookie === '', 'deleteAllCookies test failed');
