// Importing the readline module to accept input from the console
const readline = require('readline').createInterface({
  input: process.stdin,
  output: process.stdout
});

// Initial game state
let board = ["", "", "", "", "", "", "", "", ""];
let currentPlayer = "X";
let gameOver = false;

/**
 * Function to print the current game board
 */
function printBoard() {
  console.log(`
  ${board[0] || 1} | ${board[1] || 2} | ${board[2] || 3}
  ---------
  ${board[3] || 4} | ${board[4] || 5} | ${board[5] || 6}
  ---------
  ${board[6] || 7} | ${board[7] || 8} | ${board[8] || 9}
  `);
}

/**
 * Function to swap the current player
 */
function swapTurn() {
  currentPlayer = currentPlayer === "X" ? "O" : "X";
}

/**
 * Function to check for a win or a draw
 */
function checkWin() {
  const winConditions = [
    [0, 1, 2],
    [3, 4, 5],
    [6, 7, 8],
    [0, 3, 6],
    [1, 4, 7],
    [2, 5, 8],
    [0, 4, 8],
    [2, 4, 6],
  ];

  for (let condition of winConditions) {
    if (
      board[condition[0]] &&
      board[condition[0]] === board[condition[1]] &&
      board[condition[1]] === board[condition[2]]
    ) {
      console.log(`${currentPlayer} Wins!`);
      gameOver = true;
      return;
    }
  }

  if (!board.includes("")) {
    console.log("It's a draw!");
    gameOver = true;
  }
}

/**
 * Function to start the game
 */
function startGame() {
  printBoard();
  readline.question(`Player ${currentPlayer}, enter your move (1-9): `, (input) => {
    const move = parseInt(input) - 1;
    if (move >= 0 && move <= 8 && !board[move]) {
      board[move] = currentPlayer;
      checkWin();
      if (!gameOver) {
        swapTurn();
      } else {
        readline.close();
        return;
      }
    } else {
      console.log("Invalid move. Try again.");
    }
    startGame();
  });
}

// Start the game
startGame();
