import { Circle } from "./Circle";
import { Rectangle } from "./Rectangle";
import { getDistance } from "../../Utils/NumberUtils";

export class QuadTree {
    constructor(rectangle, capacity) {
        this.rectangle = rectangle;
        this.capacity = capacity;
        this.points = [];
        this.divided = false;
    }

    insert(point) {
        if (!this.rectangle.contains(point.position)) {
            return false;
        }
        if (this.points.length < this.capacity) {
            this.points.push(point);
            return true;
        }
        if (!this.divided) {
            this.subdivide();
        }
        return (
            this.northEast.insert(point) ||
            this.northWest.insert(point) ||
            this.southEast.insert(point) ||
            this.southWest.insert(point)
        );
    }

    query(range, check, found = []) {
        if (!range.intersects(this.rectangle)) {
            return [];
        }
        for (const p of this.points) {
            if (range.contains(p.position) || getDistance(range.position, p.position) <= p.radius) {
                if (!check || check(p)) {
                    found.push(p);
                }
            }
        }
        if (this.divided) {
            this.northEast.query(range, check, found);
            this.northWest.query(range, check, found);
            this.southEast.query(range, check, found);
            this.southWest.query(range, check, found);
        }
        return found;
    }

    queryCircle(position, radius, check) {
        return this.query(new Circle(position.x, position.y, radius), check);
    }

    queryRectangle(position, size, check) {
        return this.query(new Rectangle(position.x, position.y, size.width, size.height), check);
    }

    subdivide() {
        const x = this.rectangle.position.x;
        const y = this.rectangle.position.y;
        const w = this.rectangle.size.width;
        const h = this.rectangle.size.height;
        const capacity = this.capacity;
        this.northEast = new QuadTree(new Rectangle(x, y, w / 2, h / 2), capacity);
        this.northWest = new QuadTree(new Rectangle(x + w / 2, y, w / 2, h / 2), capacity);
        this.southEast = new QuadTree(new Rectangle(x, y + h / 2, w / 2, h / 2), capacity);
        this.southWest = new QuadTree(new Rectangle(x + w / 2, y + h / 2, w / 2, h / 2), capacity);
        this.divided = true;
    }
}

// Test cases
const boundary = new Rectangle(0, 0, 400, 400);
const qt = new QuadTree(boundary, 4);

// Insert particles
qt.insert({ position: { x: 100, y: 100 }, radius: 10 });
qt.insert({ position: { x: 150, y: 150 }, radius: 10 });
qt.insert({ position: { x: 200, y: 200 }, radius: 10 });
qt.insert({ position: { x: 250, y: 250 }, radius: 10 });

// Query within a rectangle
const foundRect = qt.queryRectangle({ x: 50, y: 50 }, { width: 200, height: 200 });
console.log('Particles within rectangle:', foundRect);

// Query within a circle
const foundCircle = qt.queryCircle({ x: 200, y: 200 }, 100);
console.log('Particles within circle:', foundCircle);
