/**
 * ActionExecutor.js
 *
 * This module exports a function `executeAction` that simulates the execution of an asynchronous action.
 * It takes an action type and an array of arguments, then returns a promise that resolves with a result string
 * formatted as "Action {type} executed with arguments: {args}". If the inputs are invalid, the promise is rejected.
 *
 * Usage:
 * const [promise, resolve, reject] = executeAction('MY_ACTION', ['arg1', 'arg2']);
 * promise.then(result => console.log(result)).catch(error => console.error(error));
 * // To simulate action completion
 * resolve();
 * // To simulate action failure
 * reject(new Error('Simulated failure'));
 */

import Promise from "bluebird";

export function executeAction(type, args) {
    if (typeof type !== 'string') {
        return Promise.reject(new Error('Action type must be a string.'));
    }
    if (!Array.isArray(args)) {
        return Promise.reject(new Error('Arguments must be an array.'));
    }

    let resolve, reject;
    const promise = new Promise((res, rej) => {
        resolve = res;
        reject = rej;
    });

    promise.then(() => {
        return `Action ${type} executed with arguments: ${args.join(", ")}`;
    }).catch(error => {
        console.error(`Error executing action ${type} with arguments (${args.join(", ")}).`);
        console.log(`Message: ${error.message}`);
        throw error;
    });

    return [promise, resolve, reject];
}

// Test cases
const [promise1, resolve1] = executeAction('LOGIN', ['user1', 'password123']);
promise1.then(console.log).catch(console.error); // Should log: "Action LOGIN executed with arguments: user1, password123"
resolve1(); // Manually resolve the promise

const [promise2, , reject2] = executeAction('LOGOUT', []);
promise2.then(console.log).catch(console.error); // Should log: "Action LOGOUT executed with arguments: "
reject2(new Error('User session not found')); // Manually reject the promise with an error

const promise3 = executeAction(123, ['arg1']);
promise3.catch(console.error); // Should log: "Action type must be a string."

const promise4 = executeAction('UPDATE_PROFILE', 'not-an-array');
promise4.catch(console.error); // Should log: "Arguments must be an array."
