"use strict";

const nats = require("node-nats-streaming");
const EventEmitter = require("events").EventEmitter;
const inherits = require("util").inherits;

function Adapter(options) {
  EventEmitter.call(this);
  this.options = options;
  this.natsClient = null;
  this.subClients = [];
}

inherits(Adapter, EventEmitter);

Adapter.prototype.connect = function(callback) {
  this.natsClient = nats.connect(
    this.options.cluster,
    this.options.client,
    this.options.server
  );

  this.natsClient.on("connect", () => {
    this.emit("connect");
    callback(null);
  });

  this.natsClient.on("error", (err) => {
    this.emit("error", err);
    callback(err);
  });

  this.natsClient.on("message", (msg) => {
    this.emit("message", msg);
  });
};

Adapter.prototype.publish = function(topic, message, callback) {
  this.natsClient.publish(topic, message, callback);
};

Adapter.prototype.subscribe = function(topic, options, callback) {
  let subscription = this.natsClient.subscribe(topic, options);
  this.subClients.push(subscription);
  subscription.on("message", (msg) => {
    this.emit("message", msg);
  });
  callback(null, subscription);
};

Adapter.prototype.unsubscribe = function(subscription, callback) {
  subscription.unsubscribe();
  subscription.on("unsubscribed", () => {
    const index = this.subClients.indexOf(subscription);
    if (index > -1) {
      this.subClients.splice(index, 1);
    }
    callback(null);
  });
};

Adapter.prototype.disconnect = function(callback) {
  Promise.all(this.subClients.map((sub) => {
    return new Promise((resolve) => {
      sub.unsubscribe();
      sub.on("unsubscribed", resolve);
    });
  })).then(() => {
    this.natsClient.close();
    callback(null);
  }).catch(callback);
};

module.exports = Adapter;

// Example usage:
const adapter = new Adapter({
  cluster: 'test-cluster',
  client: 'test-client',
  server: 'nats://localhost:4222'
});

// Connect to NATS server
adapter.connect((err) => {
  if (err) {
    console.error('Connection error:', err);
  } else {
    console.log('Connected to NATS server');
  }
});

// Subscribe to a topic
adapter.subscribe('test.topic', {}, (err, subscription) => {
  if (err) {
    console.error('Subscribe error:', err);
  } else {
    console.log('Subscribed to test.topic');
  }
});

// Publish a message
adapter.publish('test.topic', 'Hello, NATS!', (err) => {
  if (err) {
    console.error('Publish error:', err);
  } else {
    console.log('Message published to test.topic');
  }
});

// Disconnect from NATS server
adapter.disconnect((err) => {
  if (err) {
    console.error('Disconnect error:', err);
  } else {
    console.log('Disconnected from NATS server');
  }
});
