'use strict';

const { google } = require('googleapis');
const { GoogleAuth } = require('google-auth-library');
const { HubServiceClient } = require('@google-cloud/network-connectivity');
const axios = require('axios');

// Load environment variables
require('dotenv').config();

// Initialize Google Cloud clients
const auth = new GoogleAuth();
const compute = google.compute('v1');
const hubServiceClient = new HubServiceClient();

// Environment variables
const projectId = process.env.PROJECT_ID;
const instanceName = process.env.INSTANCE_NAME;
const region = process.env.REGION;
const zone = process.env.ZONE;
const hubName = process.env.HUB_NAME;
const routerName = process.env.ROUTER_NAME;
const vpcName = process.env.VPC_NAME;
const subnetName = process.env.SUBNET_NAME;
const bgpAsn = process.env.BGP_ASN;
const peerAsn = process.env.PEER_ASN;
const interfacePrivateIP1 = process.env.INTERFACE_PRIVATE_IP_1;
const interfacePrivateIP2 = process.env.INTERFACE_PRIVATE_IP_2;

// Function to fetch access token
async function fetchJwtAccessToken() {
  const accessToken = await auth.getAccessToken();
  return accessToken;
}

// Function to fetch Compute Engine instance details
async function fetchComputeEngineInstance() {
  const computeAuthClient = await auth.getClient({
    scopes: ['https://www.googleapis.com/auth/cloud-platform', 'https://www.googleapis.com/auth/compute.readonly'],
  });
  const result = await compute.instances.get({
    auth: computeAuthClient,
    project: projectId,
    instance: instanceName,
    zone: zone,
  });
  return {
    selfLink: result.data.selfLink,
    networkIP: result.data.networkInterfaces[0].networkIP,
  };
}

// Function to update Cloud Router with BGP peers and interfaces
async function updateCloudRouter(jwtAccessToken, instanceDetails) {
  const crPatchURI = `https://compute.googleapis.com/compute/beta/projects/${projectId}/regions/${region}/routers/${routerName}`;
  const header = { Authorization: `Bearer ${jwtAccessToken}` };

  const crObj = {
    network: vpcName,
    bgp: {
      asn: bgpAsn,
    },
    bgpPeers: [
      {
        name: `${routerName}-bgppeer1`,
        interfaceName: `${routerName}-interface0`,
        ipAddress: interfacePrivateIP1,
        peerIpAddress: instanceDetails.networkIP,
        routerApplianceInstance: instanceDetails.selfLink,
        peerAsn: peerAsn,
      },
      {
        name: `${routerName}-bgppeer2`,
        interfaceName: `${routerName}-interface1`,
        ipAddress: interfacePrivateIP2,
        peerIpAddress: instanceDetails.networkIP,
        routerApplianceInstance: instanceDetails.selfLink,
        peerAsn: peerAsn,
      },
    ],
    interfaces: [
      {
        name: `${routerName}-interface0`,
        privateIpAddress: interfacePrivateIP1,
        subnetwork: subnetName,
      },
      {
        name: `${routerName}-interface1`,
        privateIpAddress: interfacePrivateIP2,
        subnetwork: subnetName,
        redundantInterface: `${routerName}-interface0`,
      },
    ],
  };

  await axios.patch(crPatchURI, crObj, { headers: header });
}

// Function to validate if the Hub exists
async function validateIfHubExists() {
  try {
    await hubServiceClient.getHub({
      name: `projects/${projectId}/locations/global/hubs/${hubName}`,
    });
    return true;
  } catch (err) {
    return false;
  }
}

// Function to create a Hub
async function createHub() {
  const [operation] = await hubServiceClient.createHub({
    parent: `projects/${projectId}/locations/global`,
    hubId: hubName,
  });
  await operation.promise();
}

// Function to create a Spoke and attach it to the Hub
async function createSpoke(instanceDetails) {
  const spokeProperties = {
    name: `${hubName}-${region}-${instanceName}`,
    hub: `projects/${projectId}/locations/global/hubs/${hubName}`,
    siteToSiteDataTransfer: false,
    linkedRouterApplianceInstances: [
      {
        ipAddress: instanceDetails.networkIP,
        virtualMachine: instanceDetails.selfLink,
      },
    ],
  };

  const [operation] = await hubServiceClient.createSpoke({
    parent: `projects/${projectId}/locations/${region}`,
    spoke: spokeProperties,
    spokeId: `${hubName}-${region}-${instanceName}`,
  });
  await operation.promise();
}

// Main function to construct NCC configuration
async function constructNCC() {
  try {
    const instanceDetails = await fetchComputeEngineInstance();
    const jwtAccessToken = await fetchJwtAccessToken();
    await updateCloudRouter(jwtAccessToken, instanceDetails);

    const hubExists = await validateIfHubExists();
    if (!hubExists) {
      await createHub();
      console.info('Successfully created Hub.');
    }

    await createSpoke(instanceDetails);
    console.info('Successfully created Spoke and attached to the Hub.');
  } catch (err) {
    console.error('Error during NCC configuration:', err);
    throw err;
  }
}

// Invoke the main function
constructNCC()
  .then(() => console.info('NCC configuration complete.'))
  .catch((err) => console.error('NCC configuration failed:', err));
```

