import { observer } from 'mobx-react-lite';
import { Context } from '../../index';
import { updateUser } from '../../http/userApi';
import jwtDecode from 'jwt-decode';

const UserProfileEditor = observer(({ show, onHide }) => {
  const { userStore } = useContext(Context);

  const [lastName, setLastName] = useState('');
  const [middleName, setMiddleName] = useState('');
  const [firstName, setFirstName] = useState('');
  const [email, setEmail] = useState('');
  const [phoneNumber, setPhoneNumber] = useState('');
  const [birthDate, setBirthDate] = useState('');

  useEffect(() => {
    if (userStore.currentUser) {
      setLastName(userStore.currentUser.lastName);
      setMiddleName(userStore.currentUser.middleName);
      setFirstName(userStore.currentUser.firstName);
      setEmail(userStore.currentUser.email);
      setPhoneNumber(userStore.currentUser.phoneNumber);
      setBirthDate(userStore.currentUser.birthDate);
    }
  }, [userStore.currentUser]);

  const handleSave = () => {
    const updatedUser = {
      id: userStore.currentUser.id,
      lastName,
      middleName,
      firstName,
      email,
      phoneNumber,
      birthDate
    };
    updateUser(updatedUser).then(data => {
      onHide();
      userStore.setCurrentUser(jwtDecode(localStorage.token));
    });
  };

  return (
    <Modal show={show} onHide={onHide} centered>
      <Modal.Header closeButton>
        <Modal.Title>Edit Profile</Modal.Title>
      </Modal.Header>
      <Modal.Body>
        <Form.Control
          value={lastName}
          onChange={e => setLastName(e.target.value)}
          placeholder="Enter last name"
          type="text"
        />
        <Form.Control
          value={firstName}
          onChange={e => setFirstName(e.target.value)}
          placeholder="Enter first name"
          type="text"
        />
        <Form.Control
          value={middleName}
          onChange={e => setMiddleName(e.target.value)}
          placeholder="Enter middle name"
          type="text"
        />
        <Form.Control
          value={email}
          onChange={e => setEmail(e.target.value)}
          placeholder="Enter email"
          type="email"
        />
        <Form.Control
          value={phoneNumber}
          onChange={e => setPhoneNumber(e.target.value)}
          placeholder="Enter phone number"
        />
        <Form.Control
          value={birthDate}
          onChange={e => setBirthDate(e.target.value)}
          type="date"
        />
      </Modal.Body>
      <Modal.Footer>
        <Button variant="secondary" onClick={onHide}>
          Close
        </Button>
        <Button variant="primary" onClick={handleSave}>
          Save Changes
        </Button>
      </Modal.Footer>
    </Modal>
  );
});

export default UserProfileEditor;
