 * @param {string} contextMenuContent - The HTML content for the context menu.
 */
function initializeInteractiveMap(mapElementId, mapStatusElementId, contextMenuContent) {
    // Initialize the map on the specified element with a given initial position and zoom level
    const map = L.map(mapElementId).setView([39.5, -98.35], 4);

    // Define the map layers
    const topoLayer = L.tileLayer('https://api.mapbox.com/v4/mapbox.outdoors/{z}/{x}/{y}.png?access_token=YOUR_MAPBOX_ACCESS_TOKEN', {});
    const satLayer = L.tileLayer('https://api.mapbox.com/v4/mapbox.satellite/{z}/{x}/{y}.png?access_token=YOUR_MAPBOX_ACCESS_TOKEN', {});
    const geoLayer = L.tileLayer('https://webmaps.geology.utah.gov/arcgis/rest/services/GeolMap/30x60_Quads/MapServer/tile/{z}/{y}/{x}?blankTile=false');
    const geoTopoLayer = L.tileLayer('https://api.mapbox.com/v4/mapbox.outdoors/{z}/{x}/{y}.png?access_token=YOUR_MAPBOX_ACCESS_TOKEN', { opacity: 0.6 });
    const geoGroup = L.layerGroup([geoLayer, geoTopoLayer]);

    // Add the Topographic layer by default
    topoLayer.addTo(map);

    // Define the base maps for layer control
    const baseMaps = {
        "Topo": topoLayer,
        "Sat": satLayer,
        "Geo": geoGroup
    };

    // Add layer control to the map
    L.control.layers(baseMaps, {}).addTo(map);

    // Set up the map status element to display latitude and longitude
    const mapStatus = document.getElementById(mapStatusElementId);
    map.on('mousemove', e => {
        const display = `${e.latlng.lat.toFixed(5)}, ${e.latlng.lng.toFixed(5)}`;
        if (mapStatus) {
            mapStatus.innerHTML = display;
        }
    });

    // Set up the context menu with custom content
    if (contextMenuContent) {
        map.on('contextmenu', e => {
            const popup = L.popup()
                .setLatLng(e.latlng)
                .setContent(contextMenuContent);
            popup.openOn(map);
        });
    }
}

