const util = require('util');

/**
 * This function takes an array of mixed data types and returns a promise that resolves
 * with an array of the string elements from the input array, converted to lowercase.
 * If there are no string elements, the promise is rejected with a specific message.
 * 
 * @param {Array} arr - The array containing mixed data types.
 * @returns {Promise<Array<string>, string>} A promise that resolves with an array of lowercase strings or rejects with an error message.
 */
let lowerCaseStringElements = (arr) => {
    return new Promise((resolve, reject) => {
        let stringElements = arr.filter(e => typeof(e) === 'string');
        let lowerCaseElements = stringElements.map(e => e.toLowerCase());

        if (lowerCaseElements.length > 0) {
            resolve(lowerCaseElements);
        } else {
            reject("No string elements found");
        }
    });
};

