var reduceArray = require('@f/reduce-array')
var reduceObj = require('@f/reduce-obj')
var isObject = require('@f/is-object')
var isArray = require('@f/is-array')

/**
 * Expose universalReduce
 */

module.exports = universalReduce

/**
 * universalReduce
 * @param {Function} fn - The reducer function to apply.
 * @param {*} acc - The initial accumulator value.
 * @param {Array|Object} container - The array or object to reduce.
 * @returns {*} The final accumulator value after reduction.
 */
function universalReduce(fn, acc, container) {
  if (isArray(container)) return reduceArray(fn, acc, container)
  if (isObject(container)) return reduceObj(fn, acc, container)

  return acc
}

