    let embedColor = '#3498db'; // Default embed color, can be loaded from a config file
    let editEmbed = new Discord.RichEmbed()
        .setAuthor(`${message.author.tag} | Deleted message`, message.author.displayAvatarURL)
        .setDescription(`**Message sent by ${message.author} deleted in ${message.channel.toString()}**
**Message Content:**\n\n${message.content}`)
        .setFooter(`ID: ${message.id}`)
        .setColor(embedColor)
        .setTimestamp();

    let logSettingsPath = './src/database/logonoff.json';
    let logPath = './src/database/logging.json';

    if (!fs.existsSync(logSettingsPath) || !fs.existsSync(logPath)) {
        console.error('Logging configuration files are missing.');
        return;
    }

    let logSetting = JSON.parse(fs.readFileSync(logSettingsPath, 'utf8'));
    let log = JSON.parse(fs.readFileSync(logPath, 'utf8'));

    if (!logSetting[message.guild.id] || !log[message.guild.id]) {
        console.error('Logging is not configured for this guild.');
        return;
    }

    let values = logSetting[message.guild.id].checker;
    if (values === undefined || values === 0) return;

    let channel = message.guild.channels.get(log[message.guild.id].channel);
    if (!channel) {
        console.error('Logging channel is not found in the guild.');
        return;
    }

    channel.send(editEmbed);
}

