/**
 * Initiates an AJAX GET request to a specified URL with given parameters and calls the provided callback function upon success.
 *
 * @param {string} url - The URL to which the request is sent.
 * @param {string} command - The command to be appended as a query parameter.
 * @param {string|null} params - Additional query parameters to be appended to the URL, formatted as a query string.
 * @param {function} callback - The callback function to be called with the response text upon successful completion of the request.
 */
function makeAjaxGetRequest(url, command, params, callback) {
    // Construct the full URL with parameters
    let fullUrl = `${url}?cmd=${encodeURIComponent(command)}`;
    if (params) {
        fullUrl += `&${params}`;
    }

    // Create a new XMLHttpRequest object
    const xhr = new XMLHttpRequest();

    // Set up the request
    xhr.open('GET', fullUrl, true);

    // Define what happens on successful data submission
    xhr.onload = function () {
        if (xhr.status === 200) {
            callback(xhr.responseText);
        } else {
            console.error('Request failed. Returned status of ' + xhr.status);
        }
    };

    // Define what happens in case of an error
    xhr.onerror = function () {
        console.error('There was a network error.');
    };

    // Send the request
    xhr.send();
}

