// FallingBox class definition
class FallingBox {
  constructor(x, y) {
    this.x = x;
    this.y = y;
    this.vx = 0;
    this.vy = 0;
    this.ax = 0;
    this.ay = 0;
    this.maxSpeed = 25;
    this.size = 60;
    this.active = true;
    this.fill = {
      r: 20,
      g: 100,
      b: 100
    };
  }

  gravity(force) {
    this.ay += force;
  }

  move(height) {
    this.vx += this.ax;
    this.vy += this.ay;

    this.vx = constrain(this.vx, -this.maxSpeed, this.maxSpeed);
    this.vy = constrain(this.vy, -this.maxSpeed, this.maxSpeed);

    this.x += this.vx;
    this.y += this.vy;

    if (this.y - this.size / 2 > height) {
      this.active = false;
    }
  }

  display() {
    console.log(`Box at (${this.x}, ${this.y}) with size ${this.size} and color rgb(${this.fill.r}, ${this.fill.g}, ${this.fill.b})`);
  }

  checkIfTouched(gate) {
    let d = dist(this.x, this.y, gate.x, gate.y);
    return d < this.size / 2 + gate.width / 2;
  }
}

// Test cases
