const express = require('express');
const multer = require('multer');
const fs = require('fs');
const path = require('path');

const app = express();
app.use(express.json());
app.use(express.urlencoded({ extended: true }));

const folder = './public/uploads/';
if (!fs.existsSync(folder)) {
  fs.mkdirSync(folder, { recursive: true });
}

var storage = multer.diskStorage({
  destination: (req, file, cb) => {
    cb(null, folder);
  },
  filename: (req, file, cb) => {
    cb(null, file.fieldname + '-' + Date.now() + path.extname(file.originalname));
  }
});

const fileFilter = (req, file, cb) => {
  if (file.mimetype === 'image/jpeg' || file.mimetype === 'image/png') {
    cb(null, true);
  } else {
    cb(new Error('Only .png and .jpeg format allowed!'));
  }
};

const upload = multer({ storage: storage, fileFilter: fileFilter }).single('file');

app.post('/upload', (req, res) => {
  upload(req, res, function(err) {
    if (err) {
      res.status(400).send({ msg: err.message });
    } else {
      res.json({ msg: 'Success, Image uploaded!' });
    }
  });
});

app.get('/files', (req, res) => {
  let files = readFiles();
  res.json({ fileArr: files.reverse() });
});

app.post('/delete', (req, res) => {
  let fileName = req.body.fileName;
  let filePath = path.join(folder, fileName);
  fs.unlink(filePath, (err) => {
    if (err) {
      res.status(400).send({ msg: 'File does not exist' });
    } else {
      let files = readFiles();
      res.send({ msg: 'File unlinked successfully', fileArr: files.reverse() });
    }
  });
});

const readFiles = () => {
  try {
    return fs.readdirSync(folder);
  } catch (err) {
    console.error(err);
