class Workout {
  date = new Date();
  id = Date.now();

  constructor(distance, duration, coords) {
    this.distance = distance;
    this.duration = duration;
    this.coords = coords; // [latitude, longitude]
  }
}

// Running class extending Workout
class Running extends Workout {
  type = 'running';

  constructor(distance, duration, coords, cadence) {
    super(distance, duration, coords);
    this.cadence = cadence;
    this._pace();
    this._description();
  }

  _pace() {
    this.pace = this.duration / this.distance;
  }

  _description() {
    const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
    this.description = `🏃‍♂️ Running on ${months[this.date.getMonth()]} ${this.date.getDate()}`;
  }
}

// Cycling class extending Workout
class Cycling extends Workout {
  type = 'cycling';

  constructor(distance, duration, coords, elevation) {
    super(distance, duration, coords);
    this.elevation = elevation;
    this._speed();
    this._description();
  }

  _speed() {
    this.speed = this.distance / (this.duration / 60);
  }

  _description() {
    const months = ['January', 'February', 'March', 'April', 'May', 'June', 'July', 'August', 'September', 'October', 'November', 'December'];
    this.description = `🚴‍♂️ Cycling on ${months[this.date.getMonth()]} ${this.date.getDate()}`;
  }
}

