const http = require("http");
const StringDecoder = require("string_decoder").StringDecoder;

// Function to parse the request body
const getBody = (req, callback) => {
  const decoder = new StringDecoder("utf-8");
  let body = "";
  req.on("data", (data) => {
    body += decoder.write(data);
  });
  req.on("end", () => {
    body += decoder.end();
    const parsedBody = decodeURI(body)
      .split("&")
      .reduce((acc, part) => {
        const [key, value] = part.split("=");
        acc[key] = value;
        return acc;
      }, {});
    callback(parsedBody);
  });
};

// Generate a random number between 0 and 100
let randomNumber = Math.floor(Math.random() * 101);
let message = "Guess a number between 0 and 100";

// Function to generate the HTML form
const form = () => {
  return `
    <html>
      <body>
        <p>${message}</p>
        <form method="POST">
          <input type="number" min="0" max="100" name="number" required>
          <button type="submit">Submit</button>
        </form>
      </body>
    </html>
  `;
};

// Create the HTTP server
const server = http.createServer((req, res) => {
  if (req.method === "POST") {
    getBody(req, (body) => {
      const guessNumber = parseInt(body.number, 10);
      if (isNaN(guessNumber) || guessNumber < 0 || guessNumber > 100) {
        message = "Please enter a valid number between 0 and 100.";
      } else if (guessNumber > randomNumber) {
        message = "Your guess is too high. Try again.";
      } else if (guessNumber < randomNumber) {
        message = "Your guess is too low. Try again.";
      } else {
        message = `Congratulations! The number was ${randomNumber}.`;
        // Reset the game
        randomNumber = Math.floor(Math.random() * 101);
      }
      res.writeHead(303, { Location: "/" });
      res.end();
    });
  } else {
    res.writeHead(200, { "Content-Type": "text/html" });
    res.end(form());
  }
});

// Start the server
server.listen(3000, () => {
  console.log("Server listening on port 3000");
});

// Test cases
