import $ from 'jquery';

/**
 * Searches for cocktails by name.
 * @param {string} searchTerm - The term to search for in cocktail names.
 * @param {function} callback - The callback function to execute with the search results.
 */
function searchCocktails(searchTerm, callback) {
    $.get(`https://www.thecocktaildb.com/api/json/v1/1/search.php?s=${searchTerm}`)
        .done(function(data) {
            callback(data);
        })
        .fail(function(error) {
            console.error('Error searching for cocktails:', error);
        });
}

/**
 * Searches for details about an ingredient.
 * @param {string} ingredientName - The name of the ingredient to search for.
 * @param {function} callback - The callback function to execute with the search results.
 */
function searchIngredient(ingredientName, callback) {
    $.get(`https://www.thecocktaildb.com/api/json/v1/1/search.php?i=${ingredientName}`)
        .done(function(data) {
            callback(data);
        })
        .fail(function(error) {
            console.error('Error searching for ingredient:', error);
        });
}

