import React, { Component } from 'react';

class CheckboxList extends Component {
  constructor(props) {
    super(props);
    this.state = {
      checkboxes: props.checkboxes.map(checkbox => ({
        ...checkbox,
        checked: checkbox.checked || false,
      })),
      allDisabled: false,
    };
  }

  toggleCheckbox(index) {
    this.setState(prevState => {
      const newCheckboxes = [...prevState.checkboxes];
      newCheckboxes[index].checked = !newCheckboxes[index].checked;
      console.log(`${newCheckboxes[index].label}: ${newCheckboxes[index].checked ? 'Checked' : 'Unchecked'}`);
      return { checkboxes: newCheckboxes };
    });
  }

  toggleDisableAll() {
    this.setState(prevState => ({
      allDisabled: !prevState.allDisabled,
      checkboxes: prevState.checkboxes.map(checkbox => ({
        ...checkbox,
        disabled: !prevState.allDisabled,
      })),
    }));
  }

  render() {
    return (
      <div>
        {this.state.checkboxes.map((checkbox, index) => (
          <label key={index}>
            <input
              type="checkbox"
              checked={checkbox.checked}
              disabled={this.state.allDisabled || checkbox.disabled}
              onChange={() => this.toggleCheckbox(index)}
            />
            {checkbox.label}
          </label>
        ))}
        <button onClick={() => this.toggleDisableAll()}>
          {this.state.allDisabled ? 'Enable All' : 'Disable All'}
        </button>
      </div>
    );
  }
}

// Example usage:
const checkboxes = [
  { label: 'Checkbox 1', checked: false },
  { label: 'Checkbox 2', checked: true },
  { label: 'Checkbox 3', checked: false, disabled: true },
];

export default function App() {
  return <CheckboxList checkboxes={checkboxes} />;
}
