function validateSignUpForm(formData) {
    const errors = {};
    let isValid = true;

    // Username validation
    const usernameRegex = /^[a-z][a-z\d]{4,19}$/;
    if (!formData.username) {
        errors.username = "Username is required.";
        isValid = false;
    } else if (!usernameRegex.test(formData.username)) {
        errors.username = "Username must be 5-20 characters long, start with a lowercase letter, and contain at least one number.";
        isValid = false;
    }

    // Password validation
    const passwordRegex = /^(?=.*\d)(?=.*[a-z])(?=.*[A-Z]).{8,20}$/;
    if (!formData.password) {
        errors.password = "Password is required.";
        isValid = false;
    } else if (!passwordRegex.test(formData.password)) {
        errors.password = "Password must be 8-20 characters long and include at least one digit, one lowercase letter, and one uppercase letter.";
        isValid = false;
    }

    // Password confirmation validation
    if (formData.password !== formData.passwordConfirmation) {
        errors.passwordConfirmation = "Password confirmation does not match the password.";
        isValid = false;
    }

    // Name validation
    if (!formData.name) {
        errors.name = "Name is required.";
        isValid = false;
    }

    // Email validation
    const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
    if (!formData.email) {
        errors.email = "Email is required.";
        isValid = false;
    } else if (!emailRegex.test(formData.email)) {
        errors.email = "Invalid email format.";
        isValid = false;
    }

    // Birthdate validation
    const birthDateRegex = /^(19|20)\d{2}(0[1-9]|1[0-2])(0[1-9]|[12]\d|3[01])$/;
    if (!formData.birthDate || !birthDateRegex.test(formData.birthDate)) {
        errors.birthDate = "Invalid birth date. Format should be YYYYMMDD.";
        isValid = false;
    }

    // Agreements validation
    if (!formData.agreements || formData.agreements.length === 0) {
        errors.agreements = "At least one agreement must be selected.";
        isValid = false;
    }

    return { isValid, errors };
}

// Test cases
console.log(validateSignUpForm({
    username: 'john123',
    password: 'Password1',
    passwordConfirmation: 'Password1',
    name: 'John Doe',
    email: 'john.doe@example.com',
    birthDate: '19900101',
    agreements: ['terms', 'privacy']
}));

console.log(validateSignUpForm({
