const express = require('express');
const mongoose = require('mongoose');
const fs = require('fs');
const path = require('path');

const router = express.Router();

module.exports = function() {
  const serviceName = process.env.SERVICE;
  const modelPath = path.join(__dirname, `${serviceName.toLowerCase()}.js`);
  const routePath = path.join(__dirname, 'web', `${serviceName.toLowerCase()}.js`);

  try {
    if (serviceName !== 'WEB') {
      if (fs.existsSync(modelPath) && fs.existsSync(routePath)) {
        const model = require(modelPath)(mongoose);
        const route = require(routePath);

        router.use('/', route(model));
      } else {
        console.error(`Model or route file for service ${serviceName} does not exist.`);
      }
    } else {
      const webRoutePath = path.join(__dirname, 'web.js');
      if (fs.existsSync(webRoutePath)) {
        router.use('/', require(webRoutePath)(mongoose));
      } else {
        console.error('Default web route file does not exist.');
      }
    }
  } catch (error) {
    console.error(`An error occurred while setting up the routes for service ${serviceName}: ${error.message}`);
  }

  return router;
}

// Example usage in an Express application
if (require.main === module) {
  const app = express();
  app.use('/', require('./dynamicRouteLoader')());

  const PORT = process.env.PORT || 3000;
  app.listen(PORT, () => {
    console.log(`Server is running on port ${PORT}`);
  });
}
