/**
 * Determines if the Fabulous piece can move to a specified location based on the current location
 * of the piece and the selected tool.
 * 
 * @param {string} currentLoc - The current location of the Fabulous piece (e.g., "d4").
 * @param {string} targetLoc - The target location to move to (e.g., "f6").
 * @param {string} tool - The tool that dictates the movement pattern ("Range" or "Location").
 * @returns {boolean} - Returns true if the Fabulous piece can move to the target location, false otherwise.
 */
export const canFabMoveTo = (currentLoc, targetLoc, tool) => {
    if (tool === "Range") {
        if (currentLoc === "d4" && targetLoc === "f6") {
            return true;
        }
        if (currentLoc === "d5" && targetLoc === "f7") {
            return true;
        }
        if (currentLoc === "e4" && targetLoc === "g6") {
            return true;
        }
        if (currentLoc === "e5" && targetLoc === "g7") {
            return true;
        }
        return false;
    }
    if (tool === "Location") {
        return targetLoc === "f6";
    }
    return false;
};

