/**
 * Converts a given time in hours and minutes to its verbal equivalent.
 * @param {number} hour - 0-23 format, hour of a day
 * @param {number} minute - 0-59 format, minute of a day
 * @returns {string} returns a string representation of a time
 */
function convertToVerbalTime(hour, minute) {
  const numbersToWords = {
    0: 'twelve', 1: 'one', 2: 'two', 3: 'three', 4: 'four',
    5: 'five', 6: 'six', 7: 'seven', 8: 'eight', 9: 'nine',
    10: 'ten', 11: 'eleven', 12: 'twelve', 13: 'one', 14: 'two',
    15: 'three', 16: 'four', 17: 'five', 18: 'six', 19: 'seven',
    20: 'eight', 21: 'nine', 22: 'ten', 23: 'eleven'
  };

  if (hour === 0 && minute === 0) return 'midnight';
  if (hour === 12 && minute === 0) return 'noon';

  let verbalHour = numbersToWords[hour];
  if (minute > 52) {
    verbalHour = numbersToWords[(hour + 1) % 24];
    return `${verbalHour} o'clock`;
  }

  if (minute >= 0 && minute <= 7) return `${verbalHour} o'clock`;
  if (minute >= 8 && minute <= 23) return `quarter past ${verbalHour}`;
  if (minute >= 24 && minute <= 37) return `half past ${verbalHour}`;
  if (minute >= 38 && minute <= 52) return `quarter to ${numbersToWords[(hour + 1) % 24]}`;

  // This line should never be reached if all cases are covered
  return 'Invalid time';
}

// Tests:
console.assert(convertToVerbalTime(0, 0) === 'midnight', 'Test at midnight failed');
console.assert(convertToVerbalTime(12, 0) === 'noon', 'Test at noon failed');
console.assert(convertToVerbalTime(9, 0) === 'nine o\'clock', 'Test at nine o\'clock failed');
console.assert(convertToVerbalTime(9, 15) === 'quarter past nine', 'Test at quarter past nine failed');
console.assert(convertToVerbalTime(9, 30) === 'half past nine', 'Test at half past nine failed');
console.assert(convertToVerbalTime(9, 45) === 'quarter to ten', 'Test at quarter to ten failed');
console.assert(convertToVerbalTime(21, 45) === 'quarter to ten', 'Test at quarter to ten PM failed');
console.assert(convertToVerbalTime(23, 53) === 'twelve o\'clock', 'Test at twelve o\'clock failed');
console.assert(convertToVerbalTime(11, 8) === 'quarter past eleven', 'Test at quarter past eleven failed');
