const jwt = require('jsonwebtoken');

/**
 * Authenticates a user by verifying their JWT token.
 * 
 * @param {string} token - The JWT token to be verified.
 * @param {string} secret - The secret key used to sign the token.
 * @returns {Promise<Object>} A promise that resolves with the decoded user information if the token is valid, or rejects with an error if the token is invalid or expired.
 */
function authenticateUser(token, secret) {
  return new Promise((resolve, reject) => {
    jwt.verify(token, secret, (err, decoded) => {
      if (err) {
        reject(err);
      } else {
        resolve(decoded);
      }
    });
  });
}

// Test cases
const secretKey = 'mySuperSecretKey';
const user = { id: 1, username: 'testUser' };

// Create a token for the test user
const token = jwt.sign(user, secretKey, { expiresIn: '1h' });

// Test case 1: Valid token
authenticateUser(token, secretKey)
  .then(decoded => console.log('Test case 1 (valid token):', decoded))
  .catch(err => console.error('Test case 1 (valid token) error:', err));

// Test case 2: Invalid token
const invalidToken = token.slice(0, -1); // Corrupt the token to make it invalid
authenticateUser(invalidToken, secretKey)
  .then(decoded => console.log('Test case 2 (invalid token):', decoded))
  .catch(err => console.error('Test case 2 (invalid token) error:', err));

// Test case 3: Expired token
const expiredToken = jwt.sign(user, secretKey, { expiresIn: '-1h' }); // Create an already expired token
authenticateUser(expiredToken, secretKey)
  .then(decoded => console.log('Test case 3 (expired token):', decoded))
  .catch(err => console.error('Test case 3 (expired token) error:', err));
