const OrderCoupon = require('../../models/order/OrderCoupon');
const BaseService = require('../core/BaseService');
const CouponService = require('../coupon/CouponService');
const logger = require('../../lib/log4js');
const util = require('util');

class OrderCouponService extends BaseService {
    constructor() {
        super(OrderCoupon);
    }

    removeByOrderId(orderId) {
        return new Promise((resolve, reject) => {
            this.findOneAndRemove({ orderId: orderId }, (err, data) => {
                if (err) return reject(err);
                if (data && Array.isArray(data.couponIds) && data.couponIds.length > 0) {
                    CouponService.doFallback(data.couponIds).then(result => {
                        resolve(result);
                    }).catch(err => {
                        reject(err);
                    });
                } else {
                    resolve(false);
                }
            });
        });
    }

    cancelCouponsByOrderId(orderId) {
        return new Promise((resolve, reject) => {
            this.findOne({ orderId: orderId }, (err, doc) => {
                if (err) {
                    return reject(err);
                }
                if (!doc) {
                    logger.warn(util.format('Order [%d] does not have associated coupons', orderId));
                    return resolve(false);
                }
                let couponIds = doc.couponIds;
                if (!Array.isArray(couponIds) || couponIds.length < 1) {
                    return resolve(false);
                }
                CouponService.doFallback(couponIds).then(data => {
                    resolve(data);
                }).catch(err => {
                    reject(err);
                });
            });
        });
    }
}

module.exports = new OrderCouponService();

