const os = require("os");
const path = require("path");
const findCacheDir = require("find-cache-dir");

/**
 * Generates a cache file path for a given application.
 * If the cache directory cannot be found or created, it falls back to the OS's temporary directory.
 *
 * @param {string} appName - The name of the application.
 * @param {string} cacheFileName - The name of the cache file.
 * @returns {string} The full path to the cache file.
 */
function createCacheFilePath(appName, cacheFileName) {
  const cacheDir =
    findCacheDir({ name: appName, create: true }) || os.tmpdir();
  const cacheFilePath = path.join(cacheDir, cacheFileName);
  return cacheFilePath;
}

module.exports = createCacheFilePath;

