import { useState, useEffect } from "react";

export function useCart() {
  const [cart, setCart] = useState(() => {
    const storedCart = localStorage.getItem('@goods:cart');
    return storedCart ? JSON.parse(storedCart) : [];
  });

  useEffect(() => {
    localStorage.setItem('@goods:cart', JSON.stringify(cart));
  }, [cart]);

  const addToCart = (newProduct) => {
    setCart((prevCart) => {
      const existingProductIndex = prevCart.findIndex(product => product.id === newProduct.id);
      if (existingProductIndex > -1) {
        const updatedCart = [...prevCart];
        updatedCart[existingProductIndex].amount += newProduct.amount;
        return updatedCart;
      } else {
        return [...prevCart, { ...newProduct, amount: newProduct.amount || 1 }];
      }
    });
  };

  const removeFromCart = (id) => {
    setCart((prevCart) => prevCart.filter(product => product.id !== id));
  };

  return { addToCart, removeFromCart, cart };
}

// Test cases
