// @flow
import { call, put, takeEvery } from 'redux-saga/effects';
import type { User } from '../interfaces/interfaces';

/**
 * Generator function to fetch user data.
 * On success, dispatches USER_FETCH_SUCCEEDED with the users.
 * On failure, dispatches USER_FETCH_FAILED with an error message.
 */
function* fetchUser(): Generator<User[], void, User[]> {
   try {
      const users: User[] = yield call(asyncData, 'User Info');
      yield put({type: "USER_FETCH_SUCCEEDED", payload: { status: 'Fetch Succeeded payload', users}});
   } catch (e) {
      yield put({type: "USER_FETCH_FAILED", message: e.message});
   }
}

/**
 * Simulates an asynchronous API call to fetch user data.
 * Dispatches ASYNC_TYPE with the userInfo payload.
 * @param {string} userInfo - The information to be passed as payload.
 * @returns {Promise<User[]>} - A promise that resolves to an array of users.
 */
function* asyncData(userInfo: string): Generator<Promise<User[]>, void, User[]> {
   const users = yield fetch('http://www.mocky.io/v2/5dcd1b782e00007c00729ac9').then(res => res.json());
   yield put({ type: 'ASYNC_TYPE', userInfo });
   return users;
}

/**
 * Root saga that listens for USER_FETCH_REQUESTED actions and calls fetchUser.
 */
function* mySaga(): Generator<any, void, void> {
  yield takeEvery("USER_FETCH_REQUESTED", fetchUser);
}

export default mySaga;

// Test cases
function testFetchUser() {
  const generator = fetchUser();

  // Test the call to asyncData
  let next = generator.next();
  expect(next.value).toEqual(call(asyncData, 'User Info'));

  // Test the successful put action
  const mockUsers = [{ id: 1, name: 'John Doe' }];
  next = generator.next(mockUsers);
  expect(next.value).toEqual(put({type: "USER_FETCH_SUCCEEDED", payload: { status: 'Fetch Succeeded payload', users: mockUsers}}));

  // Test the end of the generator function
  next = generator.next();
  expect(next.done).toBeTruthy();
}

function testFetchUserFailure() {
  const generator = fetchUser();
  const error = new Error('Network request failed');

  // Test the call to asyncData
  generator.next();

  // Test the catch block and failure action
  const next = generator.throw(error);
  expect(next.value).toEqual(put({type: "USER_FETCH_FAILED", message: error.message}));
}

// Run test cases
testFetchUser();
testFetchUserFailure();
