import fs from 'fs';
import path from 'path';

export const readFileAsync = filePath => new Promise(
  (resolve, reject) => fs.readFile(filePath, 'utf8',
    (error, data) => (error ? reject(error) : resolve(data))),
);

export const listDirectoryAsync = dirPath => new Promise(
  (resolve, reject) => fs.readdir(dirPath,
    (error, files) => (error ? reject(error) : resolve(files))),
);

export const writeFileAsync = (filepath, data, options = 'utf8') => new Promise(
  (resolve, reject) => fs.writeFile(filepath, data, options,
    error => (error ? reject(error) : resolve())),
);

export const getFileStatsAsync = filePath => new Promise(
  (resolve, reject) => fs.stat(filePath,
    (error, stats) => error ? reject(error) : resolve(stats)),
);

export const removeFileExtension = fileName => {
  const dotSplit = fileName.split('.');
  return dotSplit.length > 1
    ? dotSplit.slice(0, -1).join('.')
    : fileName;
};

export const expandUserHome = filepath => (filepath[0] === '~')
  ? path.join(process.env.HOME, filepath.slice(1))
  : filepath;

export const checkFileExistsAsync = filePath => new Promise(resolve => {
  fs.access(filePath, fs.constants.F_OK, error => resolve(!error));
});

