  const id = uuidv4();
  todos[id] = { id, text };
  res.status(201).json(todos[id]);
});

// PUT /todos/:id - Update an existing to-do item
app.put('/todos/:id', (req, res) => {
  const { id } = req.params;
  const { text } = req.body;
  if (todos[id]) {
    todos[id].text = text;
    res.json(todos[id]);
  } else {
    res.status(404).send('To-Do not found');
  }
});

// DELETE /todos/:id - Delete an existing to-do item
app.delete('/todos/:id', (req, res) => {
  const { id } = req.params;
  if (todos[id]) {
    delete todos[id];
    res.status(204).send();
  } else {
    res.status(404).send('To-Do not found');
  }
});

