const initializePaymentForm = () => {
  // Set the PAY.JP public key
  Payjp.setPublicKey(process.env.PAYJP_PUBLIC_KEY);

  // Get the submit button and add an event listener
  const submitButton = document.getElementById("button");
  submitButton.addEventListener("click", (e) => {
    e.preventDefault();

    // Get the form and its data
    const formElement = document.getElementById("charge-form");
    const formData = new FormData(formElement);

    // Create a card object with the form data
    const card = {
      number: formData.get("order[number]"),
      cvc: formData.get("order[cvc]"),
      exp_month: formData.get("order[exp_month]"),
      exp_year: `20${formData.get("order[exp_year]")}`,
    };

    // Create a token with the card data
    Payjp.createToken(card, (status, response) => {
      if (status === 200) {
        // Token was created successfully
        const token = response.id;
        const tokenInput = document.createElement('input');
        tokenInput.setAttribute('type', 'hidden');
        tokenInput.setAttribute('name', 'token');
        tokenInput.setAttribute('value', token);
        formElement.appendChild(tokenInput);
      }

      // Remove the name attributes from the credit card details
      document.getElementById("order_number").removeAttribute("name");
      document.getElementById("order_cvc").removeAttribute("name");
      document.getElementById("order_exp_month").removeAttribute("name");
      document.getElementById("order_exp_year").removeAttribute("name");

      // Submit the form
      formElement.submit();
    });
  });
};

// Call the function when the window loads
window.addEventListener("load", initializePaymentForm);

// Test cases to verify the solution
