// Import Vue.js (assuming Vue.js is available in the environment)
const { createApp } = Vue;

// HTML audio elements should be present in the HTML with the following IDs:
// 'addSound', 'trashSound', 'errorSound'

createApp({
  data() {
    return {
      tasks: [],
      newTask: {
        text: '',
        done: false,
        showDeleteError: false
      },
      isError: false,
      doneTaskArray: []
    }
  },
  methods: {
    addTask() {
      if (this.newTask.text.length < 5) {
        this.isError = true;
        setTimeout(() => {
          this.isError = false;
        }, 4000);
        const errorSound = document.getElementById('errorSound');
        errorSound.play();
      } else {
        this.tasks.unshift({ ...this.newTask, showDeleteError: false });
        this.newTask.text = '';
        this.isError = false;
        const addSound = document.getElementById('addSound');
        addSound.play();
      }
    },
    toggleDone(index) {
      this.tasks[index].done = !this.tasks[index].done;
    },
    removeTask(index) {
      const task = this.tasks[index];
      if (!task.done) {
        task.showDeleteError = true;
        const errorSound = document.getElementById('errorSound');
        errorSound.play();
        setTimeout(() => {
          task.showDeleteError = false;
        }, 4000);
      } else {
        const deletedTask = this.tasks.splice(index, 1)[0];
        this.doneTaskArray.push(deletedTask);
        const trashSound = document.getElementById('trashSound');
        trashSound.play();
      }
    }
  }
}).mount('#app');
