class Validator {
    checkStr(value) {
        return typeof value === 'string' && value.trim().length > 0;
    }

    checkInt(value) {
        return Number.isInteger(value) && value > 0;
    }
}

class PersonValidator extends Validator {
    constructor() {
        super();
        this.datamodel_create = {
            name: this.checkStr,
            surname: this.checkStr,
            email: this.checkStr,
            age: this.checkInt,
            address: this.checkStr,
        };

        this.datamodel_read = {
            name: this.checkStr,
            surname: this.checkStr,
            email: this.checkStr,
            age: this.checkInt,
            address: this.checkStr,
        };

        this.datamodel_update = {
            name: this.checkStr,
            surname: this.checkStr,
            email: this.checkStr,
            age: this.checkInt,
            address: this.checkStr,
        };
    }

    validate(schema, data) {
        for (const key in schema) {
            if (!schema[key](data[key])) {
                throw new Error(`Invalid field: ${key}`);
            }
        }
        return true;
    }

    validateCreate(data) {
        return this.validate(this.datamodel_create, data);
    }

    validateRead(data) {
        return this.validate(this.datamodel_read, data);
    }

    validateUpdate(data) {
        return this.validate(this.datamodel_update, data);
    }
}

