const { Tensor } = require('onnxruntime');

/**
 * Creates a tensor and validates its creation based on the data type, data, and dimensions.
 * 
 * @param {string} dataType - The data type of the tensor ('float32', 'bool', 'float64', 'string').
 * @param {TypedArray|Array} data - The data for the tensor.
 * @param {number[]} dims - The dimensions of the tensor.
 * @returns {Tensor} - The created and validated tensor.
 * @throws {Error} - If the tensor creation is invalid.
 */
function createAndValidateTensor(dataType, data, dims) {
    // Validate data type and data match
    if ((dataType === 'float32' && !(data instanceof Float32Array)) ||
        (dataType === 'bool' && !(data instanceof Uint8Array)) ||
        (dataType === 'float64' && !(data instanceof Float64Array)) ||
        (dataType === 'string' && !Array.isArray(data))) {
        throw new Error('Data type and data provided do not match.');
    }

    // Validate non-negative dimensions
    if (dims.some(dim => dim < 0)) {
        throw new Error('Negative dimensions are not allowed.');
    }

    // Validate size match between data and dimensions
    const expectedSize = dims.reduce((acc, dim) => acc * dim, 1);
    if (data.length !== expectedSize) {
        throw new Error('Size mismatch between data and dimensions.');
    }

    // Create and return the tensor
    return new Tensor(dataType, data, dims);
}

// Test cases
