Write a JavaScript function `transformImports` that takes a string of code containing ES6 import statements and an object representing a set of module aliases. The function should return a new string of code where the import statements have been transformed to use the aliases provided.

The function should use Babel to parse and transform the code, applying the aliases to the import statements. The aliases object will have keys representing the original module names and values representing the corresponding aliases.

For example, given the following code and aliases:

```javascript
const code = `
import React from 'react';
import { View, Text } from 'react-native';
`;

const aliases = {
  react: 'qm-react',
  'react-native': 'qm-react-native'
};
```

The `transformImports` function should return a string with the transformed import statements:

```javascript
`
import React from 'qm-react';
import { View, Text } from 'qm-react-native';
`
```

output:
```javascript
const babel = require('@babel/core');
const aliasPlugin = require('@babel/plugin-module-resolver').default;

/**
 * Transforms import statements in the given code using the provided aliases.
 * @param {string} code - The code containing ES6 import statements.
 * @param {Object} aliases - An object with keys as original module names and values as aliases.
 * @returns {string} - The transformed code with updated import statements.
 */
function transformImports(code, aliases) {
  const { code: transformedCode } = babel.transform(code, {
    plugins: [
      [
        aliasPlugin,
        {
          alias: aliases
        }
      ]
    ]
  });
  return transformedCode;
}

// Test cases
const originalCode = `
import React from 'react';
import { View, Text } from 'react-native';
`;

const aliases = {
  react: 'qm-react',
  'react-native': 'qm-react-native'
};

const transformedCode = transformImports(originalCode, aliases);
console.log(transformedCode); // Should log the code with aliased module names

// Additional test case with different aliases
const additionalAliases = {
  react: 'custom-react',
  'react-native': 'custom-react-native'
};

const additionalTransformedCode = transformImports(originalCode, additionalAliases);
console.log(additionalTransformedCode); // Should log the code with the additional aliased module names
