/**
 * Determines whether a given year is a leap year.
 * 
 * @param {number|string} year - The year to be checked.
 * @returns {boolean} True if the year is a leap year, false otherwise.
 */
function isLeapYear(year) {
  const parsedYear = typeof year === 'string' ? parseInt(year, 10) : year;
  if (isNaN(parsedYear)) {
    throw new Error('Invalid input: year must be a number or a string representing a number.');
  }
  return (parsedYear % 4 === 0 && parsedYear % 100 !== 0) || parsedYear % 400 === 0;
}

// Test cases
console.log(isLeapYear(1996)); // true
console.log(isLeapYear(1997)); // false
console.log(isLeapYear(34992)); // true
console.log(isLeapYear(1900)); // false
console.log(isLeapYear(1600)); // true
console.log(isLeapYear(700)); // false
console.log(isLeapYear('1980')); // true
console.log(isLeapYear('2000')); // true
console.log(isLeapYear('1900')); // false
