     * @param {string} name - The name of the style.
     * @param {string} style - The CSS properties of the style.
     */
    addStyle(name, style) {
        this.styles[name] = style;
    }

    /**
     * Retrieves the style properties for a given style name.
     * @param {string} name - The name of the style to retrieve.
     * @returns {string|null} The CSS properties of the style or null if not found.
     */
    getStyle(name) {
        return this.styles[name] || null;
    }

    /**
     * Removes a style from the collection if it exists.
     * @param {string} name - The name of the style to remove.
     */
    removeStyle(name) {
        delete this.styles[name];
    }

    /**
     * Lists all style names currently in the collection.
     * @returns {Array} An array of style names.
     */
    listStyles() {
        return Object.keys(this.styles);
    }
}

