import { createNavigationEnabledStore } from "@expo/ex-navigation";
import { compose, createStore, applyMiddleware } from "redux";
import thunk from "redux-thunk";

// Define action types
const ADD_TODO = 'ADD_TODO';
const REMOVE_TODO = 'REMOVE_TODO';
const LOGIN_USER = 'LOGIN_USER';
const LOGOUT_USER = 'LOGOUT_USER';

// Define reducers
function todosReducer(state = [], action) {
  switch (action.type) {
    case ADD_TODO:
      return [...state, { id: action.id, text: action.text }];
    case REMOVE_TODO:
      return state.filter(todo => todo.id !== action.id);
    default:
      return state;
  }
}

function userReducer(state = { id: null, name: '', isLoggedIn: false }, action) {
  switch (action.type) {
    case LOGIN_USER:
      return { ...state, id: action.id, name: action.name, isLoggedIn: true };
    case LOGOUT_USER:
      return { ...state, name: '', isLoggedIn: false };
    default:
      return state;
  }
}

// Combine reducers
const rootReducer = (state = {}, action) => ({
  todos: todosReducer(state.todos, action),
  user: userReducer(state.user, action),
});

// Create store with navigation and middleware
const composeEnhancers = window.__REDUX_DEVTOOLS_EXTENSION_COMPOSE__ || compose;
const createStoreWithNavigation = createNavigationEnabledStore({
  createStore,
  navigationStateKey: "navigation"
});

const store = createStoreWithNavigation(
  rootReducer,
  {},
  composeEnhancers(applyMiddleware(thunk))
);

// Action creators
function addTodo(id, text) {
  return { type: ADD_TODO, id, text };
}

function removeTodo(id) {
  return { type: REMOVE_TODO, id };
}

function loginUser(id, name) {
  return { type: LOGIN_USER, id, name };
}

function logoutUser() {
  return { type: LOGOUT_USER };
}

// Test cases
console.log('Initial state:', store.getState());

store.dispatch(addTodo(1, 'Learn Redux'));
console.log('After ADD_TODO:', store.getState());

store.dispatch(removeTodo(1));
console.log('After REMOVE_TODO:', store.getState());

store.dispatch(loginUser(123, 'Alice'));
console.log('After LOGIN_USER:', store.getState());

store.dispatch(logoutUser());
console.log('After LOGOUT_USER:', store.getState());

export default store;
