import { CERTIFICATE_STATUS, CERTIFICATE_STATUS_COLORS } from './constants';

/**
 * Calculates the certificate status based on the issue date and validity period.
 * @param {Object} certificate - An object containing the issue date and validity period of the certificate.
 * @returns {Object} An object containing the status and color code of the certificate.
 */
export function getCertificateStatusInfo(certificate) {
  const { issueDate, validityPeriodMonths } = certificate;
  const issueDateObj = new Date(issueDate);
  const currentDate = new Date();
  const expiryDate = new Date(issueDateObj.setMonth(issueDateObj.getMonth() + validityPeriodMonths));
  const aboutToExpireDate = new Date(expiryDate);
  aboutToExpireDate.setMonth(aboutToExpireDate.getMonth() - 1);

  let status;
  if (currentDate < expiryDate) {
    if (currentDate >= aboutToExpireDate) {
      status = CERTIFICATE_STATUS.ABOUT_TO_EXPIRE;
    } else {
      status = CERTIFICATE_STATUS.VALID;
    }
  } else {
    status = CERTIFICATE_STATUS.EXPIRED;
  }

  return {
    status: status,
    color: CERTIFICATE_STATUS_COLORS[status],
  };
}

// Test cases
console.log(getCertificateStatusInfo({ issueDate: '2023-01-01', validityPeriodMonths: 12 })); // Should return { status: 'VALID', color: '#34C38F' } if the current date is before 2024-01-01
console.log(getCertificateStatusInfo({ issueDate: '2022-01-01', validityPeriodMonths: 12 })); // Should return { status: 'EXPIRED', color: '#F46A6A' } if the current date is after 2023-01-01
console.log(getCertificateStatusInfo({ issueDate: '2023-02-01', validityPeriodMonths: 6 })); // Should return { status: 'ABOUT_TO_EXPIRE', color: '#F1B44C' } if the current date is within one month of the expiry date
