import { cloneDeep } from 'lodash';

// Action types
const UPSERT_NOTIFICATION = 'UPSERT_NOTIFICATION';
const DELETE_NOTIFICATION = 'DELETE_NOTIFICATION';
const CLEAR_NOTIFICATIONS = 'CLEAR_NOTIFICATIONS';

// Initial state
const defaultState = [];

/**
 * Reducer function to manage notifications state.
 * @param {Array} state - The current state of notifications.
 * @param {Object} action - The action to be applied to the state.
 * @returns {Array} The new state after applying the action.
 */
const notificationsReducer = (state = defaultState, action) => {
  const newState = cloneDeep(state);

  const notificationIndex = newState.findIndex(
    activeNotification => action && action.payload && activeNotification.id === action.payload.id,
  );

  switch (action.type) {
    case UPSERT_NOTIFICATION: {
      if (notificationIndex !== -1) newState[notificationIndex].message = action.payload.message;
      else newState.push(action.payload);
      return newState;
    }
    case DELETE_NOTIFICATION: {
      if (notificationIndex !== -1) newState.splice(notificationIndex, 1);
      return newState;
    }
    case CLEAR_NOTIFICATIONS: {
      return [];
    }
    default: return newState;
  }
};

export default notificationsReducer;

// Test cases
const testAddNotification = () => {
  const state = [];
  const action = { type: UPSERT_NOTIFICATION, payload: { id: 1, message: 'New notification' } };
  const newState = notificationsReducer(state, action);
  console.assert(newState.length === 1 && newState[0].id === 1, 'Test add notification failed');
};

const testUpdateNotification = () => {
  const state = [{ id: 1, message: 'Old notification' }];
  const action = { type: UPSERT_NOTIFICATION, payload: { id: 1, message: 'Updated notification' } };
  const newState = notificationsReducer(state, action);
  console.assert(newState.length === 1 && newState[0].message === 'Updated notification', 'Test update notification failed');
};

const testDeleteNotification = () => {
  const state = [{ id: 1, message: 'Notification to delete' }];
  const action = { type: DELETE_NOTIFICATION, payload: { id: 1 } };
  const newState = notificationsReducer(state, action);
  console.assert(newState.length === 0, 'Test delete notification failed');
};

const testClearNotifications = () => {
  const state = [{ id: 1, message: 'Notification' }, { id: 2, message: 'Another notification' }];
  const action = { type: CLEAR_NOTIFICATIONS };
  const newState = notificationsReducer(state, action);
  console.assert(newState.length === 0, 'Test clear notifications failed');
};

// Run test cases
testAddNotification();
testUpdateNotification();
testDeleteNotification();
testClearNotifications();
