import { useEffect, useState } from "react";
import * as Location from "expo-location";

// Custom hook to fetch local weather data
export const useLocalWeather = () => {
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState(null);
  const [weather, setWeather] = useState({});

  const fetchWeatherData = async (latitude, longitude) => {
    try {
      const apiKey = process.env.REACT_APP_OPENWEATHER_API_KEY;
      const response = await fetch(
        `https://api.openweathermap.org/data/2.5/weather?lat=${latitude}&lon=${longitude}&appid=${apiKey}&units=metric`
      );
      if (!response.ok) {
        throw new Error('Failed to fetch weather data');
      }
      const data = await response.json();
      setWeather(data);
    } catch (error) {
      setError(error.message || 'Could not fetch weather data');
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => {
    (async () => {
      let { status } = await Location.requestForegroundPermissionsAsync();
      if (status !== 'granted') {
        setError('Permission to access location was denied');
        setLoading(false);
        return;
      }
      let location = await Location.getCurrentPositionAsync({});
      await fetchWeatherData(location.coords.latitude, location.coords.longitude);
    })();
  }, []);

  return { loading, error, weather };
};

// Example usage of the useLocalWeather hook
const WeatherComponent = () => {
  const { loading, error, weather } = useLocalWeather();

  if (loading) return <div>Loading...</div>;
  if (error) return <div>Error: {error}</div>;
  return (
    <div>
      <h1>Local Weather</h1>
      <p>Temperature: {weather.main?.temp}°C</p>
      <p>Conditions: {weather.weather?.[0].description}</p>
    </div>
  );
};

export default WeatherComponent;
