// Importing the necessary package for making HTTP requests
import axios from 'axios';

/**
 * Changes the background color of the document body after a specified delay.
 * @param {string} color - The color to change the body background to.
 * @param {number} delay - The delay in milliseconds before changing the color.
 * @returns {Promise} A promise that resolves after the delay and color change.
 */
function changeBodyColor(color, delay) {
  return new Promise((resolve, reject) => {
    setTimeout(() => {
      try {
        document.body.style.backgroundColor = color;
        resolve(`Changed to ${color}`);
      } catch (error) {
        reject(error);
      }
    }, delay);
  });
}

/**
 * Performs a sequence of color changes on the document body in parallel.
 * @param {Array<string>} colors - An array of color names.
 * @param {Array<number>} delays - An array of delays corresponding to each color.
 * @returns {Promise} A promise that resolves when all color changes have completed.
 */
async function performColorSequence(colors, delays) {
  if (colors.length !== delays.length) {
    throw new Error('Colors and delays arrays must be of the same length.');
  }

  const colorChangePromises = colors.map((color, index) => {
    return changeBodyColor(color, delays[index]);
  });

  const results = await Promise.all(colorChangePromises);
  return results;
}

// Test cases
performColorSequence(['red', 'green', 'blue'], [1000, 2000, 3000])
  .then(results => console.log('Color sequence completed:', results))
  .catch(error => console.error('An error occurred:', error));

performColorSequence(['purple', 'yellow'], [1500, 1500])
  .then(results => console.log('Color sequence completed:', results))
  .catch(error => console.error('An error occurred:', error));

// This should throw an error because the arrays are of different lengths
performColorSequence(['pink', 'cyan'], [1000])
  .then(results => console.log('Color sequence completed:', results))
  .catch(error => console.error('An error occurred:', error));
