import ModalComponent from '@/components/common-component/Modal.vue'

const ModalConstructor = Vue.extend(ModalComponent)

let modalInstance = null

function getModalInstance() {
  if (modalInstance) return modalInstance

  modalInstance = new ModalConstructor({
    el: document.createElement('div')
  })

  return modalInstance
}

const modal = {
  open(options = {}) {
    const instance = getModalInstance()

    if (typeof options.content === 'object') {
      instance.$slots.default = [options.content]
    } else if (typeof options.content === 'string') {
      instance.content = options.content
    }

    if (typeof options.onClose === 'function') {
      instance.onClose = options.onClose
    }

    document.body.appendChild(instance.$el)
    Vue.nextTick(() => {
      instance.visible = true
    })
  },
  close() {
    if (modalInstance) {
      modalInstance.visible = false
      modalInstance.onClose && modalInstance.onClose()
      modalInstance = null // Destroy the instance after closing
    }
  }
}

export default {
  install() {
    if (!Vue.prototype.$modal) {
      Vue.prototype.$modal = modal
    }
  }
