};

/**
 * Asynchronously reads the content of a log file.
 * @param {string} filename - The name of the log file to read.
 * @returns {Promise<string|null>} A promise that resolves to the content of the log file, or null if an error occurs.
 */
async function getLogContent(filename) {
    const filePath = path.join(auditDirPath, filename);
    try {
        const content = await fs.promises.readFile(filePath, 'utf-8');
        return content;
    } catch (error) {
        console.error(`Error reading file '${filename}':`, error);
        return null;
    }
}

/**
 * Asynchronously retrieves the list of log filenames in the 'audit' directory.
 * @returns {Promise<string[]>} A promise that resolves to an array of log filenames, or an empty array if an error occurs.
 */
async function getLogFilenames() {
    try {
        const filenames = await fs.promises.readdir(auditDirPath);
        return filenames;
    } catch (error) {
        console.error('Error reading the audit directory:', error);
        return [];
    }
}

