/**
 * Class representing a study session timer with study and break intervals.
 */
class StudySessionTimer {
  constructor() {
    this.studyTime = 0;
    this.breakTime = 0;
    this.currentIntervalStart = 0;
    this.currentIntervalType = null; // 'study' or 'break'
  }

  /**
   * Starts a study interval.
   */
  startStudy() {
    if (this.currentIntervalType === 'study') {
      throw new Error('Study interval is already in progress.');
    }
    this.currentIntervalType = 'study';
    this.currentIntervalStart = new Date().getTime();
  }

  /**
   * Starts a break interval.
   */
  startBreak() {
    if (this.currentIntervalType !== 'study') {
      throw new Error('Cannot start a break without an active study interval.');
    }
    this.stopCurrentInterval();
    this.currentIntervalType = 'break';
    this.currentIntervalStart = new Date().getTime();
  }

  /**
   * Stops the current interval.
   */
  stopCurrentInterval() {
    if (!this.currentIntervalType) {
      throw new Error('No active interval to stop.');
    }
    const now = new Date().getTime();
    const intervalDuration = now - this.currentIntervalStart;
    if (this.currentIntervalType === 'study') {
      this.studyTime += intervalDuration;
    } else {
      this.breakTime += intervalDuration;
    }
    this.currentIntervalType = null;
    this.currentIntervalStart = 0;
  }

  /**
   * Resets the timer.
   */
  reset() {
    this.studyTime = 0;
    this.breakTime = 0;
    this.currentIntervalStart = 0;
    this.currentIntervalType = null;
  }

  /**
   * Gets the total time spent in the study session.
   * @return {number} Total time in milliseconds.
   */
  getTotalTime() {
    return this.studyTime + this.breakTime;
  }

  /**
   * Gets the total time spent on study intervals.
   * @return {number} Study time in milliseconds.
   */
  getStudyTime() {
    return this.studyTime;
  }

  /**
   * Gets the total time spent on break intervals.
   * @return {number} Break time in milliseconds.
   */
  getBreakTime() {
    return this.breakTime;
  }

  /**
   * Converts time in milliseconds to a human-readable string.
   * @param {number} time Time in milliseconds.
   * @return {string} Time in the format 'HH:MM:SS'.
   */
  static convertTimeToString(time) {
    const seconds = Math.floor((time / 1000) % 60);
    const minutes = Math.floor((time / (1000 * 60)) % 60);
    const hours = Math.floor((time / (1000 * 60 * 60)) % 24);

    const hoursStr = (hours < 10) ? "0" + hours : hours;
    const minutesStr = (minutes < 10) ? "0" + minutes : minutes;
    const secondsStr = (seconds < 10) ? "0" + seconds : seconds;

    return hoursStr + ':' + minutesStr + ':' + secondsStr;
  }
}

// Test cases
const timer = new StudySessionTimer();

// Start a study interval
timer.startStudy();
setTimeout(() => {
  // After 1 second, start a break interval
  timer.stopCurrentInterval();
  timer.startBreak();
  setTimeout(() => {
    // After another second, stop the break interval
    timer.stopCurrentInterval();
    console.log('Study Time:', StudySessionTimer.convertTimeToString(timer.getStudyTime())); // Should be 00:00:01
    console.log('Break Time:', StudySessionTimer.convertTimeToString(timer.getBreakTime())); // Should be 00:00:01
    console.log('Total Time:', StudySessionTimer.convertTimeToString(timer.getTotalTime())); // Should be 00:00:02
  }, 1000);
}, 1000);
