/**
 * Converts a given integer number into its word representation in English.
 * Handles numbers from 0 to 999.
 * 
 * @param {number} number - The integer number to convert.
 * @returns {string} - The word representation of the number.
 */
function convertNumberToWords(number) {
  // Define an object that maps numbers to their word form
  const numbersToWords = {
    0: "zero", 1: "one", 2: "two", 3: "three", 4: "four", 5: "five", 6: "six", 7: "seven", 8: "eight",
    9: "nine", 10: "ten", 11: "eleven", 12: "twelve", 13: "thirteen", 14: "fourteen", 15: "fifteen",
    16: "sixteen", 17: "seventeen", 18: "eighteen", 19: "nineteen", 20: "twenty", 30: "thirty",
    40: "forty", 50: "fifty", 60: "sixty", 70: "seventy", 80: "eighty", 90: "ninety",
  };

  // Check if the number is directly mapped in the object
  if (number in numbersToWords) return numbersToWords[number];

  // Initialize the words variable to an empty string
  let words = "";

  // Handle the hundreds place
  if (number >= 100) {
    words += numbersToWords[Math.floor(number / 100)] + " hundred";
    number %= 100;
    if (number > 0) words += " and ";
  }

  // Handle the tens and ones places
  if (number >= 20) {
    words += numbersToWords[Math.floor(number / 10) * 10];
    number %= 10;
    if (number > 0) words += "-" + numbersToWords[number];
  } else if (number > 0) {
    words += numbersToWords[number];
  }

  return words;
}

// Test cases to verify the solution
console.log(convertNumberToWords(0)); // "zero"
console.log(convertNumberToWords(9)); // "nine"
console.log(convertNumberToWords(10)); // "ten"
console.log(convertNumberToWords(17)); // "seventeen"
console.log(convertNumberToWords(20)); // "twenty"
console.log(convertNumberToWords(45)); // "forty-five"
console.log(convertNumberToWords(99)); // "ninety-nine"
console.log(convertNumberToWords(100)); // "one hundred"
console.log(convertNumberToWords(101)); // "one hundred and one"
console.log(convertNumberToWords(123)); // "one hundred and twenty-three"
console.log(convertNumberToWords(300)); // "three hundred"
console.log(convertNumberToWords(310)); // "three hundred and ten"
console.log(convertNumberToWords(999)); // "nine hundred and ninety-nine"
