import { Map } from 'immutable';

// Action types
const FETCH_COURSE_SUCCESS = 'FETCH_COURSE_SUCCESS';
const SELECT_COURSE = 'SELECT_COURSE';
const UNSELECT_COURSE = 'UNSELECT_COURSE';

/**
 * Normalizes the courses array into an object with course ids as keys.
 * @param {Array} courses - The array of courses to normalize.
 * @returns {Object} The normalized courses object.
 */
function coursesNormalizer(courses) {
  return courses.reduce((acc, course) => {
    acc[course.id] = { ...course, isSelected: false };
    return acc;
  }, {});
}

/**
 * The course reducer function to manage the state of courses.
 * @param {Map} [state=Map({})] - The current state of the courses.
 * @param {Object} action - The action to be handled.
 * @returns {Map} The new state of the courses.
 */
function courseReducer(state = Map({}), action) {
  switch (action.type) {
    case FETCH_COURSE_SUCCESS:
      return Map(coursesNormalizer(action.data));
    case SELECT_COURSE:
      return state.setIn([action.index, 'isSelected'], true);
    case UNSELECT_COURSE:
      return state.setIn([action.index, 'isSelected'], false);
    default:
      return state;
  }
}

// Test cases
describe('Testing courseReducer', () => {
  it('Test that the default state returns an empty Map', () => {
    const res = courseReducer();
    expect(res.toJS()).toStrictEqual({});
  });

  it('Test that FETCH_COURSE_SUCCESS returns the data passed', () => {
    const action = {
      type: FETCH_COURSE_SUCCESS,
      data: [
        {
          id: 1,
          name: "ES6",
          credit: 60
        },
        {
          id: 2,
          name: "Webpack",
          credit: 20
        },
        {
          id: 3,
          name: "React",
          credit: 40
        }
      ]
    };
    const expected = {
      1: { id: 1, name: "ES6", isSelected: false, credit: 60 },
      2: { id: 2, name: "Webpack", isSelected: false, credit: 20 },
      3: { id: 3, name: "React", isSelected: false, credit: 40 }
