    const repo = await loadRoomsCollection();
    const code = Math.random().toString(36).substring(2, 6).toUpperCase();
    const inserted = await repo.insertOne({ code });
    res.send(inserted.ops[0]);
  } catch (error) {
    res.status(500).send(error);
  }
}

