import React, { useState } from 'react';

/**
 * A higher-order component that wraps a given component and adds a monitoring panel.
 * @param {Function} monitorStore - A function that returns the current state and actions log.
 * @returns {Function} - A function that takes a component and returns a new component with monitoring.
 */
export default function withMonitoring(monitorStore) {
  return (ComposedComponent) => {
    return class WithMonitoring extends React.Component {
      constructor(props) {
        super(props);
        this.state = {
          isPanelOpen: false,
        };
      }

      togglePanel = () => {
        this.setState(prevState => ({ isPanelOpen: !prevState.isPanelOpen }));
      };

      render() {
        const { isPanelOpen } = this.state;
        const { state, actions } = monitorStore();
        return (
          <div>
            <ComposedComponent {...this.props} />
            <div style={{ position: 'fixed', bottom: 0, width: '100%' }}>
              <button onClick={this.togglePanel}>
                {isPanelOpen ? 'Hide Monitoring Panel' : 'Show Monitoring Panel'}
              </button>
              {isPanelOpen && (
                <div>
                  <h2>State:</h2>
                  <pre>{JSON.stringify(state, null, 2)}</pre>
                  <h2>Actions:</h2>
                  <ul>
                    {actions.map((action, index) => (
                      <li key={index}>{JSON.stringify(action)}</li>
                    ))}
                  </ul>
                </div>
              )}
            </div>
          </div>
        );
      }
    };
  };
}

