const jwt = require('jsonwebtoken');
const ErrorResponse = require('../utils/errorResponse');
const SuperAdmin = require('../models/SuperAdmin');
const Admin = require('../models/Admin');
const Tutor = require('../models/Tutor');
const Student = require('../models/Student');
const Roles = require('../utils/roles');

// Middleware to protect routes and grant access based on roles
const authorizeAccess = (permittedRoles) => async (req, res, next) => {
    let token;

    // Check for token in headers or cookies
    if (req.headers.authorization && req.headers.authorization.startsWith('Bearer')) {
        token = req.headers.authorization.split(' ')[1];
    } else if (req.cookies.token) {
        token = req.cookies.token;
    }

    // If no token, respond with an error
    if (!token) {
        return next(new ErrorResponse('Not authorized to access this route', 401));
    }

    try {
        // Verify and decode the token
        const decoded = jwt.verify(token, process.env.JWT_SECRET);
        const role = decoded.role;

        // Find the user based on role and ID
        let user;
        switch (role) {
            case Roles.SUPER_ADMIN:
                user = await SuperAdmin.findById(decoded.id);
                break;
            case Roles.ADMIN:
                user = await Admin.findById(decoded.id);
                break;
            case Roles.TUTOR:
                user = await Tutor.findById(decoded.id);
                break;
            case Roles.STUDENT:
                user = await Student.findById(decoded.id);
                break;
            default:
                return next(new ErrorResponse('Invalid role found in token', 401));
        }

        // If user not found or role not permitted, respond with an error
        if (!user || !permittedRoles.includes(role)) {
            return next(new ErrorResponse(`Role ${role} is not authorized to access this route`, 403));
        }

        // Attach user to request and proceed
        req.user = user;
        next();
    } catch (err) {
        return next(new ErrorResponse('Not authorized to access this route', 401));
    }
};

module.exports = authorizeAccess;

// Example usage in an Express.js application
const express = require('express');
const app = express();

// Import routes
const adminRoutes = require('./routes/adminRoutes');
const tutorRoutes = require('./routes/tutorRoutes');
const studentRoutes = require('./routes/studentRoutes');

// Use the middleware to protect routes
app.use('/admin', authorizeAccess(['SuperAdmin', 'Admin']), adminRoutes);
app.use('/tutor', authorizeAccess(['Tutor']), tutorRoutes);
app.use('/student', authorizeAccess(['Student']), studentRoutes);

// Start the server
const PORT = process.env.PORT || 3000;
app.listen(PORT, () => console.log(`Server running on port ${PORT}`));
