require('isomorphic-fetch');

/**
 * Fetches data from the backend for a given entity type.
 * @param {string} entity - The type of entity to fetch ('orders', 'order_details', 'customers', 'items').
 * @returns {Promise<Object[]>} - A promise that resolves to an array of entities.
 */
export const fetchEntity = (entity) => 
    fetch(`http://localhost:3001/${entity}`)
        .then((response) => {
            if (response.status >= 400) {
                throw new Error("Bad response from server");
            }
            return response.json();
        });

/**
 * Finds the price of an item by its ID.
 * @param {Object[]} items - An array of item objects.
 * @param {number} item_id - The ID of the item.
 * @param {Function} priceGetter - A function to get the desired price (cost_price or sale_price).
 * @returns {number} - The price of the item.
 */
export const getPrice = (items, item_id, priceGetter) => {
    const item = items.find(item => item.id === item_id);
    return item ? priceGetter(item) : 0;
};

/**
 * Calculates the total price for a given order.
 * @param {Object} data - An object containing 'order_details' and 'items'.
 * @param {number} orderId - The ID of the order.
 * @param {Function} priceGetter - A function to get the desired price (cost_price or sale_price).
 * @returns {number} - The total price of the order.
 */
export const calculatePrice = (data, orderId, priceGetter) => {
    const { order_details, items } = data;
    const orderDetails = order_details.filter(order => order.order_id === orderId);

    return orderDetails.reduce((prev, current) => 
        getPrice(items, current.item_id, priceGetter) * current.quantity + prev, 0);
};

// Example usage:
(async () => {
    try {
        const orders = await fetchEntity('orders');
        const orderDetails = await fetchEntity('order_details');
        const items = await fetchEntity('items');
        const data = { order_details: orderDetails, items: items };

        const orderId = 1; // Assuming we want to calculate prices for order with ID 1
        const totalCostPrice = calculatePrice(data, orderId, item => item.cost_price);
        const totalSalesPrice = calculatePrice(data, orderId, item => item.sale_price);

        console.log(`Total Cost Price for order ${orderId}: $${totalCostPrice}`);
        console.log(`Total Sales Price for order ${orderId}: $${totalSalesPrice}`);
    } catch (error) {
        console.error(error);
    }
})();
