import Question from "../Question";
import Database from "./Database";
import Schema from "./Schema";
import Field from "./Field";
import Dimension from "../Dimension";
import StructuredQuery from "metabase-lib/lib/queries/StructuredQuery";
import { singularize } from "metabase/lib/formatting";
import _ from "underscore";

type SchemaName = string;
type FieldMetadata = Object;
type EntityType = string;

export default class Table {
  description: string;
  db: Database;
  schema: ?Schema;
  schema_name: ?SchemaName;
  fields: FieldMetadata[];
  entity_type: ?EntityType;

  constructor(db: Database, schema: ?Schema, fields: FieldMetadata[], entity_type: ?EntityType) {
    this.db = db;
    this.schema = schema;
    this.fields = fields;
    this.entity_type = entity_type;
    this.schema_name = schema ? schema.name : null;
  }

  hasSchema(): boolean {
    return !!this.schema_name;
  }

  newQuestion(): Question {
    return new Question(this.db.id, this.id, this.metadata).setDefaultQuery().setDefaultDisplay();
  }

  query(query = {}): StructuredQuery {
    let baseQuery = new Question(this.db.id, this.id, this.metadata).query();
    return new StructuredQuery({ ...baseQuery, ...query });
  }

  dimensions(): Dimension[] {
    return this.fields.map(field => new Dimension(field));
  }

  displayName({ includeSchema } = {}): string {
    return (includeSchema && this.schema ? this.schema.displayName() + "." : "") + this.display_name;
  }

  isQueryable(): boolean {
    return this.visibility_type == null;
  }

  objectName(): string {
    return singularize(this.displayName());
  }

  dateFields(): Field[] {
    return this.fields.filter(field => field.isDate());
  }

  aggregationOperators(): Array<Object> {
    return this.aggregation_operators || [];
  }

  aggregation(agg: string): ?Object {
    return _.findWhere(this.aggregationOperators(), { short: agg });
  }
}

// Example usage:
const db = new Database(/* ... */);
const schema = new Schema(/* ... */);
const fields = [new Field(/* ... */), new Field(/* ... */)];
const table = new Table(db, schema, fields, "entityType");

