class Fibonacci {
    constructor() {
        this.previous = 0n; // Use BigInt for large numbers
        this.current = 1n;
    }

    next() {
        const next = this.previous + this.current;
        this.previous = this.current;
        this.current = next;
        return next;
    }

    init(seed) {
        this.previous = 0n;
        this.current = 1n;
        seed = BigInt(seed); // Convert seed to BigInt

        while (this.current < seed) {
            this.next();
        }

        if (this.current !== seed) {
            throw new Error('Not a real Fibonacci number!');
        }
    }

    skip(forward) {
        for (let i = 0; i < forward; i++) {
            this.next();
        }
        return this.current;
    }
}

// Export the class if using in a Node.js environment
// module.exports = Fibonacci;

// Test cases
try {
    const fib = new Fibonacci();
    console.log(fib.next().toString()); // Should print "1"
    console.log(fib.next().toString()); // Should print "2"
    console.log(fib.next().toString()); // Should print "3"
    fib.init(21); // Should not throw an error
    console.log(fib.next().toString()); // Should print "34"
    console.log(fib.skip(5).toString()); // Should print "610"
    fib.init(22); // Should throw an error
} catch (error) {
    console.error(error.message);
}
