"use strict";

function newMap(callback) {
  if (typeof this === "string") {
    const lengthOfStr = this.length;
    if (lengthOfStr < 1) return "";

    let str = "";
    for (let count = 0; count < lengthOfStr; count++) {
      const newStr = callback({
        value: this[count],
        index: count,
        context: this
      });
      if (newStr !== undefined) {
        str += newStr;
      }
    }
    return str;

  } else if (this !== null && typeof this === "object" && !Array.isArray(this)) {
    const objectKeys = Object.keys(this);
    const newObject = {};
    objectKeys.forEach((key, index) => {
      const item = callback({
        value: this[key],
        index: index,
        context: this,
        key: key,
      });
      if (item !== undefined) {
        newObject[key] = item;
      }
    });
    return newObject;

  } else if (Array.isArray(this)) {
    const newArray = [];
    this.forEach((value, index) => {
      const newItem = callback({
        value: value,
        index: index,
        context: this,
      });
      if (newItem !== undefined) {
        newArray.push(newItem);
      }
    });
    return newArray;

  } else {
    throw new Error("Invalid Type: Map function can only work with Object, String, and Array");
  }
}

// Extend the prototype of String, Array, and Object to include the newMap function
String.prototype.newMap = newMap;
Array.prototype.newMap = newMap;
Object.prototype.newMap = newMap;

// Test cases
console.log("Test Case 1 (String):", "hello".newMap(({ value }) => value.toUpperCase())); // "HELLO"
console.log("Test Case 2 (Array):", [1, 2, 3].newMap(({ value }) => value * 2)); // [2, 4, 6]
console.log("Test Case 3 (Object):", { a: 1, b: 2, c: 3 }.newMap(({ value }) => value + 1)); // { a: 2, b: 3, c: 4 }
console.log("Test Case 4 (Exclude undefined):", "test".newMap(({ value }) => value === 'e' ? undefined : value)); // "tst"
try {
  console.log("Test Case 5 (Invalid Type):", newMap.call(123, ({ value }) => value)); // Should throw error
} catch (e) {
  console.error("Test Case 5 (Invalid Type):", e.message);
}
