    throw new Error('Challenge duration must be an integer between 1 and 365.');
  }

  if (typeof selectedOpponent !== 'string' || selectedOpponent.trim() === '') {
    throw new Error('Selected opponent must be a non-empty string.');
  }

  return {
    isValid: true,
    data: {
