class DateCalculation {
    millisecondsPerWeek = 1000 * 60 * 60 * 24 * 7;
    millisecondsPerDay = 1000 * 60 * 60 * 24;
    startDate = new Date('1970-01-05');
    weekdays_names = [
        'Воскресенье',
        'Понедельник',
        'Вторник',
        'Среда',
        'Четверг',
        'Пятница',
        'Суббота'
    ];

    get_time(date) {
        return date.getHours().toString().padStart(2, "0")
            + ':' + date.getMinutes().toString().padStart(2, "0");
    }

    get_time_period(date, duration) {
        let time_start = this.get_time(date);
        date.setMinutes(date.getMinutes() + duration);
        return time_start + ' - ' + this.get_time(date);
    }

    get_weekday(date) {
        return this.weekdays_names[date.getDay()];
    }

    get_day(date) {
        return date.getDate().toString().padStart(2, "0") + "."
            + (date.getMonth() + 1).toString().padStart(2, "0");
    }

    get_day_with_year(date) {
        return date.getDate().toString().padStart(2, "0") + "."
            + (date.getMonth() + 1).toString().padStart(2, "0") + "."
            + date.getFullYear().toString().padStart(2, "0");
    }

    get_current_day() {
        return new Date();
    }

    get_week_from_date(date) {
        let differenceInMilliseconds = date - this.startDate + this.millisecondsPerDay;
        return Math.ceil(differenceInMilliseconds / this.millisecondsPerWeek);
    }

    get_current_week() {
        return this.get_week_from_date(this.get_current_day());
    }

    get_week_range(weekNumber) {
        const startOfWeek = new Date(this.startDate.getTime() + (weekNumber - 1) * this.millisecondsPerWeek);
        const endOfWeek = new Date(startOfWeek.getTime() + this.millisecondsPerWeek);
        return [startOfWeek, endOfWeek];
    }

    get_week_range_without_monday(weekNumber) {
        const startOfWeek = new Date(this.startDate.getTime() + (weekNumber - 1) * this.millisecondsPerWeek);
        const endOfWeek = new Date(startOfWeek.getTime() + this.millisecondsPerWeek - this.millisecondsPerDay);
        return [startOfWeek, endOfWeek];
    }

    get_week_range_for_db(weekNumber) {
        let weekRange = this.get_week_range(weekNumber);
        return [
            weekRange[0].toISOString().slice(0, 19).replace('T', ' '),
            weekRange[1].toISOString().slice(0, 19).replace('T', ' '),
        ];
    }

    get_date_for_db(date) {
        return date.toISOString().slice(0, 19).replace('T', ' ');
    }

    get_week_range_for_text(weekNumber) {
        return this.get_day_with_year(this.get_week_range_without_monday(weekNumber)[0])
            + ' - ' + this.get_day_with_year(this.get_week_range_without_monday(weekNumber)[1]);
    }
}

// Export the class for use in other modules
module.exports = new DateCalculation();

// Test cases to verify the solution correctness
const dateCalc = new DateCalculation();
const testDate = new Date('2023-04-01T12:30:00');

console.log('Time period:', dateCalc.get_time_period(new Date(testDate), 90)); // Expected format: "HH:MM - HH:MM"
console.log('Weekday:', dateCalc.get_weekday(testDate)); // Expected: "Суббота"
console.log('Day and month:', dateCalc.get_day(testDate)); // Expected format: "DD.MM"
console.log('Day, month, and year:', dateCalc.get_day_with_year(testDate)); // Expected format: "DD.MM.YYYY"
console.log('Current day:', dateCalc.get_current_day()); // Expected: Current date object
console.log('Week number from date:', dateCalc.get_week_from_date(testDate)); // Expected: Week number since 1970-01-05
console.log('Current week number:', dateCalc.get_current_week()); // Expected: Current week number since 1970-01-05
console.log('Week range:', dateCalc.get_week_range(10)); // Expected: Array with start and end dates of week 10
console.log('Week range without Monday:', dateCalc.get_week_range_without_monday(10)); // Expected: Array with start and end dates of week 10, excluding Monday
console.log('Week range for DB:', dateCalc.get_week_range_for_db(10)); // Expected format: ["YYYY-MM-DD HH:MM:SS", "YYYY-MM-DD HH:MM:SS"]
console.log('Date for DB:', dateCalc.get_date_for_db(testDate)); // Expected format: "YYYY-MM-DD HH:MM:SS"
console.log('Week range for text:', dateCalc.get_week_range_for_text(10)); // Expected format: "DD.MM.YYYY - DD.MM.YYYY"
