const textToSpeech = require('@google-cloud/text-to-speech');

// Import other required libraries
const fs = require('fs');
const util = require('util');

// Creates a client
const client = new textToSpeech.TextToSpeechClient();

/**
 * Synthesizes the provided text into speech and saves it as an MP3 file.
 * 
 * @param {string} text - The text to be converted to speech.
 * @param {string} filename - The name of the file to save the speech audio to.
 * @param {string} languageCode - The language code for the speech synthesis (e.g., 'en-US').
 * @param {string} ssmlGender - The gender of the voice used in the speech synthesis ('MALE', 'FEMALE', 'NEUTRAL').
 * @returns {Promise<void>} A promise that resolves when the speech synthesis is complete and the file is saved.
 */
async function synthesizeSpeechToFile(text, filename, languageCode, ssmlGender) {
  try {
    // Construct the request
    const request = {
      input: { text: text },
      voice: { languageCode: languageCode, ssmlGender: ssmlGender },
      audioConfig: { audioEncoding: 'MP3' },
    };

    // Performs the text-to-speech request
    const [response] = await client.synthesizeSpeech(request);

    // Write the binary audio content to a local file
    const writeFile = util.promisify(fs.writeFile);
    await writeFile(filename, response.audioContent, 'binary');
    console.log(`Audio content written to file: ${filename}`);
  } catch (error) {
    console.error('Error during text-to-speech synthesis:', error);
  }
}

// Test cases
