        password: validations.password(password),
        repeatPassword: password === repeatPassword ? null : ["Passwords do not match."]
    };

    // Check if there are any errors
    const hasErrors = Object.values(errors).some(error => error !== null);

    if (hasErrors) {
        return errors;
    } else {
        return { success: "Registration form is valid." };
    }
}

