import { combineReducers } from 'redux';

// Other reducers (assume they are implemented)
import userReducer from './userReducer';
import settingsReducer from './settingsReducer';

// Action Types
const ADD_NOTE = 'ADD_NOTE';
const DELETE_NOTE = 'DELETE_NOTE';
const TOGGLE_NOTE = 'TOGGLE_NOTE';

// Notes Reducer
const notesReducer = (state = [], action) => {
  switch (action.type) {
    case ADD_NOTE:
      return [
        ...state,
        {
          id: action.id,
          text: action.text,
          completed: false,
        },
      ];
    case DELETE_NOTE:
      return state.filter(note => note.id !== action.id);
    case TOGGLE_NOTE:
      return state.map(note =>
        note.id === action.id ? { ...note, completed: !note.completed } : note
      );
    default:
      return state;
  }
};

// Combine reducers
const rootReducer = combineReducers({
  notes: notesReducer,
  user: userReducer,
  settings: settingsReducer,
});

export default rootReducer;

// Test cases
const testAddNote = () => {
  const stateBefore = [];
  const action = { type: ADD_NOTE, id: 1, text: 'Learn Redux' };
  const stateAfter = [{ id: 1, text: 'Learn Redux', completed: false }];

  console.assert(
    JSON.stringify(notesReducer(stateBefore, action)) === JSON.stringify(stateAfter),
    'Test add note failed'
  );
};

const testDeleteNote = () => {
  const stateBefore = [{ id: 1, text: 'Learn Redux', completed: false }];
  const action = { type: DELETE_NOTE, id: 1 };
  const stateAfter = [];

  console.assert(
    JSON.stringify(notesReducer(stateBefore, action)) === JSON.stringify(stateAfter),
    'Test delete note failed'
  );
};

const testToggleNote = () => {
  const stateBefore = [{ id: 1, text: 'Learn Redux', completed: false }];
  const action = { type: TOGGLE_NOTE, id: 1 };
  const stateAfter = [{ id: 1, text: 'Learn Redux', completed: true }];

  console.assert(
    JSON.stringify(notesReducer(stateBefore, action)) === JSON.stringify(stateAfter),
    'Test toggle note failed'
  );
};

// Run test cases
testAddNote();
testDeleteNote();
testToggleNote();
console.log('All tests passed!');
