            return newToken;
        } catch (error) {
            throw new Error('Error adding token to whitelist: ' + error.message);
        }
    },
    checkToken: async function(token) {
        try {
            const tokenExists = await Whitelist.findOne({ token });
            return tokenExists !== null;
        } catch (error) {
            throw new Error('Error checking token in whitelist: ' + error.message);
        }
    },
    removeToken: async function(token) {
        try {
            const result = await Whitelist.deleteOne({ token });
