const mongoose = require("mongoose");
const Schema = mongoose.Schema;

// Define the balance schema
const balanceSchema = new Schema(
  {
    address: { type: String, required: true },
    balance: { type: String, required: true },
  },
  {
    timestamps: true,
  }
);

// Create the model
const Balance = mongoose.model("Balance", balanceSchema);

/**
 * Creates a new balance entry with the given address and balance.
 * @param {string} address - The wallet address.
 * @param {string} balance - The balance as a string.
 * @returns {Promise<Object>} The created balance entry.
 */
async function createBalance(address, balance) {
  if (!address || typeof address !== 'string') {
    throw new Error('Address must be a non-empty string.');
  }
  if (!balance || typeof balance !== 'string' || !/^\d+$/.test(balance)) {
    throw new Error('Balance must be a non-negative integer string.');
  }
  const balanceEntry = new Balance({ address, balance });
  return balanceEntry.save();
}

/**
 * Updates the balance for the given address with newBalance.
 * @param {string} address - The wallet address.
 * @param {string} newBalance - The new balance as a string.
 * @returns {Promise<Object>} The updated balance entry.
 */
async function updateBalance(address, newBalance) {
  if (!newBalance || typeof newBalance !== 'string' || !/^\d+$/.test(newBalance)) {
    throw new Error('New balance must be a non-negative integer string.');
  }
  return Balance.findOneAndUpdate({ address }, { balance: newBalance }, { new: true });
}

/**
 * Retrieves the balance for the given address.
 * @param {string} address - The wallet address.
 * @returns {Promise<Object>} The balance entry.
 */
async function getBalance(address) {
  return Balance.findOne({ address });
}

/**
 * Deletes the balance entry for the given address.
 * @param {string} address - The wallet address.
 * @returns {Promise<Object>} The deleted balance entry.
 */
async function deleteBalance(address) {
  return Balance.findOneAndDelete({ address });
}

// Export the functions
module.exports = {
  createBalance,
  updateBalance,
  getBalance,
  deleteBalance,
};

