/**
 * Finds and returns the element at the specified index in the given array.
 * If the index is negative, it counts from the end of the array.
 * Returns `undefined` if the index is out of bounds.
 *
 * @param {Array} array - The array to search in.
 * @param {number} index - The index of the element to find.
 * @return {*} The element at the specified index or `undefined`.
 */
function findElementByIndex(array, index) {
    if (!Number.isInteger(index)) {
        throw new Error('The index must be an integer.');
    }

    const adjustedIndex = index < 0 ? array.length + index : index;

    if (adjustedIndex < 0 || adjustedIndex >= array.length) {
        return undefined;
    }

    return array[adjustedIndex];
}

// Test cases
