// Import Redux to create a store and to dispatch actions
import { createStore } from 'redux';

// Action types
const INCREMENT = 'INCREMENT';
const DECREMENT = 'DECREMENT';

// Action creators
function incrementAction(amount) {
  return {
    type: INCREMENT,
    data: amount,
  };
}

function decrementAction(amount) {
  return {
    type: DECREMENT,
    data: amount,
  };
}

// Initial state of the counter
const initialState = 0;

// Reducer function
function counterReducer(state = initialState, action) {
  switch (action.type) {
    case INCREMENT:
      return state + action.data;
    case DECREMENT:
      return state - action.data;
    default:
      return state;
  }
}

// Create Redux store with the reducer
const store = createStore(counterReducer);

// Test cases
console.log('Initial state:', store.getState()); // Should log 0

store.dispatch(incrementAction(5));
console.log('After incrementing by 5:', store.getState()); // Should log 5

