import { CelsiusToFahrenheit } from "@ilihub/celsius-to-fahrenheit";

/**
 * Converts temperature from Celsius to Fahrenheit or vice versa.
 * @param {number} temperature - The temperature value to convert.
 * @param {string} unit - The unit of the input temperature ('Celsius' or 'Fahrenheit').
 * @returns {number} - The converted temperature value.
 */
function convertTemperature(temperature, unit) {
  if (unit === 'Celsius') {
    return CelsiusToFahrenheit(temperature);
  } else if (unit === 'Fahrenheit') {
    return (temperature - 32) * 5 / 9;
  } else {
    throw new Error('Invalid unit. Please provide either "Celsius" or "Fahrenheit".');
  }
}

