        case 'AUTH_LOGIN_FAILURE':
            return {
                fetching: 'FAILURE',
                session: "LOGOUT",
                currentUser: action.name,
                currentId: -1,
            };
        case 'AUTH_LOGIN_STATUS_NOT_FOUND':
            return {
                fetching: 'NOTFOUND',
                session: "LOGOUT",
                currentUser: '',
                currentId: -1,
            };
        case 'AUTH_LOGOUT':
            return {
                fetching: 'SUCCESS',
                session: "LOGOUT",
                currentUser: '',
                currentId: -1,
