// Importing necessary modules
const { addBook, removeBook, searchByTitle, searchByAuthor } = require('./libraryManager');

/**
 * Adds a new book to the collection.
 * @param {Object} book - The book object to add.
 * @param {string} book.title - The title of the book.
 * @param {string} book.author - The author of the book.
 * @param {string} book.isbn - The ISBN of the book.
 * @returns {boolean} - True if the book was added, false if the book already exists.
 */
exports.addBook = addBook;

/**
 * Removes a book from the collection by ISBN.
 * @param {string} isbn - The ISBN of the book to remove.
 * @returns {boolean} - True if the book was removed, false if the book was not found.
 */
exports.removeBook = removeBook;

/**
 * Searches for books by title.
 * @param {string} title - The title to search for.
 * @returns {Array} - An array of books that match the title.
 */
exports.searchByTitle = searchByTitle;

/**
 * Searches for books by author.
 * @param {string} author - The author to search for.
 * @returns {Array} - An array of books that match the author.
 */
exports.searchByAuthor = searchByAuthor;

// The internal book collection (not exported)
let books = [];

function addBook(book) {
    if (books.some(b => b.isbn === book.isbn)) {
        return false;
    }
    books.push(book);
    return true;
}

function removeBook(isbn) {
    const bookIndex = books.findIndex(b => b.isbn === isbn);
    if (bookIndex === -1) {
        return false;
    }
    books.splice(bookIndex, 1);
    return true;
}

function searchByTitle(title) {
    return books.filter(b => b.title.toLowerCase().includes(title.toLowerCase()));
}

function searchByAuthor(author) {
    return books.filter(b => b.author.toLowerCase().includes(author.toLowerCase()));
}

// Test cases
