console.log(addBook({ title: 'The Great Gatsby', author: 'F. Scott Fitzgerald', isbn: '1234567890' })); // false (duplicate)
console.log(removeBook('1234567890')); // true
console.log(removeBook('1234567890')); // false (already removed)
console.log(searchByTitle('1984')); // [{ title: '1984', author: 'George Orwell', isbn: '0987654321' }]
console.log(searchByAuthor('Orwell')); // [{ title: '1984', author: 'George Orwell', isbn: '0987654321' }]
