// Pagination helper module

/**
 * Calculates the pagination parameters for a database query.
 * @param {number} page - The current page number (1-indexed).
 * @param {number} size - The number of items per page.
 * @returns {object} An object containing the limit and offset.
 */
const getPagination = (page, size) => {
  const limit = size;
  const offset = (page - 1) * limit;
  return { limit, offset };
};

/**
 * Formats the paginated data for the frontend.
 * @param {object} data - The result of the database query.
 * @param {number} page - The current page number (1-indexed).
 * @param {number} limit - The number of items per page.
 * @returns {object} An object containing the count, rows, currentPage, and totalPages.
 */
const getPagingData = (data, page, limit) => {
  const { count, rows } = data;
  const currentPage = page;
  const totalPages = Math.ceil(count / limit);
  return { count, rows, currentPage, totalPages };
};

module.exports = {
  getPagination,
  getPagingData
};

// Test cases
const assert = require('assert');

// Test getPagination function
const paginationTest1 = getPagination(1, 10);
assert.deepStrictEqual(paginationTest1, { limit: 10, offset: 0 }, 'Test 1 failed');

const paginationTest2 = getPagination(3, 20);
assert.deepStrictEqual(paginationTest2, { limit: 20, offset: 40 }, 'Test 2 failed');

