const BagSchema = new Schema({
    _id: { id: false },
    price: Number,
    weight: Number,
    dimensions: String,
});

const BaggageSchema = new Schema({
    _id: { id: false },
    checked: BagSchema,
    cabin: BagSchema,
});

/**
 * Calculates the total cost of baggage for a passenger's trip.
 * @param {Array} baggageArray - An array of Baggage objects.
 * @returns {Number} - The total cost of all baggage.
 */
function calculateTotalBaggageCost(baggageArray) {
    return baggageArray.reduce((totalCost, baggage) => {
        const checkedCost = baggage.checked && baggage.checked.price ? baggage.checked.price : 0;
        const cabinCost = baggage.cabin && baggage.cabin.price ? baggage.cabin.price : 0;
        return totalCost + checkedCost + cabinCost;
    }, 0);
}

/**
 * Formats the dimensions of a baggage item.
 * @param {Object} bag - A BagSchema object.
 * @returns {String} - The formatted dimensions of the baggage.
 */
function formatBaggageDimensions(bag) {
    if (!bag || !bag.dimensions) {
        return '';
    }
    return bag.dimensions.trim() + ' cm';
}

