function fetchAndDisplayUserData(serverUrl, apiKey) {
  // Construct the URL with the API key
  const urlWithApiKey = `${serverUrl}/users?apikey=${apiKey}`;

  // Make an AJAX GET request to fetch user data
  $.getJSON(urlWithApiKey, function (data) {
    // Check if the response status is success
    if (data.status === 0 && data.status_message === "Success") {
      // Extract user data
      const users = data.users.data;
      const fields = data.users.fields;

      // Create a table element
      const table = $('<table>').addClass('user-table');
      const thead = $('<thead>');
      const tbody = $('<tbody>');

      // Create table header row
      const headerRow = $('<tr>');
      fields.forEach(field => {
        headerRow.append($('<th>').text(field));
      });
      thead.append(headerRow);

      // Populate table body with user data
      users.forEach(user => {
        const row = $('<tr>');
        user.forEach((value, index) => {
          row.append($('<td>').text(value));
        });
        tbody.append(row);
      });

      // Append thead and tbody to the table
      table.append(thead).append(tbody);

      // Append the table to the admin dashboard container
      $('#admin-dashboard').append(table);
