var mongoose = require('mongoose');
var passport = require('passport');
var LocalStrategy = require('passport-local').Strategy;
var TwitterStrategy = require('passport-twitter').Strategy;
var FacebookStrategy = require('passport-facebook').Strategy;
var GitHubStrategy = require('passport-github').Strategy;
var GoogleStrategy = require('passport-google-oauth20').Strategy;
var User = mongoose.model('User');
var config = require('./config');

module.exports = function(passport) {
    // Serialize sessions
    passport.serializeUser(function(user, done) {
        done(null, user.id);
    });

    passport.deserializeUser(function(id, done) {
        User.findById(id, function(err, user) {
            done(err, user);
        });
    });

    // Use local strategy
    passport.use(new LocalStrategy({
            usernameField: 'username',
            passwordField: 'password'
        },
        function(username, password, done) {
            User.findOne({ username: username }, function(err, user) {
                if (err) {
                    return done(err);
                }
                if (!user) {
                    return done(null, false, { message: 'Unknown user' });
                }
                if (!user.authenticate(password)) {
                    return done(null, false, { message: 'Invalid password' });
                }
                return done(null, user);
            });
        }
    ));

    // Use Twitter strategy
    passport.use(new TwitterStrategy({
            consumerKey: config.twitter.consumerKey,
            consumerSecret: config.twitter.consumerSecret,
            callbackURL: config.twitter.callbackURL
        },
        function(token, tokenSecret, profile, done) {
            User.findOrCreate({ twitterId: profile.id }, function(err, user) {
                return done(err, user);
            });
        }
    ));

    // Use Facebook strategy
    passport.use(new FacebookStrategy({
            clientID: config.facebook.clientID,
            clientSecret: config.facebook.clientSecret,
            callbackURL: config.facebook.callbackURL
        },
        function(accessToken, refreshToken, profile, done) {
            User.findOrCreate({ facebookId: profile.id }, function(err, user) {
                return done(err, user);
            });
        }
    ));

    // Use GitHub strategy
    passport.use(new GitHubStrategy({
            clientID: config.github.clientID,
            clientSecret: config.github.clientSecret,
            callbackURL: config.github.callbackURL
        },
        function(accessToken, refreshToken, profile, done) {
            User.findOrCreate({ githubId: profile.id }, function(err, user) {
                return done(err, user);
            });
        }
    ));

    // Use Google strategy
    passport.use(new GoogleStrategy({
            clientID: config.google.clientID,
            clientSecret: config.google.clientSecret,
            callbackURL: config.google.callbackURL
        },
        function(accessToken, refreshToken, profile, done) {
            User.findOrCreate({ googleId: profile.id }, function(err, user) {
                return done(err, user);
            });
        }
    ));
};

// Test cases
// Assuming you have a test framework like Mocha and Chai installed
describe('Passport Authentication Strategies', function() {
    it('should serialize and deserialize a user', function(done) {
        var user = { id: '12345' };
        passport.serializeUser(function(user, done) {
            done(null, user.id);
        });
        passport.deserializeUser(function(id, done) {
            done(null, { id: id });
        });
        passport.serializeUser(user, function(err, id) {
            if (err) return done(err);
            id.should.equal('12345');
            passport.deserializeUser(id, function(err, user) {
                if (err) return done(err);
                user.should.deep.equal({ id: '12345' });
                done();
            });
        });
    });

    // Additional test cases would be required to mock the strategy behavior and User model interactions
});
