  method: {
    type: String,
    enum: ["local", "google", "facebook"],
    required: true
  },
  local: {
    email: {
      type: String,
      lowercase: true
    },
    password: {
      type: String
    }
  },
  google: {
    id: {
      type: String
    },
    email: {
      type: String,
      lowercase: true
    }
  },
  facebook: {
    id: {
      type: String
    },
    email: {
      type: String,
      lowercase: true
    }
  },
  isadmin: {
    type: Boolean,
    default: false
  },
  isactive: {
    type: Boolean,
    default: true
  },
  isverified: {
    type: Boolean,
    default: false
  },
  osu_userid: {
    type: Number
  },
  date: {
    type: Date,
    default: Date.now
  }
});

// Pre-save hook to hash the password before saving it to the database.
userSchema.pre("save", async function(next) {
  try {
    if (this.method !== "local") {
      next();
    }
    if (!this.isModified("local.password")) return next();
    const salt = await bcrypt.genSalt(10);
    const pwHash = await bcrypt.hash(this.local.password, salt);
    this.local.password = pwHash;
    next();
  } catch (err) {
    next(err);
  }
});

// Method to validate the password for login.
userSchema.methods.isValidPassword = async function(newPassword) {
  try {
    return await bcrypt.compare(newPassword, this.local.password);
  } catch (err) {
    throw new Error(err);
  }
};

// Create a model.
