const fs = require('fs');
const path = require('path');

/**
 * Dynamically loads modules specified in the paths array.
 * @param {string[]} modulePaths - An array of relative paths to JavaScript modules.
 * @returns {Promise<any[]>} A promise that resolves to an array of imported modules.
 */
function loadModules(modulePaths) {
  return new Promise((resolve, reject) => {
    const modules = [];
    for (const modulePath of modulePaths) {
      try {
        // Check if the file exists before attempting to require it
        if (!fs.existsSync(path.resolve(modulePath))) {
          throw new Error(`Module not found: ${modulePath}`);
        }
        const module = require(modulePath);
        modules.push(module);
      } catch (error) {
        reject(error);
        return;
      }
    }
    resolve(modules);
  });
}

