 * @returns {Promise<Object>} - An object with words as keys and spell check results as values.
 */
async function checkSpelling(words) {
    const promises = words.map(async word => {
        const correct = await nodehun.spell(word);
        const suggestions = correct ? [] : await nodehun.suggest(word);
        return [word, { correct, suggestions }];
    });
    return Object.fromEntries(await Promise.all(promises));
}

/**
 * Analyzes an array of words for morphological information.
 * @param {string[]} words - An array of words to analyze.
 * @returns {Promise<Object>} - An object with words as keys and analysis results as values.
 */
async function analyzeWords(words) {
    const promises = words.map(async word => ([word, await getParsedWordAnalysis(word)]));
    return Object.fromEntries(await Promise.all(promises));
}

async function getParsedWordAnalysis(word) {
    const analysis = await nodehun.analyze(word);
    return analysis.map(a => parseWordAnalysis(a));
}

function parseWordAnalysis(analysis) {
    return Object.fromEntries(analysis.trim()
        .split(' ')
        .map(keyValuePair => keyValuePair.split(':')));
}

module.exports = {
    checkSpelling,
    analyzeWords
};

// Test cases to verify the solution correctness
(async () => {
    try {
        // Test the checkSpelling function
        const spellingResult = await checkSpelling(['māja', 'suns', 'dators', 'televizors', 'spoks']);
        console.log('Spelling Check Result:', spellingResult);

        // Test the analyzeWords function
        const analysisResult = await analyzeWords(['māja', 'suns', 'dators']);
        console.log('Word Analysis Result:', analysisResult);
    } catch (error) {
        console.error('An error occurred:', error);
    }
})();
