/**
 * Validates naming conventions for variables, typeLikes, and enumMembers.
 * 
 * @param {Object} names - An object with arrays of names for each category.
 * @param {Array} names.variables - Array of variable names to validate.
 * @param {Array} names.typeLikes - Array of typeLike names to validate.
 * @param {Array} names.enumMembers - Array of enumMember names to validate.
 * @returns {Object} - An object with arrays of invalid names for each category.
 */
function validateNamingConventions(names) {
  const conventions = {
    variables: /^(?:[a-z]+(?:[A-Z][a-z]*)*|[A-Z]+(?:_[A-Z]+)*|[A-Z][a-z]+(?:[A-Z][a-z]*)*|_[a-z]+(?:_[a-z]+)*_?)$/,
    typeLikes: /^[A-Z][a-z]+(?:[A-Z][a-z]*)*$/,
    enumMembers: /^[A-Z]+(?:_[A-Z]+)*$/,
  };

  const stripUnderscores = name => name.replace(/^_+|_+$/g, '');

  const invalidNames = {
    variables: names.variables.filter(name => !conventions.variables.test(stripUnderscores(name))),
    typeLikes: names.typeLikes.filter(name => !conventions.typeLikes.test(stripUnderscores(name))),
    enumMembers: names.enumMembers.filter(name => !conventions.enumMembers.test(stripUnderscores(name))),
  };

  return invalidNames;
}

// Test cases
