// Importing the necessary package to get the current year
const currentYear = new Date().getFullYear();

/**
 * Calculates the age of a person given their birth year.
 * @param {number} birthYear - The birth year of the person.
 * @returns {number} The age of the person.
 */
function calculateAge(birthYear) {
    return currentYear - birthYear;
}

/**
 * Calculates the number of years left until the person retires.
 * @param {string} name - The name of the person.
 * @param {number} birthYear - The birth year of the person.
 * @returns {object|string} An object containing the retirement details or a message if already retired.
 */
function yearsUntilRetirement(name, birthYear) {
    const age = calculateAge(birthYear);
    const retirementAge = 65;
    const yearsLeft = retirementAge - age;

    if (yearsLeft > 0) {
        return {
            name: name,
            currentAge: age,
            retirementAge: retirementAge,
            yearsUntilRetirement: yearsLeft
        };
    } else {
        return `${name} is already retired.`;
    }
}

// Test cases
console.log(yearsUntilRetirement('John', 1980)); // Should return an object with retirement details
console.log(yearsUntilRetirement('Jane', 1950)); // Should return 'Jane is already retired.'
