      type: "light",
    },
  };

  const themeCustomizations = {
    palette: {
      primary: { ...defaultTheme.palette.primary, ...customizations.primary },
      secondary: { ...defaultTheme.palette.secondary, ...customizations.secondary },
      type: customizations.type || defaultTheme.palette.type,
    },
  };

  return createTheme(themeCustomizations);
}

