const fs = require('fs');
const path = require('path');
const config = require('../config/aws_config');

/**
 * Prepares the email data model by loading translations and images from the file system.
 * @param {Object} userInfo - An object containing user information and email template details.
 * @returns {Object} The updated model object or a status code of 400 in case of an error.
 */
async function prepareEmailData(userInfo) {
  const model = {
    user: null,
    textDirection: null,
    dir: null,
    language: null,
    text: null,
    logo: null,
    logoDark: null,
    emailImage: null,
    emailImageDark: null
  };

  // Reset model properties to null
  Object.keys(model).forEach((key) => { model[key] = null; });

  // Set user details
  const { name, email, templateId, language, link } = userInfo;
  model.user = { name, email, templateId, language, link };
  model.textDirection = language.slice(0, 2) === 'ar' ? 'right' : 'left';
  model.dir = language.slice(0, 2) === 'ar' ? 'rtl' : 'ltr';
  model.language = language;

  try {
    const fileName = templateId.replace(/[-]/g, '').toLowerCase();
    const efsPath = process.env.NODE_ENV === 'local' || process.env.NODE_ENV === 'test'
      ? path.join(__dirname, '..', 'email_builder', 'cms', language)
      : `/mnt/cms/${language}`;
    const translationFilePath = path.join(efsPath, `email_${fileName}.json`);
    const imagesFilePath = path.join(efsPath, 'email_images.json');

    // Load translation and images files
    const translationFile = fs.readFileSync(translationFilePath, 'utf8');
    const images = fs.readFileSync(imagesFilePath, 'utf8');
    const imageBaseUrl = `${config.s3.imagesURL}/images/`;

    // Process images
    const emailImages = Object.values(JSON.parse(images)).map((img) => {
      const src = `${imageBaseUrl}${img.filename_download}`;
      img.hide = !img.show;
      img.src = src || img.src;
      if (parseInt(img.width) > 580 || img.width === '100%') {
        img.width = '580';
        img.height = 'auto';
      }
      return img;
    });

    // Set translations and images in the model
    model.text = JSON.parse(translationFile);
    model.logo = emailImages.find((img) => img.id === 'LOGO');
    model.logoDark = emailImages.find((img) => img.id === 'LOGO_DARK');
    const emailImage = emailImages.find((img) => img.id === `${fileName.toUpperCase()}_IMAGE`);
    const emailImageDark = emailImages.find((img) => img.id === `${fileName.toUpperCase()}_IMAGE_DARK`);

    model.emailImage = emailImage || { show: false, hide: true };
    model.emailImageDark = emailImageDark || { show: false, hide: true };

    // Set email subject
    model.user.subject = model.text.subject || templateId.replace(/[-]/g, ' ').replace(/(^\w{1})|(\s+\w{1})/g, (letter) => letter.toUpperCase());

    return model;
  } catch (error) {
    console.error('---------ERROR FETCHING TRANSLATIONS', error);
    return 400;
  }
}

// Test cases
(async () => {
  try {
    const userInfo = {
      name: 'John Doe',
      email: 'john.doe@example.com',
      templateId: 'welcome-email',
      language: 'en',
      link: 'https://example.com/welcome'
    };

    const emailData = await prepareEmailData(userInfo);
    if (emailData !== 400) {
      console.log('Email data prepared successfully:', emailData);
    } else {
      console.log('Failed to prepare email data.');
    }
  } catch (error) {
    console.error('An error occurred:', error);
  }
})();
