const assert = require('assert');

/**
 * Generates an ASCII representation of a Christmas tree.
 * 
 * @param {number|string} height - The height of the tree.
 * @returns {string|null} The ASCII tree or null if the height is less than 3.
 * @throws {Error} If the input is not a number or a string that can be converted to a number.
 */
function generateChristmasTree(height) {
    if (typeof height === 'string') {
        height = parseInt(height, 10);
    }
    if (typeof height !== 'number' || isNaN(height)) {
        throw new Error('TYPE_ERROR');
    }
    if (height < 3) {
        return null;
    }

    let tree = '';
    for (let i = 0; i < height - 1; i++) {
        tree += ' '.repeat(height - i - 2) + '*'.repeat(i * 2 + 1) + ' '.repeat(height - i - 2) + '\n';
    }
    tree += ' '.repeat(height - 2) + '|' + ' '.repeat(height - 2) + '\n';
    return tree;
}

// Test cases
