    '   *   \n' +
    '  ***  \n' +
    ' ***** \n' +
    '*******\n' +
    '   |   \n';

assert.strictEqual(generateChristmasTree(5), expectedTreeHeight5);
assert.strictEqual(generateChristmasTree('5'), expectedTreeHeight5);

console.log("All tests passed!");
